Future<String> _buildKieBase64UploadBodyPayload({
  required Uint8List bytes,
  required String mime,
  required String fileName,
}) async {
  const String uploadPath = '/wonderpic/references';
  if (bytes.length < 220000) {
    final String dataUri = 'data:$mime;base64,${base64Encode(bytes)}';
    return jsonEncode(<String, dynamic>{
      'base64Data': dataUri,
      'uploadPath': uploadPath,
      'fileName': fileName,
    });
  }
  final Uint8List safeBytes = Uint8List.fromList(bytes);
  return Isolate.run<String>(() {
    final String dataUri = 'data:$mime;base64,${base64Encode(safeBytes)}';
    return jsonEncode(<String, dynamic>{
      'base64Data': dataUri,
      'uploadPath': uploadPath,
      'fileName': fileName,
    });
  });
}

