class WonderPicAuthBootstrap extends StatefulWidget {
  const WonderPicAuthBootstrap({super.key});

  @override
  State<WonderPicAuthBootstrap> createState() => _WonderPicAuthBootstrapState();
}

class _WonderPicAuthBootstrapState extends State<WonderPicAuthBootstrap> {
  late Future<FirebaseApp> _firebaseInitFuture;
  bool _continueWithoutSignIn = false;

  @override
  void initState() {
    super.initState();
    _firebaseInitFuture = Firebase.initializeApp(
      options: DefaultFirebaseOptions.currentPlatform,
    );
  }

  void _retryInit() {
    setState(() {
      _firebaseInitFuture = Firebase.initializeApp(
        options: DefaultFirebaseOptions.currentPlatform,
      );
    });
  }

  void _continueAsGuest() {
    if (!mounted) return;
    setState(() {
      _continueWithoutSignIn = true;
    });
  }

  @override
  Widget build(BuildContext context) {
    return FutureBuilder<FirebaseApp>(
      future: _firebaseInitFuture,
      builder: (context, snapshot) {
        if (snapshot.connectionState != ConnectionState.done) {
          return const Scaffold(
            body: Center(child: CircularProgressIndicator()),
          );
        }

        if (snapshot.hasError) {
          return _FirebaseSetupErrorScreen(
            error: snapshot.error,
            onRetry: _retryInit,
          );
        }

        return StreamBuilder<User?>(
          stream: FirebaseAuth.instance.authStateChanges(),
          builder: (context, authSnapshot) {
            if (authSnapshot.connectionState == ConnectionState.waiting) {
              return const Scaffold(
                body: Center(child: CircularProgressIndicator()),
              );
            }
            if (authSnapshot.data == null && !_continueWithoutSignIn) {
              return WonderPicAuthScreen(
                onContinueWithoutSignIn: _continueAsGuest,
              );
            }
            return const WonderPicOnboardingScreen();
          },
        );
      },
    );
  }
}

