                ),
              ),
              const SizedBox(height: 18),
              ElevatedButton(
                onPressed: onRetry,
                style: ElevatedButton.styleFrom(
                  backgroundColor: const Color(0xFFE6F24A),
                  foregroundColor: const Color(0xFF19191A),
                ),
                child: const Text('Retry'),
              ),
            ],
          ),
        ),
      ),
    );
  }
}

class WonderPicAuthScreen extends StatefulWidget {
  const WonderPicAuthScreen({
    super.key,
    this.onContinueWithoutSignIn,
  });

  final VoidCallback? onContinueWithoutSignIn;

  @override
  State<WonderPicAuthScreen> createState() => _WonderPicAuthScreenState();
}

class _WonderPicAuthScreenState extends State<WonderPicAuthScreen> {
  final TextEditingController _emailController = TextEditingController();
  final TextEditingController _passwordController = TextEditingController();
  final TextEditingController _confirmController = TextEditingController();
  bool _isLogin = true;
  bool _isBusy = false;
  String? _errorText;
  late final GoogleSignIn _googleSignIn;

  @override
  void dispose() {
    _emailController.dispose();
    _passwordController.dispose();
    _confirmController.dispose();
    super.dispose();
  }

  @override
  void initState() {
    super.initState();
    _googleSignIn = GoogleSignIn(
      clientId: defaultTargetPlatform == TargetPlatform.iOS
          ? DefaultFirebaseOptions.ios.iosClientId
          : null,
    );
  }

  void _setBusy(bool value) {
    if (!mounted) {
      return;
    }
    setState(() {
      _isBusy = value;
    });
  }

  void _setError(String? message) {
    if (!mounted) {
      return;
    }
    setState(() {
      _errorText = message;
    });
  }

  Future<void> _submitEmailPassword() async {
    final String email = _emailController.text.trim();
    final String password = _passwordController.text;
    final String confirm = _confirmController.text;

    if (email.isEmpty || password.isEmpty) {
      _setError('Email and password are required.');
      return;
    }
    if (!_isLogin && password != confirm) {
      _setError('Password confirmation does not match.');
      return;
    }

    _setError(null);
    _setBusy(true);
    try {
      if (_isLogin) {
        await FirebaseAuth.instance.signInWithEmailAndPassword(
          email: email,
          password: password,
        );
      } else {
        await FirebaseAuth.instance.createUserWithEmailAndPassword(
          email: email,
          password: password,
        );
      }
    } on FirebaseAuthException catch (e) {
      _setError(e.message ?? 'Authentication failed.');
    } catch (_) {
      _setError('Authentication failed. Please try again.');
    } finally {
      _setBusy(false);
    }
  }

  Future<void> _signInWithGoogle() async {
    _setError(null);
    _setBusy(true);
    try {
      final GoogleSignInAccount? googleUser = await _googleSignIn.signIn();
      if (googleUser == null) {
        return;
      }

      final GoogleSignInAuthentication googleAuth =
          await googleUser.authentication;
      final OAuthCredential credential = GoogleAuthProvider.credential(
        accessToken: googleAuth.accessToken,
        idToken: googleAuth.idToken,
      );

      await FirebaseAuth.instance.signInWithCredential(credential);
    } on FirebaseAuthException catch (e) {
      _setError('Google sign-in failed (${e.code}): ${e.message ?? 'Unknown'}');
    } on PlatformException catch (e) {
      _setError(
        'Google sign-in failed (${e.code}): '
        '${e.message ?? 'Unknown'}'
        '${e.details != null ? ' | ${e.details}' : ''}',
      );
    } catch (e) {
      _setError('Google sign-in failed: $e');
    } finally {
      _setBusy(false);
    }
  }

  @override
  Widget build(BuildContext context) {
    return Scaffold(
      backgroundColor: const Color(0xFF23262C),
      body: SafeArea(
        child: Center(
          child: ConstrainedBox(
            constraints: const BoxConstraints(maxWidth: 420),
            child: SingleChildScrollView(
              padding: const EdgeInsets.fromLTRB(20, 24, 20, 24),
              child: Container(
                padding: const EdgeInsets.fromLTRB(18, 18, 18, 18),
                decoration: BoxDecoration(
                  color: const Color(0xFF1E1F22),
                  borderRadius: BorderRadius.circular(20),
                  border: Border.all(color: const Color(0xFF3D4047)),
                ),
                child: Column(
                  crossAxisAlignment: CrossAxisAlignment.start,
                  children: [
                    const Text(
                      'WonderPic',
                      style: TextStyle(
                        color: Color(0xFFF3F3F2),
                        fontSize: 28,
                        fontWeight: FontWeight.w800,
                      ),
                    ),
                    const SizedBox(height: 6),
                    Text(
                      _isLogin
                          ? 'Sign in to continue'
                          : 'Create your account to continue',
                      style: const TextStyle(
                        color: Color(0xFFB8B7B5),
                        fontSize: 14,
                        fontWeight: FontWeight.w600,
                      ),
                    ),
                    const SizedBox(height: 18),
                    TextField(
                      controller: _emailController,
                      keyboardType: TextInputType.emailAddress,
                      style: const TextStyle(color: Color(0xFFF3F3F2)),
                      decoration: _authInputDecoration('Email'),
                    ),
                    const SizedBox(height: 10),
                    TextField(
                      controller: _passwordController,
                      obscureText: true,
                      style: const TextStyle(color: Color(0xFFF3F3F2)),
                      decoration: _authInputDecoration('Password'),
                    ),
                    if (!_isLogin) ...[
                      const SizedBox(height: 10),
                      TextField(
                        controller: _confirmController,
                        obscureText: true,
                        style: const TextStyle(color: Color(0xFFF3F3F2)),
                        decoration: _authInputDecoration('Confirm Password'),
                      ),
                    ],
                    if (_errorText != null) ...[
                      const SizedBox(height: 10),
                      Text(
                        _errorText!,
                        style: const TextStyle(
                          color: Color(0xFFFF8A8A),
                          fontSize: 12.5,
                          fontWeight: FontWeight.w600,
                        ),
                      ),
                    ],
                    const SizedBox(height: 14),
                    SizedBox(
                      width: double.infinity,
                      child: ElevatedButton(
                        onPressed: _isBusy ? null : _submitEmailPassword,
                        style: ElevatedButton.styleFrom(
                          backgroundColor: const Color(0xFFE6F24A),
                          foregroundColor: const Color(0xFF19191A),
                          disabledBackgroundColor: const Color(0xFF8D9347),
                          minimumSize: const Size.fromHeight(48),
                          shape: RoundedRectangleBorder(
                            borderRadius: BorderRadius.circular(12),
                          ),
                        ),
                        child: _isBusy
                            ? const SizedBox(
                                width: 18,
                                height: 18,
                                child: CircularProgressIndicator(
                                  strokeWidth: 2,
                                  color: Color(0xFF19191A),
                                ),
                              )
                            : Text(
                                _isLogin ? 'Login' : 'Create Account',
                                style: const TextStyle(
                                  fontWeight: FontWeight.w800,
                                  fontSize: 14,
                                ),
                              ),
                      ),
                    ),
                    const SizedBox(height: 10),
                    SizedBox(
                      width: double.infinity,
                      child: OutlinedButton.icon(
                        onPressed: _isBusy ? null : _signInWithGoogle,
                        icon: const Icon(Icons.g_mobiledata, size: 24),
                        label: const Text('Continue with Google'),
                        style: OutlinedButton.styleFrom(
                          foregroundColor: const Color(0xFFF3F3F2),
                          side: const BorderSide(color: Color(0xFF3D4047)),
                          minimumSize: const Size.fromHeight(48),
                          shape: RoundedRectangleBorder(
                            borderRadius: BorderRadius.circular(12),
                          ),
                        ),
                      ),
                    ),
                    const SizedBox(height: 8),
                    SizedBox(
                      width: double.infinity,
                      child: TextButton(
                        onPressed:
                            _isBusy ? null : widget.onContinueWithoutSignIn,
                        style: TextButton.styleFrom(
                          foregroundColor: const Color(0xFFF3F3F2),
                          minimumSize: const Size.fromHeight(44),
                          shape: RoundedRectangleBorder(
                            borderRadius: BorderRadius.circular(12),
                            side: const BorderSide(color: Color(0xFF3D4047)),
                          ),
                        ),
                        child: const Text(
                          'Continue without sign in',
                          style: TextStyle(
                            fontWeight: FontWeight.w700,
                            fontSize: 14,
                          ),
                        ),
                      ),
                    ),
                    const SizedBox(height: 8),
                    Align(
                      alignment: Alignment.center,
                      child: TextButton(
                        onPressed: _isBusy
                            ? null
                            : () {
                                setState(() {
                                  _isLogin = !_isLogin;
                                  _errorText = null;
                                });
                              },
                        child: Text(
                          _isLogin
                              ? "Don't have an account? Sign up"
                              : 'Already have an account? Login',
                          style: const TextStyle(
                            color: Color(0xFFE6F24A),
                            fontWeight: FontWeight.w700,
                          ),
                        ),
                      ),
                    ),
                  ],
                ),
              ),
            ),
          ),
        ),
      ),
    );
  }

  InputDecoration _authInputDecoration(String label) {
    return InputDecoration(
      labelText: label,
      labelStyle: const TextStyle(color: Color(0xFF9D9C99)),
      filled: true,
      fillColor: const Color(0xFF181A1E),
      enabledBorder: OutlineInputBorder(
        borderRadius: BorderRadius.circular(12),
        borderSide: const BorderSide(color: Color(0xFF3D4047)),
      ),
      focusedBorder: OutlineInputBorder(
        borderRadius: BorderRadius.circular(12),
        borderSide: const BorderSide(color: Color(0xFFE6F24A)),
      ),
    );
  }
}

