enum _KieVideoModelVariant {
  seedance2Pro,
  seedance2Fast,
  sora2Medium,
  sora2High,
  veo31Fast,
  veo31Pro,
  kling30_720p,
  kling30_1080p,
}

extension _KieVideoModelVariantUi on _KieVideoModelVariant {
  String get label {
    switch (this) {
      case _KieVideoModelVariant.seedance2Pro:
        return 'Seedance 2 Pro';
      case _KieVideoModelVariant.seedance2Fast:
        return 'Seedance 2 Fast';
      case _KieVideoModelVariant.sora2Medium:
        return 'Sora 2 Medium';
      case _KieVideoModelVariant.sora2High:
        return 'Sora 2 High';
      case _KieVideoModelVariant.veo31Fast:
        return 'Veo 3.1 Fast';
      case _KieVideoModelVariant.veo31Pro:
        return 'Veo 3.1 Pro';
      case _KieVideoModelVariant.kling30_720p:
        return 'Kling 3.0 720p';
      case _KieVideoModelVariant.kling30_1080p:
        return 'Kling 3.0 1080p';
    }
  }

  IconData get icon {
    switch (this) {
      case _KieVideoModelVariant.seedance2Pro:
      case _KieVideoModelVariant.seedance2Fast:
        return Icons.movie_filter_outlined;
      case _KieVideoModelVariant.sora2Medium:
      case _KieVideoModelVariant.sora2High:
        return Icons.auto_awesome_motion_outlined;
      case _KieVideoModelVariant.veo31Fast:
      case _KieVideoModelVariant.veo31Pro:
        return Icons.smart_display_outlined;
      case _KieVideoModelVariant.kling30_720p:
      case _KieVideoModelVariant.kling30_1080p:
        return Icons.movie_creation_outlined;
    }
  }

  int get costPerVideoCredits {
    switch (this) {
      case _KieVideoModelVariant.seedance2Fast:
        return 90;
      case _KieVideoModelVariant.seedance2Pro:
        return 140;
      case _KieVideoModelVariant.sora2Medium:
        return 120;
      case _KieVideoModelVariant.sora2High:
        return 180;
      case _KieVideoModelVariant.veo31Fast:
        return 60;
      case _KieVideoModelVariant.veo31Pro:
        return 120;
      case _KieVideoModelVariant.kling30_720p:
        return 75;
      case _KieVideoModelVariant.kling30_1080p:
        return 120;
    }
  }

  bool get usesVeoEndpoint {
    switch (this) {
      case _KieVideoModelVariant.veo31Fast:
      case _KieVideoModelVariant.veo31Pro:
        return true;
      default:
        return false;
    }
  }
}

enum _KieVideoAspectPreset {
  auto,
  square,
  portrait,
  story,
  cinematic,
}

extension _KieVideoAspectPresetUi on _KieVideoAspectPreset {
  String get label {
    switch (this) {
      case _KieVideoAspectPreset.auto:
        return 'Auto';
      case _KieVideoAspectPreset.square:
        return 'Square';
      case _KieVideoAspectPreset.portrait:
        return 'Portrait';
      case _KieVideoAspectPreset.story:
        return 'Story';
      case _KieVideoAspectPreset.cinematic:
        return 'Cinematic';
    }
  }

  String get klingAspectRatio {
    switch (this) {
      case _KieVideoAspectPreset.auto:
        return 'auto';
      case _KieVideoAspectPreset.square:
        return '1:1';
      case _KieVideoAspectPreset.portrait:
      case _KieVideoAspectPreset.story:
        return '9:16';
      case _KieVideoAspectPreset.cinematic:
        return '16:9';
    }
  }

  String get veoAspectRatio {
    switch (this) {
      case _KieVideoAspectPreset.auto:
        return 'Auto';
      case _KieVideoAspectPreset.square:
        return 'Auto';
      case _KieVideoAspectPreset.portrait:
      case _KieVideoAspectPreset.story:
        return '9:16';
      case _KieVideoAspectPreset.cinematic:
        return '16:9';
    }
  }
}

enum _KieVeoInputMode {
  textOnly,
  imageToVideo,
  reference,
}

extension _KieVeoInputModeUi on _KieVeoInputMode {
  String get label {
    switch (this) {
      case _KieVeoInputMode.textOnly:
        return 'Text';
      case _KieVeoInputMode.imageToVideo:
        return 'Image';
      case _KieVeoInputMode.reference:
        return 'Reference';
    }
  }

  int get imageCount {
    switch (this) {
      case _KieVeoInputMode.textOnly:
        return 0;
      case _KieVeoInputMode.imageToVideo:
        return 2;
      case _KieVeoInputMode.reference:
        return 3;
    }
  }

  String get generationType {
    switch (this) {
      case _KieVeoInputMode.textOnly:
        return 'TEXT_2_VIDEO';
      case _KieVeoInputMode.imageToVideo:
        return 'FIRST_AND_LAST_FRAMES_2_VIDEO';
      case _KieVeoInputMode.reference:
        return 'REFERENCE_2_VIDEO';
    }
  }
}

class WonderPicGenerateVideoScreen extends StatefulWidget {
  const WonderPicGenerateVideoScreen({super.key});

  @override
  State<WonderPicGenerateVideoScreen> createState() =>
      _WonderPicGenerateVideoScreenState();
}

class _WonderPicGenerateVideoScreenState
    extends State<WonderPicGenerateVideoScreen> {
  static const Color _pageBg = Color(0xFF1B1E24);
  static const Color _panelBg = Color(0xFF171A20);
  static const Color _cardBg = Color(0xFF141820);
  static const Color _stroke = Color(0xFF4B4A48);
  static const Color _textMain = Color(0xFFF3F3F2);
  static const Color _textSub = Color(0xFFB8B7B5);

  final ImagePicker _picker = ImagePicker();
  final TextEditingController _promptController = TextEditingController();
  final GlobalKey<ScaffoldState> _scaffoldKey = GlobalKey<ScaffoldState>();

  _KieVideoModelVariant _selectedModel = _KieVideoModelVariant.veo31Fast;
  _KieVeoInputMode _selectedVeoInputMode = _KieVeoInputMode.textOnly;
  _KieVideoAspectPreset _selectedAspectPreset = _KieVideoAspectPreset.portrait;
  int _selectedDurationSeconds = 5;
  Uint8List? _frame1Bytes;
  Uint8List? _frame2Bytes;
  Uint8List? _frame3Bytes;

  bool _isPickingFrame1 = false;
  bool _isPickingFrame2 = false;
  bool _isPickingFrame3 = false;
  bool _isGenerating = false;
  bool _isDownloading = false;

  String? _resultVideoUrl;
  String? _statusMessage;

  static const List<_KieVideoModelVariant> _videoModelChoices =
      <_KieVideoModelVariant>[
    _KieVideoModelVariant.veo31Fast,
    _KieVideoModelVariant.veo31Pro,
    _KieVideoModelVariant.kling30_720p,
    _KieVideoModelVariant.kling30_1080p,
  ];

  String get _kieApiKey {
    const String fromDefine = String.fromEnvironment(
      'KIE_API_KEY',
      defaultValue: '',
    );
    if (fromDefine.trim().isNotEmpty) {
      return fromDefine.trim();
    }
    return _WonderPicEditorScreenState._kieEmbeddedApiKey;
  }

  @override
  void dispose() {
    _promptController.dispose();
    super.dispose();
  }

  bool get _isVeoModel => _selectedModel.usesVeoEndpoint;
  bool get _isKlingModel =>
      _selectedModel == _KieVideoModelVariant.kling30_720p ||
      _selectedModel == _KieVideoModelVariant.kling30_1080p;

  List<_KieVeoInputMode> get _availableInputModes {
    if (_isVeoModel) {
      return _KieVeoInputMode.values;
    }
    return const <_KieVeoInputMode>[
      _KieVeoInputMode.textOnly,
      _KieVeoInputMode.imageToVideo,
    ];
  }

  List<int> get _availableDurationOptions {
    if (_isKlingModel) {
      return const <int>[3, 4, 5];
    }
    if (_isVeoModel) {
      return const <int>[5, 8];
    }
    return const <int>[5];
  }

  List<_KieVideoAspectPreset> get _availableAspectPresets {
    if (_isVeoModel) {
      if (_selectedVeoInputMode == _KieVeoInputMode.reference) {
        return const <_KieVideoAspectPreset>[_KieVideoAspectPreset.cinematic];
      }
      return const <_KieVideoAspectPreset>[
        _KieVideoAspectPreset.portrait,
        _KieVideoAspectPreset.cinematic,
      ];
    }
    if (_isKlingModel) {
      return const <_KieVideoAspectPreset>[
        _KieVideoAspectPreset.auto,
        _KieVideoAspectPreset.square,
        _KieVideoAspectPreset.portrait,
        _KieVideoAspectPreset.cinematic,
      ];
    }
    return const <_KieVideoAspectPreset>[
      _KieVideoAspectPreset.auto,
      _KieVideoAspectPreset.square,
      _KieVideoAspectPreset.portrait,
      _KieVideoAspectPreset.cinematic,
    ];
  }

  List<Uint8List> get _selectedReferenceFrames {
    if (_selectedVeoInputMode == _KieVeoInputMode.textOnly) {
      return const <Uint8List>[];
    }
    final List<Uint8List> refs = <Uint8List>[
      if (_frame1Bytes != null) _frame1Bytes!,
      if (_frame2Bytes != null) _frame2Bytes!,
      if (_frame3Bytes != null) _frame3Bytes!,
    ];
    final int maxRefs =
        _selectedVeoInputMode == _KieVeoInputMode.reference ? 3 : 2;
    return refs.take(maxRefs).toList();
  }

  String get _selectedAspectRatioForKling {
    if (_selectedAspectPreset == _KieVideoAspectPreset.auto) {
      if (_frame1Bytes != null) {
        return _computeAspectFromFrame(_frame1Bytes!);
      }
      return '9:16';
    }
    return _selectedAspectPreset.klingAspectRatio;
  }

  String get _selectedAspectRatioForVeo {
    if (_selectedAspectPreset == _KieVideoAspectPreset.auto) {
      if (_frame1Bytes != null) {
        return _computeAspectFromFrame(_frame1Bytes!);
      }
      return 'Auto';
    }
    return _selectedAspectPreset.veoAspectRatio;
  }

  double get _previewAspectRatio {
    if (_selectedAspectPreset == _KieVideoAspectPreset.auto) {
      if (_frame1Bytes != null) {
        return _aspectRatioStringToDouble(
            _computeAspectFromFrame(_frame1Bytes!));
      }
      return 9 / 16;
    }
    switch (_selectedAspectPreset) {
      case _KieVideoAspectPreset.square:
        return 1.0;
      case _KieVideoAspectPreset.portrait:
      case _KieVideoAspectPreset.story:
        return 9 / 16;
      case _KieVideoAspectPreset.cinematic:
        return 16 / 9;
      case _KieVideoAspectPreset.auto:
        return 9 / 16;
    }
  }

  double _aspectRatioStringToDouble(String ratio) {
    switch (ratio) {
      case '1:1':
        return 1.0;
      case '16:9':
        return 16 / 9;
      case '9:16':
      default:
        return 9 / 16;
    }
  }

  void _normalizeVideoUiState() {
    if (!_availableInputModes.contains(_selectedVeoInputMode)) {
      _selectedVeoInputMode = _KieVeoInputMode.textOnly;
    }
    if (!_availableAspectPresets.contains(_selectedAspectPreset)) {
      _selectedAspectPreset = _availableAspectPresets.first;
    }
    if (!_availableDurationOptions.contains(_selectedDurationSeconds)) {
      _selectedDurationSeconds = _availableDurationOptions.first;
    }
    _clearExtraFramesForMode();
  }

  void _clearExtraFramesForMode() {
    if (_selectedVeoInputMode == _KieVeoInputMode.textOnly) {
      _frame1Bytes = null;
      _frame2Bytes = null;
      _frame3Bytes = null;
      return;
    }
    if (!_isVeoModel) {
      _frame3Bytes = null;
      return;
    }
    if (_selectedVeoInputMode == _KieVeoInputMode.imageToVideo) {
      _frame3Bytes = null;
    }
  }

  Future<void> _pickFrame({required int index}) async {
    if (_isGenerating) return;
    setState(() {
      if (index == 1) {
        _isPickingFrame1 = true;
      } else if (index == 2) {
        _isPickingFrame2 = true;
      } else {
        _isPickingFrame3 = true;
      }
      _statusMessage = null;
    });
    try {
      final XFile? picked = await _picker.pickImage(
        source: ImageSource.gallery,
        imageQuality: 100,
      );
      if (picked == null) return;
      final Uint8List bytes = await picked.readAsBytes();
      if (!mounted) return;
      setState(() {
        if (index == 1) {
          _frame1Bytes = bytes;
        } else if (index == 2) {
          _frame2Bytes = bytes;
        } else {
          _frame3Bytes = bytes;
        }
      });
    } finally {
      if (mounted) {
        setState(() {
          if (index == 1) {
            _isPickingFrame1 = false;
          } else if (index == 2) {
            _isPickingFrame2 = false;
          } else {
            _isPickingFrame3 = false;
          }
        });
      }
    }
  }

  Future<void> _generateVideo() async {
    if (_isGenerating) return;
    final String prompt = _promptController.text.trim();
    if (prompt.isEmpty) {
      _showMessage('Write a prompt first.', isError: true);
      return;
    }
    final String apiKey = _kieApiKey.trim();
    if (apiKey.isEmpty) {
      _showMessage('KIE API key missing. Add --dart-define=KIE_API_KEY=...',
          isError: true);
      return;
    }

    if (_selectedVeoInputMode == _KieVeoInputMode.imageToVideo &&
        _frame1Bytes == null) {
      _showMessage('Upload Frame 1. Frame 2 is optional.', isError: true);
      return;
    }
    if (_isVeoModel &&
        _selectedVeoInputMode == _KieVeoInputMode.reference &&
        (_frame1Bytes == null ||
            _frame2Bytes == null ||
            _frame3Bytes == null)) {
      _showMessage('Upload 3 reference images for Reference mode.',
          isError: true);
      return;
    }

    _KieVideoModelVariant modelForTask = _selectedModel;
    if (_isVeoModel &&
        _selectedVeoInputMode == _KieVeoInputMode.reference &&
        _selectedModel != _KieVideoModelVariant.veo31Fast) {
      modelForTask = _KieVideoModelVariant.veo31Fast;
      setState(() {
        _selectedModel = _KieVideoModelVariant.veo31Fast;
      });
      _showMessage('Reference mode uses Veo 3.1 Fast on KIE.');
    }

    setState(() {
      _isGenerating = true;
      _statusMessage = 'Preparing frames...';
      _resultVideoUrl = null;
    });

    try {
      final List<Uint8List> refs = _selectedReferenceFrames;
      final List<String> uploadedRefs = <String>[];
      for (final Uint8List refBytes in refs) {
        uploadedRefs.add(await _uploadKieReferenceFile(refBytes));
      }

      if (!mounted) return;
      setState(() {
        _statusMessage = 'Creating video task...';
      });

      final String taskId = modelForTask.usesVeoEndpoint
          ? await _createKieVeoTask(
              model: modelForTask,
              prompt: prompt,
              referenceUrls: uploadedRefs,
              mode: _selectedVeoInputMode,
              durationSeconds: _selectedDurationSeconds,
              aspectRatio: _selectedAspectRatioForVeo,
            )
          : await _createKieVideoTask(
              model: modelForTask,
              prompt: prompt,
              referenceUrls: uploadedRefs,
            );

      if (!mounted) return;
      setState(() {
        _statusMessage = 'Generating video...';
      });

      final String outputUrl = modelForTask.usesVeoEndpoint
          ? await _pollKieVeoTask(taskId: taskId)
          : await _pollKieJobTask(taskId: taskId);

      if (!mounted) return;
      setState(() {
        _resultVideoUrl = outputUrl;
        _statusMessage = 'Video generated successfully.';
      });
      _showMessage('Video generated.');
    } catch (e) {
      if (!mounted) return;
      setState(() {
        _statusMessage = 'Generation failed.';
      });
      _showMessage(e.toString(), isError: true);
    } finally {
      if (mounted) {
        setState(() {
          _isGenerating = false;
        });
      }
    }
  }

  Future<void> _downloadVideo() async {
    final String? url = _resultVideoUrl;
    if (_isDownloading || url == null || url.isEmpty) return;
    setState(() {
      _isDownloading = true;
    });
    try {
      final http.Response response =
          await http.get(Uri.parse(url)).timeout(const Duration(minutes: 3));
      if (response.statusCode < 200 || response.statusCode >= 300) {
        throw StateError('Video download failed (${response.statusCode}).');
      }

      final String extension = _guessVideoExtension(
        url: url,
        contentType: response.headers['content-type'],
      );
      final String filePath =
          '${Directory.systemTemp.path}/wonderpic_video_${DateTime.now().millisecondsSinceEpoch}.$extension';
      final File file = File(filePath);
      await file.writeAsBytes(response.bodyBytes, flush: true);

      final dynamic saveResult = await ImageGallerySaverPlus.saveFile(
        file.path,
        name: 'wonderpic_video_${DateTime.now().millisecondsSinceEpoch}',
        isReturnPathOfIOS: false,
      );
      if (!_isGallerySaveSuccess(saveResult)) {
        throw StateError('Saving video to gallery failed.');
      }
      _showMessage('Video saved to gallery.');
    } catch (e) {
      _showMessage(e.toString(), isError: true);
    } finally {
      if (mounted) {
        setState(() {
          _isDownloading = false;
        });
      }
    }
  }

  Future<String> _uploadKieReferenceFile(Uint8List bytes) async {
    final Uri uri =
        Uri.parse('https://kieai.redpandaai.co/api/file-base64-upload');
    final String dataUri = _toDataUri(bytes);
    final String fileName =
        'video_ref_${DateTime.now().microsecondsSinceEpoch}.${_dataUriMime(bytes) == 'image/png' ? 'png' : 'jpg'}';
    final http.Response response = await http
        .post(
          uri,
          headers: <String, String>{
            'Authorization': 'Bearer ${_kieApiKey.trim()}',
            'Content-Type': 'application/json',
          },
          body: jsonEncode(<String, dynamic>{
            'base64Data': dataUri,
            'uploadPath': '/wonderpic/video-references',
            'fileName': fileName,
          }),
        )
        .timeout(const Duration(minutes: 2));

    final Map<String, dynamic> decoded = _decodeKieJson(
      response.bodyBytes,
      contextLabel: 'KIE file-base64-upload',
    );
    final int code = _readKieCode(decoded['code']);
    final bool hasCode = decoded.containsKey('code');
    final String message = (decoded['msg'] as String?)?.trim() ??
        (decoded['message'] as String?)?.trim() ??
        'Unknown KIE error.';
    if (response.statusCode < 200 || response.statusCode >= 300) {
      throw StateError(
          'KIE file upload failed (${response.statusCode}): $message');
    }
    if (hasCode && code != 200) {
      throw StateError('KIE file upload failed ($code): $message');
    }
    final dynamic data = decoded['data'];
    String url = '';
    if (data is Map<String, dynamic>) {
      url = ((data['downloadUrl'] as String?) ??
              (data['url'] as String?) ??
              (data['fileUrl'] as String?) ??
              (data['outputUrl'] as String?) ??
              '')
          .trim();
    } else if (data is String) {
      url = data.trim();
    }
    url = url.isNotEmpty
        ? url
        : ((decoded['downloadUrl'] as String?) ??
                (decoded['url'] as String?) ??
                (decoded['fileUrl'] as String?) ??
                '')
            .trim();
    if (url.isEmpty) {
      throw const FormatException('KIE upload returned empty file URL.');
    }
    return url;
  }

  Future<String> _createKieVideoTask({
    required _KieVideoModelVariant model,
    required String prompt,
    required List<String> referenceUrls,
  }) async {
    final Uri uri = Uri.parse('https://api.kie.ai/api/v1/jobs/createTask');
    final bool hasRefs = referenceUrls.isNotEmpty;
    final String selectedModel = _resolveKieVideoModel(
      model: model,
      hasReferenceUrls: hasRefs,
    );
    final Map<String, dynamic> input = _buildKieVideoInput(
      model: model,
      prompt: prompt,
      referenceUrls: referenceUrls,
    );

    final http.Response response = await http
        .post(
          uri,
          headers: <String, String>{
            'Authorization': 'Bearer ${_kieApiKey.trim()}',
            'Content-Type': 'application/json',
          },
          body: jsonEncode(<String, dynamic>{
            'model': selectedModel,
            'input': input,
          }),
        )
        .timeout(const Duration(minutes: 2));

    final Map<String, dynamic> decoded = _decodeKieJson(
      response.bodyBytes,
      contextLabel: 'KIE createTask (video)',
    );
    final int code = _readKieCode(decoded['code']);
    final String message =
        (decoded['msg'] as String?)?.trim() ?? 'Unknown KIE error.';
    if (response.statusCode < 200 ||
        response.statusCode >= 300 ||
        code != 200) {
      throw StateError(
        'KIE video createTask failed (${response.statusCode}): $message',
      );
    }

    final Map<String, dynamic>? data = decoded['data'] is Map<String, dynamic>
        ? decoded['data'] as Map<String, dynamic>
        : null;
    final String taskId = (data?['taskId'] as String?)?.trim() ?? '';
    if (taskId.isEmpty) {
      throw const FormatException(
          'KIE video createTask returned empty taskId.');
    }
    return taskId;
  }

  Future<String> _createKieVeoTask({
    required _KieVideoModelVariant model,
    required String prompt,
    required List<String> referenceUrls,
    required _KieVeoInputMode mode,
    required int durationSeconds,
    required String aspectRatio,
  }) async {
    final Uri uri = Uri.parse('https://api.kie.ai/api/v1/veo/generate');
    final int maxRefs = mode.imageCount;
    final List<String> refs = referenceUrls.take(maxRefs).toList();
    final String generationType = mode == _KieVeoInputMode.imageToVideo
        ? (refs.length > 1 ? 'FIRST_AND_LAST_FRAMES_2_VIDEO' : 'IMAGE_2_VIDEO')
        : mode.generationType;
    final String selectedAspectRatio =
        mode == _KieVeoInputMode.reference ? '16:9' : aspectRatio;
    final String veoModel =
        model == _KieVideoModelVariant.veo31Fast ? 'veo3_fast' : 'veo3';
    final String promptWithDurationHint =
        '$prompt\nTarget duration: ${durationSeconds}s';

    final http.Response response = await http
        .post(
          uri,
          headers: <String, String>{
            'Authorization': 'Bearer ${_kieApiKey.trim()}',
            'Content-Type': 'application/json',
          },
          body: jsonEncode(
            <String, dynamic>{
              'prompt': promptWithDurationHint,
              'model': veoModel,
              'aspect_ratio': selectedAspectRatio,
              'generationType': generationType,
              if (refs.isNotEmpty) 'imageUrls': refs,
            },
          ),
        )
        .timeout(const Duration(minutes: 2));

    final Map<String, dynamic> decoded = _decodeKieJson(
      response.bodyBytes,
      contextLabel: 'KIE veo generate',
    );
    final int code = _readKieCode(decoded['code']);
    final String message =
        (decoded['msg'] as String?)?.trim() ?? 'Unknown KIE error.';
    if (response.statusCode < 200 ||
        response.statusCode >= 300 ||
        code != 200) {
      throw StateError(
        'KIE Veo generate failed (${response.statusCode}): $message',
      );
    }
    final Map<String, dynamic>? data = decoded['data'] is Map<String, dynamic>
        ? decoded['data'] as Map<String, dynamic>
        : null;
    final String taskId = (data?['taskId'] as String?)?.trim() ?? '';
    if (taskId.isEmpty) {
      throw const FormatException('KIE Veo returned empty taskId.');
    }
    return taskId;
  }

  String _resolveKieVideoModel({
    required _KieVideoModelVariant model,
    required bool hasReferenceUrls,
  }) {
    switch (model) {
      case _KieVideoModelVariant.seedance2Pro:
        return 'bytedance/seedance-1.5-pro';
      case _KieVideoModelVariant.seedance2Fast:
        return hasReferenceUrls
            ? 'bytedance/v1-pro-fast-image-to-video'
            : 'bytedance/v1-pro-text-to-video';
      case _KieVideoModelVariant.sora2Medium:
        return hasReferenceUrls
            ? 'sora-2-image-to-video'
            : 'sora-2-text-to-video';
      case _KieVideoModelVariant.sora2High:
        return hasReferenceUrls
            ? 'sora-2-pro-image-to-video'
            : 'sora-2-pro-text-to-video';
      case _KieVideoModelVariant.kling30_720p:
      case _KieVideoModelVariant.kling30_1080p:
        return 'kling-3.0/video';
      case _KieVideoModelVariant.veo31Fast:
      case _KieVideoModelVariant.veo31Pro:
        throw ArgumentError('Veo uses dedicated endpoint.');
    }
  }

  Map<String, dynamic> _buildKieVideoInput({
    required _KieVideoModelVariant model,
    required String prompt,
    required List<String> referenceUrls,
  }) {
    final bool hasRefs = referenceUrls.isNotEmpty;
    switch (model) {
      case _KieVideoModelVariant.seedance2Pro:
        return <String, dynamic>{
          'prompt': prompt,
          if (hasRefs) 'input_urls': referenceUrls.take(2).toList(),
          'aspect_ratio': _seedanceAspectRatio,
          'resolution': '720p',
          'duration': '5',
          'fixed_lens': false,
          'generate_audio': false,
        };
      case _KieVideoModelVariant.seedance2Fast:
        return <String, dynamic>{
          'prompt': prompt,
          if (hasRefs) 'image_url': referenceUrls.first,
          'resolution': '720p',
          'duration': '5',
          'camera_fixed': false,
          'seed': -1,
          'enable_safety_checker': true,
        };
      case _KieVideoModelVariant.sora2Medium:
        return <String, dynamic>{
          'prompt': prompt,
          if (hasRefs) 'image_urls': referenceUrls.take(2).toList(),
          'aspect_ratio': _soraAspectRatio,
          'n_frames': '10',
          'size': 'standard',
          'remove_watermark': true,
          'upload_method': 's3',
        };
      case _KieVideoModelVariant.sora2High:
        return <String, dynamic>{
          'prompt': prompt,
          if (hasRefs) 'image_urls': referenceUrls.take(2).toList(),
          'aspect_ratio': _soraAspectRatio,
          'n_frames': '10',
          'size': 'high',
          'remove_watermark': true,
          'upload_method': 's3',
        };
      case _KieVideoModelVariant.kling30_720p:
      case _KieVideoModelVariant.kling30_1080p:
        return <String, dynamic>{
          'prompt': prompt,
          if (hasRefs) 'image_urls': referenceUrls.take(2).toList(),
          'mode': model == _KieVideoModelVariant.kling30_1080p ? 'pro' : 'std',
          'duration': _selectedDurationSeconds.toString(),
          'aspect_ratio': _selectedAspectRatioForKling,
          'sound': true,
          'multi_shots': false,
        };
      case _KieVideoModelVariant.veo31Fast:
      case _KieVideoModelVariant.veo31Pro:
        throw ArgumentError('Veo uses dedicated endpoint.');
    }
  }

  String get _seedanceAspectRatio {
    if (_frame1Bytes == null) return '9:16';
    return _computeAspectFromFrame(_frame1Bytes!);
  }

  String get _soraAspectRatio {
    if (_frame1Bytes == null) return 'portrait';
    final String ratio = _computeAspectFromFrame(_frame1Bytes!);
    if (ratio == '1:1') return 'square';
    if (ratio == '9:16') return 'portrait';
    return 'landscape';
  }

  String _computeAspectFromFrame(Uint8List bytes) {
    final img.Image? decoded = img.decodeImage(bytes);
    if (decoded == null) return '9:16';
    final int w = decoded.width;
    final int h = decoded.height;
    if (w <= 0 || h <= 0) return '9:16';
    final double r = w / h;
    if (r > 1.12) return '16:9';
    if (r < 0.88) return '9:16';
    return '1:1';
  }

  Future<String> _pollKieJobTask({required String taskId}) async {
    final Uri uri =
        Uri.parse('https://api.kie.ai/api/v1/jobs/recordInfo?taskId=$taskId');
    const int maxAttempts = 160;
    for (int attempt = 0; attempt < maxAttempts; attempt++) {
      final http.Response response = await http.get(
        uri,
        headers: <String, String>{
          'Authorization': 'Bearer ${_kieApiKey.trim()}',
          'Content-Type': 'application/json',
        },
      ).timeout(const Duration(seconds: 45));

      if (response.statusCode == 429 ||
          (response.statusCode >= 500 && response.statusCode < 600)) {
        await Future.delayed(const Duration(seconds: 2));
        continue;
      }
      final Map<String, dynamic> decoded = _decodeKieJson(
        response.bodyBytes,
        contextLabel: 'KIE recordInfo',
      );
      final int code = _readKieCode(decoded['code']);
      final String message =
          (decoded['msg'] as String?)?.trim() ?? 'Unknown KIE error.';
      if (response.statusCode < 200 ||
          response.statusCode >= 300 ||
          code != 200) {
        throw StateError(
            'KIE recordInfo failed (${response.statusCode}): $message');
      }
      final Map<String, dynamic>? data = decoded['data'] is Map<String, dynamic>
          ? decoded['data'] as Map<String, dynamic>
          : null;
      if (data == null) {
        await Future.delayed(const Duration(seconds: 2));
        continue;
      }
      final String state =
          (data['state'] as String? ?? '').toLowerCase().trim();
      if (state == 'success') {
        final String url = _extractKieResultUrl(data);
        if (url.isEmpty) {
          throw const FormatException(
            'KIE task completed but output URL is missing.',
          );
        }
        return url;
      }
      if (state == 'fail') {
        final String failMsg = (data['failMsg'] as String?)?.trim() ?? message;
        throw StateError('KIE generation failed: $failMsg');
      }
      await Future.delayed(const Duration(seconds: 2));
    }
    throw TimeoutException('KIE video timeout. Please try again.');
  }

  Future<String> _pollKieVeoTask({required String taskId}) async {
    final Uri uri =
        Uri.parse('https://api.kie.ai/api/v1/veo/record-info?taskId=$taskId');
    const int maxAttempts = 160;
    for (int attempt = 0; attempt < maxAttempts; attempt++) {
      final http.Response response = await http.get(
        uri,
        headers: <String, String>{
          'Authorization': 'Bearer ${_kieApiKey.trim()}',
          'Content-Type': 'application/json',
        },
      ).timeout(const Duration(seconds: 45));

      if (response.statusCode == 429 ||
          (response.statusCode >= 500 && response.statusCode < 600)) {
        await Future.delayed(const Duration(seconds: 2));
        continue;
      }

      final Map<String, dynamic> decoded = _decodeKieJson(
        response.bodyBytes,
        contextLabel: 'KIE veo record-info',
      );
      final int code = _readKieCode(decoded['code']);
      final String message =
          (decoded['msg'] as String?)?.trim() ?? 'Unknown KIE error.';
      if (response.statusCode < 200 ||
          response.statusCode >= 300 ||
          code != 200) {
        throw StateError(
            'KIE Veo record-info failed (${response.statusCode}): $message');
      }

      final Map<String, dynamic>? data = decoded['data'] is Map<String, dynamic>
          ? decoded['data'] as Map<String, dynamic>
          : null;
      if (data == null) {
        await Future.delayed(const Duration(seconds: 2));
        continue;
      }
      final int successFlag = data['successFlag'] is int
          ? data['successFlag'] as int
          : int.tryParse('${data['successFlag'] ?? ''}') ?? -1;
      final Map<String, dynamic>? responseMap =
          data['response'] is Map<String, dynamic>
              ? data['response'] as Map<String, dynamic>
              : null;
      final dynamic resultUrls = responseMap?['resultUrls'];
      if (successFlag == 1 && resultUrls is List && resultUrls.isNotEmpty) {
        final String url = resultUrls.first.toString().trim();
        if (url.isNotEmpty) return url;
      }
      final String errorMessage =
          (data['errorMessage'] as String?)?.trim() ?? '';
      if (errorMessage.isNotEmpty && successFlag == 0) {
        throw StateError('KIE Veo generation failed: $errorMessage');
      }
      await Future.delayed(const Duration(seconds: 2));
    }
    throw TimeoutException('KIE Veo timeout. Please try again.');
  }

  String _extractKieResultUrl(Map<String, dynamic> data) {
    dynamic resultJson = data['resultJson'];
    if (resultJson is String && resultJson.trim().isNotEmpty) {
      try {
        resultJson = jsonDecode(resultJson);
      } catch (_) {
        resultJson = null;
      }
    }
    if (resultJson is Map<String, dynamic>) {
      final dynamic urls = resultJson['resultUrls'];
      if (urls is List && urls.isNotEmpty) {
        final dynamic first = urls.first;
        if (first is String && first.trim().isNotEmpty) {
          return first.trim();
        }
        if (first is Map<String, dynamic>) {
          final String nestedUrl = (first['url'] as String?)?.trim() ?? '';
          if (nestedUrl.isNotEmpty) return nestedUrl;
        }
      }
    }
    final dynamic directUrls = data['resultUrls'];
    if (directUrls is List && directUrls.isNotEmpty) {
      final String first = directUrls.first.toString().trim();
      if (first.isNotEmpty) return first;
    }
    return '';
  }

  Map<String, dynamic> _decodeKieJson(
    Uint8List bodyBytes, {
    required String contextLabel,
  }) {
    final dynamic decoded = jsonDecode(utf8.decode(bodyBytes));
    if (decoded is! Map<String, dynamic>) {
      throw FormatException('$contextLabel response is invalid.');
    }
    return decoded;
  }

  int _readKieCode(dynamic value) {
    if (value is int) return value;
    if (value is String) return int.tryParse(value) ?? -1;
    return -1;
  }

  String _dataUriMime(Uint8List bytes) {
    if (bytes.length >= 12 &&
        bytes[0] == 0x89 &&
        bytes[1] == 0x50 &&
        bytes[2] == 0x4E &&
        bytes[3] == 0x47) {
      return 'image/png';
    }
    return 'image/jpeg';
  }

  String _toDataUri(Uint8List bytes) {
    final String mime = _dataUriMime(bytes);
    return 'data:$mime;base64,${base64Encode(bytes)}';
  }

  bool _isGallerySaveSuccess(dynamic result) {
    if (result is bool) return result;
    if (result is num) return result != 0;
    if (result is Map) {
      final dynamic isSuccess = result['isSuccess'] ?? result['success'];
      if (isSuccess is bool) return isSuccess;
      if (isSuccess is num) return isSuccess != 0;
      if (isSuccess is String) {
        final String normalized = isSuccess.toLowerCase().trim();
        if (normalized == 'true' || normalized == '1') return true;
      }
      final dynamic filePath = result['filePath'] ?? result['path'];
      if (filePath is String && filePath.isNotEmpty) return true;
    }
    return result != null;
  }

  String _guessVideoExtension({
    required String url,
    String? contentType,
  }) {
    final String normalizedType = (contentType ?? '').toLowerCase();
    if (normalizedType.contains('mp4')) return 'mp4';
    if (normalizedType.contains('quicktime') ||
        normalizedType.contains('mov')) {
      return 'mov';
    }
    if (normalizedType.contains('webm')) return 'webm';
    final String lowerUrl = url.toLowerCase();
    if (lowerUrl.contains('.mov')) return 'mov';
    if (lowerUrl.contains('.webm')) return 'webm';
    return 'mp4';
  }

