          'Text mode: no frames required',
          style: TextStyle(
            color: _textSub,
            fontSize: 11.5,
            fontWeight: FontWeight.w600,
          ),
        ),
      );
    }

    final List<Widget> tiles = <Widget>[
      _buildUploadTile(
        title: 'Frame 1',
        bytes: _frame1Bytes,
        isLoading: _isPickingFrame1,
        onTap: () => _pickFrame(index: 1),
        onClear: () => setState(() => _frame1Bytes = null),
      ),
      _buildUploadTile(
        title: 'Frame 2 (Optional)',
        bytes: _frame2Bytes,
        isLoading: _isPickingFrame2,
        onTap: () => _pickFrame(index: 2),
        onClear: () => setState(() => _frame2Bytes = null),
      ),
      if (_isVeoModel && _selectedVeoInputMode == _KieVeoInputMode.reference)
        _buildUploadTile(
          title: 'Frame 3',
          bytes: _frame3Bytes,
          isLoading: _isPickingFrame3,
          onTap: () => _pickFrame(index: 3),
          onClear: () => setState(() => _frame3Bytes = null),
        ),
    ];

    return Row(
      children: [
        for (int i = 0; i < tiles.length; i++) ...[
          if (i > 0) const SizedBox(width: 8),
          tiles[i],
        ],
      ],
    );
  }

