const double _oneSpaceComposerCardMinWidth = 322;
const double _oneSpaceComposerCoreExtraHeight = 198;
const double _oneSpaceComposerConnectorTopGap = 6;
const double _oneSpaceComposerConnectorDiameter = 30;
const double _oneSpaceComposerConnectorBottomGap = 8;

enum _OneSpaceConnectorSide { left, right, top, bottom }

class _OneSpaceComposerLink {
  const _OneSpaceComposerLink({
    required this.fromCardId,
    required this.toCardId,
    required this.targetSide,
  });

  final String fromCardId;
  final String toCardId;
  final _OneSpaceConnectorSide targetSide;

  @override
  bool operator ==(Object other) {
    return other is _OneSpaceComposerLink &&
        other.fromCardId == fromCardId &&
        other.toCardId == toCardId &&
        other.targetSide == targetSide;
  }

  @override
  int get hashCode => Object.hash(fromCardId, toCardId, targetSide);
}

class _OneSpaceConnectionSegment {
  const _OneSpaceConnectionSegment({
    required this.start,
    required this.end,
    this.isLive = false,
    this.isPending = false,
  });

  final Offset start;
  final Offset end;
  final bool isLive;
  final bool isPending;

  @override
  bool operator ==(Object other) {
    return other is _OneSpaceConnectionSegment &&
        other.start == start &&
        other.end == end &&
        other.isLive == isLive &&
        other.isPending == isPending;
  }

  @override
  int get hashCode => Object.hash(start, end, isLive, isPending);
}

class _OneSpacePendingLink {
  const _OneSpacePendingLink({
    required this.sourceCardId,
    required this.dropScenePoint,
    required this.targetSide,
  });

  final String sourceCardId;
  final Offset dropScenePoint;
  final _OneSpaceConnectorSide targetSide;

  @override
  bool operator ==(Object other) {
    return other is _OneSpacePendingLink &&
        other.sourceCardId == sourceCardId &&
        other.dropScenePoint == dropScenePoint &&
        other.targetSide == targetSide;
  }

  @override
  int get hashCode => Object.hash(sourceCardId, dropScenePoint, targetSide);
}

class _WonderPicOneSpaceScreenState extends State<WonderPicOneSpaceScreen>
    with TickerProviderStateMixin {
  static const Color _pageBg = Color(0xFF23262C);
  static const Color _topBarBg = Color(0xEE2A2A2A);
  static const Color _topBarStroke = Color(0xFF605E5E);
  static const double _worldSize = 16000;

  final TransformationController _cameraController = TransformationController();
  AnimationController? _cameraAnimationController;
  late final AnimationController _createMenuController;
  late final AnimationController _sizeMenuController;
  bool _cameraInitialized = false;
  bool _showCreateMenu = false;
  bool _showSizeMenu = false;
  _OneSpaceCreateAction? _sizeMenuForAction;
  Offset? _createMenuAnchorViewport;
  Offset? _sizeMenuAnchorViewport;
  int _nextComposerCardId = 1;
  String? _focusedWorkflowId;
  final List<_OneSpaceWorkflowNode> _workflowNodes = <_OneSpaceWorkflowNode>[];
  final List<_OneSpaceComposerCardNode> _composerCards =
      <_OneSpaceComposerCardNode>[];
  final List<_OneSpaceComposerLink> _composerLinks = <_OneSpaceComposerLink>[];
  _OneSpacePendingLink? _pendingLink;
  String? _activeLinkSourceCardId;
  Offset? _activeLinkScenePoint;

  Offset get _worldCenter => const Offset(_worldSize / 2, _worldSize / 2);

  @override
  void initState() {
    super.initState();
    _createMenuController = AnimationController(
      vsync: this,
      duration: const Duration(milliseconds: 340),
      reverseDuration: const Duration(milliseconds: 220),
    );
    _sizeMenuController = AnimationController(
      vsync: this,
      duration: const Duration(milliseconds: 280),
      reverseDuration: const Duration(milliseconds: 180),
    );
  }

  @override
  void dispose() {
    for (final _OneSpaceComposerCardNode node in _composerCards) {
      node.controller.dispose();
      node.focusNode.dispose();
    }
    _sizeMenuController.dispose();
    _createMenuController.dispose();
    _cameraAnimationController?.dispose();
    _cameraController.dispose();
    super.dispose();
  }

  @override
  Widget build(BuildContext context) {
    return Scaffold(
      backgroundColor: _pageBg,
      body: LayoutBuilder(
        builder: (context, constraints) {
          final Size viewport =
              Size(constraints.maxWidth, constraints.maxHeight);
          _initializeCameraIfNeeded(viewport);
          return Stack(
            children: [
              Positioned.fill(child: _buildInfiniteCanvas(viewport)),
              _buildCreateMenuOverlay(),
              _buildSizeMenuOverlay(),
              _buildTopControls(),
            ],
          );
        },
      ),
    );
  }

  Widget _buildTopControls() {
    return SafeArea(
      child: Padding(
        padding: const EdgeInsets.fromLTRB(14, 8, 14, 0),
        child: Align(
          alignment: Alignment.topCenter,
          child: Container(
            constraints: const BoxConstraints(maxWidth: 340),
            height: 58,
            padding: const EdgeInsets.symmetric(horizontal: 10, vertical: 8),
            decoration: BoxDecoration(
              color: _topBarBg,
              borderRadius: BorderRadius.circular(18),
              border: Border.all(color: _topBarStroke),
              boxShadow: const <BoxShadow>[
                BoxShadow(
                  color: Color(0x33000000),
                  blurRadius: 20,
                  spreadRadius: 0,
                  offset: Offset(0, 8),
                ),
              ],
            ),
            child: Row(
              children: [
                _buildTopCircleButton(
                  icon: Icons.person_outline_rounded,
                  onTap: () {},
                ),
                const Spacer(),
                _buildTopCircleButton(
                  icon: Icons.add_rounded,
                  filled: true,
                  buttonSize: 44,
                  iconSize: 26,
                  onTap: _toggleCreateMenu,
                ),
                const Spacer(),
                _buildTopCircleButton(
                  icon: Icons.close_rounded,
                  onTap: () => Navigator.of(context).maybePop(),
                ),
              ],
            ),
          ),
        ),
      ),
    );
  }

  Widget _buildTopCircleButton({
    required IconData icon,
    required VoidCallback onTap,
    bool filled = false,
    double buttonSize = 38,
    double iconSize = 20,
  }) {
    return Material(
      color: Colors.transparent,
      child: InkWell(
        borderRadius: BorderRadius.circular(buttonSize / 2),
        onTap: onTap,
        child: Container(
          width: buttonSize,
          height: buttonSize,
          decoration: BoxDecoration(
            color: filled ? kActiveAccent : const Color(0xFF1E1F22),
            shape: BoxShape.circle,
            border: Border.all(
              color: filled ? const Color(0x99FFFFFF) : const Color(0xFF605E5E),
            ),
            boxShadow: <BoxShadow>[
              BoxShadow(
                color:
                    filled ? const Color(0x33000000) : const Color(0x22000000),
                blurRadius: 10,
                spreadRadius: 0,
                offset: const Offset(0, 4),
              ),
            ],
          ),
          child: Icon(
            icon,
            size: iconSize,
            color: filled ? kActiveAccentForeground : const Color(0xFFF3F3F2),
          ),
        ),
      ),
    );
  }

  Widget _buildInfiniteCanvas(Size viewport) {
    final List<_OneSpaceConnectionSegment> linkSegments =
        _buildComposerLinkSegments();
    final _OneSpaceConnectionSegment? liveSegment = _buildLiveLinkSegment();
    return InteractiveViewer(
      transformationController: _cameraController,
      constrained: false,
      boundaryMargin: const EdgeInsets.all(_worldSize),
      minScale: 0.16,
      maxScale: 5.0,
      panEnabled: true,
      scaleEnabled: true,
      trackpadScrollCausesScale: true,
      scaleFactor: 180,
      clipBehavior: Clip.none,
      onInteractionStart: (_) => _stopCameraAnimation(),
      child: SizedBox(
        width: _worldSize,
        height: _worldSize,
        child: Stack(
          children: [
            const Positioned.fill(
              child: CustomPaint(
                painter: _OneSpaceStarfieldPainter(
                  background: _pageBg,
                ),
              ),
            ),
            Positioned.fill(
              child: IgnorePointer(
                child: CustomPaint(
                  painter: _OneSpaceConnectionsPainter(
                    segments: linkSegments,
                    liveSegment: liveSegment,
                  ),
                ),
              ),
            ),
            for (final _OneSpaceWorkflowNode node in _workflowNodes)
              Positioned(
                left: node.position.dx - 120,
                top: node.position.dy - 72,
                child: _OneSpaceWorkflowCard(
                  node: node,
                  focused: _focusedWorkflowId == node.id,
                  onTap: () => _focusWorkflow(node, viewport),
                ),
              ),
            for (final _OneSpaceComposerCardNode node in _composerCards)
              Builder(
                builder: (context) {
                  final Size composerSize = _composerCardSize(
                    node.action,
                    node.sizePreset,
                  );
                  return Positioned(
                    left: node.position.dx - (composerSize.width / 2),
                    top: node.position.dy - (composerSize.height / 2),
                    child: _OneSpacePromptWorkflowCard(
                      key: ValueKey<String>(node.id),
                      action: node.action,
                      sizePreset: node.sizePreset,
                      previewSize: _composerPreviewSize(
                        node.action,
                        node.sizePreset,
                      ),
                      controller: node.controller,
                      focusNode: node.focusNode,
                      onHeaderPanStart: (details) =>
                          _onComposerHeaderPanStart(node.id, details),
                      onHeaderPanUpdate: (details) =>
                          _onComposerHeaderPanUpdate(node.id, details),
                      onConnectorPanStart: (details) =>
                          _onComposerConnectorPanStart(node.id, details),
                      onConnectorPanUpdate: (details) =>
                          _onComposerConnectorPanUpdate(node.id, details),
                      onConnectorPanEnd: (details) =>
                          _onComposerConnectorPanEnd(node.id, details),
                      onOkTap: () => _onComposerOkTap(node.id),
                    ),
                  );
                },
              ),
          ],
        ),
      ),
    );
  }

  Widget _buildCreateMenuOverlay() {
    if (!_showCreateMenu && !_createMenuController.isAnimating) {
      return const SizedBox.shrink();
    }
    final Size viewport = MediaQuery.sizeOf(context);
    final EdgeInsets viewPadding = MediaQuery.viewPaddingOf(context);
    return Positioned.fill(
      child: AnimatedBuilder(
        animation: _createMenuController,
        builder: (context, _) {
          final double value = _createMenuController.value;
          return IgnorePointer(
            ignoring: value <= 0.001,
            child: Stack(
              children: [
                GestureDetector(
                  behavior: HitTestBehavior.opaque,
                  onTap: () {
                    unawaited(_closeCreateMenu());
                  },
                  child:
                      Container(color: Colors.black.withOpacity(0.16 * value)),
                ),
                _buildMenuAtAnchor(
                  child: _buildCreateMenuList(),
                  anchorViewport: _createMenuAnchorViewport,
                  menuSize: _createMenuSize,
                  viewport: viewport,
                  viewPadding: viewPadding,
                  fallbackTopPadding: 74,
                ),
              ],
            ),
          );
        },
      ),
    );
  }

  Size get _createMenuSize {
    final double itemCount = _visibleCreateActions.length.toDouble();
    return Size(220, (itemCount * 42) + ((itemCount - 1) * 7));
  }

  Widget _buildCreateMenuList() {
    final List<_OneSpaceCreateAction> actions = _visibleCreateActions;
    return Column(
      mainAxisSize: MainAxisSize.min,
      children: <Widget>[
        for (int i = 0; i < actions.length; i++) ...[
          _buildCreateMenuActionTile(actions[i], i),
          if (i < actions.length - 1) const SizedBox(height: 7),
        ],
      ],
    );
  }

  List<_OneSpaceCreateAction> get _visibleCreateActions {
    if (_pendingLink != null) {
      return const <_OneSpaceCreateAction>[
        _OneSpaceCreateAction.text,
        _OneSpaceCreateAction.image,
        _OneSpaceCreateAction.video,
      ];
    }
    return _OneSpaceCreateAction.values;
  }

  Widget _buildSizeMenuOverlay() {
    if (!_showSizeMenu && !_sizeMenuController.isAnimating) {
      return const SizedBox.shrink();
    }
    final Size viewport = MediaQuery.sizeOf(context);
    final EdgeInsets viewPadding = MediaQuery.viewPaddingOf(context);
    return Positioned.fill(
      child: AnimatedBuilder(
        animation: _sizeMenuController,
        builder: (context, _) {
          final double value = _sizeMenuController.value;
          return IgnorePointer(
            ignoring: value <= 0.001,
            child: Stack(
              children: [
                GestureDetector(
                  behavior: HitTestBehavior.opaque,
                  onTap: () {
                    unawaited(_closeSizeMenu());
                  },
                  child:
                      Container(color: Colors.black.withOpacity(0.14 * value)),
                ),
                _buildMenuAtAnchor(
                  child: _buildSizeMenuList(),
                  anchorViewport: _sizeMenuAnchorViewport,
                  menuSize: _sizeMenuSize,
                  viewport: viewport,
                  viewPadding: viewPadding,
                  fallbackTopPadding: 74,
                ),
              ],
            ),
          );
        },
      ),
    );
  }

  Size get _sizeMenuSize {
    final double itemCount = _OneSpaceMediaSize.values.length.toDouble();
    return Size(220, (itemCount * 42) + ((itemCount - 1) * 7));
  }

  Widget _buildMenuAtAnchor({
    required Widget child,
    required Offset? anchorViewport,
    required Size menuSize,
    required Size viewport,
    required EdgeInsets viewPadding,
    required double fallbackTopPadding,
  }) {
    if (anchorViewport == null) {
      return SafeArea(
        child: Align(
          alignment: Alignment.topCenter,
          child: Padding(
            padding: EdgeInsets.only(top: fallbackTopPadding),
            child: child,
          ),
        ),
      );
    }
    const double margin = 12;
    final double minY = viewPadding.top + 8;
    final double maxY =
        viewport.height - viewPadding.bottom - menuSize.height - margin;
    final double left = (anchorViewport.dx - (menuSize.width / 2))
        .clamp(margin, viewport.width - menuSize.width - margin)
        .toDouble();
    final double top = (anchorViewport.dy - (menuSize.height / 2))
        .clamp(minY, math.max(minY, maxY))
        .toDouble();
    return Positioned(
      left: left,
      top: top,
      child: child,
    );
  }

  Widget _buildSizeMenuList() {
    const List<_OneSpaceMediaSize> sizes = _OneSpaceMediaSize.values;
    return Column(
      mainAxisSize: MainAxisSize.min,
      children: <Widget>[
        for (int i = 0; i < sizes.length; i++) ...[
          _buildSizeMenuTile(sizes[i], i),
          if (i < sizes.length - 1) const SizedBox(height: 7),
        ],
      ],
    );
  }

  Widget _buildSizeMenuTile(_OneSpaceMediaSize size, int index) {
    final double start = (index * 0.13).clamp(0.0, 1.0);
    final double end = (start + 0.52).clamp(0.0, 1.0);
    final Animation<double> entry = CurvedAnimation(
      parent: _sizeMenuController,
      curve: Interval(start, end, curve: Curves.easeOutCubic),
    );
    final Animation<Offset> slide = Tween<Offset>(
      begin: const Offset(0, -0.07),
      end: Offset.zero,
    ).animate(entry);
    return FadeTransition(
      opacity: entry,
      child: SlideTransition(
        position: slide,
        child: Material(
          color: Colors.transparent,
          child: InkWell(
            borderRadius: BorderRadius.circular(11),
            onTap: () => _onSizePresetTap(size),
            child: Ink(
              width: 220,
              height: 42,
              padding: const EdgeInsets.symmetric(horizontal: 10),
              decoration: BoxDecoration(
                color: const Color(0xF12A2A2A),
                borderRadius: BorderRadius.circular(11),
                border: Border.all(color: const Color(0xFF605E5E)),
                boxShadow: const <BoxShadow>[
                  BoxShadow(
                    color: Color(0x2A000000),
                    blurRadius: 12,
                    spreadRadius: 0,
                    offset: Offset(0, 5),
                  ),
                ],
              ),
              child: Row(
                children: [
                  _buildSizeGlyph(size),
                  const SizedBox(width: 8),
                  Expanded(
                    child: Text(
                      size.title,
                      maxLines: 1,
                      overflow: TextOverflow.ellipsis,
                      style: const TextStyle(
                        color: Color(0xFFF3F3F2),
                        fontSize: 13.2,
                        fontWeight: FontWeight.w700,
                        letterSpacing: 0.1,
                      ),
                    ),
                  ),
                ],
              ),
            ),
          ),
        ),
      ),
    );
  }

  Widget _buildSizeGlyph(_OneSpaceMediaSize size) {
    final (double w, double h) = switch (size) {
      _OneSpaceMediaSize.square => (14, 14),
      _OneSpaceMediaSize.portrait => (11, 15),
      _OneSpaceMediaSize.story => (16, 10),
    };
    return Container(
      width: 20,
      height: 20,
      alignment: Alignment.center,
      child: Container(
        width: w,
        height: h,
        decoration: BoxDecoration(
          borderRadius: BorderRadius.circular(3),
          border: Border.all(
            color: const Color(0xFFB8B7B5),
            width: 1.2,
          ),
        ),
      ),
    );
  }

  Widget _buildCreateMenuActionTile(_OneSpaceCreateAction action, int index) {
    final double start = (index * 0.12).clamp(0.0, 1.0);
    final double end = (start + 0.48).clamp(0.0, 1.0);
    final Animation<double> entry = CurvedAnimation(
      parent: _createMenuController,
      curve: Interval(start, end, curve: Curves.easeOutCubic),
    );
    final Animation<Offset> slide = Tween<Offset>(
      begin: const Offset(0, -0.07),
      end: Offset.zero,
    ).animate(entry);

    return FadeTransition(
      opacity: entry,
      child: SlideTransition(
        position: slide,
        child: Material(
          color: Colors.transparent,
          child: InkWell(
            borderRadius: BorderRadius.circular(11),
            onTap: () => _onCreateActionTap(action),
            child: Ink(
              width: 220,
              height: 42,
              padding: const EdgeInsets.symmetric(horizontal: 10),
              decoration: BoxDecoration(
                color: const Color(0xF12A2A2A),
                borderRadius: BorderRadius.circular(11),
                border: Border.all(color: const Color(0xFF605E5E)),
                boxShadow: const <BoxShadow>[
                  BoxShadow(
                    color: Color(0x2A000000),
                    blurRadius: 12,
                    spreadRadius: 0,
                    offset: Offset(0, 5),
                  ),
                ],
              ),
              child: Row(
                children: [
                  Icon(
                    action.icon,
                    size: 16.5,
                    color: const Color(0xFFD4D4D3),
                  ),
                  const SizedBox(width: 8),
                  Expanded(
                    child: Text(
                      action.title,
                      maxLines: 1,
                      overflow: TextOverflow.ellipsis,
                      style: const TextStyle(
                        color: Color(0xFFF3F3F2),
                        fontSize: 13.2,
                        fontWeight: FontWeight.w700,
                        letterSpacing: 0.1,
                      ),
                    ),
                  ),
                ],
              ),
            ),
          ),
        ),
      ),
    );
  }

  void _toggleCreateMenu() {
    if (_showCreateMenu) {
      unawaited(_closeCreateMenu());
      return;
    }
    if (_showSizeMenu) {
      unawaited(_closeSizeMenu());
    }
    _openCreateMenu();
  }

  void _openCreateMenu({
    Offset? anchorViewport,
    _OneSpacePendingLink? pendingLink,
  }) {
    setState(() {
      _showCreateMenu = true;
      _createMenuAnchorViewport = anchorViewport;
      _pendingLink = pendingLink;
    });
    _createMenuController.forward(from: 0);
  }

  Future<void> _closeCreateMenu({bool keepPendingLink = false}) async {
    if (!_showCreateMenu) return;
    await _createMenuController.reverse();
    if (!mounted) return;
    setState(() {
      _showCreateMenu = false;
      _createMenuAnchorViewport = null;
      if (!keepPendingLink) {
        _pendingLink = null;
      }
    });
  }

  Future<void> _onCreateActionTap(_OneSpaceCreateAction action) async {
    final _OneSpacePendingLink? pendingLink = _pendingLink;
    final Offset? anchorViewport = _createMenuAnchorViewport;
    await _closeCreateMenu(keepPendingLink: true);
    if (!mounted) return;
    if (action == _OneSpaceCreateAction.upload) {
      _pendingLink = null;
      return;
    }
    if (action == _OneSpaceCreateAction.text) {
      _addComposerWorkflowCard(
        action,
        null,
        sceneAnchor: pendingLink?.dropScenePoint,
        linkSourceCardId: pendingLink?.sourceCardId,
        linkTargetSide: pendingLink?.targetSide,
      );
      _pendingLink = null;
      return;
    }
    _openSizeMenu(
      action,
      anchorViewport: anchorViewport,
    );
  }

  void _openSizeMenu(
    _OneSpaceCreateAction action, {
    Offset? anchorViewport,
  }) {
    setState(() {
      _showSizeMenu = true;
      _sizeMenuForAction = action;
      _sizeMenuAnchorViewport = anchorViewport;
    });
    _sizeMenuController.forward(from: 0);
  }

  Future<void> _closeSizeMenu({bool keepPendingLink = false}) async {
    if (!_showSizeMenu) return;
    await _sizeMenuController.reverse();
    if (!mounted) return;
    setState(() {
      _showSizeMenu = false;
      _sizeMenuForAction = null;
      _sizeMenuAnchorViewport = null;
      if (!keepPendingLink) {
        _pendingLink = null;
      }
    });
  }

  Future<void> _onSizePresetTap(_OneSpaceMediaSize size) async {
    final _OneSpaceCreateAction? action = _sizeMenuForAction;
    final _OneSpacePendingLink? pendingLink = _pendingLink;
    await _closeSizeMenu(keepPendingLink: true);
    if (!mounted || action == null) return;
    _addComposerWorkflowCard(
      action,
      size,
      sceneAnchor: pendingLink?.dropScenePoint,
      linkSourceCardId: pendingLink?.sourceCardId,
      linkTargetSide: pendingLink?.targetSide,
    );
    _pendingLink = null;
  }

  void _addComposerWorkflowCard(
    _OneSpaceCreateAction action,
    _OneSpaceMediaSize? size, {
    Offset? sceneAnchor,
    String? linkSourceCardId,
    _OneSpaceConnectorSide? linkTargetSide,
  }) {
    final Size viewport = MediaQuery.sizeOf(context);
    final EdgeInsets viewPadding = MediaQuery.viewPaddingOf(context);
    final Size cardSize = _composerCardSize(action, size);
    late final Offset clampedScenePoint;
    if (sceneAnchor != null) {
      clampedScenePoint = _clampComposerCenter(sceneAnchor, cardSize);
    } else {
      final double targetY =
          viewPadding.top + 8 + 58 + 16 + (cardSize.height / 2);
      final int slotIndex = _composerCards.length % 3;
      final double xShift = switch (slotIndex) {
        0 => 0,
        1 => -90,
        _ => 90,
      };
      final Offset targetInViewport = Offset(
        (viewport.width / 2) + xShift,
        targetY.clamp(
          (cardSize.height / 2) + 10,
          viewport.height - (cardSize.height / 2) - 10,
        ),
      );
      final Offset scenePoint = _scenePointFromViewport(targetInViewport);
      clampedScenePoint = _clampComposerCenter(scenePoint, cardSize);
    }
    final _OneSpaceComposerCardNode newNode = _OneSpaceComposerCardNode(
      id: 'composer_${_nextComposerCardId++}',
      action: action,
      sizePreset: size,
      position: clampedScenePoint,
      controller: TextEditingController(),
      focusNode: FocusNode(),
    );
    setState(() {
      _composerCards.add(newNode);
      if (linkSourceCardId != null && linkTargetSide != null) {
        _composerLinks.add(
          _OneSpaceComposerLink(
            fromCardId: linkSourceCardId,
            toCardId: newNode.id,
            targetSide: linkTargetSide,
          ),
        );
      }
    });
    if (_composerCards.length > 1) {
      _autoZoomOutForComposers(viewport);
    }
    WidgetsBinding.instance.addPostFrameCallback((_) {
      if (!mounted) return;
      newNode.focusNode.requestFocus();
    });
  }

  void _onComposerOkTap(String id) {
    for (final _OneSpaceComposerCardNode node in _composerCards) {
      if (node.id == id) {
        node.focusNode.unfocus();
        break;
      }
    }
  }

  void _onComposerHeaderPanStart(String id, DragStartDetails details) {
    for (final _OneSpaceComposerCardNode node in _composerCards) {
      if (node.id == id) {
        node.focusNode.unfocus();
        break;
      }
    }
  }

  void _onComposerConnectorPanStart(String id, DragStartDetails details) {
    _stopCameraAnimation();
    final Offset scenePoint = _scenePointFromGlobal(details.globalPosition);
    setState(() {
      _activeLinkSourceCardId = id;
      _activeLinkScenePoint = scenePoint;
    });
  }

  void _onComposerConnectorPanUpdate(String id, DragUpdateDetails details) {
    if (_activeLinkSourceCardId != id) return;
    final Offset scenePoint = _scenePointFromGlobal(details.globalPosition);
    setState(() {
      _activeLinkScenePoint = scenePoint;
    });
  }

  void _onComposerConnectorPanEnd(String id, DragEndDetails details) {
    if (_activeLinkSourceCardId != id || _activeLinkScenePoint == null) {
      setState(() {
        _activeLinkSourceCardId = null;
        _activeLinkScenePoint = null;
      });
      return;
    }
    final Offset dropPoint = _activeLinkScenePoint!;
    final _OneSpaceConnectorSide targetSide = _resolveLinkTargetSide(
      sourceCardId: id,
      dropScenePoint: dropPoint,
    );
    final _OneSpacePendingLink pendingLink = _OneSpacePendingLink(
      sourceCardId: id,
      dropScenePoint: dropPoint,
      targetSide: targetSide,
    );
    final Offset menuAnchor = _viewportPointFromScene(dropPoint);
    setState(() {
      _activeLinkSourceCardId = null;
      _activeLinkScenePoint = null;
      _pendingLink = pendingLink;
      _showCreateMenu = false;
      _showSizeMenu = false;
      _createMenuAnchorViewport = null;
      _sizeMenuAnchorViewport = null;
      _sizeMenuForAction = null;
    });
    _createMenuController.stop();
    _sizeMenuController.stop();
    _openCreateMenu(
      anchorViewport: menuAnchor,
      pendingLink: pendingLink,
    );
  }

  _OneSpaceConnectorSide _resolveLinkTargetSide({
    required String sourceCardId,
    required Offset dropScenePoint,
  }) {
    final _OneSpaceComposerCardNode? source = _composerById(sourceCardId);
    if (source == null) {
      return _OneSpaceConnectorSide.top;
    }
    final Offset delta = dropScenePoint - source.position;
    if (delta.dx.abs() >= delta.dy.abs()) {
      return delta.dx >= 0
          ? _OneSpaceConnectorSide.left
          : _OneSpaceConnectorSide.right;
    }
    return delta.dy >= 0
        ? _OneSpaceConnectorSide.top
        : _OneSpaceConnectorSide.bottom;
  }

  void _onComposerHeaderPanUpdate(String id, DragUpdateDetails details) {
    final int index = _composerCards.indexWhere((item) => item.id == id);
    if (index < 0) return;
    final _OneSpaceComposerCardNode node = _composerCards[index];
    final double scale = _cameraController.value.getMaxScaleOnAxis().clamp(
          0.1,
          20.0,
        );
    final Offset worldDelta = details.delta / scale;
    final Size cardSize = _composerCardSize(node.action, node.sizePreset);
    final Offset nextCenter = node.position + worldDelta;
    final _OneSpaceComposerCardNode updated = node.copyWith(
      position: _clampComposerCenter(nextCenter, cardSize),
    );
    setState(() {
      _composerCards[index] = updated;
    });
  }

  List<_OneSpaceConnectionSegment> _buildComposerLinkSegments() {
    if (_composerLinks.isEmpty && _pendingLink == null) {
      return const <_OneSpaceConnectionSegment>[];
    }
    final Map<String, _OneSpaceComposerCardNode> byId =
        <String, _OneSpaceComposerCardNode>{
      for (final _OneSpaceComposerCardNode node in _composerCards)
        node.id: node,
    };
    final List<_OneSpaceConnectionSegment> segments =
        <_OneSpaceConnectionSegment>[];
    for (final _OneSpaceComposerLink link in _composerLinks) {
      final _OneSpaceComposerCardNode? fromNode = byId[link.fromCardId];
      final _OneSpaceComposerCardNode? toNode = byId[link.toCardId];
      if (fromNode == null || toNode == null) {
        continue;
      }
      segments.add(
        _OneSpaceConnectionSegment(
          start: _composerConnectorScenePoint(fromNode),
          end: _composerAttachmentScenePoint(toNode, link.targetSide),
        ),
      );
    }
    final _OneSpacePendingLink? pending = _pendingLink;
    if (pending != null) {
      final _OneSpaceComposerCardNode? source = byId[pending.sourceCardId];
      if (source != null) {
        segments.add(
          _OneSpaceConnectionSegment(
            start: _composerConnectorScenePoint(source),
            end: pending.dropScenePoint,
            isPending: true,
          ),
        );
      }
    }
    return segments;
  }

  _OneSpaceConnectionSegment? _buildLiveLinkSegment() {
    final String? sourceCardId = _activeLinkSourceCardId;
    final Offset? activePoint = _activeLinkScenePoint;
    if (sourceCardId == null || activePoint == null) {
      return null;
    }
    final _OneSpaceComposerCardNode? sourceNode = _composerById(sourceCardId);
    if (sourceNode == null) return null;
    return _OneSpaceConnectionSegment(
      start: _composerConnectorScenePoint(sourceNode),
      end: activePoint,
      isLive: true,
    );
  }

  void _autoZoomOutForComposers(Size viewport) {
    final double currentScale = _cameraController.value.getMaxScaleOnAxis();
    if (currentScale <= 0.31) return;
    final double targetScale = (currentScale * 0.9).clamp(0.16, 5.0);
    if ((targetScale - currentScale).abs() < 0.001) return;
    final Offset sceneCenter = _scenePointFromViewport(
      Offset(viewport.width / 2, viewport.height / 2),
    );
    final Matrix4 target = _matrixForSceneCenter(
      sceneCenter: sceneCenter,
      viewportSize: viewport,
      scale: targetScale,
    );
    _animateCameraTo(target);
  }

  Offset _scenePointFromViewport(Offset viewportPoint) {
    final Matrix4 inverted = Matrix4.inverted(_cameraController.value);
    return painting.MatrixUtils.transformPoint(inverted, viewportPoint);
  }

  Offset _scenePointFromGlobal(Offset globalPoint) {
    final RenderBox box = context.findRenderObject()! as RenderBox;
    final Offset viewportPoint = box.globalToLocal(globalPoint);
    return _scenePointFromViewport(viewportPoint);
  }

  Offset _viewportPointFromScene(Offset scenePoint) {
    return painting.MatrixUtils.transformPoint(
        _cameraController.value, scenePoint);
  }

  _OneSpaceComposerCardNode? _composerById(String id) {
    for (final _OneSpaceComposerCardNode node in _composerCards) {
      if (node.id == id) return node;
    }
    return null;
  }

  Size _composerCardSize(
    _OneSpaceCreateAction action,
    _OneSpaceMediaSize? size,
  ) {
    final Size preview = _composerPreviewSize(action, size);
    final double width =
        math.max(_oneSpaceComposerCardMinWidth, preview.width + 38);
    final double coreHeight = _composerCoreHeight(action, size);
    final double height = coreHeight +
        _oneSpaceComposerConnectorTopGap +
        _oneSpaceComposerConnectorDiameter +
        _oneSpaceComposerConnectorBottomGap;
    return Size(width, height);
  }

  double _composerCoreHeight(
    _OneSpaceCreateAction action,
    _OneSpaceMediaSize? size,
  ) {
    return _composerPreviewSize(action, size).height +
        _oneSpaceComposerCoreExtraHeight;
  }

  Offset _composerConnectorScenePoint(_OneSpaceComposerCardNode node) {
    final Size size = _composerCardSize(node.action, node.sizePreset);
    final double top = node.position.dy - (size.height / 2);
    final double coreHeight = _composerCoreHeight(node.action, node.sizePreset);
    final double y = top +
        coreHeight +
        _oneSpaceComposerConnectorTopGap +
        (_oneSpaceComposerConnectorDiameter / 2);
    return Offset(node.position.dx, y);
  }

  Offset _composerAttachmentScenePoint(
    _OneSpaceComposerCardNode node,
    _OneSpaceConnectorSide side,
  ) {
    final Size size = _composerCardSize(node.action, node.sizePreset);
    final double coreHeight = _composerCoreHeight(node.action, node.sizePreset);
    final double top = node.position.dy - (size.height / 2);
    final double left = node.position.dx - (size.width / 2);
    switch (side) {
      case _OneSpaceConnectorSide.left:
        return Offset(left, top + (coreHeight / 2));
      case _OneSpaceConnectorSide.right:
        return Offset(left + size.width, top + (coreHeight / 2));
      case _OneSpaceConnectorSide.top:
        return Offset(node.position.dx, top);
      case _OneSpaceConnectorSide.bottom:
        return Offset(node.position.dx, top + coreHeight);
    }
  }

  Size _composerPreviewSize(
    _OneSpaceCreateAction action,
    _OneSpaceMediaSize? size,
  ) {
    if (action == _OneSpaceCreateAction.text || size == null) {
      return const Size(230, 182);
    }
    if (action == _OneSpaceCreateAction.image) {
      switch (size) {
        case _OneSpaceMediaSize.square:
          return const Size(208, 208);
        case _OneSpaceMediaSize.portrait:
          return const Size(188, 248);
        case _OneSpaceMediaSize.story:
          return const Size(146, 258);
      }
    }
    if (action == _OneSpaceCreateAction.video) {
      switch (size) {
        case _OneSpaceMediaSize.square:
          return const Size(206, 206);
        case _OneSpaceMediaSize.portrait:
          return const Size(182, 240);
        case _OneSpaceMediaSize.story:
          return const Size(248, 140);
      }
    }
    return const Size(230, 182);
  }

  Offset _clampComposerCenter(Offset point, Size cardSize) {
    const double outerMargin = 28;
    final double halfW = cardSize.width / 2;
    final double halfH = cardSize.height / 2;
    return Offset(
      point.dx
          .clamp(
            halfW + outerMargin,
            _worldSize - halfW - outerMargin,
          )
          .toDouble(),
      point.dy
          .clamp(
            halfH + outerMargin,
            _worldSize - halfH - outerMargin,
          )
          .toDouble(),
    );
  }

  void _initializeCameraIfNeeded(Size viewport) {
    if (_cameraInitialized) return;
    WidgetsBinding.instance.addPostFrameCallback((_) {
      if (!mounted || _cameraInitialized) return;
      _cameraController.value = _matrixForSceneCenter(
        sceneCenter: _worldCenter,
        viewportSize: viewport,
        scale: 0.55,
      );
      _cameraInitialized = true;
      setState(() {});
    });
  }

  void _focusWorkflow(_OneSpaceWorkflowNode node, Size viewport) {
    setState(() {
      _focusedWorkflowId = node.id;
    });
    final double currentScale = _cameraController.value.getMaxScaleOnAxis();
    final double targetScale =
        currentScale < 0.9 ? 0.9 : currentScale.clamp(0.9, 1.25).toDouble();
    final Matrix4 target = _matrixForSceneCenter(
      sceneCenter: node.position,
      viewportSize: viewport,
      scale: targetScale,
    );
    _animateCameraTo(target);
  }

  Matrix4 _matrixForSceneCenter({
    required Offset sceneCenter,
    required Size viewportSize,
    required double scale,
  }) {
    final double tx = viewportSize.width / 2 - (sceneCenter.dx * scale);
    final double ty = viewportSize.height / 2 - (sceneCenter.dy * scale);
    return Matrix4.identity()
      ..translate(tx, ty)
      ..scale(scale);
  }

  void _animateCameraTo(Matrix4 target) {
    _stopCameraAnimation();
    final AnimationController controller = AnimationController(
      vsync: this,
      duration: const Duration(milliseconds: 360),
    );
    final Animation<Matrix4> animation = Matrix4Tween(
      begin: _cameraController.value.clone(),
      end: target,
    ).animate(
      CurvedAnimation(parent: controller, curve: Curves.easeOutCubic),
    );
    animation.addListener(() {
      _cameraController.value = animation.value;
    });
    controller.addStatusListener((status) {
      if (status == AnimationStatus.completed ||
          status == AnimationStatus.dismissed) {
        if (_cameraAnimationController == controller) {
          _cameraAnimationController?.dispose();
          _cameraAnimationController = null;
        }
      }
    });
    _cameraAnimationController = controller;
    controller.forward();
  }

  void _stopCameraAnimation() {
    _cameraAnimationController?.stop();
    _cameraAnimationController?.dispose();
    _cameraAnimationController = null;
  }
}

class _OneSpaceWorkflowNode {
  const _OneSpaceWorkflowNode({
    required this.id,
    required this.title,
    required this.subtitle,
    required this.position,
  });

  final String id;
  final String title;
  final String subtitle;
  final Offset position;
}

class _OneSpaceComposerCardNode {
  const _OneSpaceComposerCardNode({
    required this.id,
    required this.action,
    required this.sizePreset,
    required this.position,
    required this.controller,
    required this.focusNode,
  });

  final String id;
  final _OneSpaceCreateAction action;
  final _OneSpaceMediaSize? sizePreset;
  final Offset position;
  final TextEditingController controller;
  final FocusNode focusNode;

  _OneSpaceComposerCardNode copyWith({
    Offset? position,
  }) {
    return _OneSpaceComposerCardNode(
      id: id,
      action: action,
      sizePreset: sizePreset,
      position: position ?? this.position,
      controller: controller,
      focusNode: focusNode,
    );
  }
}

class _OneSpaceWorkflowCard extends StatelessWidget {
  const _OneSpaceWorkflowCard({
    required this.node,
    required this.focused,
    required this.onTap,
  });

