  final bool focused;
  final VoidCallback onTap;

  @override
  Widget build(BuildContext context) {
    return Material(
      color: Colors.transparent,
      child: InkWell(
        borderRadius: BorderRadius.circular(18),
        onTap: onTap,
        child: AnimatedContainer(
          duration: const Duration(milliseconds: 220),
          curve: Curves.easeOutCubic,
          width: 240,
          height: 144,
          padding: const EdgeInsets.fromLTRB(14, 12, 14, 12),
          decoration: BoxDecoration(
            color: const Color(0xFF121A2A),
            borderRadius: BorderRadius.circular(18),
            border: Border.all(
              color:
                  focused ? const Color(0xFF7E95FF) : const Color(0xFF303B55),
              width: focused ? 1.8 : 1,
            ),
            boxShadow: <BoxShadow>[
              BoxShadow(
                color:
                    focused ? const Color(0x447E95FF) : const Color(0x22000000),
                blurRadius: focused ? 20 : 12,
                spreadRadius: 0,
                offset: const Offset(0, 6),
              ),
            ],
          ),
          child: Column(
            crossAxisAlignment: CrossAxisAlignment.start,
            children: [
              Container(
                width: 34,
                height: 34,
                decoration: BoxDecoration(
                  color: focused
                      ? const Color(0xFF24314D)
                      : const Color(0xFF1A2438),
                  borderRadius: BorderRadius.circular(10),
                ),
                child: Icon(
                  Icons.auto_awesome_rounded,
                  size: 18,
                  color: focused
                      ? const Color(0xFFA8B8FF)
                      : const Color(0xFF7E8AA2),
                ),
              ),
              const SizedBox(height: 10),
              Text(
                node.title,
                maxLines: 1,
                overflow: TextOverflow.ellipsis,
                style: const TextStyle(
                  fontSize: 16,
                  fontWeight: FontWeight.w800,
                  color: Color(0xFFF5F8FF),
                ),
              ),
              const SizedBox(height: 5),
              Text(
                node.subtitle,
                maxLines: 2,
                overflow: TextOverflow.ellipsis,
                style: const TextStyle(
                  fontSize: 12.5,
                  fontWeight: FontWeight.w600,
                  color: Color(0xFF9AA6C1),
                  height: 1.3,
                ),
              ),
            ],
          ),
        ),
      ),
    );
  }
}

class _OneSpacePromptWorkflowCard extends StatelessWidget {
  const _OneSpacePromptWorkflowCard({
    super.key,
    required this.action,
    required this.sizePreset,
    required this.previewSize,
    required this.controller,
    required this.focusNode,
    required this.onHeaderPanStart,
    required this.onHeaderPanUpdate,
    required this.onConnectorPanStart,
    required this.onConnectorPanUpdate,
    required this.onConnectorPanEnd,
    required this.onOkTap,
  });

  final _OneSpaceCreateAction action;
  final _OneSpaceMediaSize? sizePreset;
  final Size previewSize;
  final TextEditingController controller;
  final FocusNode focusNode;
  final GestureDragStartCallback onHeaderPanStart;
  final GestureDragUpdateCallback onHeaderPanUpdate;
  final GestureDragStartCallback onConnectorPanStart;
  final GestureDragUpdateCallback onConnectorPanUpdate;
  final GestureDragEndCallback onConnectorPanEnd;
  final VoidCallback onOkTap;

  String get _promptHint {
    switch (action) {
      case _OneSpaceCreateAction.text:
        return 'Write text prompt...';
      case _OneSpaceCreateAction.image:
        return 'Describe image to generate...';
      case _OneSpaceCreateAction.video:
        return 'Describe video to generate...';
      case _OneSpaceCreateAction.upload:
        return 'Write prompt...';
    }
  }

  String get _previewLabel {
    final String sizeName = sizePreset?.title ?? 'Default';
    switch (action) {
      case _OneSpaceCreateAction.text:
        return 'Text Output';
      case _OneSpaceCreateAction.image:
        return 'Image Output • $sizeName';
      case _OneSpaceCreateAction.video:
        return 'Video Output • $sizeName';
      case _OneSpaceCreateAction.upload:
        return 'Output';
    }
  }

  IconData get _previewIcon {
    switch (action) {
      case _OneSpaceCreateAction.text:
        return Icons.text_fields_rounded;
      case _OneSpaceCreateAction.image:
        return Icons.image_outlined;
      case _OneSpaceCreateAction.video:
        return Icons.videocam_outlined;
      case _OneSpaceCreateAction.upload:
        return Icons.auto_awesome_rounded;
    }
  }

  IconData get _actionIcon {
    switch (action) {
      case _OneSpaceCreateAction.text:
        return Icons.check_rounded;
      case _OneSpaceCreateAction.image:
      case _OneSpaceCreateAction.video:
        return Icons.auto_awesome_rounded;
      case _OneSpaceCreateAction.upload:
        return Icons.check_rounded;
    }
  }

  String get _composerTitle {
    if (sizePreset == null) {
      return action.title;
    }
    return '${action.title} • ${sizePreset!.title}';
  }

  @override
  Widget build(BuildContext context) {
    const double promptHeight = 46;
    const double downloadHeight = 36;
    final double cardWidth =
        math.max(_oneSpaceComposerCardMinWidth, previewSize.width + 38);
    final double coreHeight =
        previewSize.height + _oneSpaceComposerCoreExtraHeight;
    final double cardHeight = coreHeight +
        _oneSpaceComposerConnectorTopGap +
        _oneSpaceComposerConnectorDiameter +
        _oneSpaceComposerConnectorBottomGap;
    return SizedBox(
      width: cardWidth,
      height: cardHeight,
      child: Stack(
        clipBehavior: Clip.none,
        children: [
          Positioned(
            left: 0,
            right: 0,
            top: 0,
            child: Container(
              height: coreHeight,
              padding: const EdgeInsets.fromLTRB(14, 12, 14, 14),
              decoration: BoxDecoration(
                color: const Color(0xC4111A2A),
                borderRadius: BorderRadius.circular(22),
                border: Border.all(color: const Color(0xFF2F3D58)),
                boxShadow: const <BoxShadow>[
                  BoxShadow(
                    color: Color(0x3F000000),
                    blurRadius: 24,
                    spreadRadius: 0,
                    offset: Offset(0, 10),
                  ),
                ],
              ),
              child: Column(
                crossAxisAlignment: CrossAxisAlignment.stretch,
                children: [
                  GestureDetector(
                    behavior: HitTestBehavior.opaque,
                    onPanStart: onHeaderPanStart,
                    onPanUpdate: onHeaderPanUpdate,
                    child: Padding(
                      padding: const EdgeInsets.fromLTRB(2, 2, 2, 10),
                      child: Row(
                        children: [
                          Expanded(
                            child: Text(
                              _composerTitle,
                              maxLines: 1,
                              overflow: TextOverflow.ellipsis,
                              style: const TextStyle(
                                color: Color(0xFFF0F5FF),
                                fontSize: 16.5,
                                fontWeight: FontWeight.w800,
                                letterSpacing: 0.15,
                              ),
                            ),
                          ),
                          const SizedBox(width: 8),
                          const Icon(
                            Icons.drag_indicator_rounded,
                            size: 18,
                            color: Color(0xA7DCE7FF),
                          ),
                        ],
                      ),
                    ),
                  ),
                  const SizedBox(height: 4),
                  Center(
                    child: Container(
                      width: previewSize.width,
                      height: previewSize.height,
                      decoration: BoxDecoration(
                        color: const Color(0x180A1020),
                        borderRadius: BorderRadius.circular(20),
                        border: Border.all(
                          color: const Color(0xFFF3F6FF),
                          width: 3,
                        ),
                      ),
                      child: Center(
                        child: Column(
                          mainAxisSize: MainAxisSize.min,
                          children: [
                            Icon(
                              _previewIcon,
                              size: 40,
                              color: const Color(0xBEE7EEFF),
                            ),
                            const SizedBox(height: 8),
                            Text(
                              _previewLabel,
                              textAlign: TextAlign.center,
                              style: const TextStyle(
                                color: Color(0xD9F1F6FF),
                                fontSize: 14,
                                fontWeight: FontWeight.w700,
                              ),
                            ),
                          ],
                        ),
                      ),
                    ),
                  ),
                  const SizedBox(height: 10),
                  Row(
                    children: [
                      Expanded(
