class _OneSpaceConnectionsPainter extends CustomPainter {
  const _OneSpaceConnectionsPainter({
    required this.segments,
    required this.liveSegment,
  });

  final List<_OneSpaceConnectionSegment> segments;
  final _OneSpaceConnectionSegment? liveSegment;

  @override
  void paint(Canvas canvas, Size size) {
    for (final _OneSpaceConnectionSegment segment in segments) {
      _drawSegment(
        canvas,
        segment,
        glowOpacity: segment.isPending ? 0.44 : 0.34,
        coreOpacity: segment.isPending ? 0.93 : 0.84,
      );
    }
    if (liveSegment != null) {
      _drawSegment(
        canvas,
        liveSegment!,
        glowOpacity: 0.54,
        coreOpacity: 0.98,
      );
    }
  }

  void _drawSegment(
    Canvas canvas,
    _OneSpaceConnectionSegment segment, {
    required double glowOpacity,
    required double coreOpacity,
  }) {
    final Path path = _buildPath(segment.start, segment.end);
    final Paint glow = Paint()
      ..style = PaintingStyle.stroke
      ..strokeWidth = segment.isLive ? 6.6 : 5.0
      ..strokeCap = StrokeCap.round
      ..color = Colors.white.withOpacity(glowOpacity)
      ..maskFilter = const MaskFilter.blur(BlurStyle.normal, 7.5)
      ..isAntiAlias = true;
    final Paint core = Paint()
      ..style = PaintingStyle.stroke
      ..strokeWidth = segment.isLive ? 2.7 : 2.2
      ..strokeCap = StrokeCap.round
      ..color = Colors.white.withOpacity(coreOpacity)
      ..isAntiAlias = true;
    canvas.drawPath(path, glow);
    canvas.drawPath(path, core);
  }

  Path _buildPath(Offset start, Offset end) {
    final double dx = end.dx - start.dx;
    final double dy = end.dy - start.dy;
    final double distance = (end - start).distance;
    final double bend = (distance * 0.22).clamp(26, 120).toDouble();
    late final Offset c1;
    late final Offset c2;
    if (dx.abs() >= dy.abs()) {
      final double sign = dx >= 0 ? 1 : -1;
      c1 = Offset(start.dx + bend * sign, start.dy);
      c2 = Offset(end.dx - bend * sign, end.dy);
    } else {
      final double sign = dy >= 0 ? 1 : -1;
      c1 = Offset(start.dx, start.dy + bend * sign);
      c2 = Offset(end.dx, end.dy - bend * sign);
    }
    return Path()
      ..moveTo(start.dx, start.dy)
      ..cubicTo(c1.dx, c1.dy, c2.dx, c2.dy, end.dx, end.dy);
  }

  @override
  bool shouldRepaint(covariant _OneSpaceConnectionsPainter oldDelegate) {
    return !listEquals(oldDelegate.segments, segments) ||
        oldDelegate.liveSegment != liveSegment;
  }
}

class _OneSpaceStarfieldPainter extends CustomPainter {
  const _OneSpaceStarfieldPainter({required this.background});

  final Color background;

  @override
  void paint(Canvas canvas, Size size) {
    final Paint fill = Paint()..color = background;
    canvas.drawRect(Offset.zero & size, fill);

    const double step = 150;
    final int cols = (size.width / step).ceil() + 1;
    final int rows = (size.height / step).ceil() + 1;

    final Paint bright = Paint()
      ..color = const Color(0xCCFFFFFF)
      ..isAntiAlias = true;
    final Paint mid = Paint()
      ..color = const Color(0x80FFFFFF)
      ..isAntiAlias = true;
    final Paint faint = Paint()
      ..color = const Color(0x4DFFFFFF)
      ..isAntiAlias = true;

    for (int row = 0; row < rows; row++) {
      for (int col = 0; col < cols; col++) {
        final int seed = (row * 92837111) ^ (col * 689287499);
        final double jitterX = (_hashToUnit(seed) - 0.5) * step * 0.88;
        final double jitterY =
            (_hashToUnit(seed ^ 0x9E3779B9) - 0.5) * step * 0.88;
        final Offset center =
            Offset(col * step + jitterX, row * step + jitterY);
        if (center.dx < -2 ||
            center.dx > size.width + 2 ||
            center.dy < -2 ||
            center.dy > size.height + 2) {
          continue;
        }

        final double density = _hashToUnit(seed ^ 0x85EBCA6B);
        if (density > 0.84) {
          canvas.drawCircle(center, 1.3, bright);
        } else if (density > 0.46) {
          canvas.drawCircle(center, 0.95, mid);
        } else {
          canvas.drawCircle(center, 0.62, faint);
        }
      }
    }

    final Paint depthGlow = Paint()
      ..shader = ui.Gradient.radial(
        Offset(size.width * 0.52, size.height * 0.48),
        size.shortestSide * 0.68,
        const <Color>[Color(0x1A3B4F8A), Color(0x003B4F8A)],
        const <double>[0.0, 1.0],
      );
    canvas.drawRect(Offset.zero & size, depthGlow);
  }

  static double _hashToUnit(int value) {
    int x = value;
    x = ((x >> 16) ^ x) * 0x45D9F3B;
    x = ((x >> 16) ^ x) * 0x45D9F3B;
    x = (x >> 16) ^ x;
    return (x & 0x7FFFFFFF) / 0x7FFFFFFF;
  }

  @override
  bool shouldRepaint(covariant _OneSpaceStarfieldPainter oldDelegate) {
    return oldDelegate.background != background;
  }
}

