class _AiShimmerPlaceholder extends StatefulWidget {
  const _AiShimmerPlaceholder();

  @override
  State<_AiShimmerPlaceholder> createState() => _AiShimmerPlaceholderState();
}

class _AiShimmerPlaceholderState extends State<_AiShimmerPlaceholder>
    with SingleTickerProviderStateMixin {
  late final AnimationController _controller = AnimationController(
    vsync: this,
    duration: const Duration(milliseconds: 1100),
  )..repeat();

  @override
  void dispose() {
    _controller.dispose();
    super.dispose();
  }

  @override
  Widget build(BuildContext context) {
    return AnimatedBuilder(
      animation: _controller,
      builder: (context, child) {
        final double t = _controller.value;
        return ShaderMask(
          shaderCallback: (bounds) {
            const double band = 0.35;
            return LinearGradient(
              begin: Alignment(-1.4 + (2.8 * t), 0),
              end: Alignment(-0.4 + (2.8 * t), 0),
              colors: const <Color>[
                Color(0x00FFFFFF),
                Color(0x88605E5E),
                Color(0x00FFFFFF),
              ],
              stops: const <double>[0, band, 1],
            ).createShader(bounds);
          },
          blendMode: BlendMode.srcATop,
          child: child,
        );
      },
      child: Container(
        color: const Color(0xFFDEE3EB),
      ),
    );
  }
}

