class _AiMagicProgressIndicator extends StatefulWidget {
  const _AiMagicProgressIndicator({
    required this.progress,
    required this.panelSize,
    required this.statusText,
  });

  final double progress;
  final Size panelSize;
  final String statusText;

  @override
  State<_AiMagicProgressIndicator> createState() =>
      _AiMagicProgressIndicatorState();
}

class _AiMagicProgressIndicatorState extends State<_AiMagicProgressIndicator>
    with SingleTickerProviderStateMixin {
  late final AnimationController _controller = AnimationController(
    vsync: this,
    duration: const Duration(milliseconds: 1700),
  )..repeat();

  @override
  void dispose() {
    _controller.dispose();
    super.dispose();
  }

  @override
  Widget build(BuildContext context) {
    final double targetProgress = widget.progress.clamp(0.0, 1.0).toDouble();
    final Size panelSize = widget.panelSize;
    final double minSide = math.min(panelSize.width, panelSize.height);
    final double percentFontSize =
        (minSide * 0.14).clamp(16.0, 29.0).toDouble();
    final double statusFontSize =
        (minSide * 0.075).clamp(11.0, 15.0).toDouble();
    final double horizontalPadding =
        (panelSize.width * 0.08).clamp(12.0, 28.0).toDouble();
    return TweenAnimationBuilder<double>(
      tween: Tween<double>(end: targetProgress),
      duration: const Duration(milliseconds: 210),
      curve: Curves.easeOutCubic,
      builder: (context, smoothProgress, _) {
        return AnimatedBuilder(
          animation: _controller,
          builder: (context, _) {
            final double phase = _controller.value;
            final int percent =
                (smoothProgress * 100).round().clamp(0, 100).toInt();
            final double blurBandWidth =
                (panelSize.width * 0.34).clamp(72.0, 260.0).toDouble();
            final double blurBandTravel = panelSize.width + blurBandWidth;
            final double blurBandLeft =
                (phase * blurBandTravel) - blurBandWidth;
            return RepaintBoundary(
              child: SizedBox(
                width: panelSize.width,
                height: panelSize.height,
                child: ClipRect(
                  child: Stack(
                    fit: StackFit.expand,
                    children: [
                      const ColoredBox(
                        color: Color(0x16191C22),
                      ),
                      BackdropFilter(
                        filter: ui.ImageFilter.blur(sigmaX: 3.2, sigmaY: 3.2),
                        child: Container(
                          color: const Color(0x12191C22),
                        ),
                      ),
                      Positioned(
                        left: blurBandLeft,
                        top: 0,
                        bottom: 0,
                        width: blurBandWidth,
                        child: BackdropFilter(
                          filter: ui.ImageFilter.blur(sigmaX: 6.4, sigmaY: 6.4),
                          child: Container(
                            decoration: const BoxDecoration(
                              gradient: LinearGradient(
                                begin: Alignment.centerLeft,
                                end: Alignment.centerRight,
                                colors: <Color>[
                                  Color(0x00FFFFFF),
                                  Color(0x14FFFFFF),
                                  Color(0x00FFFFFF),
                                ],
                                stops: <double>[0.0, 0.5, 1.0],
                              ),
                            ),
                          ),
                        ),
                      ),
                      Container(
                        decoration: BoxDecoration(
                          gradient: LinearGradient(
                            begin: Alignment(-1.6 + (phase * 3.2), -0.16),
                            end: Alignment(-0.65 + (phase * 3.2), 0.16),
                            colors: const <Color>[
                              Color(0x00FFFFFF),
                              Color(0x10FFFFFF),
                              Color(0x00FFFFFF),
                            ],
                            stops: const <double>[0.0, 0.52, 1.0],
                          ),
                        ),
                      ),
                      const DecoratedBox(
                        decoration: BoxDecoration(
                          gradient: RadialGradient(
                            center: Alignment(0.0, 0.06),
                            radius: 1.08,
                            colors: <Color>[
                              Color(0x182A2F38),
                              Color(0x081A1D24),
                              Color(0x001A1D24),
                            ],
                            stops: <double>[0.0, 0.7, 1.0],
                          ),
                        ),
                      ),
                      CustomPaint(
                        painter: _AiMagicSparklesPainter(phase: phase),
                      ),
                      Center(
                        child: Padding(
                          padding: EdgeInsets.symmetric(
                            horizontal: horizontalPadding,
                          ),
                          child: Column(
                            mainAxisSize: MainAxisSize.min,
                            children: [
                              Text(
                                '$percent%',
                                style: TextStyle(
                                  color: const Color(0xFFF3F3F2),
                                  fontSize: percentFontSize,
                                  fontWeight: FontWeight.w800,
                                ),
                              ),
                              const SizedBox(height: 6),
                              Text(
                                widget.statusText,
                                maxLines: 2,
                                overflow: TextOverflow.ellipsis,
                                textAlign: TextAlign.center,
                                style: TextStyle(
                                  color: const Color(0xFFD4D4D3),
                                  fontSize: statusFontSize,
                                  fontWeight: FontWeight.w700,
                                  height: 1.25,
                                ),
                              ),
                            ],
                          ),
                        ),
                      ),
                    ],
                  ),
                ),
              ),
            );
          },
        );
      },
    );
  }
}

class _AiMagicSparklesPainter extends CustomPainter {
  const _AiMagicSparklesPainter({required this.phase});

  final double phase;

  @override
  void paint(Canvas canvas, Size size) {
    if (size.width <= 1 || size.height <= 1) return;
    final List<Offset> anchors = <Offset>[
      Offset(size.width * 0.23, size.height * 0.24),
      Offset(size.width * 0.76, size.height * 0.3),
      Offset(size.width * 0.28, size.height * 0.77),
      Offset(size.width * 0.72, size.height * 0.73),
    ];
    for (int i = 0; i < anchors.length; i++) {
      final double t = ((phase + (i * 0.19)) % 1.0) * (2 * math.pi);
      final double pulse = 0.45 + (0.55 * ((math.sin(t) + 1) / 2));
      final double radius = 1.0 + (1.6 * pulse);
      final Offset c = anchors[i];
      final Paint core = Paint()
        ..style = PaintingStyle.fill
        ..isAntiAlias = true
        ..color = const Color(0xFFE6F24A).withOpacity(0.045 + (0.07 * pulse));
      canvas.drawCircle(c, radius * 0.48, core);

      final Paint cross = Paint()
        ..style = PaintingStyle.stroke
        ..isAntiAlias = true
        ..strokeWidth = 0.72
        ..strokeCap = StrokeCap.round
        ..color = const Color(0xFFF7FFB0).withOpacity(0.06 + (0.11 * pulse));
      canvas.drawLine(
        Offset(c.dx - radius, c.dy),
        Offset(c.dx + radius, c.dy),
        cross,
      );
      canvas.drawLine(
        Offset(c.dx, c.dy - radius),
        Offset(c.dx, c.dy + radius),
        cross,
      );
    }
  }

  @override
  bool shouldRepaint(covariant _AiMagicSparklesPainter oldDelegate) {
    return oldDelegate.phase != phase;
  }
}

