_OverlayCutShapeType? _overlayCutShapeTypeFromKey(String? key) {
  if (key == null || key.isEmpty) return null;
  for (final _OverlayCutShapeType shape in _OverlayCutShapeType.values) {
    if (shape.name == key) return shape;
  }
  return null;
}

