extension _ExportQualityPresetUi on _ExportQualityPreset {
  String get label {
    switch (this) {
      case _ExportQualityPreset.low:
        return 'Low';
      case _ExportQualityPreset.medium:
        return 'Medium';
      case _ExportQualityPreset.high:
        return 'High';
      case _ExportQualityPreset.ultra:
        return 'Ultra';
    }
  }

  int jpegQualityForFormat(_ExportFormat format) {
    if (format == _ExportFormat.png) {
      return 100;
    }
    switch (this) {
      case _ExportQualityPreset.low:
        return 65;
      case _ExportQualityPreset.medium:
        return 78;
      case _ExportQualityPreset.high:
        return 90;
      case _ExportQualityPreset.ultra:
        return 100;
    }
  }

  int? maxLongEdgeForFormat(_ExportFormat format) {
    if (format == _ExportFormat.png) {
      switch (this) {
        case _ExportQualityPreset.low:
          return 1280;
        case _ExportQualityPreset.medium:
          return 2048;
        case _ExportQualityPreset.high:
          return 4096;
        case _ExportQualityPreset.ultra:
          return null;
      }
    }
    switch (this) {
      case _ExportQualityPreset.low:
        return 1280;
      case _ExportQualityPreset.medium:
        return 1920;
      case _ExportQualityPreset.high:
        return 4096;
      case _ExportQualityPreset.ultra:
        return null;
    }
  }
}

