  double _textFloatingPanelBottomOffset(double baseOffset) {
    if (!_isTextQuickDockVisible) return baseOffset;
    final double quickDockTopOffset =
        _bottomNavHeight + _textQuickDockBottomGap + _textQuickDockHeight;
    return quickDockTopOffset + _textFloatingPanelClearance;
  }

  Widget _buildBottomUpPanelAnimation({
    required Widget child,
    required String keyId,
    double delay = 0.0,
  }) {
    final double clampedDelay = delay.clamp(0.0, 0.72).toDouble();
    const Curve bounceOut = Cubic(0.175, 0.885, 0.32, 1.275);
    return TweenAnimationBuilder<double>(
      key: ValueKey<String>(keyId),
      tween: Tween<double>(begin: 0, end: 1),
      duration: const Duration(milliseconds: 430),
      curve: Curves.easeOutCubic,
      builder: (context, value, _) {
        final double staged = ((value - clampedDelay) / (1 - clampedDelay))
            .clamp(0.0, 1.0)
            .toDouble();
        final double eased = bounceOut.transform(staged);
        return Transform.translate(
          offset: Offset(0, (1 - eased) * 22),
          child: Opacity(
            opacity: Curves.easeOut.transform(staged),
            child: Transform.scale(
              scale: 0.94 + (0.06 * eased),
              alignment: Alignment.bottomCenter,
              child: child,
            ),
          ),
        );
      },
    );
  }

