  Widget _buildAiCanvasGeneratingOverlay() {
    final bool minimalCounterOnly =
        _isUpscaleLayerProcessing && _upscaleEffectLayerId != null;
    final double normalizedProgress =
        _aiCanvasGeneratingProgress.clamp(0.0, 1.0).toDouble();
    final String statusText = _aiCanvasGeneratingStatusText(normalizedProgress);
    return Positioned.fill(
      child: IgnorePointer(
        child: LayoutBuilder(
          builder: (context, constraints) {
            final Size canvasSize = Size(
              constraints.maxWidth,
              constraints.maxHeight,
            );
            final Rect? rawArtboardRect =
                _aiCanvasGeneratingArtboardRect(canvasSize);
            final Rect? artboardRect = rawArtboardRect == null
                ? null
                : Rect.fromLTRB(
                    rawArtboardRect.left.floorToDouble(),
                    rawArtboardRect.top.floorToDouble(),
                    rawArtboardRect.right.ceilToDouble(),
                    rawArtboardRect.bottom.ceilToDouble(),
                  );
            final Size panelSize = artboardRect?.size ?? const Size(148, 148);
            if (minimalCounterOnly) {
              final Widget counter = TweenAnimationBuilder<double>(
                tween: Tween<double>(end: normalizedProgress),
                duration: const Duration(milliseconds: 220),
                curve: Curves.easeOutCubic,
                builder: (context, smooth, _) {
                  final int smoothPercent =
                      (smooth * 100).round().clamp(0, 100);
                  return Text(
                    '$smoothPercent%',
                    style: const TextStyle(
                      color: Color(0xFFF3F3F2),
                      fontSize: 24,
                      fontWeight: FontWeight.w800,
                      shadows: <Shadow>[
                        Shadow(
                          color: Color(0xAA111418),
                          blurRadius: 16,
                          offset: Offset(0, 4),
                        ),
                      ],
                    ),
                  );
                },
              );
              return Stack(
                fit: StackFit.expand,
                children: [
                  if (artboardRect != null)
                    Positioned.fromRect(
                      rect: artboardRect,
                      child: Center(child: counter),
                    )
                  else
                    Center(child: counter),
                ],
              );
            }
            return Stack(
              fit: StackFit.expand,
              children: [
                Container(color: const Color(0x08111418)),
                if (artboardRect != null)
                  Positioned.fromRect(
                    rect: artboardRect,
                    child: _AiMagicProgressIndicator(
                      progress: _aiCanvasGeneratingProgress,
                      panelSize: panelSize,
                      statusText: statusText,
                    ),
                  )
                else
                  Center(
                    child: _AiMagicProgressIndicator(
                      progress: _aiCanvasGeneratingProgress,
                      panelSize: panelSize,
                      statusText: statusText,
                    ),
                  ),
              ],
            );
          },
        ),
      ),
    );
  }

  Rect? _aiCanvasGeneratingArtboardRect(Size canvasSize) {
    if (canvasSize.width <= 0 || canvasSize.height <= 0) return null;
    final EditorLayer? workspace = _workspaceLayerForEdit(_layers);
    final Size? workspaceSize =
        workspace == null ? null : _workspaceSourceSize(workspace);
    final Size sourceSize = workspaceSize ??
        (_aiCanvasGeneratingSizePreset?.baseSize ??
            _defaultAiCanvasSizePreset.baseSize);
    if (sourceSize.width <= 0 || sourceSize.height <= 0) return null;
    return _computeArtboardRect(
      canvasSize: canvasSize,
      workspaceSize: sourceSize,
    );
  }

  String _aiCanvasGeneratingStatusText(double progress) {
    final double p = progress.clamp(0.0, 1.0).toDouble();
    if (p < 0.12) return 'Preparing your image...';
    if (p < 0.3) return 'Uploading references...';
    if (p < 0.54) return 'Generating image details...';
    if (p < 0.78) return 'Refining composition...';
    if (p < 0.94) return 'Almost done, your image is on the way...';
    if (p < 1.0) return 'Finalizing output...';
    return 'Completed.';
  }

  _OverlayCutConfig? _activeOverlayCutConfigForCanvas() {
    if (!_isOverlayCutFloatingOpen) return null;
    final _OverlayCutConfig? config = _overlayCutConfig;
    final EditorLayer? selectedOverlay = _selectedOverlayImageLayer();
    if (config == null || selectedOverlay == null) return null;
    if (config.layerId != selectedOverlay.id) return null;
    return config;
  }

  _CropToolConfig? _activeCropConfigForCanvas() {
    if (!_isToolEnabled || _activeTool != EditorTool.crop) return null;
    final EditorLayer? selectedImage = _selectedCropLayer();
    if (selectedImage == null) return null;
    return _resolvedCropConfigForLayer(selectedImage.id);
  }

  _ExpandToolConfig? _activeExpandConfigForCanvas() {
    if (!_isToolEnabled || _activeTool != EditorTool.expand) return null;
    final EditorLayer? selectedImage = _selectedExpandLayer();
    if (selectedImage == null) return null;
    return _resolvedExpandConfigForLayer(selectedImage.id);
  }

  void _setActiveTool(
    EditorTool tool, {
    bool toggleWhenSame = true,
  }) {
    setState(() {
      if (_activeTool == tool) {
        _isToolEnabled = toggleWhenSame ? !_isToolEnabled : true;
      } else {
        _activeTool = tool;
        _isToolEnabled = true;
      }
      if (!_isToolEnabled || tool != EditorTool.clone) {
        _isCloneSourceArmed = false;
        _isCloneBrushSelected = false;
        _isCloneEraseSelected = false;
        _isCloneBrushPreviewVisible = false;
        _isCloneSettingsFloatingOpen = false;
        _isCloneSettingsBottomSheetOpen = false;
        _cloneSettingsFloatingBaseline = null;
        _cloneSourceArmedFloatingBaseline = null;
        _cloneBrushSelectedFloatingBaseline = null;
        _cloneEraseSelectedFloatingBaseline = null;
        _resetCloneJoystickControls();
      }
      if (!_isToolEnabled || tool != EditorTool.blur) {
        _isBlurSettingsBottomSheetOpen = false;
        _resetBlurPreviewSession();
      }
      if ((!_isToolEnabled || tool != EditorTool.marquee) &&
          _marqueeSelection != null) {
        _marqueeSelection = null;
      }
      if (!_isToolEnabled || tool != EditorTool.crop) {
        _isCropFloatingOpen = false;
      }
      if (_isToolEnabled && tool == EditorTool.crop) {
        final EditorLayer? selectedImage = _selectedCropLayer();
        if (selectedImage != null) {
          _selectedLayerId = selectedImage.id;
          _cropToolConfig = _resolvedCropConfigForLayer(selectedImage.id);
        } else {
          _cropToolConfig = null;
        }
      }
      if (_isToolEnabled && tool == EditorTool.expand) {
        final EditorLayer? selectedImage = _selectedExpandLayer();
        if (selectedImage != null) {
          _selectedLayerId = selectedImage.id;
          _expandToolConfig = _resolvedExpandConfigForLayer(selectedImage.id);
        } else {
          _expandToolConfig = null;
        }
      }
      if (!_isToolEnabled || tool != EditorTool.expand) {
        // Leaving Expand should fully cancel the pending expand session.
        _expandToolConfig = null;
      }
      if (!_isToolEnabled || tool != EditorTool.removeBg) {
        _isPhotoRoomRemoveBgFloatingOpen = false;
        _isPhotoRoomRemoveBgProcessing = false;
      }
      if (!_isToolEnabled || tool != EditorTool.sketchReplace) {
        _isSketchReplaceFloatingOpen = false;
        _isSketchReplaceProcessing = false;
        _sketchReplaceError = null;
      }
      if (_isToolEnabled && tool == EditorTool.sketchReplace) {
        _sketchReplaceLayerId = _selectedImageLayer()?.id;
        _isSketchReplaceMaskDrawingEnabled = true;
      }
      if (!_isToolEnabled || tool != EditorTool.replaceObject) {
        _isReplaceObjectFloatingOpen = false;
        _isReplaceObjectProcessing = false;
        _replaceObjectError = null;
      }
      if (_isToolEnabled && tool == EditorTool.replaceObject) {
        _replaceObjectLayerId = _selectedImageLayer()?.id;
        _isReplaceObjectMaskDrawingEnabled = true;
      }
      if (!_isToolEnabled || tool != EditorTool.text) {
        _resetTextQuickFloatingPanels();
        _activeTextEffectFloatingPanel = null;
        _isTextSettingsDockEnabled = false;
      }
      if (!_isToolEnabled || tool != EditorTool.pencil) {
        _isPencilSettingsFloatingOpen = false;
        _pencilSettingsFloatingBaseline = null;
      }
      if (!_isToolEnabled || tool != EditorTool.move) {
        _resetMoveJoystickControls();
      }
      if (!_isToolEnabled) {
        _isOverlayCutFloatingOpen = false;
        _overlayCutBaseline = null;
        _isCropFloatingOpen = false;
        _expandToolConfig = null;
        _isOverlayImageShadowFloatingOpen = false;
        _overlayImageShadowFloatingBaseline = null;
        _overlayImageShadowFloatingLayerId = null;
        _isImageAdjustFloatingOpen = false;
        _imageAdjustFloatingBaseline = null;
        _imageAdjustFloatingLayerId = null;
        _isPhotoRoomRemoveBgFloatingOpen = false;
        _isPhotoRoomRemoveBgProcessing = false;
        _isSketchReplaceFloatingOpen = false;
        _isSketchReplaceProcessing = false;
        _sketchReplaceError = null;
        _isSketchReplaceBrushPreviewVisible = false;
        _isReplaceObjectFloatingOpen = false;
        _isReplaceObjectProcessing = false;
        _replaceObjectError = null;
        _resetTextQuickFloatingPanels();
        _isTextSettingsDockEnabled = false;
      }
      if (!_isToolEnabled ||
          (tool != EditorTool.sketchReplace &&
              tool != EditorTool.replaceObject)) {
        _isSketchReplaceBrushPreviewVisible = false;
      }
    });
    if (!_isToolEnabled ||
        (tool != EditorTool.sketchReplace &&
            tool != EditorTool.replaceObject)) {
      _sketchReplaceBrushPreviewTimer?.cancel();
    }
    if (!_isToolEnabled || tool != EditorTool.clone) {
      _cloneBrushPreviewTimer?.cancel();
    }
  }

  void _onRemoveBgToolTap() {
    final EditorLayer? selectedImage = _selectedImageLayer();
    if (selectedImage == null) {
      _showExportMessage('Select an overlay image layer first.', isError: true);
      return;
    }
    if (selectedImage.isBackground) {
      _showExportMessage(
        'Background layer is locked and cannot use Remove Background.',
        isError: true,
      );
      return;
    }
    _setActiveTool(EditorTool.removeBg, toggleWhenSame: false);
    _openPhotoRoomRemoveBgFloatingPanel(engine: _removeBgEngine);
  }

  void _onExpandToolTap() {
    final EditorLayer? selectedImage = _selectedExpandLayer();
    if (selectedImage == null) {
      _showExportMessage('Select an image layer first.', isError: true);
      return;
    }
    _setActiveTool(EditorTool.expand, toggleWhenSame: false);
    _closeToolSettingsSidebarIfOpen();
  }

  void _onRegenerateToolTap() {
    final EditorLayer? selectedImage = _selectedImageLayer();
    if (selectedImage == null) {
      _showExportMessage('Select an image layer first.', isError: true);
      return;
    }
    if (_isAiCanvasGenerating || _isExporting || _isExpandGenerating) {
      _showExportMessage(
        'Wait for the current task to finish first.',
        isError: true,
      );
      return;
    }
    _setActiveTool(EditorTool.regenerate, toggleWhenSame: false);
    _closeToolSettingsSidebarIfOpen();
    unawaited(_openRegenerateBottomSheet());
  }

  List<_RegenerateQualityPreset> _regenerateQualityOptionsForModel(
    _RegenerateModel model,
  ) {
    switch (model) {
      case _RegenerateModel.seedream5Lite:
        return const <_RegenerateQualityPreset>[
          _RegenerateQualityPreset.autoReference,
          _RegenerateQualityPreset.k2,
        ];
      case _RegenerateModel.nanoBanana2:
      case _RegenerateModel.flux2Pro:
        return const <_RegenerateQualityPreset>[
          _RegenerateQualityPreset.autoReference,
          _RegenerateQualityPreset.k1,
          _RegenerateQualityPreset.k2,
        ];
    }
  }

  _AiGenerationQuality _resolveRegenerateQuality({
    required _RegenerateModel model,
    required _RegenerateQualityPreset preset,
    required ui.Image baseImage,
  }) {
    final int longestSide = math.max(baseImage.width, baseImage.height);
    switch (model) {
      case _RegenerateModel.nanoBanana2:
        switch (preset) {
          case _RegenerateQualityPreset.autoReference:
            return longestSide >= 1700
                ? _AiGenerationQuality.k2
                : _AiGenerationQuality.k1;
          case _RegenerateQualityPreset.k1:
            return _AiGenerationQuality.k1;
          case _RegenerateQualityPreset.k2:
            return _AiGenerationQuality.k2;
        }
      case _RegenerateModel.flux2Pro:
        switch (preset) {
          case _RegenerateQualityPreset.autoReference:
            return longestSide >= 1600
                ? _AiGenerationQuality.k2
                : _AiGenerationQuality.k1;
          case _RegenerateQualityPreset.k1:
            return _AiGenerationQuality.k1;
          case _RegenerateQualityPreset.k2:
            return _AiGenerationQuality.k2;
        }
      case _RegenerateModel.seedream5Lite:
        switch (preset) {
          case _RegenerateQualityPreset.autoReference:
            return _AiGenerationQuality.k2;
          case _RegenerateQualityPreset.k1:
            return _AiGenerationQuality.k2;
          case _RegenerateQualityPreset.k2:
            return _AiGenerationQuality.k2;
        }
    }
  }

  _AiCanvasSizePreset _sizePresetFromImage(ui.Image image) {
    final double ratio = image.width / math.max(1, image.height);
    if (ratio >= 0.92 && ratio <= 1.08) {
      return _AiCanvasSizePreset.square;
    }
    if (ratio < 0.82) {
      return _AiCanvasSizePreset.story;
    }
    return _AiCanvasSizePreset.portrait;
  }

  int _regenerateMaxLongEdgeForQuality(_AiGenerationQuality quality) {
    switch (quality) {
      case _AiGenerationQuality.k1:
      case _AiGenerationQuality.medium:
        return 1536;
      case _AiGenerationQuality.k2:
      case _AiGenerationQuality.high:
        return 2048;
      case _AiGenerationQuality.k4:
        return 2560;
    }
  }

  int _regenerateJpegQualityForQuality(_AiGenerationQuality quality) {
    switch (quality) {
      case _AiGenerationQuality.k1:
      case _AiGenerationQuality.medium:
        return 84;
      case _AiGenerationQuality.k2:
      case _AiGenerationQuality.high:
        return 88;
      case _AiGenerationQuality.k4:
        return 90;
    }
  }

  Future<Uint8List> _encodeUiImageForRegenerateUpload(
    ui.Image sourceImage, {
    required _AiGenerationQuality quality,
  }) async {
    final ByteData? rawData = await sourceImage.toByteData(
      format: ui.ImageByteFormat.rawRgba,
    );
    if (rawData == null) {
      return _encodeUiImageToPngBytes(sourceImage);
    }
    final Uint8List rgba = Uint8List.fromList(
      rawData.buffer.asUint8List(0, rawData.lengthInBytes),
    );
    final int width = sourceImage.width;
    final int height = sourceImage.height;
    final int jpegQuality = _regenerateJpegQualityForQuality(quality);
    final int maxLongEdge = _regenerateMaxLongEdgeForQuality(quality);
    return Isolate.run<Uint8List>(
      () => _encodeJpgFromRgbaForAiUploadIsolate(
        rgba: rgba,
        width: width,
        height: height,
        quality: jpegQuality,
        maxLongEdge: maxLongEdge,
      ),
    );
  }

  Future<Uint8List> _encodeBytesForRegenerateUpload(
    Uint8List sourceBytes, {
    required _AiGenerationQuality quality,
  }) async {
    final Uint8List safeBytes = Uint8List.fromList(sourceBytes);
    final int jpegQuality = _regenerateJpegQualityForQuality(quality);
    final int maxLongEdge = _regenerateMaxLongEdgeForQuality(quality);
    return Isolate.run<Uint8List>(
      () => _encodeJpgFromBytesForAiUploadIsolate(
        encodedBytes: safeBytes,
        quality: jpegQuality,
        maxLongEdge: maxLongEdge,
      ),
    );
  }

  Future<void> _openRegenerateBottomSheet() async {
    final EditorLayer? initialLayer = _selectedImageLayer();
    if (initialLayer == null || initialLayer.image == null) {
      _showExportMessage('Select an image layer first.', isError: true);
      return;
    }

    final TextEditingController promptController =
        TextEditingController(text: _lastRegeneratePrompt);
    _RegenerateModel selectedModel = _defaultRegenerateModel;
    _RegenerateQualityPreset selectedQuality = _defaultRegenerateQualityPreset;
    Uint8List? secondReferenceBytes;
    bool sheetOpen = true;
    bool isUploadingReference = false;
    String? sheetError;

    try {
      final _RegenerateGenerateRequest? result =
          await showModalBottomSheet<_RegenerateGenerateRequest>(
        context: context,
        isScrollControlled: true,
        useSafeArea: true,
        barrierColor: Colors.transparent,
        backgroundColor: const Color(0xFF23262C),
        shape: const RoundedRectangleBorder(
          borderRadius: BorderRadius.vertical(top: Radius.circular(24)),
        ),
        builder: (sheetContext) {
          Future<void> pickSecondReference(StateSetter setSheetState) async {
            if (isUploadingReference) return;
            setSheetState(() {
              isUploadingReference = true;
              sheetError = null;
            });
            try {
              final XFile? file = await _picker.pickImage(
                source: ImageSource.gallery,
                imageQuality: 95,
              );
              if (file == null || !sheetContext.mounted || !sheetOpen) return;
              final Uint8List bytes = await file.readAsBytes();
              if (!sheetContext.mounted || !sheetOpen) return;
              setSheetState(() {
                secondReferenceBytes = bytes;
              });
            } catch (_) {
              if (!sheetContext.mounted || !sheetOpen) return;
              setSheetState(() {
                sheetError = 'Could not load the second reference image.';
              });
            } finally {
              if (sheetContext.mounted && sheetOpen) {
                setSheetState(() {
                  isUploadingReference = false;
                });
              }
            }
          }

          void submitRegenerate(StateSetter setSheetState) {
            if (isUploadingReference || _isAiCanvasGenerating) {
              return;
            }
            final String prompt = promptController.text.trim();
            if (prompt.isEmpty) {
              setSheetState(() {
                sheetError = 'Type a prompt first.';
              });
              return;
            }
            final List<_RegenerateQualityPreset> qualityOptions =
                _regenerateQualityOptionsForModel(selectedModel);
            final _RegenerateQualityPreset effectivePreset =
                qualityOptions.contains(selectedQuality)
                    ? selectedQuality
                    : qualityOptions.first;
            if (!sheetContext.mounted || !sheetOpen) return;
            sheetOpen = false;
            Navigator.of(sheetContext).pop(
              _RegenerateGenerateRequest(
                layerId: initialLayer.id,
                prompt: prompt,
                model: selectedModel,
                qualityPreset: effectivePreset,
                secondaryReferenceBytes: secondReferenceBytes,
              ),
            );
          }

