            _RegenerateQualityPreset preset,
            StateSetter setSheetState,
          ) {
            final bool selected = selectedQuality == preset;
            return _BouncyInkWell(
              pressedScale: 0.975,
              borderRadius: BorderRadius.circular(10),
              onTap: () {
