  Future<Uint8List> _prepareExpandSourcePayload({
    required ui.Image sourceImage,
    required _ExpandToolConfig config,
  }) async {
    final ByteData? rawData = await sourceImage.toByteData(
      format: ui.ImageByteFormat.rawRgba,
    );
    Uint8List sourceRgba;
    int sourceWidth = sourceImage.width;
    int sourceHeight = sourceImage.height;
    if (rawData != null) {
      sourceRgba = Uint8List.fromList(
        rawData.buffer.asUint8List(0, rawData.lengthInBytes),
      );
    } else {
      final Uint8List fallbackPngBytes =
          await _encodeUiImageToPngBytes(sourceImage);
      final img.Image? decoded = img.decodeImage(fallbackPngBytes);
      if (decoded == null || decoded.width <= 0 || decoded.height <= 0) {
        throw StateError('Unable to prepare Expand source image.');
      }
      sourceWidth = decoded.width;
      sourceHeight = decoded.height;
      sourceRgba = Uint8List.fromList(
        decoded.getBytes(order: img.ChannelOrder.rgba),
      );
    }

    final Map<String, Object> result = await Isolate.run<Map<String, Object>>(
      () => _prepareExpandSourcePayloadIsolate(
        sourceRgba: sourceRgba,
        sourceWidth: sourceWidth,
        sourceHeight: sourceHeight,
        leftExpand: config.leftExpand,
        topExpand: config.topExpand,
        rightExpand: config.rightExpand,
        bottomExpand: config.bottomExpand,
        maxLongSide: 2048,
        maxPixels: 4000000,
        sourceJpegQuality: 86,
      ),
    );
    return result['sourceImageBytes'] as Uint8List;
  }

  double _expandedAspectRatioForExpand(
    ui.Image sourceImage,
    _ExpandToolConfig config,
  ) {
    if (sourceImage.width <= 0 || sourceImage.height <= 0) {
      return 1.0;
    }
    final double widthFactor = 1.0 + config.leftExpand + config.rightExpand;
    final double heightFactor = 1.0 + config.topExpand + config.bottomExpand;
    if (widthFactor <= 0 || heightFactor <= 0) return 1.0;
    return (sourceImage.width * widthFactor) /
        (sourceImage.height * heightFactor);
  }

  String _nearestImageToImageAspectRatio(double ratio) {
    final double safeRatio = ratio.isFinite && ratio > 0 ? ratio : 1.0;
    const Map<String, double> options = <String, double>{
      '1:1': 1.0,
      '4:3': 4 / 3,
      '3:4': 3 / 4,
      '16:9': 16 / 9,
      '9:16': 9 / 16,
    };
    String selected = '1:1';
    double bestDelta = double.infinity;
    for (final MapEntry<String, double> entry in options.entries) {
      final double delta = (entry.value - safeRatio).abs();
      if (delta < bestDelta) {
        bestDelta = delta;
        selected = entry.key;
      }
    }
    return selected;
  }

  String _buildExpandOutpaintPrompt() {
    return 'Outpaint all newly added border areas with natural continuation of the scene from all sides. Keep center content consistent, avoid mirrored patterns, avoid repeated top strips, and remove empty/black borders completely.';
  }

  Future<String> _createKieGrokImagineExpandTask({
    required String imageUrl,
    required String aspectRatio,
    required String prompt,
  }) async {
    final String apiKey = _kieApiKey.trim();
    if (apiKey.isEmpty) {
      throw StateError('KIE API key missing.');
    }
    final Uri uri = Uri.parse('https://api.kie.ai/api/v1/jobs/createTask');
    final http.Response response = await http
        .post(
          uri,
          headers: <String, String>{
            'Authorization': 'Bearer $apiKey',
            'Content-Type': 'application/json',
          },
          body: jsonEncode(
            <String, dynamic>{
              'model': 'grok-imagine/image-to-image',
              'input': <String, dynamic>{
                'prompt': prompt,
                'image_urls': <String>[imageUrl],
                'aspect_ratio': aspectRatio,
              },
            },
          ),
        )
        .timeout(const Duration(minutes: 2));

    final Map<String, dynamic> decoded = _decodeKieJson(
      response.bodyBytes,
      contextLabel: 'KIE createTask (grok-imagine/image-to-image)',
    );
    final int code = _readKieCode(decoded['code']);
    final String message =
        (decoded['msg'] as String?)?.trim() ?? 'Unknown KIE error.';

    if (response.statusCode < 200 ||
        response.statusCode >= 300 ||
        code != 200) {
      throw StateError(
        'KIE grok-imagine/image-to-image createTask failed (${response.statusCode}): $message',
      );
    }

    final Map<String, dynamic>? data = decoded['data'] is Map<String, dynamic>
        ? decoded['data'] as Map<String, dynamic>
        : null;
    final String taskId =
        ((data?['taskId'] as String?) ?? (data?['recordId'] as String?) ?? '')
            .trim();
    if (taskId.isEmpty) {
      throw const FormatException(
        'KIE grok-imagine/image-to-image returned empty taskId.',
      );
    }
    return taskId;
  }

