  bool _looksLikeUnfilledExpandOutput({
    required Uint8List outputBytes,
    required _ExpandToolConfig config,
  }) {
    final img.Image? decoded = img.decodeImage(outputBytes);
    if (decoded == null || decoded.width <= 0 || decoded.height <= 0) {
      return false;
    }
    final int width = decoded.width;
    final int height = decoded.height;
    final double widthFactor = 1.0 + config.leftExpand + config.rightExpand;
    final double heightFactor = 1.0 + config.topExpand + config.bottomExpand;
    if (widthFactor <= 0 || heightFactor <= 0) return false;
    final int leftPx =
        math.max(0, (width * (config.leftExpand / widthFactor)).round());
    final int rightPx =
        math.max(0, (width * (config.rightExpand / widthFactor)).round());
    final int topPx =
        math.max(0, (height * (config.topExpand / heightFactor)).round());
    final int bottomPx =
        math.max(0, (height * (config.bottomExpand / heightFactor)).round());
    if (leftPx <= 0 && rightPx <= 0 && topPx <= 0 && bottomPx <= 0) {
      return false;
    }
    int sampled = 0;
    int nearBlack = 0;
    bool inExpandedArea(int x, int y) {
      if (leftPx > 0 && x < leftPx) return true;
      if (rightPx > 0 && x >= (width - rightPx)) return true;
      if (topPx > 0 && y < topPx) return true;
      if (bottomPx > 0 && y >= (height - bottomPx)) return true;
      return false;
    }

    for (int y = 0; y < height; y++) {
      for (int x = 0; x < width; x++) {
        if (!inExpandedArea(x, y)) continue;
        final img.Pixel p = decoded.getPixel(x, y);
        final int r = p.r.toInt();
        final int g = p.g.toInt();
        final int b = p.b.toInt();
        sampled++;
        if (r < 24 && g < 24 && b < 24) {
          nearBlack++;
        }
      }
    }
    if (sampled == 0) return false;
    final double blackRatio = nearBlack / sampled;
    return blackRatio >= 0.32;
  }

  String _normalizeExpandError(String raw) {
    final String message = _normalizeSketchReplaceError(raw);
    final String lower = message.toLowerCase();
    if (lower.contains('failed to load the image') ||
        lower.contains('image file is not corrupted') ||
        lower.contains('unsupported format')) {
      return 'Expand failed: the AI service could not load the prepared image. Try a smaller expand area and retry.';
    }
    if (lower.contains('mask') && lower.contains('black and white')) {
      return 'Expand failed: generated mask is invalid. Please retry.';
    }
    if (lower.contains('this field is required')) {
      return 'Expand request is missing required AI fields. Please retry.';
    }
    if (lower.contains('timeout')) {
      return 'Expand timed out. Please retry.';
    }
    return message;
  }

  Size? _currentCanvasViewportSize() {
    final BuildContext? viewportContext = _canvasViewportKey.currentContext;
    if (viewportContext == null) return null;
    final RenderObject? renderObject = viewportContext.findRenderObject();
    if (renderObject is! RenderBox || !renderObject.hasSize) {
      return null;
    }
    final Size canvasSize = renderObject.size;
    if (canvasSize.width <= 0 || canvasSize.height <= 0) {
      return null;
    }
    return canvasSize;
  }

  Map<String, _WorkspaceResizeLayerTransform>
      _captureNonBackgroundTransformsForWorkspaceResize({
    required Size oldWorkspaceSize,
    required Size newWorkspaceSize,
    required String backgroundLayerId,
  }) {
    final Size? canvasSize = _currentCanvasViewportSize();
    if (canvasSize == null) {
      return const <String, _WorkspaceResizeLayerTransform>{};
    }
    if (oldWorkspaceSize.width <= 0 ||
        oldWorkspaceSize.height <= 0 ||
        newWorkspaceSize.width <= 0 ||
        newWorkspaceSize.height <= 0) {
      return const <String, _WorkspaceResizeLayerTransform>{};
    }

    final Rect oldArtboard = _computeArtboardRect(
      canvasSize: canvasSize,
      workspaceSize: oldWorkspaceSize,
    );
    final Rect newArtboard = _computeArtboardRect(
      canvasSize: canvasSize,
      workspaceSize: newWorkspaceSize,
    );
    if (oldArtboard.width <= 0 ||
        oldArtboard.height <= 0 ||
        newArtboard.width <= 0 ||
        newArtboard.height <= 0) {
      return const <String, _WorkspaceResizeLayerTransform>{};
    }

    final double oldUnitScale = oldArtboard.width / oldWorkspaceSize.width;
    final double newUnitScale = newArtboard.width / newWorkspaceSize.width;
    if (oldUnitScale <= 0 || newUnitScale <= 0) {
      return const <String, _WorkspaceResizeLayerTransform>{};
    }

    final double layerScaleFactor = oldUnitScale / newUnitScale;
    final Map<String, _WorkspaceResizeLayerTransform> result =
        <String, _WorkspaceResizeLayerTransform>{};
    for (final EditorLayer layer in _layers) {
      if (layer.id == backgroundLayerId || layer.isBackground) continue;
      final Offset oldPosition = layer.position ??
          Offset(oldWorkspaceSize.width / 2, oldWorkspaceSize.height / 2);
      final Offset oldSceneCenter = oldArtboard.topLeft +
          Offset(oldPosition.dx * oldUnitScale, oldPosition.dy * oldUnitScale);
      final Offset newPosition = Offset(
        (oldSceneCenter.dx - newArtboard.left) / newUnitScale,
        (oldSceneCenter.dy - newArtboard.top) / newUnitScale,
      );
      result[layer.id] = _WorkspaceResizeLayerTransform(
        position: newPosition,
        layerScale: (layer.layerScale * layerScaleFactor).clamp(0.001, 1000.0),
      );
    }
    return result;
  }

  Future<void> _runExpandWithIdeogramReframe() async {
    if (_isExpandGenerating || _isAiCanvasGenerating || _isExporting) return;
    final EditorLayer? selectedLayer = _selectedExpandLayer();
    final _ExpandToolConfig? config = _expandToolConfig;
    final ui.Image? sourceImage = selectedLayer?.image;
    if (selectedLayer == null || sourceImage == null || config == null) {
      _showExportMessage('Select an image layer first.', isError: true);
      return;
    }
    if (config.layerId != selectedLayer.id) {
      _showExportMessage('Expand config is not synced with selected layer.',
          isError: true);
      return;
    }
    final double totalExpand = config.leftExpand +
        config.topExpand +
        config.rightExpand +
        config.bottomExpand;
    if (totalExpand <= 0.0001) {
      _showExportMessage('Drag one of the expand handles first.',
          isError: true);
      return;
    }
    final String apiKey = _kieApiKey.trim();
    if (apiKey.isEmpty) {
      _showExportMessage('KIE API key missing.', isError: true);
      return;
    }

    setState(() {
      _isExpandGenerating = true;
    });

    try {
      final Uint8List sourcePayloadBytes = await _prepareExpandSourcePayload(
        sourceImage: sourceImage,
        config: config,
      );
      final String imageUrl = await _uploadKieReferenceFile(
        sourcePayloadBytes,
        preserveFormat: true,
      );
      final String aspectRatio = _nearestImageToImageAspectRatio(
        _expandedAspectRatioForExpand(sourceImage, config),
      );
      String taskId = await _createKieGrokImagineExpandTask(
        imageUrl: imageUrl,
        aspectRatio: aspectRatio,
        prompt: _buildExpandOutpaintPrompt(),
      );
      Uint8List outputBytes = await _pollKieTaskAndDownload(taskId: taskId);
      if (_looksLikeUnfilledExpandOutput(
          outputBytes: outputBytes, config: config)) {
        taskId = await _createKieFlux2ProExpandTask(
          imageUrl: imageUrl,
          aspectRatio: aspectRatio,
          prompt: _buildExpandOutpaintPrompt(),
        );
        outputBytes = await _pollKieTaskAndDownload(taskId: taskId);
      }
      final ui.Image nextImage = await _decodeUiImage(outputBytes);
      if (!mounted) return;
      final Map<String, _WorkspaceResizeLayerTransform>
          preservedLayerTransforms = selectedLayer.isBackground
              ? _captureNonBackgroundTransformsForWorkspaceResize(
                  oldWorkspaceSize: Size(
                    sourceImage.width.toDouble(),
                    sourceImage.height.toDouble(),
                  ),
                  newWorkspaceSize: Size(
                    nextImage.width.toDouble(),
                    nextImage.height.toDouble(),
                  ),
                  backgroundLayerId: selectedLayer.id,
                )
              : const <String, _WorkspaceResizeLayerTransform>{};
      final EditorLayer? workspace = _workspaceLayerForEdit(_layers);
      final Size? workspaceSize =
          workspace == null ? null : _workspaceSourceSize(workspace);
      final Offset oldPosition = selectedLayer.position ??
          Offset(
            (workspaceSize?.width ?? sourceImage.width.toDouble()) / 2,
            (workspaceSize?.height ?? sourceImage.height.toDouble()) / 2,
          );
      final double widthFactor = 1.0 + config.leftExpand + config.rightExpand;
      final double heightFactor = 1.0 + config.topExpand + config.bottomExpand;
      final double localShiftXPx = widthFactor <= 0
          ? 0
          : (((config.leftExpand - config.rightExpand) / (2 * widthFactor)) *
              nextImage.width);
      final double localShiftYPx = heightFactor <= 0
          ? 0
          : (((config.topExpand - config.bottomExpand) / (2 * heightFactor)) *
              nextImage.height);
      final Offset localShiftWorkspace = Offset(
        localShiftXPx * selectedLayer.layerScale,
        localShiftYPx * selectedLayer.layerScale,
      );
      final Offset rotatedShiftWorkspace =
          _rotateVector(localShiftWorkspace, selectedLayer.layerRotation);
      final Offset nextPosition = oldPosition - rotatedShiftWorkspace;
      _pushUndoSnapshot();
      setState(() {
        final int layerIndex =
            _layers.indexWhere((entry) => entry.id == selectedLayer.id);
        if (layerIndex >= 0) {
          final List<EditorLayer> nextLayers = List<EditorLayer>.from(_layers);
          final EditorLayer current = nextLayers[layerIndex];
          nextLayers[layerIndex] = current.copyWith(
            image: nextImage,
            solidSize: _imageSourceSize(nextImage),
            thumbnailBytes: null,
            position: nextPosition,
          );
          if (preservedLayerTransforms.isNotEmpty) {
            for (int i = 0; i < nextLayers.length; i++) {
              final EditorLayer layer = nextLayers[i];
              final _WorkspaceResizeLayerTransform? transform =
                  preservedLayerTransforms[layer.id];
              if (transform == null) continue;
              nextLayers[i] = layer.copyWith(
                position: transform.position,
                layerScale: transform.layerScale,
              );
            }
          }
          _layers = nextLayers;
        }
        _expandToolConfig = _defaultExpandConfig(selectedLayer.id);
      });
      _showExportMessage('Expand completed successfully.');
    } catch (error) {
      if (!mounted) return;
      _showExportMessage(_normalizeExpandError(error.toString()),
          isError: true);
    } finally {
      if (mounted) {
        setState(() {
          _isExpandGenerating = false;
        });
      }
    }
  }

  void _onTextSettingsToolTap() {
    if (_isTextSettingsBottomSheetOpen) {
      Navigator.of(context).maybePop();
      return;
    }
    if (_selectedTextLayer() == null) {
      final String? created = _createTextLayer(shouldShowError: true);
      if (created == null) return;
    }
    _setActiveTool(EditorTool.text, toggleWhenSame: false);
    setState(() {
      _isTextSettingsDockEnabled = true;
    });
    _openTextSettingsBottomSheet();
  }

  Future<void> _openTextSettingsBottomSheet() async {
    final EditorLayer? selectedLayer = _selectedTextLayer();
    if (selectedLayer == null) return;
    _syncTextLocaleFromFamily(selectedLayer.textFontFamily);

    _TextSettingsBottomSheetTab activeTab = _TextSettingsBottomSheetTab.fonts;
    _TextFontLocale locale = _textFontLocale;
    String query = '';
    final TextEditingController searchController = TextEditingController();
    final ScrollController fontsController = ScrollController();

    setState(() {
      _isTextSettingsBottomSheetOpen = true;
      _isTextSettingsDockEnabled = true;
      _resetTextQuickFloatingPanels(clearSearch: false);
      _activeTextEffectFloatingPanel = null;
    });
    _closeToolSettingsSidebarIfOpen();

    try {
      await showModalBottomSheet<void>(
        context: context,
        isScrollControlled: true,
        useSafeArea: true,
        backgroundColor: Colors.transparent,
        barrierColor: Colors.transparent,
        builder: (BuildContext sheetContext) {
          final double maxHeight =
              MediaQuery.sizeOf(sheetContext).height * 0.52;
          return Padding(
            padding: EdgeInsets.only(
              bottom: MediaQuery.viewInsetsOf(sheetContext).bottom,
            ),
            child: StatefulBuilder(
              builder: (context, modalSetState) {
                final EditorLayer? selectedTextLayer = _selectedTextLayer();
                if (selectedTextLayer == null) {
                  return const SizedBox.shrink();
                }
                const double uiScale = 0.82;
                double scaled(double value, {required double min}) =>
                    math.max(min, value * uiScale);

                final List<_TextFontOption> localeOptions =
                    _fontOptionsForLocale(locale);
                final List<_TextFontOption> options = _filteredTextFontOptions(
                  locale: locale,
                  query: query,
                );
                final String selectedFamily =
                    selectedTextLayer.textFontFamily ??
                        localeOptions.first.family;
                final int selectedIndexRaw = options
                    .indexWhere((option) => option.family == selectedFamily);
                final int selectedIndex = selectedIndexRaw < 0
                    ? 0
                    : selectedIndexRaw
                        .clamp(0, math.max(0, options.length - 1))
                        .toInt();
                final bool canGoBack = options.isNotEmpty && selectedIndex > 0;
                final bool canGoNext =
                    options.isNotEmpty && selectedIndex < options.length - 1;
                final Color selectedColor =
                    selectedTextLayer.textColor ?? const Color(0xFF1F2937);
                final Color selectedStrokeColor =
                    selectedTextLayer.textStrokeColor ??
                        const Color(0xFFFFFFFF);
                final double selectedStrokeWidth =
                    selectedTextLayer.textStrokeWidth ?? 0;
                final Color selectedShadowColor =
                    selectedTextLayer.textShadowColor ??
                        const Color(0xFF19191A);
                final double selectedShadowOffsetX =
                    selectedTextLayer.textShadowOffsetX ?? 0;
                final double selectedShadowOffsetY =
                    selectedTextLayer.textShadowOffsetY ?? 0;
                final double selectedShadowBlur =
                    selectedTextLayer.textShadowBlur ?? 0;
                final double selectedShadowOpacity =
                    selectedTextLayer.textShadowOpacity ?? 0;
                final double selectedTextOpacity =
                    selectedTextLayer.textOpacity ?? 100;
                final double selectedTextBend = selectedTextLayer.textBend ?? 0;
                final int selectedWeight = _resolveSupportedWeight(
                  selectedFamily,
                  selectedTextLayer.textFontWeight ?? 400,
                );
                final List<int> availableWeights =
                    _availableWeightsForFamily(selectedFamily);
                final double cardHeight = scaled(47, min: 38);
                final double cardSpacing = scaled(6, min: 4);
                final double itemExtent = cardHeight + cardSpacing;

                void jumpFontSelection(int direction) {
                  if (options.isEmpty) return;
                  final int nextIndex = (selectedIndex + direction)
                      .clamp(0, options.length - 1)
                      .toInt();
                  if (nextIndex == selectedIndex) return;
                  _applyTextFontOption(options[nextIndex]);
                  modalSetState(() {});
                  WidgetsBinding.instance.addPostFrameCallback((_) {
                    if (!fontsController.hasClients) return;
                    final double max = fontsController.position.maxScrollExtent;
                    final double target =
                        (nextIndex * itemExtent).clamp(0.0, max);
                    fontsController.animateTo(
                      target,
                      duration: const Duration(milliseconds: 180),
                      curve: Curves.easeOutCubic,
                    );
                  });
                }

                Widget effectContent() {
                  switch (activeTab) {
                    case _TextSettingsBottomSheetTab.fonts:
                      return const SizedBox.shrink();
                    case _TextSettingsBottomSheetTab.weight:
                      return Container(
                        width: double.infinity,
                        padding: EdgeInsets.all(scaled(8, min: 6)),
                        decoration: BoxDecoration(
                          color: _floatingPanelSurface,
                          borderRadius: BorderRadius.circular(
                            scaled(12, min: 9),
                          ),
                        ),
                        child: SizedBox(
                          height: scaled(42, min: 34),
                          child: ListView.separated(
                            scrollDirection: Axis.horizontal,
                            itemCount: availableWeights.length,
                            separatorBuilder: (_, __) =>
                                SizedBox(width: scaled(7, min: 5)),
                            itemBuilder: (context, index) {
                              final int weightValue = availableWeights[index];
                              final bool isSelected =
                                  selectedWeight == weightValue;
                              return _BouncyInkWell(
                                borderRadius: BorderRadius.circular(
                                  scaled(8, min: 6),
                                ),
                                onTap: () {
                                  _updateTextLayer(
                                    selectedTextLayer.id,
                                    textFontWeight: weightValue,
                                    recordHistory: false,
                                  );
                                  modalSetState(() {});
                                },
                                pressedScale: 0.965,
                                child: Container(
                                  width: scaled(34, min: 28),
                                  height: scaled(34, min: 28),
                                  alignment: Alignment.center,
                                  decoration: BoxDecoration(
                                    color: isSelected
                                        ? kActiveAccent
                                        : _floatingPanelSurfaceSolid,
                                    shape: BoxShape.circle,
                                  ),
                                  child: Text(
                                    'B',
                                    style: TextStyle(
                                      color: isSelected
                                          ? kActiveAccentForeground
                                          : const Color(0xFFF3F3F2),
                                      fontSize: scaled(16, min: 12),
                                      fontFamily: selectedFamily,
