  void _onCloneToolTap() {
    _setActiveTool(EditorTool.clone, toggleWhenSame: false);
    _openCloneSettingsFloatingPanel();
  }

  void _resetBlurPreviewSession({
    bool clearError = true,
    bool clearBaseline = true,
  }) {
    _blurPreviewDirty = false;
    if (clearBaseline) {
      _blurSettingsBaseline = null;
      _blurSettingsAtOpen = null;
    }
    if (clearError) {
      _blurError = null;
    }
  }

  bool _hasBlurSettingsChangedFromOpen() {
    final BlurToolSettings? baseline = _blurSettingsAtOpen;
    if (baseline == null) return true;
    if (baseline.mode != _blurSettings.mode) return true;
    if ((baseline.radius - _blurSettings.radius).abs() > 0.001) return true;
    if ((baseline.amount - _blurSettings.amount).abs() > 0.001) return true;
    return false;
  }

  BlurToolSettings _resolvedBlurSettingsForLayer(EditorLayer layer) {
    final String? modeKey = layer.imageBlurModeKey;
    final BlurMode mode = BlurMode.values.firstWhere(
      (entry) => entry.name == modeKey,
      orElse: () => BlurMode.gaussian,
    );
    final double radius = (layer.imageBlurRadius ?? _blurSettings.radius)
        .clamp(0.0, 60.0)
        .toDouble();
    final double amount = (layer.imageBlurAmount ?? _blurSettings.amount)
        .clamp(0.0, 100.0)
        .toDouble();
    return BlurToolSettings(mode: mode, radius: radius, amount: amount);
  }

  void _applyLiveBlurSettings({
    BlurMode? mode,
    double? radius,
    double? amount,
  }) {
    final EditorLayer? selectedLayer = _selectedImageLayer();
    if (selectedLayer == null) return;
    final int index =
        _layers.indexWhere((entry) => entry.id == selectedLayer.id);
    if (index < 0) return;

    final BlurToolSettings nextSettings = _blurSettings.copyWith(
      mode: mode,
      radius: radius?.clamp(0.0, 60.0).toDouble(),
      amount: amount?.clamp(0.0, 100.0).toDouble(),
    );
    final List<EditorLayer> nextLayers = List<EditorLayer>.from(_layers);
    nextLayers[index] = selectedLayer.copyWith(
      imageBlurModeKey: nextSettings.mode.name,
      imageBlurRadius: nextSettings.radius,
      imageBlurAmount: nextSettings.amount,
    );
    setState(() {
      _blurSettings = nextSettings;
      _layers = nextLayers;
      _blurError = null;
      _blurPreviewDirty = _hasBlurSettingsChangedFromOpen();
    });
  }

  void _onBlurToolTap() {
    final EditorLayer? selectedImage = _selectedImageLayer();
    if (selectedImage == null) {
      _showExportMessage('Select an image layer first.', isError: true);
      return;
    }
    _setActiveTool(EditorTool.blur, toggleWhenSame: false);
    _openBlurSettingsBottomSheet();
  }

  void _onRemoveObjectToolTap() {
    _setActiveTool(EditorTool.sketchReplace, toggleWhenSame: false);
    _openSketchReplaceFloatingPanel();
  }

  void _openToolSettingsSidebar() {
    if (_isToolEnabled &&
        _activeTool == EditorTool.clone &&
        _selectedImageLayer() != null) {
      _openCloneSettingsBottomSheet();
      return;
    }
    if (_isToolEnabled &&
        _activeTool == EditorTool.blur &&
        _selectedImageLayer() != null) {
      _openBlurSettingsBottomSheet();
      return;
    }
    _scaffoldKey.currentState?.openEndDrawer();
  }

  void _closeToolSettingsSidebarIfOpen() {
    final ScaffoldState? scaffoldState = _scaffoldKey.currentState;
    if (scaffoldState == null || !scaffoldState.isEndDrawerOpen) return;
    Navigator.of(context).maybePop();
  }

  Widget _buildToolSettingsSidebar(BuildContext context) {
    final double width = MediaQuery.sizeOf(context).width * 0.80;
    return Drawer(
      width: width,
      backgroundColor: const Color(0xFF1E1F22),
      shape: const RoundedRectangleBorder(
        borderRadius: BorderRadius.only(
          topLeft: Radius.circular(18),
          bottomLeft: Radius.circular(18),
        ),
      ),
      child: SafeArea(
        child: Padding(
          padding: const EdgeInsets.fromLTRB(14, 10, 14, 16),
          child: Column(
            crossAxisAlignment: CrossAxisAlignment.start,
            children: [
              Row(
                children: [
                  Expanded(
                    child: Text(
                      _toolSettingsTitle(),
                      style: const TextStyle(
                        fontSize: 16,
                        fontWeight: FontWeight.w700,
                        color: Color(0xFFF3F3F2),
                      ),
                    ),
                  ),
                  IconButton(
                    visualDensity: VisualDensity.compact,
                    onPressed: () => Navigator.of(context).maybePop(),
                    icon: const Icon(
                      Icons.close,
                      size: 20,
                      color: Color(0xFFD4D4D3),
                    ),
                  ),
                ],
              ),
              const SizedBox(height: 6),
              Expanded(
                child: SingleChildScrollView(
                  child: _buildToolSettingsContent(),
                ),
              ),
            ],
          ),
        ),
      ),
    );
  }

  EditorTool? _resolvedSettingsTool() {
    if (!_isToolEnabled) return null;
    switch (_activeTool) {
      case EditorTool.pencil:
      case EditorTool.clone:
      case EditorTool.blur:
      case EditorTool.crop:
      case EditorTool.expand:
      case EditorTool.marquee:
      case EditorTool.regenerate:
      case EditorTool.removeBg:
      case EditorTool.replaceObject:
        return _activeTool;
      case EditorTool.sketchReplace:
        return _activeTool;
      case EditorTool.text:
        final EditorLayer? selectedLayer = _selectedSidebarLayerContext();
        if (selectedLayer?.type == EditorLayerType.text) {
          return EditorTool.text;
        }
        return null;
      case EditorTool.move:
        return null;
    }
  }

  EditorLayer? _selectedSidebarLayerContext() {
    final EditorLayer? selectedLayer = _selectedLayer();
    if (selectedLayer == null || !selectedLayer.isVisible) {
      return null;
    }
    return selectedLayer;
  }

  String _toolSettingsTitle() {
    final EditorLayer? selectedLayer = _selectedSidebarLayerContext();
    final EditorTool? resolved = _resolvedSettingsTool();
    switch (resolved) {
      case EditorTool.pencil:
        return 'Pencil Tool Settings';
      case EditorTool.text:
        return 'Text Tool Settings';
      case EditorTool.clone:
        return 'Clone Tool Settings';
      case EditorTool.blur:
        return 'Blur Tool Settings';
      case EditorTool.crop:
        return 'Crop Tool Settings';
      case EditorTool.expand:
        return 'Expand Tool Settings';
      case EditorTool.marquee:
        return 'Selection Tool Settings';
      case EditorTool.regenerate:
        return 'Regenerate Settings';
      case EditorTool.removeBg:
        return 'Remove Background Settings';
      case EditorTool.sketchReplace:
        return 'Remove Object Settings';
      case EditorTool.replaceObject:
        return 'Replace Object Settings';
      case null:
        if (selectedLayer == null) {
          return _isToolEnabled ? 'Layer Settings' : 'View Mode';
        }
        if (selectedLayer.type == EditorLayerType.image &&
            selectedLayer.isBackground) {
          return 'Background Layer Settings';
        }
        if (selectedLayer.type == EditorLayerType.image &&
            !selectedLayer.isBackground) {
          return 'Overlay Layer Settings';
        }
        return '${selectedLayer.type.label} Layer Settings';
      case EditorTool.move:
        return 'Layer Settings';
    }
  }

  Widget _buildToolSettingsContent() {
    final EditorLayer? selectedLayer = _selectedSidebarLayerContext();
    final EditorTool? resolved = _resolvedSettingsTool();
    switch (resolved) {
      case EditorTool.pencil:
        return _buildPencilSettingsPanel();
      case EditorTool.text:
        return _buildTextSettingsPanel();
      case EditorTool.clone:
        return _buildCloneSettingsPanel();
      case EditorTool.blur:
        return _buildBlurSettingsPanel();
      case EditorTool.crop:
        return _buildCropSettingsPanel();
      case EditorTool.expand:
        return _buildExpandSettingsPanel();
      case EditorTool.marquee:
        return _buildMarqueeSettingsPanel();
      case EditorTool.regenerate:
        return _buildRegenerateSettingsPanel();
      case EditorTool.removeBg:
        return _buildRemoveBackgroundSettingsPanel();
      case EditorTool.sketchReplace:
        return _buildSketchReplaceSettingsPanel();
      case EditorTool.replaceObject:
        return _buildReplaceObjectSettingsPanel();
      case null:
        if (selectedLayer == null) {
          if (_isToolEnabled) {
            return const _ToolHintCard(
              title: 'No Layer Selected',
              message: 'Select a layer to view and edit its settings.',
            );
          }
          return const _ToolHintCard(
            title: 'View Mode',
            message:
                'No active tool. Tap any tool button to enable editing controls.',
          );
        }
        if (selectedLayer.type == EditorLayerType.image) {
          return _buildImageLayerSettingsPanel(selectedLayer);
        }
        if (selectedLayer.type == EditorLayerType.text) {
          return _buildTextSettingsPanel();
        }
        return _ToolHintCard(
          title: '${selectedLayer.type.label} Layer',
          message:
              'Layer selected. Settings shown for the currently selected layer.',
        );
      case EditorTool.move:
        return const _ToolHintCard(
          title: 'Layer Settings',
          message:
              'Selection tool has no direct settings. Select a layer to view related options.',
        );
    }
  }

  void _onOverlayCutConfigChangedFromCanvas(_OverlayCutConfig nextConfig) {
    _updateOverlayCutConfig(
      shape: nextConfig.shape,
      centerUv: nextConfig.centerUv,
      scaleX: nextConfig.scaleX,
      scaleY: nextConfig.scaleY,
      rotationRadians: nextConfig.rotationRadians,
    );
  }

  void _onCropToolConfigChangedFromCanvas(_CropToolConfig nextConfig) {
    final EditorLayer? selectedImage = _selectedCropLayer();
    if (selectedImage == null) return;
    if (selectedImage.id != nextConfig.layerId) return;
    setState(() {
      _cropToolConfig = _normalizedCropConfig(nextConfig);
    });
  }

  void _onExpandToolConfigChangedFromCanvas(_ExpandToolConfig nextConfig) {
    final EditorLayer? selectedImage = _selectedExpandLayer();
    if (selectedImage == null) return;
    if (selectedImage.id != nextConfig.layerId) return;
    setState(() {
      _expandToolConfig = _normalizedExpandConfig(nextConfig);
    });
  }

  void _onCropCommitRequestedFromCanvas() {
    unawaited(_applyCropFloatingPanel());
  }

  bool get _canUndo => _undoStack.isNotEmpty;
  bool get _canRedo => _redoStack.isNotEmpty;

  _EditorSnapshot _captureSnapshot() {
    return _EditorSnapshot(
      layers: List<EditorLayer>.from(_layers),
      pencilStrokes: _cloneBrushStrokes(_pencilStrokes),
      selectedLayerId: _selectedLayerId,
      activeTool: _activeTool,
      isToolEnabled: _isToolEnabled,
      nextLayerId: _nextLayerId,
      isCloneSourceArmed: _isCloneSourceArmed,
      isCloneBrushSelected: _isCloneBrushSelected,
      isCloneEraseSelected: _isCloneEraseSelected,
      textFontLocale: _textFontLocale,
      marqueeMode: _marqueeMode,
      marqueeSelection: _marqueeSelection,
    );
  }

  bool _snapshotsEqual(_EditorSnapshot a, _EditorSnapshot b) {
    if (!_brushStrokeListsEqual(a.pencilStrokes, b.pencilStrokes)) {
      return false;
    }
    if (a.selectedLayerId != b.selectedLayerId) return false;
    if (a.activeTool != b.activeTool) return false;
    if (a.isToolEnabled != b.isToolEnabled) return false;
    if (a.nextLayerId != b.nextLayerId) return false;
    if (a.isCloneSourceArmed != b.isCloneSourceArmed) return false;
    if (a.isCloneBrushSelected != b.isCloneBrushSelected) return false;
    if (a.isCloneEraseSelected != b.isCloneEraseSelected) return false;
    if (a.textFontLocale != b.textFontLocale) return false;
    if (a.marqueeMode != b.marqueeMode) return false;
    if (!_marqueeSelectionsEqual(a.marqueeSelection, b.marqueeSelection)) {
      return false;
    }
    if (a.layers.length != b.layers.length) return false;
    for (int i = 0; i < a.layers.length; i++) {
      if (!identical(a.layers[i], b.layers[i])) return false;
    }
    return true;
  }

  void _pushUndoSnapshot() {
    final _EditorSnapshot snapshot = _captureSnapshot();
    if (_undoStack.isNotEmpty && _snapshotsEqual(_undoStack.last, snapshot)) {
      return;
    }
    _undoStack.add(snapshot);
    if (_undoStack.length > _historyLimit) {
      _undoStack.removeAt(0);
    }
    _redoStack.clear();
  }

  void _pushUndoSnapshotFrom(_EditorSnapshot snapshot) {
    final _EditorSnapshot current = _captureSnapshot();
    if (_snapshotsEqual(snapshot, current)) return;
    if (_undoStack.isNotEmpty && _snapshotsEqual(_undoStack.last, snapshot)) {
      return;
    }
    _undoStack.add(snapshot);
    if (_undoStack.length > _historyLimit) {
      _undoStack.removeAt(0);
    }
    _redoStack.clear();
  }

  void _applySnapshot(_EditorSnapshot snapshot) {
    setState(() {
      _layers = List<EditorLayer>.from(snapshot.layers);
      _pencilStrokes = _cloneBrushStrokes(snapshot.pencilStrokes);
      _selectedLayerId = snapshot.selectedLayerId;
      _activeTool = snapshot.activeTool;
      _isToolEnabled = snapshot.isToolEnabled;
      _nextLayerId = snapshot.nextLayerId;
      _isCloneSourceArmed = snapshot.isCloneSourceArmed;
      _isCloneBrushSelected = snapshot.isCloneBrushSelected;
      _isCloneEraseSelected = snapshot.isCloneEraseSelected;
      _textFontLocale = snapshot.textFontLocale;
      _marqueeMode = snapshot.marqueeMode;
      _marqueeSelection = snapshot.marqueeSelection;
      _activeTextEffectFloatingPanel = null;
      _isPencilSettingsFloatingOpen = false;
      _pencilSettingsFloatingBaseline = null;
      _isCloneSettingsFloatingOpen = false;
      _isCloneSettingsBottomSheetOpen = false;
      _isCloneBrushPreviewVisible = false;
      _cloneSettingsFloatingBaseline = null;
      _cloneSourceArmedFloatingBaseline = null;
      _cloneBrushSelectedFloatingBaseline = null;
      _cloneEraseSelectedFloatingBaseline = null;
      _isOverlayCutFloatingOpen = false;
      _overlayCutConfig = null;
      _overlayCutBaseline = null;
      _isCropFloatingOpen = false;
      _cropToolConfig = null;
      _expandToolConfig = null;
      _isOverlayImageShadowFloatingOpen = false;
      _overlayImageShadowFloatingBaseline = null;
      _overlayImageShadowFloatingLayerId = null;
      _isPhotoRoomRemoveBgFloatingOpen = false;
      _isPhotoRoomRemoveBgProcessing = false;
      _resetTextQuickFloatingPanels();
      _photoRoomRemoveBgFloatingBaseline = null;
      _isTransformHistoryCaptured = false;
      _isTextEditHistoryCaptured = false;
    });
    _syncTextInputFromSelectedLayer();
  }

  void _onPencilStrokeCommitted(_BrushStroke stroke) {
    if (stroke.points.isEmpty) return;
    _pushUndoSnapshot();
    setState(() {
      _pencilStrokes = List<_BrushStroke>.from(_pencilStrokes)
        ..add(stroke.copy());
    });
  }

  List<_BrushStroke> _cloneBrushStrokes(List<_BrushStroke> strokes) {
    return strokes.map((stroke) => stroke.copy()).toList(growable: false);
  }

  bool _brushStrokeListsEqual(List<_BrushStroke> a, List<_BrushStroke> b) {
    if (identical(a, b)) return true;
    if (a.length != b.length) return false;
    for (int i = 0; i < a.length; i++) {
      if (!a[i].isContentEqual(b[i])) return false;
    }
    return true;
  }

  void _undo() {
    if (!_canUndo) return;
    final _EditorSnapshot current = _captureSnapshot();
    final _EditorSnapshot target = _undoStack.removeLast();
    _redoStack.add(current);
    if (_redoStack.length > _historyLimit) {
      _redoStack.removeAt(0);
    }
    _applySnapshot(target);
  }

  void _redo() {
    if (!_canRedo) return;
    final _EditorSnapshot current = _captureSnapshot();
    final _EditorSnapshot target = _redoStack.removeLast();
    _undoStack.add(current);
    if (_undoStack.length > _historyLimit) {
      _undoStack.removeAt(0);
    }
    _applySnapshot(target);
  }

  void _onTransformInteractionStart() {
    if (_isTransformHistoryCaptured) return;
    _pushUndoSnapshot();
    _isTransformHistoryCaptured = true;
  }

  void _onTransformInteractionEnd() {
    _isTransformHistoryCaptured = false;
  }

  bool _marqueeSelectionsEqual(MarqueeSelection? a, MarqueeSelection? b) {
    if (identical(a, b)) return true;
    if (a == null || b == null) return false;
    if (a.layerId != b.layerId) return false;
    if (a.mode != b.mode) return false;
    if (a.boundsUv != b.boundsUv) return false;
    if (a.freePathUv.length != b.freePathUv.length) return false;
    for (int i = 0; i < a.freePathUv.length; i++) {
      if (a.freePathUv[i] != b.freePathUv[i]) return false;
    }
    return true;
  }

  void _onMarqueeSelectionChanged(MarqueeSelection? selection) {
    final MarqueeSelection? sanitized =
        selection != null && selection.hasUsableArea ? selection : null;
    if (_marqueeSelectionsEqual(_marqueeSelection, sanitized)) return;
    setState(() {
      _marqueeSelection = sanitized;
    });
  }

  void _onTextFocusChanged() {
    if (_textInputFocusNode.hasFocus) return;
    _isTextEditHistoryCaptured = false;
  }

