  EditorLayer? _selectedLayer() {
    if (_selectedLayerId == null) return null;
    for (final EditorLayer layer in _layers) {
      if (layer.id == _selectedLayerId) {
        return layer;
      }
    }
    return null;
  }

  EditorLayer? _selectedImageLayer() {
    final EditorLayer? layer = _selectedLayer();
    if (layer == null) return null;
    if (!layer.isVisible) return null;
    if (layer.type != EditorLayerType.image) return null;
    if (layer.image == null) return null;
    return layer;
  }

  EditorLayer? _selectedOverlayImageLayer() {
    final EditorLayer? layer = _selectedImageLayer();
    if (layer == null) return null;
    if (layer.isBackground) return null;
    return layer;
  }

  EditorLayer? _selectedMarqueeLayer() {
    final EditorLayer? layer = _selectedImageLayer();
    return layer;
  }

  EditorLayer? _selectedCropLayer() {
    return _selectedOverlayImageLayer();
  }

  EditorLayer? _selectedExpandLayer() {
    return _selectedImageLayer();
  }

  EditorLayer? _selectedTextLayer() {
    final EditorLayer? layer = _selectedLayer();
    if (layer == null) return null;
    if (!layer.isVisible) return null;
    if (layer.type != EditorLayerType.text) return null;
    return layer;
  }

  List<_SketchMaskStroke> _activeSketchMaskStrokes() {
    final String? layerId = _selectedImageLayer()?.id;
    if (layerId == null) return const <_SketchMaskStroke>[];
    final Map<String, List<_SketchMaskStroke>> sourceMap =
        _activeTool == EditorTool.replaceObject
            ? _replaceObjectMaskStrokesByLayer
            : _sketchMaskStrokesByLayer;
    final List<_SketchMaskStroke>? existing = sourceMap[layerId];
    if (existing == null || existing.isEmpty) {
      return const <_SketchMaskStroke>[];
    }
    return List<_SketchMaskStroke>.unmodifiable(existing);
  }

  void _onSketchMaskStrokeCommitted(_SketchMaskStroke stroke) {
    final bool isReplaceTool = _activeTool == EditorTool.replaceObject;
    final Map<String, List<_SketchMaskStroke>> targetMap = isReplaceTool
        ? _replaceObjectMaskStrokesByLayer
        : _sketchMaskStrokesByLayer;
    final List<_SketchMaskStroke> current = List<_SketchMaskStroke>.from(
      targetMap[stroke.layerId] ?? const <_SketchMaskStroke>[],
    );
    current.add(stroke);
    setState(() {
      targetMap[stroke.layerId] = current;
      if (isReplaceTool) {
        _replaceObjectLayerId = stroke.layerId;
        _replaceObjectError = null;
      } else {
        _sketchReplaceLayerId = stroke.layerId;
        _sketchReplaceError = null;
      }
    });
  }

  _OverlayCutConfig _defaultOverlayCutConfig(String layerId) {
    return _OverlayCutConfig(
      layerId: layerId,
      shape: _OverlayCutShapeType.rectRounded,
      centerUv: const Offset(0.5, 0.5),
      scaleX: 0.5,
      scaleY: 0.5,
      rotationRadians: 0.0,
    );
  }

  _OverlayCutConfig _resolvedOverlayCutConfigForLayer(String layerId) {
    final _OverlayCutConfig? current = _overlayCutConfig;
    if (current != null && current.layerId == layerId) {
      return current;
    }
    return _defaultOverlayCutConfig(layerId);
  }

  void _openOverlayCutFloatingPanel() {
    final EditorLayer? layer = _selectedOverlayImageLayer();
    if (layer == null) return;
    final _OverlayCutConfig config =
        _resolvedOverlayCutConfigForLayer(layer.id);
    setState(() {
      _overlayCutConfig = config;
      _overlayCutBaseline = config;
      _isOverlayCutFloatingOpen = true;
      _isCropFloatingOpen = false;
      _isOverlayImageShadowFloatingOpen = false;
      _overlayImageShadowFloatingBaseline = null;
      _overlayImageShadowFloatingLayerId = null;
      _isImageAdjustFloatingOpen = false;
      _imageAdjustFloatingBaseline = null;
      _imageAdjustFloatingLayerId = null;
      _isPhotoRoomRemoveBgFloatingOpen = false;
      _isPhotoRoomRemoveBgProcessing = false;
    });
    _closeToolSettingsSidebarIfOpen();
  }

  void _cancelOverlayCutFloatingPanel() {
    setState(() {
      if (_overlayCutBaseline != null) {
        _overlayCutConfig = _overlayCutBaseline;
      }
      _isOverlayCutFloatingOpen = false;
      _overlayCutBaseline = null;
    });
  }

