  void _openImageAdjustFloatingPanel() {
    final EditorLayer? layer = _selectedImageLayer();
    if (layer == null || layer.type != EditorLayerType.image) return;
    final bool wasOpen =
        _isImageAdjustFloatingOpen && _imageAdjustFloatingLayerId == layer.id;
