  void _applyImageAdjustFloatingPanel() {
    final _EditorSnapshot? baseline = _imageAdjustFloatingBaseline;
    if (baseline != null) {
      _pushUndoSnapshotFrom(baseline);
    }
    setState(() {
      _isImageAdjustFloatingOpen = false;
      _imageAdjustFloatingBaseline = null;
