  void _openPhotoRoomRemoveBgFloatingPanel({
    _RemoveBgEngine? engine,
  }) {
    final EditorLayer? selectedImageLayer = _selectedImageLayer();
    if (selectedImageLayer == null) return;
    if (selectedImageLayer.isBackground) {
      _showExportMessage(
        'Background layer is locked and cannot use Remove Background.',
        isError: true,
      );
      return;
    }
    final bool wasOpen = _isPhotoRoomRemoveBgFloatingOpen;
    final _EditorSnapshot baseline = _captureSnapshot();
    setState(() {
      if (engine != null) {
        _removeBgEngine = engine;
      }
      if (!wasOpen) {
        _photoRoomRemoveBgFloatingBaseline = baseline;
      }
      _isPhotoRoomRemoveBgFloatingOpen = true;
      _isPhotoRoomRemoveBgProcessing = false;
      _isOverlayCutFloatingOpen = false;
      _overlayCutBaseline = null;
      _isCropFloatingOpen = false;
      _isOverlayImageShadowFloatingOpen = false;
      _overlayImageShadowFloatingBaseline = null;
      _overlayImageShadowFloatingLayerId = null;
      _isImageAdjustFloatingOpen = false;
      _imageAdjustFloatingBaseline = null;
      _imageAdjustFloatingLayerId = null;
      _activeTextEffectFloatingPanel = null;
      _isPencilSettingsFloatingOpen = false;
      _pencilSettingsFloatingBaseline = null;
      _isCloneSettingsFloatingOpen = false;
      _isCloneSettingsBottomSheetOpen = false;
      _cloneSettingsFloatingBaseline = null;
      _cloneSourceArmedFloatingBaseline = null;
      _cloneBrushSelectedFloatingBaseline = null;
      _cloneEraseSelectedFloatingBaseline = null;
    });
    _closeToolSettingsSidebarIfOpen();
  }

  void _cancelPhotoRoomRemoveBgFloatingPanel() {
    final _EditorSnapshot? baseline = _photoRoomRemoveBgFloatingBaseline;
    if (baseline != null) {
      _applySnapshot(baseline);
    }
    setState(() {
      _isPhotoRoomRemoveBgFloatingOpen = false;
      _isPhotoRoomRemoveBgProcessing = false;
      _photoRoomRemoveBgFloatingBaseline = null;
      _isToolEnabled = false;
    });
  }

  void _donePhotoRoomRemoveBgFloatingPanel() {
    final _EditorSnapshot? baseline = _photoRoomRemoveBgFloatingBaseline;
    if (baseline != null) {
      _pushUndoSnapshotFrom(baseline);
    }
    setState(() {
      _isPhotoRoomRemoveBgFloatingOpen = false;
      _isPhotoRoomRemoveBgProcessing = false;
      _photoRoomRemoveBgFloatingBaseline = null;
    });
  }

  Future<Uint8List> _upscaleImageWithKieRecraftCrisp({
    required Uint8List sourceBytes,
    required _UpscaleAmount amount,
  }) async {
    final String imageUrl = await _uploadKieReferenceFile(
      sourceBytes,
      normalizeOrientation: false,
    );
    final int upscaleFactor = amount == _UpscaleAmount.k2 ? 2 : 4;
    final String taskId = await _createKieRecraftUpscaleTask(
      imageUrl: imageUrl,
      upscaleFactor: upscaleFactor,
    );
    return _pollKieTaskAndDownload(taskId: taskId);
  }

  Future<Uint8List> _encodeUiImageToPngBytes(ui.Image sourceImage) async {
    ByteData? pngData = await sourceImage.toByteData(
      format: ui.ImageByteFormat.png,
    );
    if (pngData == null) {
      final ByteData? rawData = await sourceImage.toByteData(
        format: ui.ImageByteFormat.rawRgba,
      );
      if (rawData == null) {
        throw StateError('Unable to encode source image.');
      }
      final img.Image rgbaImage = img.Image.fromBytes(
        width: sourceImage.width,
        height: sourceImage.height,
        bytes: rawData.buffer,
        order: img.ChannelOrder.rgba,
        numChannels: 4,
      );
      pngData = ByteData.view(
        Uint8List.fromList(img.encodePng(rgbaImage)).buffer,
      );
    }
    return pngData.buffer.asUint8List();
  }

  Future<Uint8List> _encodeUiImageForRemoveBgUpload(
    ui.Image sourceImage,
  ) async {
    final ByteData? rawData = await sourceImage.toByteData(
      format: ui.ImageByteFormat.rawRgba,
    );
    if (rawData == null) {
      return _encodeUiImageToPngBytes(sourceImage);
    }
    final Uint8List rgba = Uint8List.fromList(
      rawData.buffer.asUint8List(0, rawData.lengthInBytes),
    );
    final int width = sourceImage.width;
    final int height = sourceImage.height;
    return Isolate.run<Uint8List>(
      () => _encodeJpgFromRgbaForAiUploadIsolate(
        rgba: rgba,
        width: width,
        height: height,
        quality: 90,
        maxLongEdge: 2560,
      ),
    );
  }

  Future<bool> _hasVisibleAlphaContent(
    ui.Image image, {
    int alphaThreshold = 8,
    double minVisibleRatio = 0.0001,
  }) async {
    final ByteData? rawData = await image.toByteData(
      format: ui.ImageByteFormat.rawRgba,
    );
    if (rawData == null) return true;
    final Uint8List rgba = rawData.buffer.asUint8List(0, rawData.lengthInBytes);
    final int totalPixels = image.width * image.height;
    if (totalPixels <= 0) return false;
    final int minVisiblePixels = math.max(
      1,
      (totalPixels * minVisibleRatio).round(),
    );
    int visiblePixels = 0;
    for (int i = 3; i < rgba.length; i += 4) {
      if (rgba[i] > alphaThreshold) {
        visiblePixels++;
        if (visiblePixels >= minVisiblePixels) {
          return true;
        }
      }
    }
    return false;
  }

  Future<void> _applyRemoveBgFloatingPanel() async {
    if (_removeBgEngine == _RemoveBgEngine.mlKitLogo) {
      await _applyOnDeviceLogoRemoveBgFloatingPanel();
      return;
    }
    await _applyBriaRemoveBgFloatingPanel();
  }

  Future<void> _applyBriaRemoveBgFloatingPanel() async {
    if (_isPhotoRoomRemoveBgProcessing) return;
    final EditorLayer? selectedLayer = _selectedImageLayer();
    final ui.Image? sourceImage = selectedLayer?.image;
    if (selectedLayer == null || sourceImage == null) {
      _showExportMessage('Select an image layer first.', isError: true);
      return;
    }
    if (selectedLayer.isBackground) {
      _showExportMessage(
        'Background layer is locked and cannot use Remove Background.',
        isError: true,
      );
      return;
    }
    final String selectedLayerId = selectedLayer.id;
    final String apiKey = _kieApiKey.trim();
    if (apiKey.isEmpty) {
      _showExportMessage(
        'KIE API key missing. Use --dart-define=KIE_API_KEY=...',
        isError: true,
      );
      return;
    }

    setState(() {
      _isPhotoRoomRemoveBgProcessing = true;
      _isUpscaleLayerProcessing = true;
      _upscaleEffectLayerId = selectedLayerId;
    });

    try {
      final Uint8List sourceBytes =
          await _encodeUiImageForRemoveBgUpload(sourceImage);
      final String imageUrl = await _uploadKieReferenceFile(
        sourceBytes,
        normalizeOrientation: false,
      );
      final String taskId = await _createKieRecraftRemoveBgTask(
        imageUrl: imageUrl,
      );
      final Uint8List decodedBytes = await _pollKieTaskAndDownload(
        taskId: taskId,
        verifyOutputIsImage: true,
      );
      final ui.Image nextImage = await _decodeUiImage(decodedBytes);
      final bool hasVisibleContent = await _hasVisibleAlphaContent(nextImage);
      if (!hasVisibleContent) {
        throw StateError(
          'Remove Background returned an empty image. Please try again.',
        );
      }
      if (!mounted) return;

      final _EditorSnapshot? baseline = _photoRoomRemoveBgFloatingBaseline;
      if (baseline == null) {
        _pushUndoSnapshot();
      }
      setState(() {
        _replaceLayerImage(selectedLayerId, nextImage);
      });
      _showExportMessage('Background removed successfully.');
    } catch (error) {
      if (!mounted) return;
      _showExportMessage(error.toString(), isError: true);
    } finally {
      if (mounted) {
        setState(() {
          _isPhotoRoomRemoveBgProcessing = false;
          _isUpscaleLayerProcessing = false;
          _upscaleEffectLayerId = null;
        });
      }
    }
  }

  Future<void> _applyOnDeviceLogoRemoveBgFloatingPanel() async {
    if (_isPhotoRoomRemoveBgProcessing) return;
    final EditorLayer? selectedLayer = _selectedImageLayer();
    final ui.Image? sourceImage = selectedLayer?.image;
    if (selectedLayer == null || sourceImage == null) {
      _showExportMessage('Select an image layer first.', isError: true);
      return;
    }
    if (selectedLayer.isBackground) {
      _showExportMessage(
        'Background layer is locked and cannot use Remove Background.',
        isError: true,
      );
      return;
    }
    final String selectedLayerId = selectedLayer.id;

    setState(() {
      _isPhotoRoomRemoveBgProcessing = true;
      _isUpscaleLayerProcessing = true;
      _upscaleEffectLayerId = selectedLayerId;
    });

    try {
      final Uint8List sourcePngBytes =
          await _encodeUiImageToPngBytes(sourceImage);
      final Uint8List outputPngBytes = await compute<Uint8List, Uint8List>(
        _removeBackgroundForLogoPngCompute,
        sourcePngBytes,
      );
      final ui.Image nextImage = await _decodeUiImage(outputPngBytes);
      if (!mounted) return;

      final _EditorSnapshot? baseline = _photoRoomRemoveBgFloatingBaseline;
      if (baseline == null) {
        _pushUndoSnapshot();
      }
      setState(() {
        _replaceLayerImage(selectedLayerId, nextImage);
      });
      _showExportMessage('Logo background removed successfully.');
    } catch (error) {
      if (!mounted) return;
      _showExportMessage(error.toString(), isError: true);
    } finally {
      if (mounted) {
        setState(() {
          _isPhotoRoomRemoveBgProcessing = false;
          _isUpscaleLayerProcessing = false;
          _upscaleEffectLayerId = null;
        });
      }
    }
  }

  void _updateOverlayCutConfig({
    _OverlayCutShapeType? shape,
    Offset? centerUv,
    double? scaleX,
    double? scaleY,
    double? rotationRadians,
  }) {
    final _OverlayCutConfig? current = _overlayCutConfig;
    if (current == null) return;
    final double nextScaleX =
        (scaleX ?? current.scaleX).clamp(0.06, 1.0).toDouble();
    final double nextScaleY =
        (scaleY ?? current.scaleY).clamp(0.06, 1.0).toDouble();
    Offset nextCenter = centerUv ?? current.centerUv;
    nextCenter = _clampOverlayCutCenter(nextCenter, nextScaleX, nextScaleY);
    setState(() {
      _overlayCutConfig = current.copyWith(
        shape: shape,
        centerUv: nextCenter,
        scaleX: nextScaleX,
        scaleY: nextScaleY,
        rotationRadians: rotationRadians,
      );
    });
  }

  Offset _clampOverlayCutCenter(
    Offset centerUv,
    double scaleX,
    double scaleY,
  ) {
    final double halfX = (scaleX / 2).clamp(0.0, 0.5).toDouble();
    final double halfY = (scaleY / 2).clamp(0.0, 0.5).toDouble();
    final double minX = halfX;
    final double maxX = 1 - halfX;
    final double minY = halfY;
    final double maxY = 1 - halfY;
    if (minX >= maxX || minY >= maxY) {
      return const Offset(0.5, 0.5);
    }
    return Offset(
      centerUv.dx.clamp(minX, maxX).toDouble(),
      centerUv.dy.clamp(minY, maxY).toDouble(),
    );
  }

  _ExpandToolConfig _defaultExpandConfig(String layerId) {
    return _ExpandToolConfig(layerId: layerId);
  }

  _ExpandToolConfig _resolvedExpandConfigForLayer(String layerId) {
    final _ExpandToolConfig? current = _expandToolConfig;
    if (current != null && current.layerId == layerId) {
      return _normalizedExpandConfig(current);
    }
    return _defaultExpandConfig(layerId);
  }

  _ExpandToolConfig _normalizedExpandConfig(_ExpandToolConfig config) {
    double clampSide(double value) => value.clamp(0.0, 3.0).toDouble();
    return config.copyWith(
      leftExpand: clampSide(config.leftExpand),
      topExpand: clampSide(config.topExpand),
      rightExpand: clampSide(config.rightExpand),
      bottomExpand: clampSide(config.bottomExpand),
    );
  }

  _CropToolConfig _defaultCropConfig(String layerId) {
    return _CropToolConfig(
      layerId: layerId,
      ratioPreset: _CropRatioPreset.free,
      cropRectUv: const Rect.fromLTWH(0.1, 0.1, 0.8, 0.8),
      quarterTurns: 0,
      straightenDegrees: 0,
    );
  }

  double? _cropUvAspectRatio({
    required _CropRatioPreset preset,
    required int sourceWidth,
    required int sourceHeight,
    int quarterTurns = 0,
  }) {
    final double? targetAspect = preset.aspectRatio;
    if (targetAspect == null || targetAspect <= 0) return null;
    double orientedWidth = sourceWidth.toDouble();
    double orientedHeight = sourceHeight.toDouble();
    final int turns = ((quarterTurns % 4) + 4) % 4;
    if (turns.isOdd) {
      final double swap = orientedWidth;
      orientedWidth = orientedHeight;
      orientedHeight = swap;
    }
    if (orientedWidth <= 0 || orientedHeight <= 0) return null;
    final double imageAspect = orientedWidth / orientedHeight;
    if (imageAspect <= 0) return null;
    return targetAspect / imageAspect;
  }

  ({int w, int h})? _cropRatioPair(_CropRatioPreset preset) {
    switch (preset) {
      case _CropRatioPreset.free:
        return null;
      case _CropRatioPreset.ratio1x1:
        return (w: 1, h: 1);
      case _CropRatioPreset.ratio4x5:
        return (w: 4, h: 5);
      case _CropRatioPreset.ratio9x16Portrait:
        return (w: 9, h: 16);
    }
  }

  _CropToolConfig _resolvedCropConfigForLayer(String layerId) {
    final _CropToolConfig? current = _cropToolConfig;
    if (current != null && current.layerId == layerId) {
      return _normalizedCropConfig(current);
    }
    return _defaultCropConfig(layerId);
  }

  _CropToolConfig _normalizedCropConfig(_CropToolConfig config) {
    final int normalizedTurns = ((config.quarterTurns % 4) + 4) % 4;
    final double normalizedStraighten =
        config.straightenDegrees.clamp(-30.0, 30.0).toDouble();
    EditorLayer? layer;
    for (final EditorLayer entry in _layers) {
      if (entry.id == config.layerId) {
        layer = entry;
        break;
      }
    }
    final double? uvAspect =
        (layer?.type == EditorLayerType.image && layer?.image != null)
            ? _cropUvAspectRatio(
                preset: config.ratioPreset,
                sourceWidth: layer!.image!.width,
                sourceHeight: layer.image!.height,
                quarterTurns: normalizedTurns,
              )
            : config.ratioPreset.aspectRatio;
    final Rect normalizedRect = _clampCropRectUv(
      config.cropRectUv,
      aspectRatio: uvAspect,
    );
    return config.copyWith(
      cropRectUv: normalizedRect,
      quarterTurns: normalizedTurns,
      straightenDegrees: normalizedStraighten,
    );
  }

  Rect _clampCropRectUv(
    Rect rect, {
    double? aspectRatio,
  }) {
    const double minSize = 0.06;
    final Rect normalized = Rect.fromLTRB(
      rect.left.clamp(0.0, 1.0).toDouble(),
      rect.top.clamp(0.0, 1.0).toDouble(),
      rect.right.clamp(0.0, 1.0).toDouble(),
      rect.bottom.clamp(0.0, 1.0).toDouble(),
    );
    double width = normalized.width.abs().clamp(minSize, 1.0).toDouble();
    double height = normalized.height.abs().clamp(minSize, 1.0).toDouble();
    final double? ratio = aspectRatio;
    if (ratio != null && ratio > 0) {
      if ((width / height) > ratio) {
        width = height * ratio;
      } else {
        height = width / ratio;
      }
      width = width.clamp(minSize, 1.0).toDouble();
      height = (width / ratio).clamp(minSize, 1.0).toDouble();
      if (height > 1.0) {
        height = 1.0;
        width = (height * ratio).clamp(minSize, 1.0).toDouble();
      }
      if (width > 1.0) {
        width = 1.0;
        height = (width / ratio).clamp(minSize, 1.0).toDouble();
      }
    }
    final Offset center = normalized.center;
    final double halfW = (width / 2).clamp(0.0, 0.5).toDouble();
    final double halfH = (height / 2).clamp(0.0, 0.5).toDouble();
    final Offset clampedCenter = Offset(
      center.dx.clamp(halfW, 1 - halfW).toDouble(),
      center.dy.clamp(halfH, 1 - halfH).toDouble(),
    );
    return Rect.fromCenter(
      center: clampedCenter,
      width: width,
      height: height,
    );
  }

  void _updateCropToolConfig({
    _CropRatioPreset? ratioPreset,
    Rect? cropRectUv,
    int? quarterTurns,
    double? straightenDegrees,
  }) {
    final _CropToolConfig? current = _cropToolConfig;
    if (current == null) return;
    final _CropToolConfig next = _normalizedCropConfig(
      current.copyWith(
        ratioPreset: ratioPreset,
        cropRectUv: cropRectUv,
        quarterTurns: quarterTurns,
        straightenDegrees: straightenDegrees,
      ),
    );
    setState(() {
      _cropToolConfig = next;
    });
  }

  void _setCropRatioPreset(_CropRatioPreset preset) {
    final _CropToolConfig? current = _cropToolConfig;
    if (current == null) return;
    final EditorLayer? selectedImage = _selectedCropLayer();
    if (selectedImage == null || selectedImage.image == null) return;
    Rect nextRect = current.cropRectUv;
    final double? aspect = preset.aspectRatio;
    if (aspect != null && aspect > 0) {
      double imageWidth = selectedImage.image!.width.toDouble();
      double imageHeight = selectedImage.image!.height.toDouble();
      final int normalizedTurns = ((current.quarterTurns % 4) + 4) % 4;
      if (normalizedTurns.isOdd) {
        final double swap = imageWidth;
        imageWidth = imageHeight;
        imageHeight = swap;
      }
      final double imageAspect = imageWidth / imageHeight;
      double width;
      double height;
      if (imageAspect >= aspect) {
        height = 1.0;
        width = (aspect / imageAspect).clamp(0.06, 1.0).toDouble();
      } else {
        width = 1.0;
        height = (imageAspect / aspect).clamp(0.06, 1.0).toDouble();
      }
      nextRect = Rect.fromCenter(
        center: const Offset(0.5, 0.5),
        width: width,
        height: height,
      );
    } else if (preset == _CropRatioPreset.free) {
      nextRect = _clampCropRectUv(nextRect);
    }
    _updateCropToolConfig(
      ratioPreset: preset,
      cropRectUv: nextRect,
    );
  }

  void _rotateCropQuarterTurns(int delta) {
    final _CropToolConfig? current = _cropToolConfig;
    if (current == null) return;
    _updateCropToolConfig(
      quarterTurns: current.quarterTurns + delta,
    );
  }

  Future<void> _applyCropFloatingPanel() async {
    final EditorLayer? layer = _selectedCropLayer();
    final _CropToolConfig? config = _cropToolConfig;
    if (layer == null || config == null || config.layerId != layer.id) return;
    if (layer.isBackground) {
      _showExportMessage(
        'Background workspace crop is locked to keep canvas size stable.',
        isError: true,
      );
      return;
    }
    final ui.Image? sourceImage = layer.image;
    if (sourceImage == null) return;
    final Uint8List? rgba = await _readImagePixels(sourceImage);
    if (rgba == null) return;

    img.Image working = img.Image.fromBytes(
      width: sourceImage.width,
      height: sourceImage.height,
      bytes: rgba.buffer,
      order: img.ChannelOrder.rgba,
      numChannels: 4,
    );

    final int turns = ((config.quarterTurns % 4) + 4) % 4;
    if (turns != 0) {
      working = img.copyRotate(
        working,
        angle: turns * 90,
        interpolation: img.Interpolation.linear,
      );
    }
    final double straighten = config.straightenDegrees.clamp(-30.0, 30.0);
    if (straighten.abs() >= 0.01) {
      working = img.copyRotate(
        working,
        angle: straighten,
        interpolation: img.Interpolation.linear,
      );
    }

    final double? uvAspect = _cropUvAspectRatio(
      preset: config.ratioPreset,
      sourceWidth: working.width,
      sourceHeight: working.height,
      quarterTurns: 0,
    );
    final Rect cropRectUv = _clampCropRectUv(
      config.cropRectUv,
      aspectRatio: uvAspect,
    );
    int left =
        (cropRectUv.left * working.width).floor().clamp(0, working.width - 1);
    int top =
        (cropRectUv.top * working.height).floor().clamp(0, working.height - 1);
    int right =
        (cropRectUv.right * working.width).ceil().clamp(1, working.width);
    int bottom =
        (cropRectUv.bottom * working.height).ceil().clamp(1, working.height);
    int cropWidth = math.max(1, right - left);
    int cropHeight = math.max(1, bottom - top);

    final ({int w, int h})? ratioPair = _cropRatioPair(config.ratioPreset);
    if (ratioPair != null) {
      final double centerX = left + (cropWidth / 2);
      final double centerY = top + (cropHeight / 2);
      int targetW;
      int targetH;
      final int fitFactor =
          math.min(cropWidth ~/ ratioPair.w, cropHeight ~/ ratioPair.h);
      if (fitFactor > 0) {
        targetW = ratioPair.w * fitFactor;
        targetH = ratioPair.h * fitFactor;
      } else {
        final double targetAspect = ratioPair.w / ratioPair.h;
        double fitW = cropWidth.toDouble();
        double fitH = cropHeight.toDouble();
        if ((fitW / fitH) > targetAspect) {
          fitW = fitH * targetAspect;
        } else {
          fitH = fitW / targetAspect;
        }
        targetW = math.max(1, fitW.round());
        targetH = math.max(1, fitH.round());
      }
      targetW = targetW.clamp(1, working.width);
      targetH = targetH.clamp(1, working.height);
      int targetLeft = (centerX - (targetW / 2)).round();
      int targetTop = (centerY - (targetH / 2)).round();
      targetLeft = targetLeft.clamp(0, working.width - targetW);
      targetTop = targetTop.clamp(0, working.height - targetH);
      left = targetLeft;
      top = targetTop;
      right = left + targetW;
      bottom = top + targetH;
      cropWidth = targetW;
      cropHeight = targetH;
    }

    final img.Image cropped = img.copyCrop(
      working,
      x: left,
      y: top,
      width: cropWidth,
      height: cropHeight,
    );
    final ui.Image nextImage = await _buildUiImageFromRgba(
      pixels: Uint8List.fromList(
        cropped.getBytes(order: img.ChannelOrder.rgba),
      ),
      width: cropped.width,
      height: cropped.height,
    );
    if (!mounted) return;

    _pushUndoSnapshot();
    setState(() {
      _replaceLayerImage(layer.id, nextImage);
      _cropToolConfig = null;
      _isToolEnabled = false;
      _isCropFloatingOpen = false;
    });
  }

  void _updateOverlayImageLayer(
    String layerId, {
    Color? imageShadowColor,
    double? imageShadowOffsetX,
    double? imageShadowOffsetY,
    double? imageShadowBlur,
    double? imageShadowOpacity,
    bool recordHistory = true,
  }) {
    final int index = _layers.indexWhere((layer) => layer.id == layerId);
    if (index < 0) return;
    final List<EditorLayer> nextLayers = List<EditorLayer>.from(_layers);
    final EditorLayer current = nextLayers[index];
    if (current.type != EditorLayerType.image || current.isBackground) {
      return;
    }

    final Color nextShadowColor =
        imageShadowColor ?? current.imageShadowColor ?? const Color(0xFF19191A);
    final Color currentShadowColor =
        current.imageShadowColor ?? const Color(0xFF19191A);
    final double nextShadowOffsetX =
        imageShadowOffsetX ?? current.imageShadowOffsetX ?? 0;
    final double currentShadowOffsetX = current.imageShadowOffsetX ?? 0;
    final double nextShadowOffsetY =
        imageShadowOffsetY ?? current.imageShadowOffsetY ?? 0;
    final double currentShadowOffsetY = current.imageShadowOffsetY ?? 0;
    final double nextShadowBlur =
        imageShadowBlur ?? current.imageShadowBlur ?? 0;
    final double currentShadowBlur = current.imageShadowBlur ?? 0;
    final double nextShadowOpacity =
        imageShadowOpacity ?? current.imageShadowOpacity ?? 0;
    final double currentShadowOpacity = current.imageShadowOpacity ?? 0;

    if (nextShadowColor == currentShadowColor &&
        nextShadowOffsetX == currentShadowOffsetX &&
        nextShadowOffsetY == currentShadowOffsetY &&
        nextShadowBlur == currentShadowBlur &&
        nextShadowOpacity == currentShadowOpacity) {
      return;
    }

    nextLayers[index] = current.copyWith(
      imageShadowColor: imageShadowColor,
      imageShadowOffsetX: imageShadowOffsetX,
      imageShadowOffsetY: imageShadowOffsetY,
      imageShadowBlur: imageShadowBlur,
      imageShadowOpacity: imageShadowOpacity,
    );

    if (recordHistory) {
      _pushUndoSnapshot();
    }
    setState(() {
      _layers = nextLayers;
    });
  }

  void _updateImageAdjustmentLayer(
    String layerId, {
    double? imageAdjustBrightness,
    double? imageAdjustExposure,
    double? imageAdjustContrast,
    double? imageAdjustSaturation,
    double? imageAdjustWarmth,
    double? imageAdjustShadows,
    double? imageAdjustWhites,
    double? imageAdjustBlacks,
    bool recordHistory = true,
  }) {
    final int index = _layers.indexWhere((layer) => layer.id == layerId);
    if (index < 0) return;
    final List<EditorLayer> nextLayers = List<EditorLayer>.from(_layers);
    final EditorLayer current = nextLayers[index];
    if (current.type != EditorLayerType.image) return;

    double normalize(double value) => value.clamp(-100.0, 100.0).toDouble();
    final double nextBrightness =
        normalize(imageAdjustBrightness ?? current.imageAdjustBrightness ?? 0);
    final double currentBrightness =
        normalize(current.imageAdjustBrightness ?? 0);
    final double nextExposure =
        normalize(imageAdjustExposure ?? current.imageAdjustExposure ?? 0);
    final double currentExposure = normalize(current.imageAdjustExposure ?? 0);
    final double nextContrast =
        normalize(imageAdjustContrast ?? current.imageAdjustContrast ?? 0);
    final double currentContrast = normalize(current.imageAdjustContrast ?? 0);
    final double nextSaturation =
        normalize(imageAdjustSaturation ?? current.imageAdjustSaturation ?? 0);
    final double currentSaturation =
        normalize(current.imageAdjustSaturation ?? 0);
    final double nextWarmth =
        normalize(imageAdjustWarmth ?? current.imageAdjustWarmth ?? 0);
    final double currentWarmth = normalize(current.imageAdjustWarmth ?? 0);
    final double nextShadows =
        normalize(imageAdjustShadows ?? current.imageAdjustShadows ?? 0);
    final double currentShadows = normalize(current.imageAdjustShadows ?? 0);
    final double nextWhites =
        normalize(imageAdjustWhites ?? current.imageAdjustWhites ?? 0);
    final double currentWhites = normalize(current.imageAdjustWhites ?? 0);
    final double nextBlacks =
        normalize(imageAdjustBlacks ?? current.imageAdjustBlacks ?? 0);
    final double currentBlacks = normalize(current.imageAdjustBlacks ?? 0);

    if ((nextBrightness - currentBrightness).abs() < 0.0001 &&
        (nextExposure - currentExposure).abs() < 0.0001 &&
        (nextContrast - currentContrast).abs() < 0.0001 &&
        (nextSaturation - currentSaturation).abs() < 0.0001 &&
        (nextWarmth - currentWarmth).abs() < 0.0001 &&
        (nextShadows - currentShadows).abs() < 0.0001 &&
        (nextWhites - currentWhites).abs() < 0.0001 &&
        (nextBlacks - currentBlacks).abs() < 0.0001) {
      return;
    }

    nextLayers[index] = current.copyWith(
      imageAdjustBrightness: nextBrightness,
      imageAdjustExposure: nextExposure,
      imageAdjustContrast: nextContrast,
      imageAdjustSaturation: nextSaturation,
      imageAdjustWarmth: nextWarmth,
      imageAdjustShadows: nextShadows,
      imageAdjustWhites: nextWhites,
      imageAdjustBlacks: nextBlacks,
    );

    if (recordHistory) {
      _pushUndoSnapshot();
    }
    setState(() {
      _layers = nextLayers;
    });
  }

  void _onTextInputChanged() {
    if (_isSyncingTextInput) return;
    final EditorLayer? selectedTextLayer = _selectedTextLayer();
    if (selectedTextLayer == null) return;
    if (!_isTextEditHistoryCaptured) {
      _pushUndoSnapshot();
      _isTextEditHistoryCaptured = true;
    }
    _updateTextLayer(
      selectedTextLayer.id,
      textValue: _textInputController.text,
      recordHistory: false,
    );
  }

  void _syncTextInputFromSelectedLayer() {
    final EditorLayer? selectedTextLayer = _selectedTextLayer();
    if (selectedTextLayer == null) return;
    final String value = selectedTextLayer.textValue ?? 'Write your text here';
    if (_textInputController.text != value) {
      _isSyncingTextInput = true;
      _textInputController.value = TextEditingValue(
        text: value,
        selection: TextSelection.collapsed(offset: value.length),
      );
      _isSyncingTextInput = false;
    }
  }

  void _syncTextLocaleFromFamily(String? family) {
    if (family == null) return;
    if (_kArabicFontOptions.any((option) => option.family == family)) {
      _textFontLocale = _TextFontLocale.arabic;
      return;
    }
    if (_kEnglishFontOptions.any((option) => option.family == family)) {
      _textFontLocale = _TextFontLocale.english;
    }
  }

  void _resetTextQuickFloatingPanels({bool clearSearch = true}) {
    _isTextFontsFloatingOpen = false;
    _isTextWeightFloatingOpen = false;
    _isTextColorFloatingOpen = false;
    if (clearSearch) {
      _textFontSearchQuery = '';
      _textFontSearchController.clear();
    }
  }

  List<_TextFontOption> _fontOptionsForLocale(_TextFontLocale locale) {
    return locale == _TextFontLocale.english
        ? _kEnglishFontOptions
        : _kArabicFontOptions;
  }

  _TextFontOption? _fontOptionByFamily(String? family) {
    if (family == null) return null;
    for (final _TextFontOption option in _kEnglishFontOptions) {
      if (option.family == family) return option;
    }
    for (final _TextFontOption option in _kArabicFontOptions) {
      if (option.family == family) return option;
    }
    return null;
  }

  List<_TextFontOption> _filteredTextFontOptions({
    required _TextFontLocale locale,
    required String query,
  }) {
    final List<_TextFontOption> source = _fontOptionsForLocale(locale);
    final String normalized = query.trim().toLowerCase();
    if (normalized.isEmpty) {
      return source;
    }
    return source.where((option) {
      return option.label.toLowerCase().contains(normalized) ||
          option.family.toLowerCase().contains(normalized) ||
          option.preview.toLowerCase().contains(normalized);
    }).toList();
  }

  void _openTextFontsFloatingPanel() {
    final EditorLayer? selectedTextLayer = _selectedTextLayer();
    if (selectedTextLayer == null) return;
    _syncTextLocaleFromFamily(selectedTextLayer.textFontFamily);
    setState(() {
      _resetTextQuickFloatingPanels();
      _isTextFontsFloatingOpen = true;
      _activeTextEffectFloatingPanel = null;
      _isTextEditHistoryCaptured = false;
    });
    _textFontSearchQuery = '';
    _textFontSearchController.clear();
    _closeToolSettingsSidebarIfOpen();
    WidgetsBinding.instance.addPostFrameCallback((_) {
      if (_textFontsFloatingScrollController.hasClients) {
        _textFontsFloatingScrollController.jumpTo(0);
      }
    });
  }

  void _toggleTextFontsFloatingPanel() {
    if (_isTextFontsFloatingOpen) {
      setState(() {
        _isTextFontsFloatingOpen = false;
      });
      return;
    }
    _openTextFontsFloatingPanel();
  }

  void _applyTextFontOption(_TextFontOption option) {
    final EditorLayer? selectedTextLayer = _selectedTextLayer();
    if (selectedTextLayer == null) return;
    final int currentWeight = selectedTextLayer.textFontWeight ?? 400;
    final int nextWeight =
        _resolveSupportedWeight(option.family, currentWeight);
    _syncTextLocaleFromFamily(option.family);
    _updateTextLayer(
      selectedTextLayer.id,
      textFontFamily: option.family,
      textFontWeight: nextWeight,
      recordHistory: false,
    );
  }

  void _jumpTextFontSelection(
    int direction, {
    required double itemExtent,
  }) {
    final EditorLayer? selectedTextLayer = _selectedTextLayer();
    if (selectedTextLayer == null) return;
    final List<_TextFontOption> options = _filteredTextFontOptions(
      locale: _textFontLocale,
      query: _textFontSearchQuery,
    );
    if (options.isEmpty) return;
    final String currentFamily =
        selectedTextLayer.textFontFamily ?? options.first.family;
    int currentIndex =
        options.indexWhere((option) => option.family == currentFamily);
    if (currentIndex < 0) currentIndex = 0;
    final int nextIndex =
        (currentIndex + direction).clamp(0, options.length - 1).toInt();
    if (nextIndex == currentIndex) return;
    _applyTextFontOption(options[nextIndex]);
    WidgetsBinding.instance.addPostFrameCallback((_) {
      if (!_textFontsFloatingScrollController.hasClients) return;
      final double max =
          _textFontsFloatingScrollController.position.maxScrollExtent;
      final double target = (nextIndex * itemExtent).clamp(0.0, max);
      _textFontsFloatingScrollController.animateTo(
        target,
        duration: const Duration(milliseconds: 180),
        curve: Curves.easeOutCubic,
      );
    });
  }

  void _openTextWeightFloatingPanel() {
    final EditorLayer? selectedTextLayer = _selectedTextLayer();
    if (selectedTextLayer == null) return;
    _syncTextLocaleFromFamily(selectedTextLayer.textFontFamily);
    setState(() {
      _resetTextQuickFloatingPanels(clearSearch: false);
      _isTextWeightFloatingOpen = true;
      _activeTextEffectFloatingPanel = null;
    });
    _closeToolSettingsSidebarIfOpen();
  }

  void _openTextColorFloatingPanel() {
    final EditorLayer? selectedTextLayer = _selectedTextLayer();
    if (selectedTextLayer == null) return;
    _syncTextLocaleFromFamily(selectedTextLayer.textFontFamily);
    setState(() {
