    _closeToolSettingsSidebarIfOpen();
  }

  List<int> _availableWeightsForFamily(String family) {
    return _kFontWeightSupport[family] ?? _kDefaultFontWeights;
  }

  int _resolveSupportedWeight(String family, int requestedWeight) {
    final List<int> supported = _availableWeightsForFamily(family);
    int nearest = supported.first;
    int nearestDistance = (requestedWeight - nearest).abs();
    for (final int value in supported) {
      final int distance = (requestedWeight - value).abs();
      if (distance < nearestDistance) {
        nearest = value;
        nearestDistance = distance;
      }
    }
    return nearest;
  }

  FontWeight _fontWeightFromValue(int weight) {
    return _fontWeightFromNumeric(weight);
  }

  String _formatSignedValue(double value, {int fractionDigits = 0}) {
    final String formatted = value.toStringAsFixed(fractionDigits);
    if (value > 0) {
      return '+$formatted';
    }
    return formatted;
  }

  String _hexColor(Color color) {
    final String hex = color.value.toRadixString(16).padLeft(8, '0');
    return '#${hex.substring(2).toUpperCase()}';
  }

  void _updateTextLayer(
    String layerId, {
    String? textValue,
    String? textFontFamily,
    int? textFontWeight,
    Color? textColor,
    double? textOpacity,
    double? textBend,
    Color? textStrokeColor,
    double? textStrokeWidth,
    Color? textShadowColor,
    double? textShadowOffsetX,
    double? textShadowOffsetY,
    double? textShadowBlur,
    double? textShadowSpread,
    double? textShadowOpacity,
    bool recordHistory = true,
  }) {
    final int index = _layers.indexWhere((layer) => layer.id == layerId);
    if (index < 0) return;
    final List<EditorLayer> nextLayers = List<EditorLayer>.from(_layers);
    final EditorLayer current = nextLayers[index];
    final String nextTextValue = textValue ?? current.textValue ?? '';
    final String currentTextValue = current.textValue ?? '';
    final String nextFontFamily =
        textFontFamily ?? current.textFontFamily ?? '';
    final String currentFontFamily = current.textFontFamily ?? '';
    final int nextFontWeight = textFontWeight ?? current.textFontWeight ?? 400;
    final int currentFontWeight = current.textFontWeight ?? 400;
    final Color nextTextColor =
        textColor ?? current.textColor ?? const Color(0xFF1F2937);
    final Color currentTextColor = current.textColor ?? const Color(0xFF1F2937);
    final double nextTextOpacity = textOpacity ?? current.textOpacity ?? 100;
    final double currentTextOpacity = current.textOpacity ?? 100;
    final double nextTextBend = textBend ?? current.textBend ?? 0;
    final double currentTextBend = current.textBend ?? 0;
    final Color nextStrokeColor =
        textStrokeColor ?? current.textStrokeColor ?? const Color(0xFFFFFFFF);
    final Color currentStrokeColor =
        current.textStrokeColor ?? const Color(0xFFFFFFFF);
    final double nextStrokeWidth =
        textStrokeWidth ?? current.textStrokeWidth ?? 0;
    final double currentStrokeWidth = current.textStrokeWidth ?? 0;
    final Color nextShadowColor =
        textShadowColor ?? current.textShadowColor ?? const Color(0xFF19191A);
    final Color currentShadowColor =
        current.textShadowColor ?? const Color(0xFF19191A);
    final double nextShadowOffsetX =
        textShadowOffsetX ?? current.textShadowOffsetX ?? 0;
    final double currentShadowOffsetX = current.textShadowOffsetX ?? 0;
    final double nextShadowOffsetY =
        textShadowOffsetY ?? current.textShadowOffsetY ?? 0;
    final double currentShadowOffsetY = current.textShadowOffsetY ?? 0;
    final double nextShadowBlur = textShadowBlur ?? current.textShadowBlur ?? 0;
    final double currentShadowBlur = current.textShadowBlur ?? 0;
    final double nextShadowSpread =
        textShadowSpread ?? current.textShadowSpread ?? 0;
    final double currentShadowSpread = current.textShadowSpread ?? 0;
    final double nextShadowOpacity =
        textShadowOpacity ?? current.textShadowOpacity ?? 0;
    final double currentShadowOpacity = current.textShadowOpacity ?? 0;
    if (nextTextValue == currentTextValue &&
        nextFontFamily == currentFontFamily &&
        nextFontWeight == currentFontWeight &&
        nextTextColor == currentTextColor &&
        nextTextOpacity == currentTextOpacity &&
        nextTextBend == currentTextBend &&
        nextStrokeColor == currentStrokeColor &&
        nextStrokeWidth == currentStrokeWidth &&
        nextShadowColor == currentShadowColor &&
        nextShadowOffsetX == currentShadowOffsetX &&
        nextShadowOffsetY == currentShadowOffsetY &&
        nextShadowBlur == currentShadowBlur &&
        nextShadowSpread == currentShadowSpread &&
        nextShadowOpacity == currentShadowOpacity) {
      return;
    }
    final EditorLayer next = current.copyWith(
      textValue: textValue,
      textFontFamily: textFontFamily,
      textFontWeight: textFontWeight,
      textColor: textColor,
      textOpacity: textOpacity,
      textBend: textBend,
      textStrokeColor: textStrokeColor,
      textStrokeWidth: textStrokeWidth,
      textShadowColor: textShadowColor,
      textShadowOffsetX: textShadowOffsetX,
      textShadowOffsetY: textShadowOffsetY,
      textShadowBlur: textShadowBlur,
      textShadowSpread: textShadowSpread,
      textShadowOpacity: textShadowOpacity,
    );
    nextLayers[index] = next;
    if (recordHistory) {
      _pushUndoSnapshot();
    }
    setState(() {
      _layers = nextLayers;
    });
  }

  void _openTextSidebar({required bool requestFocus}) {
    _scaffoldKey.currentState?.openEndDrawer();
    if (!requestFocus) return;
    WidgetsBinding.instance.addPostFrameCallback((_) {
      Future<void>.delayed(const Duration(milliseconds: 220), () {
        if (!mounted) return;
        _textInputFocusNode.requestFocus();
      });
    });
  }

  void _createTextLayerAndOpenEditor() {
    final String? layerId = _createTextLayer(shouldShowError: true);
    if (layerId == null) return;
    _syncTextInputFromSelectedLayer();
  }

  String? _createTextLayer({required bool shouldShowError}) {
    final EditorLayer? workspace = _workspaceLayerForEdit(_layers);
    final Size? workspaceSize =
        workspace == null ? null : _workspaceSourceSize(workspace);
    if (workspaceSize == null) {
      if (shouldShowError) {
        final ScaffoldMessengerState? messenger =
            _editorScaffoldMessengerKey.currentState;
        messenger?.showSnackBar(
          const SnackBar(
            content: Text('Add a background image or solid layer first'),
          ),
        );
      }
      return null;
    }

    final int textCount =
        _layers.where((layer) => layer.type == EditorLayerType.text).length;
    final String id = 'layer_${_nextLayerId++}';
    final EditorLayer textLayer = EditorLayer(
      id: id,
      name: textCount == 0 ? 'Text' : 'Text ${textCount + 1}',
      type: EditorLayerType.text,
      isVisible: true,
      textValue: 'Write your text here',
      textColor: const Color(0xFF1F2937),
      textFontSize: 92,
      textFontFamily: _kEnglishFontOptions.first.family,
      textFontWeight: 400,
      textOpacity: 100,
      textBend: 0,
      textStrokeColor: const Color(0xFFFFFFFF),
      textStrokeWidth: 0,
      textShadowColor: const Color(0xFF19191A),
      textShadowOffsetX: 0,
      textShadowOffsetY: 0,
      textShadowBlur: 0,
      textShadowSpread: 0,
      textShadowOpacity: 0,
      position: Offset(workspaceSize.width / 2, workspaceSize.height / 2),
      layerScale: 1.0,
      layerRotation: 0.0,
    );

    _pushUndoSnapshot();
    setState(() {
      _layers = <EditorLayer>[..._layers, textLayer];
      _selectedLayerId = id;
      _activeTool = EditorTool.text;
      _isToolEnabled = true;
      _isTextSettingsDockEnabled = false;
      _isCloneSourceArmed = false;
      _isCloneBrushSelected = false;
      _isCloneEraseSelected = false;
      _isTextEditHistoryCaptured = false;
      _isTransformHistoryCaptured = false;
    });
    return id;
  }

  void _onTextLayerDoubleTap(String layerId) {
    final int index = _layers.indexWhere((layer) => layer.id == layerId);
    if (index < 0) return;
    final EditorLayer layer = _layers[index];
    if (layer.type != EditorLayerType.text) return;
    setState(() {
      _selectedLayerId = layerId;
      _activeTool = EditorTool.text;
      _isToolEnabled = true;
      _isTextSettingsDockEnabled = false;
      _isCloneSourceArmed = false;
      _isCloneBrushSelected = false;
      _isCloneEraseSelected = false;
      _inlineTextEditRequestLayerId = layerId;
      _inlineTextEditRequestToken++;
    });
    _syncTextInputFromSelectedLayer();
  }

  void _onTextInlineEditStarted(String layerId) {
    final int index = _layers.indexWhere((layer) => layer.id == layerId);
    if (index < 0) return;
    if (_layers[index].type != EditorLayerType.text) return;
    if (_isTextEditHistoryCaptured) return;
    _pushUndoSnapshot();
    _isTextEditHistoryCaptured = true;
  }

  void _onTextInlineChanged(String layerId, String value) {
    final int index = _layers.indexWhere((layer) => layer.id == layerId);
    if (index < 0) return;
    if (_layers[index].type != EditorLayerType.text) return;
    _updateTextLayer(
      layerId,
      textValue: value,
      recordHistory: false,
    );
  }

  void _onTextInlineEditFinished(String layerId) {
    final int index = _layers.indexWhere((layer) => layer.id == layerId);
    if (index < 0) return;
    if (_layers[index].type != EditorLayerType.text) return;
    _isTextEditHistoryCaptured = false;
    _syncTextInputFromSelectedLayer();
  }

  void _onLayerCanvasDoubleTap(String layerId) {
    final int index = _layers.indexWhere((layer) => layer.id == layerId);
    if (index < 0) return;
    final EditorLayer layer = _layers[index];
    if (!layer.isVisible) return;
    if (layer.type == EditorLayerType.text) {
      _onTextLayerDoubleTap(layerId);
      return;
    }
    _onLayerSelected(layerId);
    setState(() {
      _activeTool = EditorTool.move;
      _isToolEnabled = true;
      _isTextSettingsDockEnabled = false;
      _isCloneSourceArmed = false;
      _isCloneBrushSelected = false;
      _isCloneEraseSelected = false;
      _isCloneSettingsFloatingOpen = false;
      _isCloneSettingsBottomSheetOpen = false;
      _cloneSettingsFloatingBaseline = null;
      _cloneSourceArmedFloatingBaseline = null;
      _cloneBrushSelectedFloatingBaseline = null;
      _cloneEraseSelectedFloatingBaseline = null;
      _isPencilSettingsFloatingOpen = false;
      _pencilSettingsFloatingBaseline = null;
      _isCropFloatingOpen = false;
      _isPhotoRoomRemoveBgFloatingOpen = false;
      _isPhotoRoomRemoveBgProcessing = false;
    });
    _openToolSettingsSidebar();
  }

  double get _textSidebarScale => 0.75;

  Widget _buildHorizontalColorStrip({
    required List<Color> palette,
    required Color selectedColor,
    required ValueChanged<Color> onColorSelected,
    double? scale,
  }) {
    final double uiScale = scale ?? _textSidebarScale;
    double scaled(double value, {required double min}) =>
        math.max(min, value * uiScale);
    final double swatchWidth = scaled(34, min: 24);
    final double swatchHeight = scaled(22, min: 16);
    final double radius = scaled(6, min: 4);
    final double spacing = scaled(6, min: 4);
    final double stripHeight = swatchHeight + scaled(6, min: 4);

    return SizedBox(
      height: stripHeight,
      child: ListView.separated(
        scrollDirection: Axis.horizontal,
        primary: false,
        itemCount: palette.length,
        separatorBuilder: (_, __) => SizedBox(width: spacing),
        itemBuilder: (context, index) {
          final Color color = palette[index];
          final bool isSelected = selectedColor == color;
          return GestureDetector(
            onTap: () => onColorSelected(color),
            child: AnimatedContainer(
              duration: const Duration(milliseconds: 120),
              width: swatchWidth,
              height: swatchHeight,
              decoration: BoxDecoration(
                color: color,
                borderRadius: BorderRadius.circular(radius),
                border: Border.all(
                  color: isSelected
                      ? const Color(0xFFFFFFFF)
                      : const Color(0x1A4F5358),
                  width: isSelected ? 1.1 : 0.6,
                ),
                boxShadow: isSelected
                    ? const <BoxShadow>[
                        BoxShadow(
                          color: Color(0x2219191A),
                          blurRadius: 2,
                          offset: Offset(0, 1),
                        ),
                      ]
                    : null,
              ),
            ),
          );
        },
      ),
    );
  }

  Widget _buildSidebarLauncherCard({
    required String title,
    String? subtitle,
    bool highlighted = false,
    required VoidCallback? onTap,
  }) {
    final bool enabled = onTap != null;
    return Material(
      color: Colors.transparent,
      child: InkWell(
        borderRadius: BorderRadius.circular(12),
        onTap: onTap,
        child: AnimatedContainer(
          duration: const Duration(milliseconds: 150),
          curve: Curves.easeOut,
          width: double.infinity,
          padding: const EdgeInsets.symmetric(horizontal: 12, vertical: 12),
          decoration: BoxDecoration(
            color: highlighted ? kActiveAccent : const Color(0xFF1E1F22),
            borderRadius: BorderRadius.circular(12),
            border: Border.all(
              color: highlighted ? Colors.transparent : const Color(0x2B4F5358),
              width: highlighted ? 0 : 0.55,
            ),
          ),
          child: Opacity(
            opacity: enabled ? 1 : 0.55,
            child: Column(
              crossAxisAlignment: CrossAxisAlignment.start,
              children: [
                Text(
                  title,
                  style: TextStyle(
                    fontSize: 12.5,
                    fontWeight: FontWeight.w700,
                    color: highlighted
                        ? kActiveAccentForeground
                        : const Color(0xFFF3F3F2),
                  ),
                ),
                if (subtitle != null && subtitle.isNotEmpty) ...[
                  const SizedBox(height: 4),
                  Text(
                    subtitle,
                    style: TextStyle(
                      fontSize: 11.5,
                      color: highlighted
                          ? const Color(0xCC19191A)
                          : const Color(0xFFB8B7B5),
                      fontWeight: FontWeight.w600,
                      height: 1.25,
                    ),
                  ),
                ],
              ],
            ),
          ),
        ),
      ),
    );
  }

