  Future<void> _openBlurSettingsBottomSheet() async {
    final EditorLayer? selectedImageLayer = _selectedImageLayer();
    if (selectedImageLayer == null) {
      _showExportMessage(
        'Blur tool works only when an Image Layer is selected.',
        isError: true,
      );
      return;
    }
    if (_isBlurSettingsBottomSheetOpen) return;
    final _EditorSnapshot baseline = _captureSnapshot();
    final BlurToolSettings settingsAtOpen =
        _resolvedBlurSettingsForLayer(selectedImageLayer);

    setState(() {
      _resetBlurPreviewSession(clearBaseline: false);
      _blurSettings = settingsAtOpen;
      _isBlurSettingsBottomSheetOpen = true;
      _blurSettingsBaseline = baseline;
      _blurSettingsAtOpen = settingsAtOpen;
      _isCloneSettingsFloatingOpen = false;
      _isCloneSettingsBottomSheetOpen = false;
      _isPencilSettingsFloatingOpen = false;
      _pencilSettingsFloatingBaseline = null;
      _resetTextQuickFloatingPanels();
      _activeTextEffectFloatingPanel = null;
      _isCropFloatingOpen = false;
      _isOverlayImageShadowFloatingOpen = false;
      _overlayImageShadowFloatingBaseline = null;
      _overlayImageShadowFloatingLayerId = null;
      _isPhotoRoomRemoveBgFloatingOpen = false;
      _isPhotoRoomRemoveBgProcessing = false;
    });
    _closeToolSettingsSidebarIfOpen();

    try {
      await showModalBottomSheet<void>(
        context: context,
        isScrollControlled: true,
        useSafeArea: true,
        backgroundColor: Colors.transparent,
        barrierColor: Colors.transparent,
        builder: (BuildContext sheetContext) {
          const double uiScale = 0.86;
          double scaled(double value, {required double min}) =>
              math.max(min, value * uiScale);
          final double keyboardInset =
              MediaQuery.viewInsetsOf(sheetContext).bottom;
          final double contentBottomInset =
              MediaQuery.viewPaddingOf(sheetContext).bottom +
                  scaled(12, min: 9);
          return Padding(
            padding: EdgeInsets.only(bottom: keyboardInset),
            child: StatefulBuilder(
              builder: (context, modalSetState) {
                final EditorLayer? selectedImageLayer = _selectedImageLayer();
                final bool enabled = selectedImageLayer != null;
                return ConstrainedBox(
                  constraints: BoxConstraints(
                    maxHeight: MediaQuery.sizeOf(sheetContext).height * 0.42,
                  ),
                  child: Container(
                    decoration: const BoxDecoration(
                      color: WonderPicEditorScreen._pageBg,
                      borderRadius: BorderRadius.vertical(
                        top: Radius.circular(20),
                      ),
                    ),
                    child: SingleChildScrollView(
                      padding: EdgeInsets.fromLTRB(
                        scaled(12, min: 9),
                        scaled(10, min: 7),
                        scaled(12, min: 9),
                        contentBottomInset,
                      ),
                      child: IgnorePointer(
                        ignoring: !enabled,
                        child: Opacity(
                          opacity: selectedImageLayer == null ? 0.55 : 1,
                          child: Column(
                            mainAxisSize: MainAxisSize.min,
                            children: [
                              Container(
                                width: 44,
                                height: 4,
                                decoration: BoxDecoration(
                                  color: const Color(0x665A616B),
                                  borderRadius: BorderRadius.circular(99),
                                ),
                              ),
                              SizedBox(height: scaled(8, min: 6)),
                              Row(
                                children: BlurMode.values.map((mode) {
                                  final bool active =
                                      _blurSettings.mode == mode;
                                  return Expanded(
                                    child: Padding(
                                      padding: EdgeInsets.only(
                                        right: mode == BlurMode.bokeh
                                            ? 0
                                            : scaled(6, min: 4),
                                      ),
                                      child: _buildCloneHeaderHalfButton(
                                        label: mode.label,
                                        icon: mode.icon,
                                        active: active,
                                        uiScale: uiScale,
                                        onTap: enabled
                                            ? () {
                                                _applyLiveBlurSettings(
                                                  mode: mode,
                                                );
                                                modalSetState(() {});
                                              }
                                            : null,
                                      ),
                                    ),
                                  );
                                }).toList(),
                              ),
                              SizedBox(height: scaled(6, min: 5)),
                              _buildCloneCompactSlider(
                                label: 'Radius',
                                value: _blurSettings.radius,
                                min: 0,
                                max: 60,
                                valueText:
                                    _blurSettings.radius.toStringAsFixed(0),
                                uiScale: uiScale,
                                enabled: enabled,
                                onChanged: (value) {
                                  _applyLiveBlurSettings(radius: value);
                                  modalSetState(() {});
                                },
                              ),
                              SizedBox(height: scaled(4, min: 3)),
                              _buildCloneCompactSlider(
                                label: 'Amount',
                                value: _blurSettings.amount,
                                min: 0,
                                max: 100,
                                valueText:
                                    '${_blurSettings.amount.toStringAsFixed(0)}%',
                                uiScale: uiScale,
                                enabled: enabled,
                                onChanged: (value) {
                                  _applyLiveBlurSettings(amount: value);
                                  modalSetState(() {});
                                },
                              ),
                              if (_blurError != null &&
                                  _blurError!.trim().isNotEmpty) ...[
                                SizedBox(height: scaled(8, min: 6)),
                                Align(
                                  alignment: Alignment.centerLeft,
                                  child: Text(
                                    _blurError!,
                                    style: TextStyle(
                                      color: const Color(0xFFFF7D7D),
                                      fontSize: scaled(11.5, min: 10.5),
                                      fontWeight: FontWeight.w600,
                                    ),
                                  ),
                                ),
                              ],
                            ],
                          ),
                        ),
                      ),
                    ),
                  ),
                );
              },
            ),
          );
        },
      );
    } finally {
      if (mounted) {
        final _EditorSnapshot? openBaseline = _blurSettingsBaseline;
        final bool shouldCommit = _blurPreviewDirty &&
            openBaseline != null &&
            _hasBlurSettingsChangedFromOpen();
        if (shouldCommit) {
          _pushUndoSnapshotFrom(openBaseline);
        }
        setState(() {
          _resetBlurPreviewSession();
          _isBlurSettingsBottomSheetOpen = false;
        });
      }
    }
  }

  void _showCloneBrushPreviewOverlay() {
    _cloneBrushPreviewTimer?.cancel();
    if (!_isCloneBrushPreviewVisible) {
      setState(() {
        _isCloneBrushPreviewVisible = true;
      });
    }
    _cloneBrushPreviewTimer = Timer(
      const Duration(milliseconds: 650),
      () {
        if (!mounted) return;
        setState(() {
          _isCloneBrushPreviewVisible = false;
        });
      },
    );
  }

