  Widget _buildImageLayerSettingsPanel(EditorLayer imageLayer) {
    final bool isOverlay = !imageLayer.isBackground;
    final _OverlayCutConfig config = _resolvedOverlayCutConfigForLayer(
      imageLayer.id,
    );
    final bool floatingOpen = _isOverlayCutFloatingOpen &&
        _overlayCutConfig?.layerId == imageLayer.id;
    final bool shadowFloatingOpen = _isOverlayImageShadowFloatingOpen &&
        _overlayImageShadowFloatingLayerId == imageLayer.id;
    final bool adjustFloatingOpen = _isImageAdjustFloatingOpen &&
        _imageAdjustFloatingLayerId == imageLayer.id;
    return Column(
      crossAxisAlignment: CrossAxisAlignment.start,
      children: [
        if (isOverlay) ...[
          _buildSidebarLauncherCard(
            title: 'Shape Cut',
            subtitle: floatingOpen
                ? 'Floating panel active'
