        _buildSidebarLauncherCard(
          title: 'Adjustment',
          subtitle: adjustFloatingOpen ? 'Floating panel active' : null,
          highlighted: adjustFloatingOpen,
          onTap: _openImageAdjustFloatingPanel,
        ),
