  Future<void> _applyOverlayShapeCut() async {
    final EditorLayer? layer = _selectedOverlayImageLayer();
    final _OverlayCutConfig? config = _overlayCutConfig;
    if (layer == null || config == null || config.layerId != layer.id) return;
    final ui.Image? sourceImage = layer.image;
    if (sourceImage == null) return;

    final int imageWidth = sourceImage.width;
    final int imageHeight = sourceImage.height;
    final Rect shapeRect = Rect.fromCenter(
      center: Offset(
        config.centerUv.dx * imageWidth,
        config.centerUv.dy * imageHeight,
      ),
      width: math.max(2, imageWidth * config.scaleX),
      height: math.max(2, imageHeight * config.scaleY),
    );
    final Path shapePath = _buildOverlayCutShapePath(
      shape: config.shape,
      shapeRect: shapeRect,
      rotationRadians: config.rotationRadians,
    );
    final Rect shapeBounds = shapePath.getBounds();
    if (shapeBounds.right <= 0 ||
        shapeBounds.bottom <= 0 ||
        shapeBounds.left >= imageWidth ||
        shapeBounds.top >= imageHeight) {
      _showExportMessage(
        'Selected shape is outside visible pixels.',
        isError: true,
      );
      return;
    }
    final int cropLeft = shapeBounds.left.floor().clamp(0, imageWidth - 1);
    final int cropTop = shapeBounds.top.floor().clamp(0, imageHeight - 1);
    final int cropRight = shapeBounds.right.ceil().clamp(1, imageWidth);
    final int cropBottom = shapeBounds.bottom.ceil().clamp(1, imageHeight);
    final int cropWidth = (cropRight - cropLeft).clamp(1, imageWidth);
    final int cropHeight = (cropBottom - cropTop).clamp(1, imageHeight);
    final ui.PictureRecorder recorder = ui.PictureRecorder();
    final Canvas cutCanvas = Canvas(recorder);
    final Rect sourceRect = Rect.fromLTWH(
      cropLeft.toDouble(),
      cropTop.toDouble(),
      cropWidth.toDouble(),
      cropHeight.toDouble(),
    );
    final Rect destinationRect = Rect.fromLTWH(
      0,
      0,
      cropWidth.toDouble(),
      cropHeight.toDouble(),
    );
    final Path localShapePath = shapePath.shift(
      Offset(-cropLeft.toDouble(), -cropTop.toDouble()),
    );
    cutCanvas.save();
    cutCanvas.clipPath(localShapePath, doAntiAlias: true);
    cutCanvas.drawImageRect(
      sourceImage,
      sourceRect,
      destinationRect,
      Paint()
        ..isAntiAlias = true
        ..filterQuality = FilterQuality.high,
    );
    cutCanvas.restore();
    final ui.Picture picture = recorder.endRecording();
    final ui.Image nextImage = await picture.toImage(cropWidth, cropHeight);
    if (!mounted) return;

    final EditorLayer? workspace = _workspaceLayerForEdit(_layers);
    final Size? workspaceSize =
        workspace == null ? null : _workspaceSourceSize(workspace);
    final Offset oldPosition = layer.position ??
        Offset(
          (workspaceSize?.width ?? imageWidth.toDouble()) / 2,
          (workspaceSize?.height ?? imageHeight.toDouble()) / 2,
        );
    final Offset oldImageCenter = Offset(
      imageWidth / 2,
      imageHeight / 2,
    );
    final Offset cropCenter = Offset(
      cropLeft + (cropWidth / 2),
      cropTop + (cropHeight / 2),
    );
    final Offset localDeltaWorkspace = Offset(
      (cropCenter.dx - oldImageCenter.dx) * layer.layerScale,
      (cropCenter.dy - oldImageCenter.dy) * layer.layerScale,
    );
    final Offset rotatedDeltaWorkspace =
        _rotateVector(localDeltaWorkspace, layer.layerRotation);
    final Offset nextPosition = oldPosition + rotatedDeltaWorkspace;

    _pushUndoSnapshot();
    setState(() {
      final int layerIndex =
          _layers.indexWhere((entry) => entry.id == layer.id);
      if (layerIndex >= 0) {
        final List<EditorLayer> nextLayers = List<EditorLayer>.from(_layers);
        final EditorLayer current = nextLayers[layerIndex];
        nextLayers[layerIndex] = current.copyWith(
          image: nextImage,
          solidSize: _imageSourceSize(nextImage),
          thumbnailBytes: null,
          position: nextPosition,
          overlayShapeTypeKey: config.shape.name,
        );
        _layers = nextLayers;
      }
      _isOverlayCutFloatingOpen = false;
      _overlayCutBaseline = null;
      _overlayCutConfig = config.copyWith(layerId: layer.id);
    });
  }

