  Widget _buildImageAdjustSectionControls({
    required EditorLayer layer,
    required _ImageAdjustSection section,
    required double scale,
  }) {
    final String layerId = layer.id;
    final double brightness = layer.imageAdjustBrightness ?? 0;
    final double exposure = layer.imageAdjustExposure ?? 0;
    final double contrast = layer.imageAdjustContrast ?? 0;
    final double saturation = layer.imageAdjustSaturation ?? 0;
    final double warmth = layer.imageAdjustWarmth ?? 0;
    final double shadows = layer.imageAdjustShadows ?? 0;
    final double whites = layer.imageAdjustWhites ?? 0;
    final double blacks = layer.imageAdjustBlacks ?? 0;
    switch (section) {
      case _ImageAdjustSection.light:
        return Column(
          children: [
            _SettingsSliderTile(
              label: 'Brightness',
              value: brightness,
              min: -100,
              max: 100,
              valueText: _formatSignedValue(brightness, fractionDigits: 0),
              scale: scale,
              onChanged: (value) {
                _updateImageAdjustmentLayer(
                  layerId,
                  imageAdjustBrightness: value,
                  recordHistory: false,
                );
              },
            ),
            SizedBox(height: (8 * scale).clamp(6, 8).toDouble()),
            _SettingsSliderTile(
              label: 'Exposure',
              value: exposure,
              min: -100,
              max: 100,
              valueText: _formatSignedValue(exposure, fractionDigits: 0),
              scale: scale,
              onChanged: (value) {
                _updateImageAdjustmentLayer(
                  layerId,
                  imageAdjustExposure: value,
                  recordHistory: false,
                );
              },
            ),
            SizedBox(height: (8 * scale).clamp(6, 8).toDouble()),
            _SettingsSliderTile(
              label: 'Contrast',
              value: contrast,
              min: -100,
              max: 100,
              valueText: _formatSignedValue(contrast, fractionDigits: 0),
              scale: scale,
              onChanged: (value) {
                _updateImageAdjustmentLayer(
                  layerId,
                  imageAdjustContrast: value,
                  recordHistory: false,
                );
              },
            ),
          ],
        );
      case _ImageAdjustSection.colors:
        return Column(
          children: [
            _SettingsSliderTile(
              label: 'Saturation',
              value: saturation,
              min: -100,
              max: 100,
              valueText: _formatSignedValue(saturation, fractionDigits: 0),
              scale: scale,
              onChanged: (value) {
                _updateImageAdjustmentLayer(
                  layerId,
                  imageAdjustSaturation: value,
                  recordHistory: false,
                );
              },
            ),
            SizedBox(height: (8 * scale).clamp(6, 8).toDouble()),
            _SettingsSliderTile(
              label: 'Warmth',
              value: warmth,
              min: -100,
              max: 100,
              valueText: _formatSignedValue(warmth, fractionDigits: 0),
              scale: scale,
              onChanged: (value) {
                _updateImageAdjustmentLayer(
                  layerId,
                  imageAdjustWarmth: value,
                  recordHistory: false,
                );
              },
            ),
          ],
        );
      case _ImageAdjustSection.dark:
        return _SettingsSliderTile(
          label: 'Blacks',
          value: blacks,
          min: -100,
          max: 100,
          valueText: _formatSignedValue(blacks, fractionDigits: 0),
          scale: scale,
          onChanged: (value) {
            _updateImageAdjustmentLayer(
              layerId,
              imageAdjustBlacks: value,
              recordHistory: false,
            );
          },
        );
      case _ImageAdjustSection.white:
        return _SettingsSliderTile(
          label: 'Whites',
          value: whites,
          min: -100,
          max: 100,
          valueText: _formatSignedValue(whites, fractionDigits: 0),
          scale: scale,
          onChanged: (value) {
            _updateImageAdjustmentLayer(
              layerId,
              imageAdjustWhites: value,
              recordHistory: false,
            );
          },
        );
      case _ImageAdjustSection.shadow:
        return _SettingsSliderTile(
          label: 'Shadows',
          value: shadows,
          min: -100,
          max: 100,
          valueText: _formatSignedValue(shadows, fractionDigits: 0),
          scale: scale,
          onChanged: (value) {
            _updateImageAdjustmentLayer(
              layerId,
              imageAdjustShadows: value,
              recordHistory: false,
            );
          },
        );
    }
  }

