  Widget _buildExpandSettingsPanel() {
    final EditorLayer? selectedImageLayer = _selectedExpandLayer();
    if (selectedImageLayer == null) {
      return const _ToolHintCard(
        title: 'Expand Tool',
        message: 'Select an image layer, then drag a side handle on canvas.',
      );
    }
    final _ExpandToolConfig config =
        _resolvedExpandConfigForLayer(selectedImageLayer.id);
    final int left = (config.leftExpand * 100).round();
    final int top = (config.topExpand * 100).round();
    final int right = (config.rightExpand * 100).round();
    final int bottom = (config.bottomExpand * 100).round();
    return _ToolHintCard(
      title: 'Expand Tool',
      message:
          'Drag each side independently on canvas.\nLeft: $left% • Top: $top% • Right: $right% • Bottom: $bottom%',
    );
  }

