  Widget _buildSketchReplaceSettingsPanel() {
    final EditorLayer? selectedImageLayer = _selectedImageLayer();
    final bool enabled = selectedImageLayer != null;
    final int maskStrokeCount = selectedImageLayer == null
        ? 0
        : (_sketchMaskStrokesByLayer[selectedImageLayer.id]?.length ?? 0);
    return Column(
      crossAxisAlignment: CrossAxisAlignment.start,
      children: [
        _buildSidebarLauncherCard(
          title: 'Remove Object',
          subtitle: _isSketchReplaceFloatingOpen
              ? 'Floating panel active'
              : maskStrokeCount > 0
                  ? 'Mask strokes: $maskStrokeCount'
                  : null,
          highlighted: _isSketchReplaceFloatingOpen,
          onTap: enabled ? _openSketchReplaceFloatingPanel : null,
        ),
        const SizedBox(height: 10),
        _buildSidebarLauncherCard(
          title: 'Mask Brush',
          subtitle: _isSketchReplaceMaskDrawingEnabled ? 'Enabled' : 'Disabled',
          highlighted: _isSketchReplaceMaskDrawingEnabled,
          onTap: enabled
              ? () {
                  setState(() {
                    _isSketchReplaceMaskDrawingEnabled =
                        !_isSketchReplaceMaskDrawingEnabled;
                  });
                }
              : null,
        ),
        if (enabled && maskStrokeCount > 0) ...[
          const SizedBox(height: 10),
          _buildSidebarLauncherCard(
            title: 'Clear Mask',
            subtitle: 'Remove all painted mask strokes',
            onTap: () {
              setState(() {
                _sketchMaskStrokesByLayer.remove(selectedImageLayer.id);
                _sketchReplaceError = null;
              });
            },
          ),
        ],
        if (!enabled) ...[
          const SizedBox(height: 10),
          const _ToolHintCard(
            title: 'No Image Selected',
            message: 'Select an image layer first.',
          ),
        ],
      ],
    );
  }

