  void _showSketchReplaceBrushPreviewOverlay() {
    _sketchReplaceBrushPreviewTimer?.cancel();
    if (!_isSketchReplaceBrushPreviewVisible) {
      setState(() {
        _isSketchReplaceBrushPreviewVisible = true;
      });
    }
    _sketchReplaceBrushPreviewTimer = Timer(
      const Duration(milliseconds: 700),
      () {
        if (!mounted) return;
        setState(() {
          _isSketchReplaceBrushPreviewVisible = false;
        });
      },
    );
  }

