  Future<void> _pickReplaceObjectReferenceImage() async {
    if (_isReplaceObjectProcessing) return;
    try {
      final XFile? file = await _picker.pickImage(
        source: ImageSource.gallery,
        requestFullMetadata: false,
      );
      if (file == null || !mounted) return;
      final Uint8List bytes = await file.readAsBytes();
      if (!mounted) return;
      setState(() {
        _replaceObjectReferenceImageBytes = bytes;
        _replaceObjectError = null;
      });
    } on PlatformException {
      if (!mounted) return;
      setState(() {
        _replaceObjectError =
            'Gallery access failed. Please allow photo access.';
      });
    } catch (_) {
      if (!mounted) return;
      setState(() {
        _replaceObjectError = 'Could not load image from gallery.';
      });
    }
  }

