  Future<void> _runSketchReplaceWithKieIdeogram() async {
    if (_isSketchReplaceProcessing) return;
    final EditorLayer? selectedLayer = _selectedImageLayer();
    final ui.Image? sourceImage = selectedLayer?.image;
    if (selectedLayer == null || sourceImage == null) {
      setState(() {
        _sketchReplaceError = 'Select an image layer first.';
      });
      return;
    }
    final List<_SketchMaskStroke> maskStrokes =
        _sketchMaskStrokesByLayer[selectedLayer.id] ??
            const <_SketchMaskStroke>[];
    if (maskStrokes.isEmpty) {
      setState(() {
        _sketchReplaceError = 'Draw a mask first.';
      });
      return;
    }
    final String promptText = _sketchReplacePromptController.text.trim();
    if (promptText.isEmpty) {
      setState(() {
        _sketchReplaceError = 'Enter prompt first.';
      });
      return;
    }
    final String apiKey = _kieApiKey.trim();
    if (apiKey.isEmpty) {
      setState(() {
        _sketchReplaceError = 'KIE API key missing.';
      });
      return;
    }

    setState(() {
      _isSketchReplaceProcessing = true;
      _sketchReplaceError = null;
    });

    try {
      final Uint8List sourceImageBytes =
          await _encodeUiImageToPngBytes(sourceImage);
      final Uint8List maskBytes = _buildSketchMaskPngBytes(
        width: sourceImage.width,
        height: sourceImage.height,
        strokes: maskStrokes,
      );
      final List<String> uploadedUrls =
          await Future.wait<String>(<Future<String>>[
        _uploadKieReferenceFile(sourceImageBytes),
        _uploadKieReferenceFile(maskBytes),
      ]);
      final String imageUrl = uploadedUrls[0];
      final String maskUrl = uploadedUrls[1];
      final String taskId = await _createKieIdeogramV3EditTask(
        imageUrl: imageUrl,
        maskUrl: maskUrl,
        prompt: promptText,
      );
      final Uint8List outputBytes =
          await _pollKieTaskAndDownload(taskId: taskId);
      final ui.Image nextImage = await _decodeUiImage(outputBytes);
      if (!mounted) return;
      _pushUndoSnapshot();
      setState(() {
        _replaceLayerImage(selectedLayer.id, nextImage);
        _sketchMaskStrokesByLayer.remove(selectedLayer.id);
        _isSketchReplaceProcessing = false;
        _isSketchReplaceFloatingOpen = false;
        _sketchReplaceError = null;
      });
      _showExportMessage('Sketch replace completed.');
    } catch (error) {
      if (!mounted) return;
      setState(() {
        _isSketchReplaceProcessing = false;
        _sketchReplaceError = _normalizeSketchReplaceError(error.toString());
      });
      _showExportMessage(_sketchReplaceError!, isError: true);
    }
  }

  Future<String> _createKieIdeogramV3EditTask({
    required String imageUrl,
    required String maskUrl,
    required String prompt,
  }) async {
    final String apiKey = _kieApiKey.trim();
    if (apiKey.isEmpty) {
      throw StateError('KIE API key missing.');
    }
    final Uri uri = Uri.parse('https://api.kie.ai/api/v1/jobs/createTask');
    final http.Response response = await http
        .post(
          uri,
          headers: <String, String>{
            'Authorization': 'Bearer $apiKey',
            'Content-Type': 'application/json',
          },
          body: jsonEncode(
            <String, dynamic>{
              'model': 'ideogram/v3-edit',
              'input': <String, dynamic>{
                'prompt': prompt,
                'image_url': imageUrl,
                'mask_url': maskUrl,
                'rendering_speed': 'TURBO',
              },
            },
          ),
        )
        .timeout(const Duration(minutes: 2));

    final Map<String, dynamic> decoded = _decodeKieJson(
      response.bodyBytes,
      contextLabel: 'KIE createTask (Ideogram v3-edit)',
    );
    final int code = _readKieCode(decoded['code']);
    final String message =
        (decoded['msg'] as String?)?.trim() ?? 'Unknown KIE error.';

    if (response.statusCode < 200 ||
        response.statusCode >= 300 ||
        code != 200) {
      throw StateError(
        'KIE Ideogram v3-edit createTask failed (${response.statusCode}): $message',
      );
    }

    final Map<String, dynamic>? data = decoded['data'] is Map<String, dynamic>
        ? decoded['data'] as Map<String, dynamic>
        : null;
    final String taskId = (data?['taskId'] as String?)?.trim() ?? '';
    if (taskId.isEmpty) {
      throw const FormatException(
        'KIE Ideogram v3-edit returned empty taskId.',
      );
    }
    return taskId;
  }

  Future<
      ({
        Uint8List expandedMaskBytes,
        Uint8List cleanupMaskBytes,
        bool hasCleanupMask,
        Uint8List detailCleanupMaskBytes,
        bool hasDetailCleanupMask
      })> _prepareObjectRemovalMasks({
    required Uint8List baseMaskPngBytes,
    required double brushSizePx,
  }) async {
    final int expandRadiusPx = _objectRemovalExpandRadius(brushSizePx);
    final int cleanupRadiusPx = _objectRemovalCleanupRadius(expandRadiusPx);
    final Uint8List baseMaskCopy = Uint8List.fromList(baseMaskPngBytes);
    final Map<String, Object> result = await Isolate.run<Map<String, Object>>(
      () => _prepareObjectRemovalMasksCompute(
        baseMaskPngBytes: baseMaskCopy,
        expandRadiusPx: expandRadiusPx,
        cleanupRadiusPx: cleanupRadiusPx,
      ),
    );
    return (
      expandedMaskBytes:
          result['expandedMaskBytes'] as Uint8List? ?? baseMaskPngBytes,
      cleanupMaskBytes:
          result['cleanupMaskBytes'] as Uint8List? ?? Uint8List(0),
      hasCleanupMask: result['hasCleanupMask'] as bool? ?? false,
      detailCleanupMaskBytes:
          result['detailCleanupMaskBytes'] as Uint8List? ?? Uint8List(0),
      hasDetailCleanupMask: result['hasDetailCleanupMask'] as bool? ?? false,
    );
  }

  int _objectRemovalExpandRadius(double brushSizePx) {
    final int computed = (brushSizePx * 0.12).round();
    return computed.clamp(1, 10);
  }

  int _objectRemovalCleanupRadius(int expandRadiusPx) {
    // BRIA API works best with a clean single-pass mask. Extra ring passes
    // can introduce halos on flat backgrounds.
    return 0;
  }

  int _objectRemovalRoiMargin(double brushSizePx) {
    final int computed = (brushSizePx * 1.15).round();
    return computed.clamp(16, 180);
  }

  int _objectRemovalBlendFeather(double brushSizePx) {
    final int computed = (brushSizePx * 0.32).round();
    return computed.clamp(3, 30);
  }

  Future<
      ({
        Uint8List sourceRoiBytes,
        Uint8List expandedMaskRoiBytes,
        Uint8List cleanupMaskRoiBytes,
        bool hasCleanupMask,
        Uint8List detailCleanupMaskRoiBytes,
        bool hasDetailCleanupMask,
        Uint8List blendMaskRoiBytes,
        int roiLeft,
        int roiTop,
        int roiWidth,
        int roiHeight
      })> _prepareObjectRemovalRoiBundle({
    required Uint8List sourceImagePngBytes,
    required Uint8List expandedMaskPngBytes,
    required Uint8List cleanupMaskPngBytes,
    required bool hasCleanupMask,
    required Uint8List detailCleanupMaskPngBytes,
    required bool hasDetailCleanupMask,
    required int roiMarginPx,
    required int blendFeatherPx,
  }) async {
    final Uint8List sourceCopy = Uint8List.fromList(sourceImagePngBytes);
    final Uint8List expandedMaskCopy = Uint8List.fromList(expandedMaskPngBytes);
    final Uint8List cleanupMaskCopy = Uint8List.fromList(cleanupMaskPngBytes);
    final Uint8List detailCleanupMaskCopy = Uint8List.fromList(
      detailCleanupMaskPngBytes,
    );
    final Map<String, Object> result = await Isolate.run<Map<String, Object>>(
      () => _prepareObjectRemovalRoiBundleCompute(
        sourceImagePngBytes: sourceCopy,
        expandedMaskPngBytes: expandedMaskCopy,
        cleanupMaskPngBytes: cleanupMaskCopy,
        hasCleanupMask: hasCleanupMask,
        detailCleanupMaskPngBytes: detailCleanupMaskCopy,
        hasDetailCleanupMask: hasDetailCleanupMask,
        roiMarginPx: roiMarginPx,
        blendFeatherPx: blendFeatherPx,
      ),
    );
    return (
      sourceRoiBytes:
          result['sourceRoiBytes'] as Uint8List? ?? sourceImagePngBytes,
      expandedMaskRoiBytes:
          result['expandedMaskRoiBytes'] as Uint8List? ?? expandedMaskPngBytes,
      cleanupMaskRoiBytes:
          result['cleanupMaskRoiBytes'] as Uint8List? ?? Uint8List(0),
      hasCleanupMask: result['hasCleanupMask'] as bool? ?? false,
      detailCleanupMaskRoiBytes:
          result['detailCleanupMaskRoiBytes'] as Uint8List? ?? Uint8List(0),
      hasDetailCleanupMask: result['hasDetailCleanupMask'] as bool? ?? false,
      blendMaskRoiBytes:
          result['blendMaskRoiBytes'] as Uint8List? ?? Uint8List(0),
      roiLeft: result['roiLeft'] as int? ?? 0,
      roiTop: result['roiTop'] as int? ?? 0,
      roiWidth: result['roiWidth'] as int? ?? 0,
      roiHeight: result['roiHeight'] as int? ?? 0,
    );
  }

  Future<Uint8List> _compositeObjectRemovalRoiResult({
    required Uint8List sourceImagePngBytes,
    required Uint8List outputRoiPngBytes,
    required Uint8List blendMaskRoiBytes,
    required int roiLeft,
    required int roiTop,
    required int roiWidth,
    required int roiHeight,
  }) async {
    if (roiWidth < 1 || roiHeight < 1 || blendMaskRoiBytes.isEmpty) {
      return sourceImagePngBytes;
    }
    final Uint8List sourceCopy = Uint8List.fromList(sourceImagePngBytes);
    final Uint8List outputCopy = Uint8List.fromList(outputRoiPngBytes);
    final Uint8List blendMaskCopy = Uint8List.fromList(blendMaskRoiBytes);
    return Isolate.run<Uint8List>(
      () => _compositeObjectRemovalRoiResultCompute(
        sourceImagePngBytes: sourceCopy,
        outputRoiPngBytes: outputCopy,
        blendMaskRoiBytes: blendMaskCopy,
        roiLeft: roiLeft,
        roiTop: roiTop,
        roiWidth: roiWidth,
        roiHeight: roiHeight,
      ),
    );
  }

  Future<Uint8List> _runObjectRemovalPass({
    required String token,
    required Uint8List sourceImageBytes,
    required Uint8List maskBytes,
    required String filenamePrefix,
  }) async {
    // Upload source+mask concurrently to reduce network latency.
    final List<String> uploadUrls = await Future.wait<String>(<Future<String>>[
      _uploadReplicateFileWithRetry(
        token: token,
        bytes: sourceImageBytes,
        filename: '${filenamePrefix}_source.png',
      ),
      _uploadReplicateFileWithRetry(
        token: token,
        bytes: maskBytes,
        filename: '${filenamePrefix}_mask.png',
      ),
    ]);
    final String imageUrl = uploadUrls[0];
    final String maskUrl = uploadUrls[1];
    final String predictionId = await _createObjectRemovalPredictionWithRetry(
      token: token,
      imageUrl: imageUrl,
      maskUrl: maskUrl,
    );
    final String outputUrl = await _pollReplicatePredictionOutputUrl(
      token: token,
      predictionId: predictionId,
    );
    final http.Response outputResponse = await http
        .get(Uri.parse(outputUrl))
        .timeout(const Duration(minutes: 2));
    if (outputResponse.statusCode < 200 || outputResponse.statusCode >= 300) {
      throw StateError(
        'Output download failed (${outputResponse.statusCode}).',
      );
    }
    return outputResponse.bodyBytes;
  }

  Future<void> _runReplaceObjectWithFluxFillPro() async {
    if (_isReplaceObjectProcessing) return;
    final EditorLayer? selectedLayer = _selectedImageLayer();
    final ui.Image? sourceImage = selectedLayer?.image;
    if (selectedLayer == null || sourceImage == null) {
      setState(() {
        _replaceObjectError = 'Select an image layer first.';
      });
      return;
    }
    final List<_SketchMaskStroke> maskStrokes =
        _replaceObjectMaskStrokesByLayer[selectedLayer.id] ??
            const <_SketchMaskStroke>[];
    if (maskStrokes.isEmpty) {
      setState(() {
        _replaceObjectError = 'Draw a mask first.';
      });
      return;
    }
    final String promptText = _replaceObjectPromptController.text.trim();
    if (promptText.isEmpty) {
      setState(() {
        _replaceObjectError = 'Enter replacement prompt.';
      });
      return;
    }
    final Uint8List? referenceBytes = _replaceObjectReferenceImageBytes;
    if (referenceBytes == null || referenceBytes.isEmpty) {
      setState(() {
        _replaceObjectError = 'Upload reference image first.';
      });
      return;
    }
    final String token = _replicateApiToken.trim();
    if (token.isEmpty) {
      setState(() {
        _replaceObjectError =
            'Replicate API token missing. Use --dart-define=REPLICATE_API_TOKEN=...';
      });
      return;
    }

    setState(() {
      _isReplaceObjectProcessing = true;
      _replaceObjectError = null;
    });

    try {
      final Uint8List sourceImageBytes =
          await _encodeUiImageToPngBytes(sourceImage);
      final Uint8List maskBytes = _buildSketchMaskPngBytes(
        width: sourceImage.width,
        height: sourceImage.height,
        strokes: maskStrokes,
      );
      final Uint8List preparedSource = await _prepareReplaceObjectSourceBytes(
        sourcePngBytes: sourceImageBytes,
        maskPngBytes: maskBytes,
        referencePngBytes: referenceBytes,
      );

      final String imageUrl = await _uploadReplicateFileWithRetry(
        token: token,
        bytes: preparedSource,
        filename: 'replace_object_source.png',
      );
      final String maskUrl = await _uploadReplicateFileWithRetry(
        token: token,
        bytes: maskBytes,
        filename: 'replace_object_mask.png',
      );

      final String effectivePrompt =
          'Replace only masked area with uploaded reference object. $promptText. Keep object identity from reference, preserve all unmasked content exactly, keep natural perspective, lighting, and shadow integration.';
      final String predictionId = await _createFluxFillPredictionWithRetry(
        token: token,
        imageUrl: imageUrl,
        maskUrl: maskUrl,
        prompt: effectivePrompt,
      );
      final String outputUrl = await _pollReplicatePredictionOutputUrl(
        token: token,
        predictionId: predictionId,
      );
      final http.Response outputResponse = await http
          .get(Uri.parse(outputUrl))
          .timeout(const Duration(minutes: 2));
      if (outputResponse.statusCode < 200 || outputResponse.statusCode >= 300) {
        throw StateError(
          'Output download failed (${outputResponse.statusCode}).',
        );
      }
      final ui.Image nextImage = await _decodeUiImage(outputResponse.bodyBytes);
      if (!mounted) return;
      _pushUndoSnapshot();
      setState(() {
        _replaceLayerImage(selectedLayer.id, nextImage);
        _replaceObjectMaskStrokesByLayer.remove(selectedLayer.id);
        _isReplaceObjectProcessing = false;
        _isReplaceObjectFloatingOpen = false;
        _replaceObjectError = null;
      });
      _showExportMessage('Replace object completed.');
    } catch (error) {
      if (!mounted) return;
      setState(() {
        _isReplaceObjectProcessing = false;
        _replaceObjectError = _normalizeSketchReplaceError(error.toString());
      });
      _showExportMessage(_replaceObjectError!, isError: true);
    }
  }

  Future<Uint8List> _prepareReplaceObjectSourceBytes({
    required Uint8List sourcePngBytes,
    required Uint8List maskPngBytes,
    required Uint8List referencePngBytes,
  }) async {
    final Uint8List sourceCopy = Uint8List.fromList(sourcePngBytes);
    final Uint8List maskCopy = Uint8List.fromList(maskPngBytes);
    final Uint8List referenceCopy = Uint8List.fromList(referencePngBytes);
    return Isolate.run<Uint8List>(
      () => _composeReferenceIntoMaskedRegionPng(
        sourcePngBytes: sourceCopy,
        maskPngBytes: maskCopy,
        referencePngBytes: referenceCopy,
      ),
    );
  }

  String _normalizeSketchReplaceError(String raw) {
    String message = raw.trim();
    for (final String prefix in <String>[
      'StateError: ',
      'FormatException: ',
      'Exception: ',
    ]) {
      if (message.startsWith(prefix)) {
        message = message.substring(prefix.length);
      }
    }
    return message;
  }

  Future<String> _uploadReplicateFileWithRetry({
    required String token,
    required Uint8List bytes,
    required String filename,
  }) async {
    const int maxAttempts = 3;
    for (int attempt = 0; attempt < maxAttempts; attempt++) {
      final http.MultipartRequest request = http.MultipartRequest(
        'POST',
        Uri.parse('https://api.replicate.com/v1/files'),
      )
        ..headers['Authorization'] = 'Bearer $token'
        ..files.add(
          http.MultipartFile.fromBytes(
            'content',
            bytes,
            filename: filename,
          ),
        );

      final http.StreamedResponse response =
          await request.send().timeout(const Duration(minutes: 2));
      final Uint8List bodyBytes = await response.stream.toBytes();
      if (response.statusCode >= 200 && response.statusCode < 300) {
        final dynamic decoded = jsonDecode(utf8.decode(bodyBytes));
        if (decoded is! Map<String, dynamic>) {
          throw const FormatException('Replicate upload response is invalid.');
        }
        final dynamic urls = decoded['urls'];
        if (urls is! Map<String, dynamic>) {
          throw const FormatException('Replicate upload URL is missing.');
        }
        final String fileUrl = (urls['get'] as String?)?.trim() ?? '';
        if (fileUrl.isEmpty) {
          throw const FormatException('Replicate upload URL is empty.');
        }
        return fileUrl;
      }
      final bool retryable = _isRetryableReplicateStatus(response.statusCode);
      if (!retryable || attempt >= maxAttempts - 1) {
        throw StateError(
          _replicateHttpErrorMessage(
            statusCode: response.statusCode,
            bodyBytes: bodyBytes,
          ),
        );
      }
      final Duration wait = _replicateRetryDelay(
        attempt: attempt,
        retryAfterHeader: response.headers['retry-after'],
      );
      await Future.delayed(wait);
    }
    throw StateError('Replicate upload failed.');
  }

  Future<String> _createReplicatePredictionWithRetry({
    required String token,
    required String imageUrl,
    required String maskUrl,
    required String prompt,
    required String negativePrompt,
    required int steps,
    required double guidanceScale,
    required int width,
    required int height,
  }) async {
    const int maxAttempts = 3;
    final Uri uri = Uri.parse('https://api.replicate.com/v1/predictions');
    final Map<String, dynamic> payload = <String, dynamic>{
      'version': _replicateInpaintModelVersion,
      'input': <String, dynamic>{
        'image': imageUrl,
        'mask': maskUrl,
        'prompt': prompt,
        'negative_prompt': negativePrompt,
        'num_outputs': 1,
        'num_inference_steps': steps.clamp(1, 75),
        'guidance_scale': guidanceScale.clamp(1.0, 20.0),
        'width': width,
        'height': height,
      },
    };
    for (int attempt = 0; attempt < maxAttempts; attempt++) {
      final http.Response response = await http
          .post(
            uri,
            headers: <String, String>{
              'Authorization': 'Bearer $token',
              'Content-Type': 'application/json',
              'Prefer': 'wait=60',
            },
            body: jsonEncode(payload),
          )
          .timeout(const Duration(minutes: 2));
      if (response.statusCode >= 200 && response.statusCode < 300) {
        final dynamic decoded = jsonDecode(utf8.decode(response.bodyBytes));
        if (decoded is! Map<String, dynamic>) {
          throw const FormatException('Prediction response is invalid.');
        }
        final String predictionId = (decoded['id'] as String?)?.trim() ?? '';
        if (predictionId.isEmpty) {
          throw const FormatException('Prediction id missing.');
        }
        return predictionId;
      }
      final bool retryable = _isRetryableReplicateStatus(response.statusCode);
      if (!retryable || attempt >= maxAttempts - 1) {
        throw StateError(
          _replicateHttpErrorMessage(
            statusCode: response.statusCode,
            bodyBytes: response.bodyBytes,
          ),
        );
      }
      await Future.delayed(
        _replicateRetryDelay(
          attempt: attempt,
          retryAfterHeader: response.headers['retry-after'],
        ),
      );
    }
    throw StateError('Prediction creation failed.');
  }

