  Future<String> _pollReplicatePredictionOutputUrl({
    required String token,
    required String predictionId,
  }) async {
    final Uri uri =
        Uri.parse('https://api.replicate.com/v1/predictions/$predictionId');
    final DateTime deadline = DateTime.now().add(const Duration(minutes: 3));
    int retryAttempt = 0;
    while (DateTime.now().isBefore(deadline)) {
      final http.Response response = await http.get(
        uri,
        headers: <String, String>{'Authorization': 'Bearer $token'},
      );
      if (response.statusCode == 429 ||
          (response.statusCode >= 500 && response.statusCode < 600)) {
        await Future.delayed(
          _replicateRetryDelay(
            attempt: retryAttempt,
            retryAfterHeader: response.headers['retry-after'],
          ),
        );
        retryAttempt++;
        continue;
      }
      if (response.statusCode < 200 || response.statusCode >= 300) {
        throw StateError(
          _replicateHttpErrorMessage(
            statusCode: response.statusCode,
            bodyBytes: response.bodyBytes,
          ),
        );
      }
      final dynamic decoded = jsonDecode(utf8.decode(response.bodyBytes));
      if (decoded is! Map<String, dynamic>) {
        throw const FormatException('Prediction status payload is invalid.');
      }
      final String status =
          (decoded['status'] as String? ?? '').trim().toLowerCase();
      if (status == 'succeeded') {
        final dynamic output = decoded['output'];
        if (output is String && output.trim().isNotEmpty) {
          return output.trim();
        }
        if (output is List && output.isNotEmpty) {
          final String first = output.first.toString().trim();
          if (first.isNotEmpty) {
            return first;
          }
        }
        throw const FormatException('Prediction output is empty.');
      }
      if (status == 'failed' || status == 'canceled') {
        final String reason = (decoded['error'] as String?)?.trim() ?? status;
        throw StateError('Prediction $status: $reason');
      }
      await Future.delayed(const Duration(seconds: 2));
    }
    throw TimeoutException('Prediction timeout.');
  }

  bool _isRetryableReplicateStatus(int statusCode) {
    if (statusCode == 429) return true;
    return statusCode >= 500 && statusCode < 600;
  }

  Duration _replicateRetryDelay({
    required int attempt,
    String? retryAfterHeader,
  }) {
    final int? retryAfterSeconds =
        int.tryParse((retryAfterHeader ?? '').trim());
    if (retryAfterSeconds != null && retryAfterSeconds > 0) {
      return Duration(seconds: retryAfterSeconds.clamp(1, 20));
    }
    final int backoffMs = 1200 * (1 << attempt.clamp(0, 4));
    return Duration(milliseconds: backoffMs.clamp(1200, 8500));
  }

  String _replicateHttpErrorMessage({
    required int statusCode,
    required Uint8List bodyBytes,
  }) {
    String bodyText = '';
    try {
      bodyText = utf8.decode(bodyBytes).trim();
    } catch (_) {}

    String? apiMessage;
    if (bodyText.isNotEmpty) {
      try {
        final dynamic decoded = jsonDecode(bodyText);
        if (decoded is Map<String, dynamic>) {
          apiMessage = (decoded['error'] as String?)?.trim() ??
              (decoded['detail'] as String?)?.trim() ??
              (decoded['message'] as String?)?.trim();
        }
      } catch (_) {
        apiMessage = bodyText;
      }
    }

    if (statusCode == 401) {
      return 'Invalid Replicate token (401).';
    }
    if (statusCode == 402) {
      return 'Replicate credits are insufficient (402).';
    }
    if (statusCode == 404) {
      return 'Replicate model/version was not found (404).';
    }
    if (statusCode == 429) {
      return 'Too many requests (429). Please retry.';
    }
    if (apiMessage != null && apiMessage.isNotEmpty) {
      return 'Replicate error ($statusCode): $apiMessage';
    }
    return 'Replicate request failed ($statusCode).';
  }

  ({int width, int height}) _replicateTargetSize(int width, int height) {
    double w = width.toDouble();
    double h = height.toDouble();
    final double maxSide = 1024;
    final double longest = math.max(w, h);
    if (longest > maxSide) {
      final double scale = maxSide / longest;
      w *= scale;
      h *= scale;
    }
    int safeW = _nearestMultipleOf64(w.round().clamp(64, 1536));
    int safeH = _nearestMultipleOf64(h.round().clamp(64, 1536));
    safeW = safeW.clamp(64, 1536);
    safeH = safeH.clamp(64, 1536);
    return (width: safeW, height: safeH);
  }

  int _nearestMultipleOf64(int value) {
    final int safe = math.max(64, value);
    final int lower = (safe ~/ 64) * 64;
    final int upper = lower + 64;
    if (lower < 64) return 64;
    if ((safe - lower) <= (upper - safe)) {
      return lower;
    }
    return upper;
  }

  Uint8List _buildSketchMaskPngBytes({
    required int width,
    required int height,
    required List<_SketchMaskStroke> strokes,
  }) {
    final Uint8List rgba = Uint8List(width * height * 4);
    for (int i = 0; i < rgba.length; i += 4) {
      rgba[i] = 0;
      rgba[i + 1] = 0;
      rgba[i + 2] = 0;
      rgba[i + 3] = 255;
    }
    for (final _SketchMaskStroke stroke in strokes) {
      _paintSketchMaskStrokeOnRgba(
        rgba: rgba,
        width: width,
        height: height,
        stroke: stroke,
      );
    }
    final img.Image maskImage = img.Image.fromBytes(
      width: width,
      height: height,
      bytes: rgba.buffer,
      order: img.ChannelOrder.rgba,
      numChannels: 4,
    );
    return Uint8List.fromList(img.encodePng(maskImage));
  }

  void _paintSketchMaskStrokeOnRgba({
    required Uint8List rgba,
    required int width,
    required int height,
    required _SketchMaskStroke stroke,
  }) {
    if (stroke.pointsUv.isEmpty) return;
    final double radiusPx =
        math.max(1.0, stroke.radiusUv * math.max(width, height));
    Offset previous = stroke.pointsUv.first;
    for (final Offset point in stroke.pointsUv) {
      final Offset current = Offset(
        point.dx.clamp(0.0, 1.0).toDouble(),
        point.dy.clamp(0.0, 1.0).toDouble(),
      );
      final Offset delta = current - previous;
      final double distancePx = delta.distance * math.max(width, height);
      final int steps =
          math.max(1, (distancePx / math.max(1.0, radiusPx * 0.35)).ceil());
      for (int i = 0; i <= steps; i++) {
        final double t = steps == 0 ? 1 : i / steps;
        final Offset p = Offset.lerp(previous, current, t) ?? current;
        final int cx = (p.dx * (width - 1)).round();
        final int cy = (p.dy * (height - 1)).round();
        _paintSketchMaskDot(
          rgba: rgba,
          width: width,
          height: height,
          centerX: cx,
          centerY: cy,
          radiusPx: radiusPx,
        );
      }
      previous = current;
    }
  }

  void _paintSketchMaskDot({
    required Uint8List rgba,
    required int width,
    required int height,
    required int centerX,
    required int centerY,
    required double radiusPx,
  }) {
    final int radius = math.max(1, radiusPx.ceil());
    final int minX = math.max(0, centerX - radius);
    final int maxX = math.min(width - 1, centerX + radius);
    final int minY = math.max(0, centerY - radius);
    final int maxY = math.min(height - 1, centerY + radius);
    final double radiusSquared = radiusPx * radiusPx;
    for (int y = minY; y <= maxY; y++) {
      for (int x = minX; x <= maxX; x++) {
        final double dx = (x - centerX).toDouble();
        final double dy = (y - centerY).toDouble();
        if ((dx * dx) + (dy * dy) > radiusSquared) continue;
        final int index = ((y * width) + x) * 4;
        rgba[index] = 255;
        rgba[index + 1] = 255;
        rgba[index + 2] = 255;
        rgba[index + 3] = 255;
      }
    }
  }

