  Future<void> _runMarqueeAction(Future<void> Function() action) async {
    if (_isMarqueeActionInProgress) return;
    setState(() {
      _isMarqueeActionInProgress = true;
    });
    try {
      await action();
    } finally {
      if (mounted) {
        setState(() {
          _isMarqueeActionInProgress = false;
        });
      }
    }
  }

  Future<void> _copyMarqueeSelection() async {
    final EditorLayer? layer = _selectedMarqueeLayer();
    final MarqueeSelection? selection = _marqueeSelection;
    if (layer == null || selection == null || selection.layerId != layer.id) {
      return;
    }
    final Uint8List? sourcePixels = await _readImagePixels(layer.image!);
    if (sourcePixels == null) return;
    final _SelectionRaster? raster = _rasterizeSelection(
      sourcePixels: sourcePixels,
      imageWidth: layer.image!.width,
      imageHeight: layer.image!.height,
      selection: selection,
    );
    if (raster == null || !raster.hasVisiblePixels) return;
    if (!mounted) return;
    setState(() {
      _marqueeClipboard = _MarqueeClipboard(
        pixels: raster.pixels,
        width: raster.width,
        height: raster.height,
        sourceBoundsUv: selection.boundsUv,
      );
    });
  }

  Future<void> _cutMarqueeSelection() async {
    final EditorLayer? layer = _selectedMarqueeLayer();
    final MarqueeSelection? selection = _marqueeSelection;
    if (layer == null || selection == null || selection.layerId != layer.id) {
      return;
    }
    final Uint8List? sourcePixels = await _readImagePixels(layer.image!);
    if (sourcePixels == null) return;
    final _SelectionRaster? raster = _rasterizeSelection(
      sourcePixels: sourcePixels,
      imageWidth: layer.image!.width,
      imageHeight: layer.image!.height,
      selection: selection,
    );
    if (raster == null || !raster.hasVisiblePixels) return;

    final Uint8List nextPixels = Uint8List.fromList(sourcePixels);
    _eraseSelectionFromPixels(
      pixels: nextPixels,
      imageWidth: layer.image!.width,
      imageHeight: layer.image!.height,
      selection: selection,
      bounds: raster.bounds,
    );
    final ui.Image nextImage = await _buildUiImageFromRgba(
      pixels: nextPixels,
      width: layer.image!.width,
      height: layer.image!.height,
    );
    if (!mounted) return;

    _pushUndoSnapshot();
    setState(() {
      _replaceLayerImage(layer.id, nextImage);
      _marqueeClipboard = _MarqueeClipboard(
        pixels: raster.pixels,
        width: raster.width,
        height: raster.height,
        sourceBoundsUv: selection.boundsUv,
      );
    });
  }

  Future<void> _deleteMarqueeSelection() async {
    final EditorLayer? layer = _selectedMarqueeLayer();
    final MarqueeSelection? selection = _marqueeSelection;
    if (layer == null || selection == null || selection.layerId != layer.id) {
      return;
    }
    final Uint8List? sourcePixels = await _readImagePixels(layer.image!);
    if (sourcePixels == null) return;
    final _SelectionPixelBounds? bounds = _selectionPixelBounds(
      selection: selection,
      imageWidth: layer.image!.width,
      imageHeight: layer.image!.height,
    );
    if (bounds == null) return;

    final Uint8List nextPixels = Uint8List.fromList(sourcePixels);
    _eraseSelectionFromPixels(
      pixels: nextPixels,
      imageWidth: layer.image!.width,
      imageHeight: layer.image!.height,
      selection: selection,
      bounds: bounds,
    );
    final ui.Image nextImage = await _buildUiImageFromRgba(
      pixels: nextPixels,
      width: layer.image!.width,
      height: layer.image!.height,
    );
    if (!mounted) return;

    _pushUndoSnapshot();
    setState(() {
      _replaceLayerImage(layer.id, nextImage);
    });
  }

  Future<void> _createLayerFromMarqueeSelection() async {
    final EditorLayer? layer = _selectedMarqueeLayer();
    final MarqueeSelection? selection = _marqueeSelection;
    if (layer == null || selection == null || selection.layerId != layer.id) {
      return;
    }
    final EditorLayer? workspaceLayer = _workspaceLayerForEdit(_layers);
    final Size? workspaceSize =
        workspaceLayer == null ? null : _workspaceSourceSize(workspaceLayer);
    if (workspaceSize == null) return;
    final Uint8List? sourcePixels = await _readImagePixels(layer.image!);
    if (sourcePixels == null) return;
    final _SelectionRaster? raster = _rasterizeSelection(
      sourcePixels: sourcePixels,
      imageWidth: layer.image!.width,
      imageHeight: layer.image!.height,
      selection: selection,
    );
    if (raster == null || !raster.hasVisiblePixels) return;

    final ui.Image extractedImage = await _buildUiImageFromRgba(
      pixels: raster.pixels,
      width: raster.width,
      height: raster.height,
    );
    if (!mounted) return;

    final Offset selectionCenter = Offset(
      selection.boundsUv.center.dx * workspaceSize.width,
      selection.boundsUv.center.dy * workspaceSize.height,
    );

    _pushUndoSnapshot();
    setState(() {
      final int overlayImageCount = _layers
          .where((entry) =>
              entry.type == EditorLayerType.image && !entry.isBackground)
          .length;
      final String newId = 'layer_${_nextLayerId++}';
      final EditorLayer extractedLayer = EditorLayer(
        id: newId,
        name: overlayImageCount == 0
            ? 'Selection Layer'
            : 'Selection Layer ${overlayImageCount + 1}',
        type: EditorLayerType.image,
        isVisible: true,
        image: extractedImage,
        solidSize: _imageSourceSize(extractedImage),
        position: selectionCenter,
        layerScale: 1.0,
        layerRotation: 0.0,
      );
      _layers = <EditorLayer>[..._layers, extractedLayer];
      _selectedLayerId = newId;
      _activeTool = EditorTool.move;
      _isToolEnabled = true;
      _marqueeSelection = null;
    });
  }

  Future<void> _pasteMarqueeClipboard() async {
    final EditorLayer? layer = _selectedMarqueeLayer();
    final _MarqueeClipboard? clipboard = _marqueeClipboard;
    if (layer == null || clipboard == null) return;
    final EditorLayer? workspaceLayer = _workspaceLayerForEdit(_layers);
    final Size? workspaceSize =
        workspaceLayer == null ? null : _workspaceSourceSize(workspaceLayer);
    if (workspaceSize == null) return;
    final Rect targetBoundsUv = (_marqueeSelection != null &&
            _marqueeSelection!.layerId == layer.id &&
            _marqueeSelection!.hasUsableArea)
        ? _marqueeSelection!.boundsUv
        : clipboard.sourceBoundsUv;
    final MarqueeSelection targetSelection = MarqueeSelection(
      layerId: layer.id,
      mode: MarqueeSelectionMode.rectangular,
      boundsUv: targetBoundsUv,
    );
    final _SelectionPixelBounds? targetBounds = _selectionPixelBounds(
      selection: targetSelection,
      imageWidth: layer.image!.width,
      imageHeight: layer.image!.height,
    );
    if (targetBounds == null) return;

    final Uint8List pastedPixels =
        Uint8List(targetBounds.width * targetBounds.height * 4);
    for (int y = 0; y < targetBounds.height; y++) {
      final int srcY = ((y * clipboard.height) / targetBounds.height)
          .floor()
          .clamp(0, clipboard.height - 1);
      for (int x = 0; x < targetBounds.width; x++) {
        final int srcX = ((x * clipboard.width) / targetBounds.width)
            .floor()
            .clamp(0, clipboard.width - 1);
        final int sourceIndex = ((srcY * clipboard.width) + srcX) * 4;
        final int destIndex = ((y * targetBounds.width) + x) * 4;
        pastedPixels[destIndex] = clipboard.pixels[sourceIndex];
        pastedPixels[destIndex + 1] = clipboard.pixels[sourceIndex + 1];
        pastedPixels[destIndex + 2] = clipboard.pixels[sourceIndex + 2];
        pastedPixels[destIndex + 3] = clipboard.pixels[sourceIndex + 3];
      }
    }
    final ui.Image pastedImage = await _buildUiImageFromRgba(
      pixels: pastedPixels,
      width: targetBounds.width,
      height: targetBounds.height,
    );
    if (!mounted) return;
    final Offset pasteCenter = Offset(
      targetBoundsUv.center.dx * workspaceSize.width,
      targetBoundsUv.center.dy * workspaceSize.height,
    );

    _pushUndoSnapshot();
    setState(() {
      final int overlayImageCount = _layers
          .where((entry) =>
              entry.type == EditorLayerType.image && !entry.isBackground)
          .length;
      final String newId = 'layer_${_nextLayerId++}';
      final EditorLayer pastedLayer = EditorLayer(
        id: newId,
        name: overlayImageCount == 0
            ? 'Pasted Layer'
            : 'Pasted Layer ${overlayImageCount + 1}',
        type: EditorLayerType.image,
        isVisible: true,
        image: pastedImage,
        solidSize: _imageSourceSize(pastedImage),
        position: pasteCenter,
        layerScale: 1.0,
        layerRotation: 0.0,
      );
      _layers = <EditorLayer>[..._layers, pastedLayer];
      _selectedLayerId = newId;
      _activeTool = EditorTool.move;
      _isToolEnabled = true;
      _marqueeSelection = null;
    });
  }

  Future<void> _cropToMarqueeSelection() async {
    final EditorLayer? layer = _selectedMarqueeLayer();
    final MarqueeSelection? selection = _marqueeSelection;
    if (layer == null || selection == null || selection.layerId != layer.id) {
      return;
    }
    final Uint8List? sourcePixels = await _readImagePixels(layer.image!);
    if (sourcePixels == null) return;
    final _SelectionRaster? raster = _rasterizeSelection(
      sourcePixels: sourcePixels,
      imageWidth: layer.image!.width,
      imageHeight: layer.image!.height,
      selection: selection,
    );
    if (raster == null || !raster.hasVisiblePixels) return;

    final ui.Image croppedImage = await _buildUiImageFromRgba(
      pixels: raster.pixels,
      width: raster.width,
      height: raster.height,
    );
    if (!mounted) return;

    _pushUndoSnapshot();
    setState(() {
      _replaceLayerImage(layer.id, croppedImage);
      _marqueeSelection = null;
    });
  }

  Future<Uint8List?> _readImagePixels(ui.Image image) async {
    final ByteData? data =
        await image.toByteData(format: ui.ImageByteFormat.rawRgba);
    if (data == null) return null;
    return Uint8List.fromList(data.buffer.asUint8List(0, data.lengthInBytes));
  }

  Future<ui.Image> _buildUiImageFromRgba({
    required Uint8List pixels,
    required int width,
    required int height,
  }) {
    final Completer<ui.Image> completer = Completer<ui.Image>();
    ui.decodeImageFromPixels(
      pixels,
      width,
      height,
      ui.PixelFormat.rgba8888,
      (ui.Image image) => completer.complete(image),
    );
    return completer.future;
  }

  _SelectionRaster? _rasterizeSelection({
    required Uint8List sourcePixels,
    required int imageWidth,
    required int imageHeight,
    required MarqueeSelection selection,
  }) {
    final _SelectionPixelBounds? bounds = _selectionPixelBounds(
      selection: selection,
      imageWidth: imageWidth,
      imageHeight: imageHeight,
    );
    if (bounds == null) return null;

    final Uint8List outPixels = Uint8List(bounds.width * bounds.height * 4);
    bool hasVisiblePixels = false;
    for (int y = bounds.top; y < bounds.bottom; y++) {
      for (int x = bounds.left; x < bounds.right; x++) {
        final Offset uv = Offset(
          (x + 0.5) / imageWidth,
          (y + 0.5) / imageHeight,
        );
        if (!_selectionContainsUv(selection, uv)) continue;
        final int sourceIndex = ((y * imageWidth) + x) * 4;
        final int destIndex =
            (((y - bounds.top) * bounds.width) + (x - bounds.left)) * 4;
        outPixels[destIndex] = sourcePixels[sourceIndex];
        outPixels[destIndex + 1] = sourcePixels[sourceIndex + 1];
        outPixels[destIndex + 2] = sourcePixels[sourceIndex + 2];
        outPixels[destIndex + 3] = sourcePixels[sourceIndex + 3];
        if (outPixels[destIndex + 3] > 0) {
          hasVisiblePixels = true;
        }
      }
    }
    return _SelectionRaster(
      pixels: outPixels,
      width: bounds.width,
      height: bounds.height,
      bounds: bounds,
      hasVisiblePixels: hasVisiblePixels,
    );
  }

  _SelectionPixelBounds? _selectionPixelBounds({
    required MarqueeSelection selection,
    required int imageWidth,
    required int imageHeight,
  }) {
    final int left =
        (selection.boundsUv.left * imageWidth).floor().clamp(0, imageWidth - 1);
    final int top = (selection.boundsUv.top * imageHeight)
        .floor()
        .clamp(0, imageHeight - 1);
    final int right =
        (selection.boundsUv.right * imageWidth).ceil().clamp(1, imageWidth);
    final int bottom =
        (selection.boundsUv.bottom * imageHeight).ceil().clamp(1, imageHeight);
    if (right <= left || bottom <= top) return null;
    return _SelectionPixelBounds(
      left: left,
      top: top,
      right: right,
      bottom: bottom,
    );
  }

  bool _selectionContainsUv(MarqueeSelection selection, Offset uv) {
    switch (selection.mode) {
      case MarqueeSelectionMode.rectangular:
        return selection.boundsUv.contains(uv);
      case MarqueeSelectionMode.object:
        final Rect bounds = selection.boundsUv;
        if (bounds.width <= 0 || bounds.height <= 0) return false;
        return _pointInPolygon(
          uv,
          <Offset>[
            Offset(bounds.center.dx, bounds.top),
            bounds.bottomRight,
            bounds.bottomLeft,
          ],
        );
      case MarqueeSelectionMode.elliptical:
        final Rect bounds = selection.boundsUv;
        if (bounds.width <= 0 || bounds.height <= 0) return false;
        final double dx = (uv.dx - bounds.center.dx) / (bounds.width / 2);
        final double dy = (uv.dy - bounds.center.dy) / (bounds.height / 2);
        return (dx * dx) + (dy * dy) <= 1;
      case MarqueeSelectionMode.freehand:
        if (selection.freePathUv.length < 3) return false;
        return _pointInPolygon(uv, selection.freePathUv);
    }
  }

  bool _pointInPolygon(Offset point, List<Offset> polygon) {
    bool inside = false;
    for (int i = 0, j = polygon.length - 1; i < polygon.length; j = i++) {
      final Offset a = polygon[i];
      final Offset b = polygon[j];
      final bool intersect = ((a.dy > point.dy) != (b.dy > point.dy)) &&
          (point.dx <
              ((b.dx - a.dx) * (point.dy - a.dy) / (b.dy - a.dy + 0.0000001)) +
                  a.dx);
      if (intersect) inside = !inside;
    }
    return inside;
  }

  void _eraseSelectionFromPixels({
    required Uint8List pixels,
    required int imageWidth,
    required int imageHeight,
    required MarqueeSelection selection,
    required _SelectionPixelBounds bounds,
  }) {
    for (int y = bounds.top; y < bounds.bottom; y++) {
      for (int x = bounds.left; x < bounds.right; x++) {
        final Offset uv = Offset(
          (x + 0.5) / imageWidth,
          (y + 0.5) / imageHeight,
        );
        if (!_selectionContainsUv(selection, uv)) continue;
        final int index = ((y * imageWidth) + x) * 4;
        pixels[index] = 0;
        pixels[index + 1] = 0;
        pixels[index + 2] = 0;
        pixels[index + 3] = 0;
      }
    }
  }

  void _replaceLayerImage(
    String layerId,
    ui.Image image,
  ) {
    final int layerIndex = _layers.indexWhere((entry) => entry.id == layerId);
    if (layerIndex < 0) return;
    final List<EditorLayer> nextLayers = List<EditorLayer>.from(_layers);
    final EditorLayer current = nextLayers[layerIndex];
    nextLayers[layerIndex] = current.copyWith(
      isBackground: current.isBackground,
      image: image,
      solidSize: _imageSourceSize(image),
      thumbnailBytes: null,
    );
    _layers = nextLayers;
  }

  void _armCloneSourceSelection({
    bool closeSidebar = true,
    bool closeCloneSheet = false,
  }) {
    _cloneBrushPreviewTimer?.cancel();
    setState(() {
      _isCloneSourceArmed = true;
      _isCloneBrushSelected = false;
      _isCloneEraseSelected = false;
      _isCloneBrushPreviewVisible = false;
      _isCloneSettingsFloatingOpen = false;
      if (closeCloneSheet) {
        _isCloneSettingsBottomSheetOpen = false;
      }
    });
    if (closeSidebar) {
      _closeToolSettingsSidebarIfOpen();
    }
    if (closeCloneSheet) {
      Navigator.of(context).maybePop();
    }
  }

  void _selectCloneBrushMode() {
    setState(() {
      _isCloneSourceArmed = false;
      _isCloneBrushSelected = true;
      _isCloneEraseSelected = false;
      _isCloneBrushPreviewVisible = false;
    });
  }

  void _selectCloneEraseMode() {
    setState(() {
      _isCloneSourceArmed = false;
      _isCloneBrushSelected = false;
      _isCloneEraseSelected = true;
      _isCloneBrushPreviewVisible = false;
    });
  }

  void _requestCloneClear() {
    setState(() {
      _cloneClearRequestToken++;
      _isCloneSourceArmed = false;
      if (!_isCloneBrushSelected && !_isCloneEraseSelected) {
        _isCloneBrushSelected = true;
      }
      _isCloneBrushPreviewVisible = false;
    });
  }

  void _onCloneSourcePicked() {
    if (!_isCloneSourceArmed) return;
    setState(() {
      _isCloneSourceArmed = false;
      _isCloneBrushSelected = true;
      _isCloneEraseSelected = false;
      _isCloneBrushPreviewVisible = false;
      _isCloneSettingsFloatingOpen = false;
      _isCloneSettingsBottomSheetOpen = false;
    });
  }

  Future<void> _openExportBottomSheet() async {
    if (_isExporting) return;
    final EditorLayer? workspace = _workspaceLayerForEdit(_layers);
    final Size? workspaceSize =
        workspace == null ? null : _workspaceSourceSize(workspace);
    if (workspaceSize == null) {
      _showExportMessage(
        'Add a background image or solid layer first.',
        isError: true,
      );
      return;
    }

    if (!mounted) return;
    await Navigator.of(context).push(
      MaterialPageRoute<void>(
        builder: (context) {
          return _ExportRenderScreen(
            workspaceSize: workspaceSize,
            buildPreview: () => _buildExportPreviewPng(workspaceSize),
            runExport: (
              _ExportSettings settings,
              _ExportProgressReporter onProgress,
            ) {
              return _exportComposition(
                settings,
                onProgress: onProgress,
              );
            },
          );
        },
      ),
    );
  }

  Future<Uint8List> _buildExportPreviewPng(Size workspaceSize) async {
    ui.Image? preview;
    try {
      final Size previewSize = _resolveExportPreviewPixelSize(workspaceSize);
      preview = await _renderCompositionAtResolution(
        workspaceSize: workspaceSize,
        outputWidth: math.max(1, previewSize.width.round()),
        outputHeight: math.max(1, previewSize.height.round()),
        flattenForJpeg: false,
      );
      final ByteData? data = await preview.toByteData(
        format: ui.ImageByteFormat.png,
      );
      if (data == null) {
        throw StateError('Preview render failed.');
      }
      return data.buffer.asUint8List();
    } finally {
      preview?.dispose();
    }
  }

  Size _resolveExportPreviewPixelSize(Size workspaceSize) {
    final int baseWidth = math.max(1, workspaceSize.width.round());
    final int baseHeight = math.max(1, workspaceSize.height.round());
    const int previewMaxLongEdge = 1280;
    final int longEdge = math.max(baseWidth, baseHeight);
    if (longEdge <= previewMaxLongEdge) {
      return Size(baseWidth.toDouble(), baseHeight.toDouble());
    }
    final double scale = previewMaxLongEdge / longEdge;
    return Size(
      math.max(1, (baseWidth * scale).round()).toDouble(),
      math.max(1, (baseHeight * scale).round()).toDouble(),
    );
  }

  Future<bool> _exportComposition(
    _ExportSettings settings, {
    _ExportProgressReporter? onProgress,
  }) async {
    final EditorLayer? workspace = _workspaceLayerForEdit(_layers);
    final Size? workspaceSize =
        workspace == null ? null : _workspaceSourceSize(workspace);
    if (workspaceSize == null) {
      _showExportMessage(
        'Add a background image or solid layer first.',
        isError: true,
      );
      return false;
    }

    setState(() {
      _isExporting = true;
    });

    ui.Image? rendered;
    Timer? renderPulse;
    try {
      onProgress?.call('Preparing export...', 0.0);
      await Future<void>.delayed(const Duration(milliseconds: 1));
      final Size outputSize = _resolveExportPixelSize(
        workspaceSize,
        settings.quality,
        settings.format,
      );
      onProgress?.call('Preparing layers...', 0.02);
      await Future<void>.delayed(const Duration(milliseconds: 1));

      Uint8List? encoded = await _tryFastPathWorkspaceImageExport(
        settings: settings,
        workspaceLayer: workspace!,
        workspaceSize: workspaceSize,
        outputSize: outputSize,
        onProgress: onProgress,
      );
      if (encoded == null) {
        onProgress?.call('Rendering layers...', 0.08);
        renderPulse = _startProgressPulse(
          onProgress,
          label: 'Rendering layers...',
          from: 0.08,
          to: 0.32,
          step: 0.0025,
        );
        rendered = await _renderCompositionImage(
          workspaceSize: workspaceSize,
          outputSize: outputSize,
          flattenForJpeg: settings.format == _ExportFormat.jpg,
          quality: settings.quality,
          format: settings.format,
          preferSpeed: true,
        );
        renderPulse?.cancel();
        renderPulse = null;
        onProgress?.call('Encoding image...', 0.42);
        await Future<void>.delayed(const Duration(milliseconds: 1));
        encoded = await _encodeRenderedImage(
          image: rendered,
          format: settings.format,
          quality: settings.quality,
        );
      }

      final String fileName = _buildExportFileName(settings.format);
      onProgress?.call('Saving to gallery...', 0.68);
      final dynamic saveResult = await _saveImageToGallery(
        bytes: encoded,
        quality: settings.quality.jpegQualityForFormat(settings.format),
        name: fileName,
      );
      if (!_isGallerySaveSuccess(saveResult)) {
        throw StateError('Gallery save failed.');
      }

      onProgress?.call('Export complete', 1.0);
      _showExportMessage('Saved to gallery as $fileName');
      return true;
    } catch (_) {
      renderPulse?.cancel();
      onProgress?.call('Export failed', 1.0);
      _showExportMessage('Export failed. Please try again.', isError: true);
      return false;
    } finally {
      renderPulse?.cancel();
      rendered?.dispose();
      if (mounted) {
        setState(() {
          _isExporting = false;
        });
      }
    }
  }

  Future<dynamic> _saveImageToGallery({
    required Uint8List bytes,
    required int quality,
    required String name,
  }) {
    // iOS must save through add-only flow to avoid the plugin path-read branch
    // that can hang waiting for fullSizeImageURL.
    final Future<dynamic> saveFuture = Future<dynamic>.value(
      ImageGallerySaverPlus.saveImage(
        bytes,
        quality: quality,
        name: name,
        isReturnImagePathOfIOS: false,
      ),
    );
    return saveFuture.timeout(
      const Duration(seconds: 25),
      onTimeout: () => <String, dynamic>{
        'isSuccess': false,
        'errorMessage': 'Save timeout',
      },
    );
  }

  bool _isGallerySaveSuccess(dynamic result) {
    if (result is bool) return result;
    if (result is num) return result != 0;
    if (result is Map) {
      final dynamic isSuccess = result['isSuccess'] ?? result['success'];
      if (isSuccess is bool) return isSuccess;
      if (isSuccess is num) return isSuccess != 0;
      if (isSuccess is String) {
        final String normalized = isSuccess.toLowerCase().trim();
        if (normalized == 'true' || normalized == '1') return true;
      }
      final dynamic filePath = result['filePath'] ?? result['path'];
      if (filePath is String && filePath.isNotEmpty) return true;
    }
    return result != null;
  }

  Size _resolveExportPixelSize(
    Size workspaceSize,
    _ExportQualityPreset quality,
    _ExportFormat format,
  ) {
    final int baseWidth = math.max(1, workspaceSize.width.round());
    final int baseHeight = math.max(1, workspaceSize.height.round());
    final int? maxLongEdge = quality.maxLongEdgeForFormat(format);
    if (maxLongEdge == null) {
      return Size(baseWidth.toDouble(), baseHeight.toDouble());
    }

    final double longEdge =
        math.max(baseWidth.toDouble(), baseHeight.toDouble());
    if (longEdge <= maxLongEdge) {
      return Size(baseWidth.toDouble(), baseHeight.toDouble());
    }

    final double scaleFactor = maxLongEdge / longEdge;
    return Size(
      math.max(1, (baseWidth * scaleFactor).round()).toDouble(),
      math.max(1, (baseHeight * scaleFactor).round()).toDouble(),
    );
  }

  Timer? _startProgressPulse(
    _ExportProgressReporter? onProgress, {
    required String label,
    required double from,
    required double to,
    required double step,
  }) {
    if (onProgress == null || to <= from || step <= 0) return null;
    double current = from;
    return Timer.periodic(const Duration(milliseconds: 110), (timer) {
      current = (current + step).clamp(from, to);
      onProgress(label, current);
      if (current >= to - 0.0001) {
        timer.cancel();
      }
    });
  }

  bool _hasVisibleForegroundLayersForExport() {
    for (final EditorLayer layer in _layers) {
      if (!layer.isVisible || layer.isBackground) continue;
      return true;
    }
    return false;
  }

  bool _layerHasImageAdjustmentsForExport(EditorLayer layer) {
    if (layer.type != EditorLayerType.image) return false;
    final List<double> adjustments = <double>[
      layer.imageAdjustBrightness ?? 0,
      layer.imageAdjustExposure ?? 0,
      layer.imageAdjustContrast ?? 0,
      layer.imageAdjustSaturation ?? 0,
      layer.imageAdjustWarmth ?? 0,
      layer.imageAdjustShadows ?? 0,
      layer.imageAdjustWhites ?? 0,
      layer.imageAdjustBlacks ?? 0,
    ];
    for (final double value in adjustments) {
      if (value.abs() > 0.001) return true;
    }
    return false;
  }

  bool _layerHasImageEffectsForExport(EditorLayer layer) {
    if (layer.type != EditorLayerType.image) return false;
    if (_layerHasImageAdjustmentsForExport(layer)) return true;
    if ((layer.imageShadowOpacity ?? 0).abs() > 0.001) return true;
    if ((layer.imageShadowBlur ?? 0).abs() > 0.001) return true;
    if ((layer.imageShadowOffsetX ?? 0).abs() > 0.001) return true;
    if ((layer.imageShadowOffsetY ?? 0).abs() > 0.001) return true;
    final String shapeKey = (layer.overlayShapeTypeKey ?? '').trim();
    if (shapeKey.isNotEmpty && shapeKey.toLowerCase() != 'none') return true;
    return false;
  }

  bool _isWorkspaceLayerIdentityForExport(
    EditorLayer layer,
    Size workspaceSize,
  ) {
    final Offset center = Offset(
      workspaceSize.width / 2,
      workspaceSize.height / 2,
    );
    final Offset position = layer.position ?? center;
    final bool atCenter = (position - center).distanceSquared <= 0.16;
    final bool defaultScale = (layer.layerScale - 1).abs() <= 0.0001;
    final bool defaultRotation = layer.layerRotation.abs() <= 0.0001;
    return atCenter && defaultScale && defaultRotation;
  }

  Future<Uint8List?> _tryFastPathWorkspaceImageExport({
    required _ExportSettings settings,
    required EditorLayer workspaceLayer,
    required Size workspaceSize,
    required Size outputSize,
    _ExportProgressReporter? onProgress,
  }) async {
    if (workspaceLayer.type != EditorLayerType.image ||
        workspaceLayer.image == null ||
        !workspaceLayer.isVisible) {
      return null;
    }
    if (_pencilStrokes.isNotEmpty || _hasVisibleForegroundLayersForExport()) {
      return null;
    }
    if (_layerHasImageEffectsForExport(workspaceLayer)) {
      return null;
    }
    if (!_isWorkspaceLayerIdentityForExport(workspaceLayer, workspaceSize)) {
      return null;
    }

    final ui.Image sourceImage = workspaceLayer.image!;
    final int targetWidth = math.max(1, outputSize.width.round());
    final int targetHeight = math.max(1, outputSize.height.round());

    ui.Image? resizedImage;
    ui.Image exportImage = sourceImage;
    try {
      onProgress?.call('Preparing source layer...', 0.03);
      if (sourceImage.width != targetWidth ||
          sourceImage.height != targetHeight) {
        onProgress?.call('Resizing image...', 0.12);
        resizedImage = await _downscaleRenderedImageForExport(
          image: sourceImage,
          targetWidth: targetWidth,
          targetHeight: targetHeight,
          applySharpen: settings.quality != _ExportQualityPreset.low,
        );
        exportImage = resizedImage;
      }
      onProgress?.call('Encoding image...', 0.32);
      return _encodeRenderedImage(
        image: exportImage,
        format: settings.format,
        quality: settings.quality,
      );
    } finally {
      resizedImage?.dispose();
    }
  }

  Future<ui.Image> _renderCompositionImage({
    required Size workspaceSize,
    required Size outputSize,
    required bool flattenForJpeg,
    required _ExportQualityPreset quality,
    required _ExportFormat format,
    bool preferSpeed = false,
  }) async {
    final int outputWidth = math.max(1, outputSize.width.round());
    final int outputHeight = math.max(1, outputSize.height.round());
    final bool needsFineEdges = _exportSceneNeedsFineEdgeSupersampling();
    final double supersampleFactor = _resolveExportSupersampleFactor(
      quality: quality,
      format: format,
      outputWidth: outputWidth,
      outputHeight: outputHeight,
      needsFineEdges: needsFineEdges,
      preferSpeed: preferSpeed,
    );
    final int supersampleWidth =
        math.max(outputWidth, (outputWidth * supersampleFactor).round());
    final int supersampleHeight =
        math.max(outputHeight, (outputHeight * supersampleFactor).round());

    if (supersampleWidth == outputWidth && supersampleHeight == outputHeight) {
      return _renderCompositionAtResolution(
        workspaceSize: workspaceSize,
        outputWidth: outputWidth,
        outputHeight: outputHeight,
        flattenForJpeg: flattenForJpeg,
      );
    }

    final ui.Image supersampled = await _renderCompositionAtResolution(
      workspaceSize: workspaceSize,
      outputWidth: supersampleWidth,
      outputHeight: supersampleHeight,
      flattenForJpeg: flattenForJpeg,
    );
    try {
      return _downscaleRenderedImageForExport(
        image: supersampled,
        targetWidth: outputWidth,
        targetHeight: outputHeight,
        applySharpen: false,
      );
    } finally {
      supersampled.dispose();
    }
  }

  double _resolveExportSupersampleFactor({
    required _ExportQualityPreset quality,
    required _ExportFormat format,
    required int outputWidth,
    required int outputHeight,
    required bool needsFineEdges,
    required bool preferSpeed,
  }) {
    if (!needsFineEdges) return 1.0;
    final double longEdge =
        math.max(outputWidth.toDouble(), outputHeight.toDouble());
    if (longEdge >= 3840) return 1.0;
    final double desired = switch (quality) {
      _ExportQualityPreset.low => 1.0,
      _ExportQualityPreset.medium => 1.0,
      _ExportQualityPreset.high => preferSpeed ? 1.06 : 1.12,
      _ExportQualityPreset.ultra => preferSpeed ? 1.12 : 1.18,
    };
    if (desired <= 1.01) return 1.0;
    final double maxLongEdge = switch (quality) {
      _ExportQualityPreset.low => 0,
      _ExportQualityPreset.medium => 0,
      _ExportQualityPreset.high => preferSpeed ? 2600.0 : 3200.0,
      _ExportQualityPreset.ultra => preferSpeed ? 3200.0 : 3800.0,
    };
    final double edgeLimit = (maxLongEdge / longEdge).clamp(1.0, desired);

    final double targetPixels = switch (quality) {
      _ExportQualityPreset.low => 0,
      _ExportQualityPreset.medium => 0,
      _ExportQualityPreset.high => preferSpeed ? 9000000.0 : 12000000.0,
      _ExportQualityPreset.ultra => preferSpeed ? 12000000.0 : 16000000.0,
    };
    if (targetPixels <= 0 || maxLongEdge <= 0) return 1.0;
    final double pixelLimit = math
        .sqrt(targetPixels / (outputWidth.toDouble() * outputHeight.toDouble()))
        .clamp(1.0, desired);
    final double formatCap =
        format == _ExportFormat.png ? desired : math.min(desired, 1.12);
    return math.min(formatCap, math.min(edgeLimit, pixelLimit));
  }

  bool _exportSceneNeedsFineEdgeSupersampling() {
    if (_pencilStrokes.isNotEmpty) return true;
    for (final EditorLayer layer in _layers) {
      if (!layer.isVisible || layer.isBackground) continue;
      if (layer.type == EditorLayerType.text) return true;
      if (layer.type == EditorLayerType.image) {
        final String? shapeKey = layer.overlayShapeTypeKey;
        if (shapeKey != null && shapeKey.trim().isNotEmpty) {
          if (shapeKey.toLowerCase() != 'none') return true;
        }
      }
    }
    return false;
  }

  Future<ui.Image> _renderCompositionAtResolution({
    required Size workspaceSize,
    required int outputWidth,
    required int outputHeight,
    required bool flattenForJpeg,
  }) async {
    final ui.PictureRecorder recorder = ui.PictureRecorder();
    final Rect outputRect = Rect.fromLTWH(
      0,
      0,
      outputWidth.toDouble(),
      outputHeight.toDouble(),
    );
    final Canvas canvas = Canvas(recorder, outputRect);
    if (flattenForJpeg) {
      canvas.drawRect(
        outputRect,
        Paint()
          ..style = PaintingStyle.fill
          ..color = Colors.white,
      );
    }

    final Rect artboard = Rect.fromLTWH(
      0,
      0,
      workspaceSize.width,
      workspaceSize.height,
    );
    final double scaleX = outputWidth / workspaceSize.width;
    final double scaleY = outputHeight / workspaceSize.height;

    canvas.save();
    canvas.scale(scaleX, scaleY);
    _drawExportLayers(
      canvas: canvas,
      artboard: artboard,
      workspaceSize: workspaceSize,
    );
    _drawExportPencilStrokes(
      canvas: canvas,
      artboard: artboard,
      workspaceSize: workspaceSize,
    );
    canvas.restore();

    final ui.Picture picture = recorder.endRecording();
    return picture.toImage(outputWidth, outputHeight);
  }

  Future<ui.Image> _downscaleRenderedImageForExport({
    required ui.Image image,
    required int targetWidth,
    required int targetHeight,
    required bool applySharpen,
  }) async {
    if (image.width == targetWidth && image.height == targetHeight) {
      return image;
    }
    final ByteData? rawData = await image.toByteData(
      format: ui.ImageByteFormat.rawRgba,
    );
    if (rawData == null) {
      throw StateError('Export downscale failed.');
    }
    final Uint8List sourceRgba = Uint8List.fromList(
      rawData.buffer.asUint8List(0, rawData.lengthInBytes),
    );
    final int sourceWidth = image.width;
    final int sourceHeight = image.height;
    final Uint8List rgba = await Isolate.run<Uint8List>(
      () => _downscaleRgbaForExportIsolate(
        sourceRgba: sourceRgba,
        sourceWidth: sourceWidth,
        sourceHeight: sourceHeight,
        targetWidth: targetWidth,
        targetHeight: targetHeight,
        applySharpen: applySharpen,
      ),
    );
    return _decodeUiImageFromRgba(
      rgba,
      width: targetWidth,
      height: targetHeight,
    );
  }

  void _drawExportLayers({
    required Canvas canvas,
    required Rect artboard,
    required Size workspaceSize,
    Set<String>? includeLayerIds,
  }) {
    final EditorLayer? workspace = _workspaceLayerForEdit(_layers);
    final bool shouldDrawWorkspace = workspace != null &&
        workspace.isBackground &&
        (includeLayerIds == null
            ? workspace.isVisible
            : includeLayerIds.contains(workspace.id));
    if (shouldDrawWorkspace) {
      if (workspace.type == EditorLayerType.image && workspace.image != null) {
        final ui.Image workspaceImage = workspace.image!;
        canvas.drawImageRect(
          workspaceImage,
          Rect.fromLTWH(
            0,
            0,
            workspaceImage.width.toDouble(),
            workspaceImage.height.toDouble(),
          ),
          artboard,
          _buildImageLayerPaint(workspace),
        );
      } else if (workspace.type == EditorLayerType.solid) {
        canvas.drawRect(
          artboard,
          Paint()
            ..style = PaintingStyle.fill
            ..color = workspace.solidColor ?? Colors.white,
        );
      }
    }

    for (final EditorLayer layer in _layers) {
      if (layer.isBackground) continue;
      if (includeLayerIds != null) {
        if (!includeLayerIds.contains(layer.id)) continue;
      } else {
        if (!layer.isVisible) continue;
      }
      switch (layer.type) {
        case EditorLayerType.image:
          final ui.Image? image = layer.image;
          if (image == null) break;
          final _ImageLayerSceneData? data = _buildImageLayerSceneData(
            layer: layer,
            image: image,
            artboard: artboard,
            workspaceSize: workspaceSize,
            rotateHandleDistance: 0,
            moveHandleDistance: 0,
          );
          if (data == null) break;
          canvas.save();
          canvas.translate(data.center.dx, data.center.dy);
          canvas.rotate(data.rotation);
          _drawImageLayerShadow(
            canvas: canvas,
            image: image,
            sourceRect: Rect.fromLTWH(
              0,
              0,
              image.width.toDouble(),
              image.height.toDouble(),
            ),
            destinationRect: Rect.fromCenter(
              center: Offset.zero,
              width: data.width,
              height: data.height,
            ),
            color: data.shadowColor,
            offset: data.shadowOffset,
            blurSigma: data.shadowBlurSigma,
            overlayShapeType: data.overlayShapeType,
          );
          canvas.drawImageRect(
            image,
            Rect.fromLTWH(
              0,
              0,
              image.width.toDouble(),
              image.height.toDouble(),
            ),
            Rect.fromCenter(
              center: Offset.zero,
              width: data.width,
              height: data.height,
            ),
            _buildImageLayerPaint(layer),
          );
          canvas.restore();
          break;
        case EditorLayerType.text:
          final _TextLayerSceneData? data = _buildTextLayerSceneData(
            layer: layer,
            artboard: artboard,
            workspaceSize: workspaceSize,
            rotateHandleDistance: 0,
            moveHandleDistance: 0,
          );
          if (data == null) break;
          canvas.save();
          canvas.translate(data.center.dx, data.center.dy);
          canvas.rotate(data.rotation);
          final _BentTextLayout? bentFillLayout = data.bentFillLayout;
          final _BentTextLayout? bentStrokeLayout = data.bentStrokeLayout;
          final _BentTextLayout? bentShadowLayout = data.bentShadowLayout;
          final bool usesBentRendering =
              bentFillLayout != null && data.textBend.abs() >= 0.5;
          if (usesBentRendering) {
            if (bentShadowLayout != null) {
              _drawBentTextLayout(
                canvas,
                bentShadowLayout,
                extraOffset: data.shadowOffset,
                spread: data.shadowSpread,
              );
            }
            if (bentStrokeLayout != null) {
              _drawBentTextLayout(canvas, bentStrokeLayout);
            }
            _drawBentTextLayout(canvas, bentFillLayout);
          } else {
            final Offset textTopLeft =
                Offset(-data.width / 2, -data.height / 2);
            final TextPainter? shadowPainter = data.shadowPainter;
            if (shadowPainter != null) {
              final Offset shadowOrigin = textTopLeft + data.shadowOffset;
              shadowPainter.paint(canvas, shadowOrigin);
              final double spread = data.shadowSpread;
              if (spread > 0.01) {
                final int ringSteps = math.max(24, (spread * 14).round());
                for (int i = 0; i < ringSteps; i++) {
                  final double angle = (2 * math.pi * i) / ringSteps;
                  final Offset spreadOffset = Offset(
                    math.cos(angle) * spread,
                    math.sin(angle) * spread,
                  );
                  shadowPainter.paint(canvas, shadowOrigin + spreadOffset);
                }
              }
            }
            data.strokePainter?.paint(canvas, textTopLeft);
            data.fillPainter.paint(canvas, textTopLeft);
          }
          canvas.restore();
          break;
        case EditorLayerType.vector:
          break;
        case EditorLayerType.mask:
          break;
        case EditorLayerType.solid:
          canvas.drawRect(
            artboard,
            Paint()
              ..style = PaintingStyle.fill
              ..color = layer.solidColor ?? Colors.white,
          );
          break;
      }
    }
  }

  void _drawExportPencilStrokes({
    required Canvas canvas,
    required Rect artboard,
    required Size workspaceSize,
  }) {
    if (_pencilStrokes.isEmpty) return;
    final Rect referenceArtboard = _referenceArtboardForStrokes(workspaceSize);
    final double sourceWidth = referenceArtboard.width <= 0
        ? workspaceSize.width
        : referenceArtboard.width;
    final double sourceHeight = referenceArtboard.height <= 0
        ? workspaceSize.height
        : referenceArtboard.height;
    final double pointScaleX = artboard.width / sourceWidth;
    final double pointScaleY = artboard.height / sourceHeight;
    final double widthScale = (pointScaleX + pointScaleY) * 0.5;

    for (final _BrushStroke stroke in _pencilStrokes) {
      if (stroke.points.isEmpty) continue;
      final List<Offset> points = stroke.points.map((point) {
        final double dx = (artboard.left + (point.dx * pointScaleX))
            .clamp(artboard.left, artboard.right)
            .toDouble();
        final double dy = (artboard.top + (point.dy * pointScaleY))
            .clamp(artboard.top, artboard.bottom)
            .toDouble();
        return Offset(dx, dy);
      }).toList(growable: false);
      _paintExportStroke(
        canvas: canvas,
        points: points,
        stroke: stroke,
        scaledStrokeWidth: math.max(0.4, stroke.width * widthScale),
      );
    }
  }

  Rect _referenceArtboardForStrokes(Size workspaceSize) {
    final BuildContext? viewportContext = _canvasViewportKey.currentContext;
    if (viewportContext == null) {
      return Rect.fromLTWH(0, 0, workspaceSize.width, workspaceSize.height);
    }
    final RenderObject? renderObject = viewportContext.findRenderObject();
    if (renderObject is! RenderBox || !renderObject.hasSize) {
      return Rect.fromLTWH(0, 0, workspaceSize.width, workspaceSize.height);
    }
    return _computeArtboardRect(
      canvasSize: renderObject.size,
      workspaceSize: workspaceSize,
    );
  }

  void _paintExportStroke({
    required Canvas canvas,
    required List<Offset> points,
    required _BrushStroke stroke,
    required double scaledStrokeWidth,
  }) {
    if (points.isEmpty) return;
    final Paint paint = Paint()
      ..color = stroke.color
      ..strokeWidth = scaledStrokeWidth
      ..style = PaintingStyle.stroke
      ..isAntiAlias = true;

    switch (stroke.brushType) {
      case PencilBrushType.round:
        paint
          ..strokeCap = StrokeCap.round
          ..strokeJoin = StrokeJoin.round;
        break;
      case PencilBrushType.soft:
        paint
          ..strokeCap = StrokeCap.round
          ..strokeJoin = StrokeJoin.round
          ..maskFilter = MaskFilter.blur(
            BlurStyle.normal,
            (100 - stroke.hardness).clamp(0, 100) / 20,
          );
        break;
      case PencilBrushType.marker:
        paint
          ..strokeCap = StrokeCap.square
          ..strokeJoin = StrokeJoin.miter;
        break;
      case PencilBrushType.calligraphy:
        paint
          ..strokeCap = StrokeCap.square
          ..strokeJoin = StrokeJoin.round;
        break;
    }

    if (points.length == 1) {
      canvas.drawCircle(points.first, scaledStrokeWidth / 2, paint);
      return;
    }

    final Path path = Path();
    path.moveTo(points.first.dx, points.first.dy);
    for (int i = 1; i < points.length; i++) {
      final Offset prev = points[i - 1];
      final Offset curr = points[i];
      final Offset mid =
          Offset((prev.dx + curr.dx) / 2, (prev.dy + curr.dy) / 2);
      path.quadraticBezierTo(prev.dx, prev.dy, mid.dx, mid.dy);
    }
    canvas.drawPath(path, paint);

    if (stroke.brushType == PencilBrushType.calligraphy) {
      final double rad = stroke.angle * (math.pi / 180);
      final Offset offset = Offset(
        math.cos(rad) * (scaledStrokeWidth * 0.18),
        math.sin(rad) * (scaledStrokeWidth * 0.18),
      );
      canvas.save();
      canvas.translate(offset.dx, offset.dy);
      final Paint secondPass = Paint()
        ..color = stroke.color.withOpacity(stroke.color.opacity * 0.65)
        ..strokeWidth = scaledStrokeWidth * 0.72
        ..style = PaintingStyle.stroke
        ..strokeCap = StrokeCap.round
        ..strokeJoin = StrokeJoin.round
        ..isAntiAlias = true;
      canvas.drawPath(path, secondPass);
      canvas.restore();
    }
  }

  Future<Uint8List> _encodeRenderedImage({
    required ui.Image image,
    required _ExportFormat format,
    required _ExportQualityPreset quality,
  }) async {
    if (format == _ExportFormat.png) {
      final ByteData? pngData = await image.toByteData(
        format: ui.ImageByteFormat.png,
      );
      if (pngData == null) {
        throw StateError('PNG encoding failed.');
      }
      return pngData.buffer.asUint8List();
    }

    final ByteData? rawData = await image.toByteData(
      format: ui.ImageByteFormat.rawRgba,
    );
    if (rawData == null) {
      throw StateError('RGBA extraction failed.');
    }
    final Uint8List rgba = Uint8List.fromList(
      rawData.buffer.asUint8List(0, rawData.lengthInBytes),
    );
    final int width = image.width;
    final int height = image.height;
    return Isolate.run<Uint8List>(
      () => _encodeJpgFromRgbaForExportIsolate(
        rgba: rgba,
        width: width,
        height: height,
        quality: quality.jpegQualityForFormat(format),
      ),
    );
  }

  String _buildExportFileName(_ExportFormat format) {
    final DateTime now = DateTime.now();
    final String mm = now.month.toString().padLeft(2, '0');
    final String dd = now.day.toString().padLeft(2, '0');
    final String hh = now.hour.toString().padLeft(2, '0');
    final String min = now.minute.toString().padLeft(2, '0');
    final String ss = now.second.toString().padLeft(2, '0');
    return 'wonderpic_${now.year}$mm${dd}_$hh$min$ss.${format.extension}';
  }

  void _showExportMessage(
    String message, {
    bool isError = false,
  }) {
    if (!mounted) return;
    final ScaffoldMessengerState? messenger =
        _editorScaffoldMessengerKey.currentState;
    if (messenger == null) return;
    messenger.showSnackBar(
      SnackBar(
        behavior: SnackBarBehavior.floating,
        backgroundColor: WonderPicEditorScreen._pageBg,
        content: Text(
          message,
          style: TextStyle(
            color: isError ? const Color(0xFFB91C1C) : const Color(0xFFF3F3F2),
            fontWeight: FontWeight.w600,
          ),
        ),
      ),
    );
  }

  Widget _buildExportingOverlay() {
    final double panelWidth = math.min(
      244,
      math.max(176, MediaQuery.sizeOf(context).width - 56),
    );
    return Positioned.fill(
      child: IgnorePointer(
        child: Container(
          color: const Color(0x2D0F172A),
          alignment: Alignment.center,
          child: Container(
            width: panelWidth,
            padding: const EdgeInsets.symmetric(horizontal: 12, vertical: 12),
            decoration: BoxDecoration(
              color: const Color(0xFFFFFFFF),
              borderRadius: BorderRadius.circular(14),
              boxShadow: const [
                BoxShadow(
                  color: Color(0x220F172A),
                  blurRadius: 18,
                  spreadRadius: 1,
                  offset: Offset(0, 8),
                ),
              ],
              border: Border.all(color: const Color(0xFF605E5E)),
            ),
            child: const Row(
              mainAxisSize: MainAxisSize.max,
              children: [
                SizedBox(
                  width: 16,
                  height: 16,
                  child: CircularProgressIndicator(
                    strokeWidth: 2.1,
                    color: Color(0xFFD4D4D3),
                  ),
                ),
                SizedBox(width: 10),
                Expanded(
                  child: Text(
                    'Rendering export...',
                    maxLines: 1,
                    overflow: TextOverflow.ellipsis,
                    softWrap: false,
                    style: TextStyle(
                      fontSize: 12.5,
                      fontWeight: FontWeight.w700,
                      color: Color(0xFFF3F3F2),
                    ),
                  ),
                ),
              ],
            ),
          ),
        ),
      ),
    );
  }

  void _showToolMessage(String message) {}

  void _onLayerImageChanged(String layerId, ui.Image image) {
    final int index = _layers.indexWhere((layer) => layer.id == layerId);
    if (index < 0) return;
    final List<EditorLayer> nextLayers = List<EditorLayer>.from(_layers);
    final EditorLayer current = nextLayers[index];
    _pushUndoSnapshot();
    nextLayers[index] = current.copyWith(
      image: image,
      solidSize: _imageSourceSize(image),
    );
    setState(() {
      _layers = nextLayers;
      if (_marqueeSelection != null && _marqueeSelection!.layerId != layerId) {
        _marqueeSelection = null;
      }
    });
  }

  void _onLayerSelected(String? layerId) {
    if (_selectedLayerId == layerId) return;
    _isTransformHistoryCaptured = false;
    _isTextEditHistoryCaptured = false;
    setState(() {
      _selectedLayerId = layerId;
      _resetMoveJoystickControls();
      final EditorLayer? selected = _selectedLayer();
      if (selected == null || selected.type != EditorLayerType.image) {
        _sketchReplaceBrushPreviewTimer?.cancel();
        _cloneBrushPreviewTimer?.cancel();
        _isCloneSourceArmed = false;
        _isCloneBrushSelected = false;
        _isCloneEraseSelected = false;
        _isCloneBrushPreviewVisible = false;
        _isCloneSettingsFloatingOpen = false;
        _isCloneSettingsBottomSheetOpen = false;
        _cloneSettingsFloatingBaseline = null;
        _cloneSourceArmedFloatingBaseline = null;
        _cloneBrushSelectedFloatingBaseline = null;
        _cloneEraseSelectedFloatingBaseline = null;
        _isCropFloatingOpen = false;
        _isPhotoRoomRemoveBgFloatingOpen = false;
        _isPhotoRoomRemoveBgProcessing = false;
        _isSketchReplaceFloatingOpen = false;
        _isSketchReplaceProcessing = false;
        _sketchReplaceError = null;
        _isSketchReplaceBrushPreviewVisible = false;
        _isReplaceObjectFloatingOpen = false;
        _isReplaceObjectProcessing = false;
        _replaceObjectError = null;
        _isBlurSettingsBottomSheetOpen = false;
        _resetBlurPreviewSession();
      }
      if (selected == null || selected.type != EditorLayerType.text) {
        _resetTextQuickFloatingPanels();
        _activeTextEffectFloatingPanel = null;
        _isTextSettingsDockEnabled = false;
      }
      if (selected == null ||
          selected.type != EditorLayerType.image ||
          selected.isBackground) {
        _isOverlayCutFloatingOpen = false;
        _overlayCutBaseline = null;
        _isOverlayImageShadowFloatingOpen = false;
        _overlayImageShadowFloatingBaseline = null;
        _overlayImageShadowFloatingLayerId = null;
      } else if (_overlayImageShadowFloatingLayerId != selected.id) {
        _isOverlayImageShadowFloatingOpen = false;
        _overlayImageShadowFloatingBaseline = null;
        _overlayImageShadowFloatingLayerId = null;
      }
      if (selected == null || selected.type != EditorLayerType.image) {
        _isImageAdjustFloatingOpen = false;
        _imageAdjustFloatingBaseline = null;
        _imageAdjustFloatingLayerId = null;
      } else if (_isImageAdjustFloatingOpen &&
          _imageAdjustFloatingLayerId != selected.id) {
        _isImageAdjustFloatingOpen = false;
        _imageAdjustFloatingBaseline = null;
        _imageAdjustFloatingLayerId = null;
      }
      if (_isCropFloatingOpen) {
        if (selected == null ||
            selected.type != EditorLayerType.image ||
            selected.image == null) {
          _isCropFloatingOpen = false;
        } else {
          final _CropToolConfig nextConfig =
              _resolvedCropConfigForLayer(selected.id);
          _cropToolConfig = nextConfig;
        }
      }
      if (_isToolEnabled && _activeTool == EditorTool.expand) {
        if (selected == null ||
            selected.type != EditorLayerType.image ||
            selected.image == null) {
          _expandToolConfig = null;
        } else {
          _expandToolConfig = _resolvedExpandConfigForLayer(selected.id);
        }
      }
      if (_marqueeSelection != null && _marqueeSelection!.layerId != layerId) {
        _marqueeSelection = null;
      }
      if (selected?.type == EditorLayerType.text) {
        _syncTextLocaleFromFamily(selected?.textFontFamily);
      }
    });
    if (layerId == null) _sketchReplaceBrushPreviewTimer?.cancel();
    _syncTextInputFromSelectedLayer();
  }

  void _onLayerTransformChanged(
    String layerId, {
    Offset? position,
    double? layerScale,
    double? layerRotation,
  }) {
    final int index = _layers.indexWhere((layer) => layer.id == layerId);
    if (index < 0) return;
    final List<EditorLayer> nextLayers = List<EditorLayer>.from(_layers);
    final EditorLayer current = nextLayers[index];
    nextLayers[index] = current.copyWith(
      position: position,
      layerScale: layerScale,
      layerRotation: layerRotation,
    );
    setState(() {
      _layers = nextLayers;
    });
  }

  Future<void> _pickImageFromGallery() async {
    if (_isPickingImage) return;
    setState(() {
      _isPickingImage = true;
    });

    try {
      final XFile? file = await _picker.pickImage(
        source: ImageSource.gallery,
        requestFullMetadata: false,
      );
      if (file == null) return;

      final bytes = await file.readAsBytes();
      final ui.Image image = await _decodeUiImage(bytes);
      if (!mounted) return;

      _pushUndoSnapshot();
      setState(() {
        final EditorLayer? workspace = _workspaceLayerForEdit(_layers);
        if (workspace == null) {
          _upsertBackgroundLayer(
            image: image,
            thumbnailBytes: bytes,
          );
          return;
        }
        final Size? workspaceSize = _workspaceSourceSize(workspace);
        if (workspaceSize == null) return;
        _addOverlayImageLayer(
          image: image,
          thumbnailBytes: bytes,
          workspaceSize: workspaceSize,
        );
      });
    } on PlatformException {
      if (!mounted) return;
      final ScaffoldMessengerState? messenger =
          _editorScaffoldMessengerKey.currentState;
      messenger?.showSnackBar(
        const SnackBar(
          content: Text(
            'Gallery access failed. Please allow photo access and try again.',
          ),
        ),
      );
    } catch (_) {
      if (!mounted) return;
      final ScaffoldMessengerState? messenger =
          _editorScaffoldMessengerKey.currentState;
      messenger?.showSnackBar(
        const SnackBar(content: Text('Could not load image from gallery')),
      );
    } finally {
      if (mounted) {
        setState(() {
          _isPickingImage = false;
        });
      }
    }
  }

  void _upsertBackgroundLayer({
    required ui.Image image,
    required Uint8List thumbnailBytes,
  }) {
    final List<EditorLayer> nextLayers = List<EditorLayer>.from(_layers);
    final int existingIndex =
        nextLayers.indexWhere((layer) => layer.isBackground);
    final String layerId = existingIndex >= 0
        ? nextLayers[existingIndex].id
        : 'layer_${_nextLayerId++}';

    final EditorLayer background = EditorLayer(
      id: layerId,
      name: 'Background',
      type: EditorLayerType.image,
      isBackground: true,
      isVisible: true,
      image: image,
      thumbnailBytes: thumbnailBytes,
      solidSize: _imageSourceSize(image),
    );

    if (existingIndex >= 0) {
      nextLayers[existingIndex] = background;
      _layers = nextLayers;
      _selectedLayerId = layerId;
      if (_marqueeSelection != null && _marqueeSelection!.layerId != layerId) {
        _marqueeSelection = null;
      }
      return;
    }

    nextLayers.insert(0, background);
    _layers = nextLayers;
    _selectedLayerId = layerId;
    if (_marqueeSelection != null && _marqueeSelection!.layerId != layerId) {
      _marqueeSelection = null;
    }
  }

  void _upsertSolidBackground({
    required Size solidSize,
    required String name,
  }) {
    final List<EditorLayer> nextLayers = List<EditorLayer>.from(_layers);
    final int existingIndex =
        nextLayers.indexWhere((layer) => layer.isBackground);
    final String layerId = existingIndex >= 0
        ? nextLayers[existingIndex].id
        : 'layer_${_nextLayerId++}';

    final EditorLayer background = EditorLayer(
      id: layerId,
      name: name,
      type: EditorLayerType.solid,
      isBackground: true,
      isVisible: true,
      solidColor: const Color(0xFFFFFFFF),
      solidSize: solidSize,
    );

    if (existingIndex >= 0) {
      nextLayers[existingIndex] = background;
      _layers = nextLayers;
      _selectedLayerId = layerId;
      if (_marqueeSelection != null && _marqueeSelection!.layerId != layerId) {
        _marqueeSelection = null;
      }
      return;
    }

    nextLayers.insert(0, background);
    _layers = nextLayers;
    _selectedLayerId = layerId;
    if (_marqueeSelection != null && _marqueeSelection!.layerId != layerId) {
      _marqueeSelection = null;
    }
  }

  void _addOverlayImageLayer({
    required ui.Image image,
    required Uint8List thumbnailBytes,
    required Size workspaceSize,
  }) {
    final int overlayImageCount = _layers
        .where(
          (entry) => entry.type == EditorLayerType.image && !entry.isBackground,
        )
        .length;
    final double fitScale = math.min(
      workspaceSize.width / image.width,
      workspaceSize.height / image.height,
    );
    final double initialScale = math.min(1.0, fitScale * 0.92);
    final String newId = 'layer_${_nextLayerId++}';
    final EditorLayer overlay = EditorLayer(
      id: newId,
      name: overlayImageCount == 0
          ? 'Overlay Image'
          : 'Overlay Image ${overlayImageCount + 1}',
      type: EditorLayerType.image,
      isBackground: false,
      isVisible: true,
      image: image,
      thumbnailBytes: thumbnailBytes,
      solidSize: _imageSourceSize(image),
      position: Offset(workspaceSize.width / 2, workspaceSize.height / 2),
      layerScale: initialScale,
      layerRotation: 0.0,
    );
    _layers = <EditorLayer>[..._layers, overlay];
    _selectedLayerId = newId;
  }

  Future<void> _openUpscaleBottomSheet() async {
    final EditorLayer? initialLayer = _selectedImageLayer();
    if (initialLayer == null || initialLayer.image == null) {
      _showExportMessage('Select an image layer first.', isError: true);
      return;
    }

    bool sheetOpen = true;
    _UpscaleAmount selectedAmount = _UpscaleAmount.k2;
    bool isUpscaling = false;
    String? sheetError;

    Future<void> runUpscale(
      BuildContext sheetContext,
      StateSetter setSheetState,
    ) async {
      if (isUpscaling) return;
      final int layerIndex =
          _layers.indexWhere((layer) => layer.id == initialLayer.id);
      if (layerIndex < 0 ||
          _layers[layerIndex].type != EditorLayerType.image ||
          _layers[layerIndex].image == null) {
        setSheetState(() {
          sheetError = 'Selected layer is no longer available.';
        });
        return;
      }
      final EditorLayer sourceLayer = _layers[layerIndex];
      final ui.Image sourceImage = sourceLayer.image!;
      setSheetState(() {
        isUpscaling = true;
        sheetError = null;
      });
      setState(() {
        _isUpscaleLayerProcessing = true;
        _upscaleEffectLayerId = sourceLayer.id;
      });
      try {
        final Uint8List sourceBytes =
            await _encodeUiImageToPngBytes(sourceImage);
        final Uint8List resultBytes = await _upscaleImageWithKieRecraftCrisp(
          sourceBytes: sourceBytes,
          amount: selectedAmount,
        );
        final ui.Image upscaledImage = await _decodeUiImage(resultBytes);
        if (!mounted) return;
        _pushUndoSnapshot();
        setState(() {
          final int targetIndex =
              _layers.indexWhere((layer) => layer.id == sourceLayer.id);
          if (targetIndex >= 0) {
            final List<EditorLayer> nextLayers =
                List<EditorLayer>.from(_layers);
            final EditorLayer current = nextLayers[targetIndex];
            final Size preservedLogicalSize = current.solidSize ??
                Size(
                  sourceImage.width.toDouble(),
                  sourceImage.height.toDouble(),
                );
            nextLayers[targetIndex] = current.copyWith(
              image: upscaledImage,
              thumbnailBytes: resultBytes,
              solidSize: preservedLogicalSize,
            );
            _layers = nextLayers;
            _selectedLayerId = current.id;
          }
        });
        _showExportMessage('Upscale ${selectedAmount.label} completed.');
        if (sheetContext.mounted && sheetOpen) {
          sheetOpen = false;
          Navigator.of(sheetContext).pop();
        }
      } catch (error) {
        if (!sheetContext.mounted || !sheetOpen) return;
        setSheetState(() {
          final String message = error.toString().trim();
          sheetError = message.startsWith('StateError: ')
              ? message.substring('StateError: '.length)
              : message;
        });
      } finally {
        if (mounted) {
          setState(() {
            _isUpscaleLayerProcessing = false;
            _upscaleEffectLayerId = null;
          });
        }
        if (sheetContext.mounted && sheetOpen) {
          setSheetState(() {
            isUpscaling = false;
          });
        }
      }
    }

    await showModalBottomSheet<void>(
      context: context,
      isScrollControlled: false,
      barrierColor: Colors.transparent,
      backgroundColor: const Color(0xFF1E1F22),
      shape: const RoundedRectangleBorder(
        borderRadius: BorderRadius.vertical(top: Radius.circular(24)),
      ),
      builder: (sheetContext) {
        return SafeArea(
          top: false,
          child: StatefulBuilder(
            builder: (sheetContext, setSheetState) {
              return SizedBox(
                height: MediaQuery.sizeOf(sheetContext).height * 0.30,
                child: Padding(
                  padding: const EdgeInsets.fromLTRB(14, 10, 14, 14),
                  child: Column(
                    children: [
                      Container(
                        width: 38,
                        height: 4,
                        decoration: BoxDecoration(
                          color: const Color(0xFF605E5E),
                          borderRadius: BorderRadius.circular(6),
                        ),
                      ),
                      const SizedBox(height: 10),
                      Row(
                        children: [
                          const Expanded(
                            child: Text(
                              'Upscale Layer',
                              style: TextStyle(
                                color: Color(0xFFF3F3F2),
                                fontWeight: FontWeight.w800,
                                fontSize: 16,
                              ),
                            ),
                          ),
                          InkWell(
                            borderRadius: BorderRadius.circular(14),
                            onTap: isUpscaling
                                ? null
                                : () {
                                    sheetOpen = false;
                                    Navigator.of(sheetContext).pop();
                                  },
                            child: const Padding(
                              padding: EdgeInsets.all(4),
                              child: Icon(
                                Icons.close_rounded,
                                size: 18,
                                color: Color(0xFFB8B7B5),
                              ),
                            ),
                          ),
                        ],
                      ),
                      const SizedBox(height: 8),
                      Align(
                        alignment: Alignment.centerLeft,
                        child: Text(
                          initialLayer.name,
                          maxLines: 1,
                          overflow: TextOverflow.ellipsis,
                          style: const TextStyle(
                            color: Color(0xFFB8B7B5),
                            fontSize: 12.4,
                            fontWeight: FontWeight.w600,
                          ),
                        ),
                      ),
                      const SizedBox(height: 10),
                      Row(
                        children: _UpscaleAmount.values.map((amount) {
                          final bool selected = amount == selectedAmount;
                          return Expanded(
                            child: Padding(
                              padding: EdgeInsets.only(
                                right: amount == _UpscaleAmount.k2 ? 5 : 0,
                                left: amount == _UpscaleAmount.k4 ? 5 : 0,
                              ),
                              child: InkWell(
                                borderRadius: BorderRadius.circular(10),
                                onTap: isUpscaling
                                    ? null
                                    : () {
                                        setSheetState(() {
                                          selectedAmount = amount;
                                        });
                                      },
                                child: AnimatedContainer(
                                  duration: const Duration(milliseconds: 120),
                                  curve: Curves.easeOut,
                                  height: 40,
                                  alignment: Alignment.center,
                                  decoration: BoxDecoration(
                                    color: selected
                                        ? kActiveAccent
                                        : const Color(0xFF1E1F22),
                                    borderRadius: BorderRadius.circular(10),
                                    border: Border.all(
                                      color: selected
                                          ? Colors.transparent
                                          : const Color(0xFF605E5E),
                                    ),
                                  ),
                                  child: Text(
                                    amount.label,
                                    style: TextStyle(
                                      color: selected
                                          ? kActiveAccentForeground
                                          : const Color(0xFF5E6775),
                                      fontWeight: FontWeight.w800,
                                      fontSize: 13.5,
                                    ),
                                  ),
                                ),
                              ),
                            ),
                          );
                        }).toList(growable: false),
                      ),
                      if (sheetError != null) ...[
                        const SizedBox(height: 8),
                        Align(
                          alignment: Alignment.centerLeft,
                          child: Text(
                            sheetError!,
                            style: const TextStyle(
                              color: Color(0xFFB91C1C),
                              fontSize: 11.8,
                              fontWeight: FontWeight.w600,
                            ),
                            maxLines: 2,
                            overflow: TextOverflow.ellipsis,
                          ),
                        ),
                      ],
                      const Spacer(),
                      SizedBox(
                        width: double.infinity,
                        child: _buildTextEffectFloatingActionButton(
                          label: isUpscaling ? 'Upscaling...' : 'Upscale',
                          onTap: isUpscaling
                              ? () {}
                              : () => runUpscale(sheetContext, setSheetState),
                        ),
                      ),
                    ],
                  ),
                ),
              );
            },
          ),
        );
      },
    ).whenComplete(() {
      sheetOpen = false;
      if (mounted && _isUpscaleLayerProcessing) {
        setState(() {
          _isUpscaleLayerProcessing = false;
          _upscaleEffectLayerId = null;
        });
      }
    });
  }

  String _dataUriMime(Uint8List bytes) {
    if (bytes.length >= 8 &&
        bytes[0] == 0x89 &&
        bytes[1] == 0x50 &&
        bytes[2] == 0x4E &&
        bytes[3] == 0x47) {
      return 'image/png';
    }
    if (bytes.length >= 3 &&
        bytes[0] == 0xFF &&
        bytes[1] == 0xD8 &&
        bytes[2] == 0xFF) {
      return 'image/jpeg';
    }
    if (bytes.length >= 12 &&
        bytes[0] == 0x52 &&
        bytes[1] == 0x49 &&
        bytes[2] == 0x46 &&
        bytes[3] == 0x46 &&
        bytes[8] == 0x57 &&
        bytes[9] == 0x45 &&
        bytes[10] == 0x42 &&
        bytes[11] == 0x50) {
      return 'image/webp';
    }
    if (bytes.length >= 6 &&
        bytes[0] == 0x47 &&
        bytes[1] == 0x49 &&
        bytes[2] == 0x46 &&
        bytes[3] == 0x38 &&
        (bytes[4] == 0x37 || bytes[4] == 0x39) &&
        bytes[5] == 0x61) {
      return 'image/gif';
    }
    return 'application/octet-stream';
  }

  String _toDataUri(Uint8List bytes) {
    final String mime = _dataUriMime(bytes);
    return 'data:$mime;base64,${base64Encode(bytes)}';
  }

  String _buildKieReferencePrompt({
    required _KieAiImageModel model,
    required String userPrompt,
    required int referenceCount,
  }) {
    final String cleanPrompt = userPrompt.trim();
    if (referenceCount <= 0) {
      return cleanPrompt;
    }
    final String modelPrefix = switch (model) {
      _KieAiImageModel.ideogramV3Remix =>
        'Use high-fidelity image remix editing.',
      _KieAiImageModel.flux2Pro =>
        'Use strict image-to-image identity-preserving edit mode.',
      _KieAiImageModel.seedream5Lite =>
        'Use strict reference-preserving edit mode.',
      _ => 'Use strict reference-based image editing mode.',
    };
    if (referenceCount == 1) {
      return '$modelPrefix Edit ONLY the uploaded reference image according to this instruction: $cleanPrompt. Keep identity, face, body, pose, composition, camera framing, perspective, lighting, and all untouched areas unchanged. Do not introduce new people, objects, logos, or random elements.';
    }
    return '$modelPrefix Reference image 1 is the BASE scene and must remain dominant. Reference image 2 is the SECONDARY reference to transfer/integrate exactly where requested. Instruction: $cleanPrompt. Preserve base composition, perspective, and lighting from image 1 and preserve subject/object identity details from image 2. Do not alter unrelated regions and do not invent extra characters or objects.';
  }

  String _buildNanoBananaPrompt({
    required String userPrompt,
    required int referenceCount,
  }) {
    final String cleanPrompt = userPrompt.trim();
    if (referenceCount <= 0) {
      return cleanPrompt;
    }
    if (referenceCount == 1) {
      return 'Edit ONLY the first uploaded reference image based on this instruction: $cleanPrompt. Keep the same person/object identity, face details, body shape, pose, camera angle, framing, perspective, lighting, and background. Change only the requested target region and keep all other pixels visually consistent with the source.';
    }
    return 'You receive exactly two reference images in order: image 1 is the BASE scene and image 2 is the REQUIRED source reference. Perform a strict reference merge edit. Copy the target subject/object from image 2 as-is (same cut/length/shape/proportions/color/material/pattern/logo/details) into image 1 at the requested location. Do not redesign, restyle, reinterpret, or beautify the reference from image 2. Keep image 1 unchanged outside the edited region (identity, face, pose, framing, perspective, lighting, and background must stay the same). If the text instruction conflicts with image 2 appearance, image 2 appearance wins. User instruction: $cleanPrompt';
  }

  String? _estimateReferenceAspectRatio(Uint8List bytes) {
    try {
      final img.Image? decoded = img.decodeImage(bytes);
      if (decoded == null || decoded.width <= 0 || decoded.height <= 0) {
        return null;
      }
      final img.Image baked = img.bakeOrientation(decoded);
      final double ratio = baked.width / baked.height;
      const List<MapEntry<String, double>> candidates =
          <MapEntry<String, double>>[
        MapEntry<String, double>('1:1', 1.0),
        MapEntry<String, double>('4:3', 4 / 3),
        MapEntry<String, double>('3:4', 3 / 4),
        MapEntry<String, double>('16:9', 16 / 9),
        MapEntry<String, double>('9:16', 9 / 16),
      ];
      MapEntry<String, double> best = candidates.first;
      double bestDelta = (ratio - best.value).abs();
      for (final MapEntry<String, double> candidate in candidates.skip(1)) {
        final double delta = (ratio - candidate.value).abs();
        if (delta < bestDelta) {
          best = candidate;
          bestDelta = delta;
        }
      }
      return best.key;
    } catch (_) {
      return null;
    }
  }

  String _kieAspectRatioForModel(
    _KieAiImageModel model,
    _AiCanvasSizePreset sizePreset, {
    String? referenceAspectRatio,
  }) {
    if (referenceAspectRatio != null && referenceAspectRatio.isNotEmpty) {
      return referenceAspectRatio;
    }
    switch (model) {
      case _KieAiImageModel.flux2Pro:
      case _KieAiImageModel.seedream5Lite:
        switch (sizePreset) {
          case _AiCanvasSizePreset.square:
            return '1:1';
          case _AiCanvasSizePreset.portrait:
            return '3:4';
          case _AiCanvasSizePreset.story:
            return '9:16';
        }
      default:
        return sizePreset.aspectRatio;
    }
  }

  bool _kieSupportsModelVersions(_KieAiImageModel model) {
    return model == _KieAiImageModel.nanoBanana;
  }

  List<_AiGenerationQuality> _kieQualityOptionsForModel(
    _KieAiImageModel model,
  ) {
    switch (model) {
      case _KieAiImageModel.nanoBanana:
        return const <_AiGenerationQuality>[
          _AiGenerationQuality.k1,
          _AiGenerationQuality.k2,
          _AiGenerationQuality.k4,
        ];
      case _KieAiImageModel.flux2Pro:
        return const <_AiGenerationQuality>[
          _AiGenerationQuality.k1,
          _AiGenerationQuality.k2,
        ];
      case _KieAiImageModel.seedream5Lite:
        return const <_AiGenerationQuality>[
          _AiGenerationQuality.k2, // basic => 2K
          _AiGenerationQuality.high, // high => 3K
        ];
      case _KieAiImageModel.ideogramV3Remix:
        return const <_AiGenerationQuality>[_AiGenerationQuality.k1];
      default:
        return const <_AiGenerationQuality>[
          _AiGenerationQuality.medium,
          _AiGenerationQuality.high,
        ];
    }
  }

  _AiGenerationQuality _kieDefaultQualityForModel(_KieAiImageModel model) {
    return _kieQualityOptionsForModel(model).first;
  }

  String _kieQualityLabelForModel(
    _KieAiImageModel model,
    _AiGenerationQuality quality,
  ) {
    if (model == _KieAiImageModel.seedream5Lite) {
      return quality == _AiGenerationQuality.high ? '3K' : '2K';
    }
    return quality.label;
  }

  List<_KieIdeogramImageSize> _kieImageSizeOptionsForModel(
    _KieAiImageModel model,
  ) {
    switch (model) {
      case _KieAiImageModel.flux2Pro:
      case _KieAiImageModel.seedream5Lite:
        return const <_KieIdeogramImageSize>[
          _KieIdeogramImageSize.square,
          _KieIdeogramImageSize.portrait43,
          _KieIdeogramImageSize.portrait169,
        ];
      default:
        return _KieIdeogramImageSize.values;
    }
  }

  Map<String, dynamic> _buildKieImageInput({
    required _KieAiImageModel model,
    required _KieNanoBananaVersion nanoVersion,
    required _KieIdeogramStyle ideogramStyle,
    required _KieIdeogramImageSize ideogramImageSize,
    required _AiCanvasSizePreset sizePreset,
    required _AiGenerationQuality quality,
    required String prompt,
    required List<String> referenceImageUrls,
    String? referenceAspectRatio,
  }) {
    final List<String> urls =
        referenceImageUrls.take(2).toList(growable: false);
    final bool hasRefs = urls.isNotEmpty;
    final String effectivePrompt = model == _KieAiImageModel.nanoBanana
        ? _buildNanoBananaPrompt(
            userPrompt: prompt,
            referenceCount: urls.length,
          )
        : _buildKieReferencePrompt(
            model: model,
            userPrompt: prompt,
            referenceCount: urls.length,
          );
    final String modelAspectRatio = _kieAspectRatioForModel(
      model,
      sizePreset,
      referenceAspectRatio: hasRefs ? referenceAspectRatio : null,
    );

    switch (model) {
      case _KieAiImageModel.nanoBanana:
        String resolutionLabel;
        switch (quality) {
          case _AiGenerationQuality.k4:
            resolutionLabel = '4K';
          case _AiGenerationQuality.k2:
            resolutionLabel = '2K';
          default:
            resolutionLabel = '1K';
        }
        return <String, dynamic>{
          'prompt': effectivePrompt,
          if (hasRefs) 'image_input': urls,
          'aspect_ratio': hasRefs ? 'auto' : sizePreset.aspectRatio,
          'resolution': resolutionLabel,
          'output_format': 'png',
          'google_search': false,
        };
      case _KieAiImageModel.ideogramV3Remix:
        final bool hasPrimaryRef = hasRefs && urls.isNotEmpty;
        final bool hasSecondRef = urls.length > 1;
        return <String, dynamic>{
          'prompt': effectivePrompt,
          if (hasPrimaryRef && hasSecondRef) 'image_url': urls.first,
          if (hasPrimaryRef)
            'reference_image_urls': hasSecondRef
                ? urls.skip(1).toList(growable: false)
                : <String>[urls.first],
          'rendering_speed': 'BALANCED',
          'style': ideogramStyle.apiValue,
          'expand_prompt': true,
          'num_images': '1',
          if (hasSecondRef) 'strength': 0.78,
          'negative_prompt': '',
          'image_size': ideogramImageSize.apiValue,
        };
      case _KieAiImageModel.gptImage15:
        return <String, dynamic>{
          'prompt': effectivePrompt,
          if (hasRefs) 'input_urls': urls,
          'aspect_ratio': sizePreset.aspectRatio,
          'quality': quality == _AiGenerationQuality.high ? 'high' : 'medium',
        };
      case _KieAiImageModel.flux2Pro:
        final String resolution = quality == _AiGenerationQuality.k2 ||
                quality == _AiGenerationQuality.high
            ? '2K'
            : '1K';
        return <String, dynamic>{
          'prompt': effectivePrompt,
          if (hasRefs) 'input_urls': urls,
          'aspect_ratio': modelAspectRatio,
          'resolution': resolution,
        };
      case _KieAiImageModel.imagen4:
        return <String, dynamic>{
          'prompt': effectivePrompt,
          'aspect_ratio': sizePreset.aspectRatio,
          'quality': quality == _AiGenerationQuality.high ? 'high' : 'medium',
        };
      case _KieAiImageModel.grokImagine:
        return <String, dynamic>{
          'prompt': effectivePrompt,
          if (hasRefs) 'image_urls': urls,
          'aspect_ratio': sizePreset.aspectRatio,
        };
      case _KieAiImageModel.qwen:
        return <String, dynamic>{
          'prompt': effectivePrompt,
          if (hasRefs && urls.isNotEmpty) 'image_url': urls.first,
          'image_size': sizePreset == _AiCanvasSizePreset.square
              ? 'square_hd'
              : (sizePreset == _AiCanvasSizePreset.story
                  ? 'portrait_16_9'
                  : 'portrait_4_3'),
          'output_format': 'png',
          'enable_safety_checker': true,
          'num_inference_steps': 28,
        };
      case _KieAiImageModel.seedreamV4:
        return <String, dynamic>{
          'prompt': effectivePrompt,
          'image_size': sizePreset == _AiCanvasSizePreset.square
              ? 'square_hd'
              : (sizePreset == _AiCanvasSizePreset.story
                  ? 'portrait_16_9'
                  : 'portrait_4_3'),
          'image_resolution':
              quality == _AiGenerationQuality.high ? '2K' : '1K',
        };
      case _KieAiImageModel.seedream5Lite:
        return <String, dynamic>{
          'prompt': effectivePrompt,
          if (hasRefs) 'image_urls': urls,
          'aspect_ratio': modelAspectRatio,
          'quality': quality == _AiGenerationQuality.high ? 'high' : 'basic',
        };
      case _KieAiImageModel.zImage:
        return <String, dynamic>{
          'prompt': effectivePrompt,
          'aspect_ratio': sizePreset.aspectRatio,
        };
    }
  }

  bool _kieSupportsReferenceImages(_KieAiImageModel model) {
    switch (model) {
      case _KieAiImageModel.nanoBanana:
      case _KieAiImageModel.ideogramV3Remix:
      case _KieAiImageModel.gptImage15:
      case _KieAiImageModel.flux2Pro:
      case _KieAiImageModel.grokImagine:
      case _KieAiImageModel.qwen:
      case _KieAiImageModel.seedream5Lite:
        return true;
      case _KieAiImageModel.imagen4:
      case _KieAiImageModel.seedreamV4:
      case _KieAiImageModel.zImage:
        return false;
    }
  }

  int _kieMaxReferenceImages(_KieAiImageModel model) {
    switch (model) {
      case _KieAiImageModel.qwen:
        return 1;
      case _KieAiImageModel.ideogramV3Remix:
        return 2;
      default:
        return 2;
    }
  }

  String _kieModelForTask({
    required _KieAiImageModel model,
    required _KieNanoBananaVersion nanoVersion,
    required bool hasReferenceImages,
    required int referenceImageCount,
  }) {
    if (!hasReferenceImages) {
      if (model == _KieAiImageModel.nanoBanana) {
        return _KieNanoBananaVersion.nanoBanana2.apiModel;
      }
      return model.apiModel;
    }
    switch (model) {
      case _KieAiImageModel.nanoBanana:
        return _KieNanoBananaVersion.nanoBanana2.apiModel;
      case _KieAiImageModel.ideogramV3Remix:
        if (referenceImageCount >= 2) {
          return 'ideogram/character-remix';
        }
        if (referenceImageCount == 1) {
          return 'ideogram/character';
        }
        return 'ideogram/v3-remix';
      case _KieAiImageModel.gptImage15:
        return 'gpt-image/1.5-image-to-image';
      case _KieAiImageModel.flux2Pro:
        return 'flux-2/pro-image-to-image';
      case _KieAiImageModel.imagen4:
        return 'google/imagen4';
      case _KieAiImageModel.grokImagine:
        return 'grok-imagine/image-to-image';
      case _KieAiImageModel.qwen:
        return 'qwen/image-to-image';
      case _KieAiImageModel.seedreamV4:
        return model.apiModel;
      case _KieAiImageModel.seedream5Lite:
        return model.apiModel;
      case _KieAiImageModel.zImage:
        return model.apiModel;
    }
  }

  Future<String> _uploadKieReferenceFile(
    Uint8List bytes, {
    bool preserveFormat = false,
    bool normalizeOrientation = true,
    bool preferStreamUpload = false,
  }) async {
    final String apiKey = _kieApiKey;
    if (apiKey.trim().isEmpty) {
      throw StateError(
          'KIE API key missing. Use --dart-define=KIE_API_KEY=...');
    }
    Uint8List uploadBytes = bytes;
    if (normalizeOrientation) {
      try {
        final img.Image? decoded = img.decodeImage(bytes);
        if (decoded != null) {
          final img.Image baked = img.bakeOrientation(decoded);
          if (preserveFormat) {
            final String sourceMime = _dataUriMime(bytes);
            if (sourceMime == 'image/jpeg') {
              uploadBytes = Uint8List.fromList(
                img.encodeJpg(baked, quality: 92),
              );
            } else {
              uploadBytes = Uint8List.fromList(img.encodePng(baked, level: 2));
            }
          } else {
            uploadBytes = Uint8List.fromList(img.encodePng(baked, level: 2));
          }
        }
      } catch (_) {}
    }

    final Uri base64Uri =
        Uri.parse('https://kieai.redpandaai.co/api/file-base64-upload');
    final Uri streamUri =
        Uri.parse('https://kieai.redpandaai.co/api/file-stream-upload');
    final String mime = _dataUriMime(uploadBytes);
    final String extension = mime == 'image/png'
        ? 'png'
        : (mime == 'image/jpeg'
            ? 'jpg'
            : (mime == 'image/webp' ? 'webp' : 'jpg'));
    const String uploadPath = 'wonderpic/references';
    final String fileName =
        'ref_${DateTime.now().microsecondsSinceEpoch}.$extension';

    Future<String> uploadViaBase64() async {
      final String requestBody = await _buildKieBase64UploadBodyPayload(
        bytes: uploadBytes,
        mime: mime,
        fileName: fileName,
      );
      final http.Response response = await http
          .post(
            base64Uri,
            headers: <String, String>{
              'Authorization': 'Bearer $apiKey',
              'Content-Type': 'application/json',
            },
            body: requestBody,
          )
          .timeout(const Duration(minutes: 2));
      return _extractKieUploadUrlFromResponse(
        response: response,
        contextLabel: 'KIE file-base64-upload',
      );
    }

    Future<String> uploadViaStream() async {
      final http.MultipartRequest request =
          http.MultipartRequest('POST', streamUri)
            ..headers['Authorization'] = 'Bearer $apiKey'
            ..fields['uploadPath'] = uploadPath
            ..fields['fileName'] = fileName
            ..files.add(
              http.MultipartFile.fromBytes(
                'file',
                uploadBytes,
                filename: fileName,
              ),
            );
      final http.StreamedResponse streamed = await request.send().timeout(
            const Duration(minutes: 2),
          );
      final http.Response response = await http.Response.fromStream(streamed)
          .timeout(const Duration(minutes: 2));
      return _extractKieUploadUrlFromResponse(
        response: response,
        contextLabel: 'KIE file-stream-upload',
      );
    }

    final bool preferStreamFirst =
        preferStreamUpload || uploadBytes.length > 900000;
    final List<Future<String> Function()> strategies = preferStreamFirst
        ? <Future<String> Function()>[uploadViaStream, uploadViaBase64]
        : <Future<String> Function()>[uploadViaBase64, uploadViaStream];
    Object? lastError;
    for (final Future<String> Function() strategy in strategies) {
      for (int attempt = 0; attempt < 3; attempt++) {
        try {
          return await strategy();
        } catch (error) {
          lastError = error;
          final bool shouldRetry =
              _isTransientKieUploadError(error) && attempt < 2;
          if (shouldRetry) {
            await Future<void>.delayed(_kieUploadRetryDelay(attempt));
            continue;
          }
          break;
        }
      }
    }
    if (lastError != null) {
      throw lastError;
    }
    throw StateError('KIE upload failed unexpectedly.');
  }

  String _extractKieUploadUrlFromResponse({
    required http.Response response,
    required String contextLabel,
  }) {
    final Map<String, dynamic> decoded = _decodeKieJson(
      response.bodyBytes,
      contextLabel: contextLabel,
    );
    final int code = _readKieCode(decoded['code']);
    final bool hasCode = decoded.containsKey('code');
    final String message = (decoded['msg'] as String?)?.trim() ??
        (decoded['message'] as String?)?.trim() ??
        'Unknown KIE error.';
    if (response.statusCode < 200 || response.statusCode >= 300) {
      throw StateError(
        'KIE file upload failed (${response.statusCode}): $message',
      );
    }
    if (hasCode && code != 200) {
      throw StateError('KIE file upload failed ($code): $message');
    }
    final dynamic data = decoded['data'];
    String url = '';
    if (data is Map<String, dynamic>) {
      url = ((data['downloadUrl'] as String?) ??
              (data['url'] as String?) ??
              (data['fileUrl'] as String?) ??
              (data['outputUrl'] as String?) ??
              '')
          .trim();
    } else if (data is String) {
      url = data.trim();
    }
    url = url.isNotEmpty
        ? url
        : ((decoded['downloadUrl'] as String?) ??
                (decoded['url'] as String?) ??
                (decoded['fileUrl'] as String?) ??
                '')
            .trim();
    if (url.isEmpty) {
      throw const FormatException('KIE upload returned empty file URL.');
    }
    return url;
  }

  bool _isTransientKieUploadError(Object error) {
    if (error is TimeoutException ||
        error is SocketException ||
        error is http.ClientException) {
      return true;
    }
    final String message = error.toString().toLowerCase();
    return message.contains('connection reset') ||
        message.contains('timed out') ||
        message.contains('errno = 54') ||
        message.contains('statuscode 429') ||
        message.contains('statuscode 500') ||
        message.contains('statuscode 502') ||
        message.contains('statuscode 503') ||
        message.contains('statuscode 504');
  }

  Duration _kieUploadRetryDelay(int attempt) {
    switch (attempt) {
      case 0:
        return const Duration(milliseconds: 500);
      case 1:
        return const Duration(milliseconds: 1100);
      default:
        return const Duration(milliseconds: 1800);
    }
  }

  Map<String, dynamic> _decodeKieJson(
    Uint8List bodyBytes, {
    required String contextLabel,
  }) {
    final dynamic decoded = jsonDecode(utf8.decode(bodyBytes));
    if (decoded is! Map<String, dynamic>) {
      throw FormatException('$contextLabel response is invalid.');
    }
    return decoded;
  }

  int _readKieCode(dynamic value) {
    if (value is int) return value;
    if (value is String) return int.tryParse(value) ?? -1;
    return -1;
  }

  List<String> _extractKieResultUrls(Map<String, dynamic> data) {
    final List<String> urls = <String>[];

    void addUrl(dynamic value) {
      if (value == null) return;
      if (value is String) {
        final String trimmed = value.trim();
        if (trimmed.isNotEmpty && !urls.contains(trimmed)) {
          urls.add(trimmed);
        }
        return;
      }
      if (value is Map<String, dynamic>) {
        addUrl(value['url']);
        addUrl(value['downloadUrl']);
        addUrl(value['outputUrl']);
        addUrl(value['fileUrl']);
        return;
      }
      if (value is Iterable) {
        for (final dynamic entry in value) {
          addUrl(entry);
        }
      }
    }

    dynamic resultJson = data['resultJson'];
    if (resultJson is String && resultJson.trim().isNotEmpty) {
      try {
        resultJson = jsonDecode(resultJson);
      } catch (_) {
        resultJson = null;
      }
    }
    if (resultJson is Map<String, dynamic>) {
      addUrl(resultJson['resultUrls']);
      addUrl(resultJson['resultUrl']);
      addUrl(resultJson['url']);
      addUrl(resultJson['downloadUrl']);
      addUrl(resultJson['outputUrl']);
      addUrl(resultJson['fileUrl']);
    }
    addUrl(data['resultUrls']);
    addUrl(data['resultUrl']);
    addUrl(data['url']);
    addUrl(data['downloadUrl']);
    addUrl(data['outputUrl']);
    addUrl(data['fileUrl']);
    return urls;
  }

  String _extractKieResultUrl(Map<String, dynamic> data) {
    final List<String> urls = _extractKieResultUrls(data);
    return urls.isEmpty ? '' : urls.first;
  }

  Future<bool> _canDecodeAsImage(Uint8List bytes) async {
    if (bytes.length < 16) return false;
    try {
      final ui.Codec codec = await ui.instantiateImageCodec(bytes);
      await codec.getNextFrame();
      return true;
    } catch (_) {
      return false;
    }
  }

  Future<String> _createKieRecraftUpscaleTask({
    required String imageUrl,
    required int upscaleFactor,
  }) async {
    final String apiKey = _kieApiKey;
    if (apiKey.trim().isEmpty) {
      throw StateError(
          'KIE API key missing. Use --dart-define=KIE_API_KEY=...');
    }

    final Uri uri = Uri.parse('https://api.kie.ai/api/v1/jobs/createTask');
    final http.Response response = await http
        .post(
          uri,
          headers: <String, String>{
            'Authorization': 'Bearer $apiKey',
            'Content-Type': 'application/json',
          },
          body: jsonEncode(
            <String, dynamic>{
              'model': 'recraft/crisp-upscale',
              'input': <String, dynamic>{
                'image': imageUrl,
                'upscale_factor': upscaleFactor.clamp(2, 4),
              },
            },
          ),
        )
        .timeout(const Duration(minutes: 2));

    final Map<String, dynamic> decoded = _decodeKieJson(
      response.bodyBytes,
      contextLabel: 'KIE createTask (Recraft Crisp Upscale)',
    );
    final int code = _readKieCode(decoded['code']);
    final String message =
        (decoded['msg'] as String?)?.trim() ?? 'Unknown KIE error.';

    if (response.statusCode < 200 ||
        response.statusCode >= 300 ||
        code != 200) {
      throw StateError(
        'KIE Recraft Crisp Upscale createTask failed (${response.statusCode}): $message',
      );
    }

    final Map<String, dynamic>? data = decoded['data'] is Map<String, dynamic>
        ? decoded['data'] as Map<String, dynamic>
        : null;
    final String taskId = (data?['taskId'] as String?)?.trim() ?? '';
    if (taskId.isEmpty) {
      throw const FormatException(
        'KIE Recraft Crisp Upscale returned empty taskId.',
      );
    }
    return taskId;
  }

