        return;
      }
      if (result.action != _AddAction.aiImageRequest ||
          result.aiGenerateRequest == null) {
        return;
      }

      await _runAiImageGenerateRequest(result.aiGenerateRequest!);
    } finally {
      promptController.dispose();
