  Future<void> _runAiImageGenerateRequest(
    _AiImageGenerateRequest request,
  ) async {
    if (_isAiCanvasGenerating || !mounted) return;
    final String apiKey = _kieApiKey.trim();
    if (apiKey.isEmpty) {
      _showExportMessage(
        'KIE API key missing. Add --dart-define=KIE_API_KEY=...',
        isError: true,
      );
      return;
    }
    final bool hadWorkspaceBefore = _workspaceLayerForEdit(_layers) != null;

    setState(() {
      if (!hadWorkspaceBefore) {
        _upsertSolidBackground(
          solidSize: request.sizePreset.baseSize,
          name: 'Background',
        );
      }
      _defaultKieAiImageModel = request.model;
      _defaultKieNanoVersion = request.nanoVersion;
      _defaultKieIdeogramStyle = request.ideogramStyle;
      _defaultKieIdeogramImageSize = request.ideogramImageSize;
      _defaultAiCanvasSizePreset = request.sizePreset;
      _defaultAiGenerationQuality = request.quality;
      _lastKiePrompt = request.prompt.trim();
      _aiCanvasGeneratingSizePreset = request.sizePreset;
      _isAiCanvasGenerating = true;
      _aiCanvasGeneratingProgress = 0.0;
    });
    _startAiCanvasGeneratingProgressEstimator();

    try {
      final Uint8List pngBytes = await _generateImageWithKie(
        model: request.model,
        nanoVersion: request.nanoVersion,
        ideogramStyle: request.ideogramStyle,
        ideogramImageSize: request.ideogramImageSize,
        sizePreset: request.sizePreset,
        quality: request.quality,
        prompt: request.prompt,
        referenceImages: request.referenceImages,
      );
      final ui.Image image = await _decodeUiImage(pngBytes);
      if (!mounted) return;

      _pushUndoSnapshot();
      setState(() {
        final EditorLayer? workspace = _workspaceLayerForEdit(_layers);
        if (!hadWorkspaceBefore || workspace == null) {
          _upsertBackgroundLayer(
            image: image,
            thumbnailBytes: pngBytes,
          );
        } else {
          final Size? workspaceSize = _workspaceSourceSize(workspace);
          if (workspaceSize != null) {
            _addOverlayImageLayer(
              image: image,
              thumbnailBytes: pngBytes,
              workspaceSize: workspaceSize,
            );
          }
        }
      });
      _showExportMessage('AI image generated successfully.');
    } catch (error) {
      _showExportMessage(error.toString(), isError: true);
    } finally {
      if (mounted) {
        await _completeAiCanvasGeneratingProgress();
      } else {
        _aiCanvasGeneratingProgressTimer?.cancel();
        _aiCanvasGeneratingProgressTimer = null;
      }
      if (mounted) {
        setState(() {
          _isAiCanvasGenerating = false;
          _aiCanvasGeneratingProgress = 0.0;
          _aiCanvasGeneratingSizePreset = null;
        });
      }
    }
  }

  void _startAiCanvasGeneratingProgressEstimator() {
    _aiCanvasGeneratingProgressTimer?.cancel();
    _aiCanvasGeneratingProgressTimer = Timer.periodic(
      const Duration(milliseconds: 110),
      (_) {
        if (!mounted || !_isAiCanvasGenerating) {
          _aiCanvasGeneratingProgressTimer?.cancel();
          _aiCanvasGeneratingProgressTimer = null;
          return;
        }
        final double current = _aiCanvasGeneratingProgress;
        final bool slowMode =
            _isUpscaleLayerProcessing && _upscaleEffectLayerId != null;
        final double step = slowMode
            ? (current < 0.2
                ? 0.0105
                : current < 0.42
                    ? 0.0084
                    : current < 0.68
                        ? 0.0059
                        : current < 0.88
                            ? 0.0036
                            : 0.0019)
            : (current < 0.24
                ? 0.022
                : current < 0.48
                    ? 0.016
                    : current < 0.74
                        ? 0.011
                        : current < 0.9
                            ? 0.0065
                            : 0.0032);
        final double next = (current + step).clamp(0.0, 0.97).toDouble();
        if ((next - current).abs() <= 0.0001) return;
        setState(() {
          _aiCanvasGeneratingProgress = next;
        });
      },
    );
  }

  Future<void> _completeAiCanvasGeneratingProgress() async {
    _aiCanvasGeneratingProgressTimer?.cancel();
    _aiCanvasGeneratingProgressTimer = null;
    if (!mounted) return;
    setState(() {
      _aiCanvasGeneratingProgress = 1.0;
    });
    await Future<void>.delayed(const Duration(milliseconds: 260));
  }

  String _buildAiVectorPrompt({
    required String userInput,
    required _AiVectorKind kind,
    required _AiVectorStyle style,
    required _AiVectorBackground background,
  }) {
    String kindHint;
    switch (kind) {
      case _AiVectorKind.icon:
        kindHint =
            'single app/UI icon, simple silhouette, clear at small sizes';
      case _AiVectorKind.logo:
        kindHint =
            'clean standalone logo mark, no brand text unless explicitly requested';
      case _AiVectorKind.symbol:
        kindHint =
            'symbolic sign/mark with universal readability and balanced geometry';
      case _AiVectorKind.illustration:
        kindHint =
            'compact icon-style illustration, still clean and design-ready';
    }

    String styleHint;
    switch (style) {
      case _AiVectorStyle.flat:
        styleHint =
            'flat design, no gradients, no texture, no 3D lighting, minimal geometric forms';
      case _AiVectorStyle.outline:
        styleHint =
            'outline style with consistent stroke weight and clean rounded joins';
      case _AiVectorStyle.filled:
        styleHint =
            'filled solid shape style with clear contrast and smooth curves';
      case _AiVectorStyle.minimal:
        styleHint =
            'ultra-minimal composition with very few shapes and high clarity';
      case _AiVectorStyle.modern:
        styleHint =
            'modern style with contemporary spacing and refined proportions';
      case _AiVectorStyle.soft3d:
        styleHint =
            'soft 3D look with subtle depth while preserving clean silhouette';
    }

    final String backgroundHint = switch (background) {
      _AiVectorBackground.transparent => 'transparent background (alpha) only',
      _AiVectorBackground.white =>
        'solid pure white background filling the full canvas',
      _AiVectorBackground.black =>
        'solid pure black background filling the full canvas',
    };

    return '''
Generate one professional ${kind.label.toLowerCase()} PNG asset.

User request: "$userInput"

Primary goal:
- beautiful flat icon quality by default, usable in real app/design work

Type guidance:
- $kindHint

Style guidance:
- $styleHint

Hard requirements:
- $backgroundHint
- single centered object with balanced padding
- crisp anti-aliased edges and smooth contours
- no watermark, no mockup, no external frame, no extra text
- export-ready PNG result for direct canvas use
''';
  }

  bool _isModelAccessError(String message) {
    final String text = message.toLowerCase();
    if (!text.contains('model')) return false;
    return text.contains('not found') ||
        text.contains('not available') ||
        text.contains('not allowed') ||
        text.contains('unsupported') ||
        text.contains('access');
  }

  Uint8List _applyAiBackgroundIfNeeded(
    Uint8List pngBytes,
    _AiVectorBackground background,
  ) {
    if (background.isTransparent) {
      return pngBytes;
    }
    final img.Image? decoded = img.decodeImage(pngBytes);
    if (decoded == null) {
      return pngBytes;
    }
    final int bgR = background == _AiVectorBackground.white ? 255 : 0;
    final int bgG = background == _AiVectorBackground.white ? 255 : 0;
    final int bgB = background == _AiVectorBackground.white ? 255 : 0;

    final Uint8List rgba = Uint8List.fromList(
      decoded.getBytes(order: img.ChannelOrder.rgba),
    );
    for (int i = 0; i < rgba.length; i += 4) {
      final int alpha = rgba[i + 3];
      if (alpha == 255) {
        continue;
      }
      if (alpha == 0) {
        rgba[i] = bgR;
        rgba[i + 1] = bgG;
        rgba[i + 2] = bgB;
        rgba[i + 3] = 255;
        continue;
      }
      final int inv = 255 - alpha;
      rgba[i] = ((rgba[i] * alpha + bgR * inv) / 255).round().clamp(0, 255);
      rgba[i + 1] =
          ((rgba[i + 1] * alpha + bgG * inv) / 255).round().clamp(0, 255);
      rgba[i + 2] =
          ((rgba[i + 2] * alpha + bgB * inv) / 255).round().clamp(0, 255);
      rgba[i + 3] = 255;
    }

    final img.Image composited = img.Image.fromBytes(
      width: decoded.width,
      height: decoded.height,
      bytes: rgba.buffer,
      numChannels: 4,
      order: img.ChannelOrder.rgba,
    );
    return Uint8List.fromList(img.encodePng(composited, level: 4));
  }

  String _geminiAspectRatioForSize(_AiVectorSize size) {
    switch (size) {
      case _AiVectorSize.square1024:
        return '1:1';
      case _AiVectorSize.portrait1024x1536:
        return '2:3';
      case _AiVectorSize.landscape1536x1024:
        return '3:2';
    }
  }

  Future<Uint8List> _generateGeminiVectorPng({
    required String userInput,
    required _GeminiImageModel model,
    required _AiVectorKind kind,
    required _AiVectorStyle style,
    required _AiVectorSize size,
    required _AiVectorBackground background,
  }) async {
    final String apiKey = _geminiApiKey;
    if (apiKey.isEmpty) {
      throw StateError('Gemini API key is missing.');
    }

    final Uri uri = Uri.parse(
      'https://generativelanguage.googleapis.com/v1beta/models/'
      '${model.apiValue}:generateContent',
    );

    final http.Response response = await http.post(
      uri,
      headers: <String, String>{
        'x-goog-api-key': apiKey,
        'Content-Type': 'application/json',
      },
      body: jsonEncode(
        <String, dynamic>{
          'contents': <Map<String, dynamic>>[
            <String, dynamic>{
              'parts': <Map<String, dynamic>>[
                <String, dynamic>{
                  'text': _buildAiVectorPrompt(
                    userInput: userInput,
                    kind: kind,
                    style: style,
                    background: background,
                  ),
                },
              ],
            },
          ],
          'generationConfig': <String, dynamic>{
            'responseModalities': <String>['IMAGE', 'TEXT'],
            'imageConfig': <String, dynamic>{
              'aspectRatio': _geminiAspectRatioForSize(size),
            },
          },
        },
      ),
    );

    if (response.statusCode < 200 || response.statusCode >= 300) {
      String apiMessage = response.body;
      try {
        final dynamic decoded = jsonDecode(response.body);
        if (decoded is Map<String, dynamic>) {
          final dynamic error = decoded['error'];
          if (error is Map<String, dynamic> &&
              error['message'] is String &&
              (error['message'] as String).trim().isNotEmpty) {
            apiMessage = (error['message'] as String).trim();
          }
        }
      } catch (_) {}
      throw StateError(
          'Gemini image error (${response.statusCode}): $apiMessage');
    }

    final dynamic decoded = jsonDecode(utf8.decode(response.bodyBytes));
    if (decoded is! Map<String, dynamic>) {
      throw const FormatException('Unexpected Gemini image response.');
    }

    final dynamic candidates = decoded['candidates'];
    if (candidates is! List || candidates.isEmpty) {
      throw const FormatException('Gemini image response has no candidates.');
    }

    String? inlineData;
    String? textFallback;
    for (final dynamic candidate in candidates) {
      if (candidate is! Map<String, dynamic>) continue;
      final dynamic content = candidate['content'];
      if (content is! Map<String, dynamic>) continue;
      final dynamic parts = content['parts'];
      if (parts is! List) continue;
      for (final dynamic part in parts) {
        if (part is! Map<String, dynamic>) continue;
        final dynamic imagePart = part['inlineData'] ?? part['inline_data'];
        if (imagePart is Map<String, dynamic>) {
          final dynamic dataValue = imagePart['data'];
          if (dataValue is String && dataValue.isNotEmpty) {
            inlineData = dataValue;
            break;
          }
        }
        final dynamic textPart = part['text'];
        if (textPart is String && textPart.trim().isNotEmpty) {
          textFallback = textPart.trim();
        }
      }
      if (inlineData != null) break;
    }

    if (inlineData == null) {
      if (textFallback != null) {
        throw StateError('Gemini returned text only: $textFallback');
      }
      throw const FormatException(
          'Gemini image response missing image payload.');
    }

    return _applyAiBackgroundIfNeeded(base64Decode(inlineData), background);
  }

  Future<Uint8List> _generateAiVectorPng({
    required String userInput,
    required _AiImageModel model,
    required _AiVectorKind kind,
    required _AiVectorStyle style,
    required _AiVectorQuality quality,
    required _AiVectorSize size,
    required _AiVectorBackground background,
    bool allowModelFallback = true,
  }) async {
    final String apiKey = _openAiApiKey;
    if (apiKey.isEmpty) {
      throw StateError('OpenAI API key is missing.');
    }
    final Uri uri = Uri.parse('https://api.openai.com/v1/images/generations');
    final http.Response response = await http.post(
      uri,
      headers: <String, String>{
        'Authorization': 'Bearer $apiKey',
        'Content-Type': 'application/json',
      },
      body: jsonEncode(
        <String, dynamic>{
          'model': model.apiValue,
          'prompt': _buildAiVectorPrompt(
            userInput: userInput,
            kind: kind,
            style: style,
            background: background,
          ),
          'size': size.apiValue,
          'quality': quality.apiValue,
          'output_format': 'png',
          'n': 1,
          if (background.isTransparent) 'background': 'transparent',
        },
      ),
    );

    if (response.statusCode < 200 || response.statusCode >= 300) {
      String apiMessage = response.body;
      try {
        final dynamic decoded = jsonDecode(response.body);
        if (decoded is Map<String, dynamic>) {
          final dynamic error = decoded['error'];
          if (error is Map<String, dynamic> &&
              error['message'] is String &&
              (error['message'] as String).trim().isNotEmpty) {
            apiMessage = (error['message'] as String).trim();
          }
        }
      } catch (_) {}
      if (allowModelFallback &&
          model == _AiImageModel.gptImage15 &&
          _isModelAccessError(apiMessage)) {
        return _generateAiVectorPng(
          userInput: userInput,
          model: _AiImageModel.gptImage1,
          kind: kind,
          style: style,
          quality: quality,
          size: size,
          background: background,
          allowModelFallback: false,
        );
      }
      throw StateError(
          'OpenAI image error (${response.statusCode}): $apiMessage');
    }

    final dynamic decoded = jsonDecode(utf8.decode(response.bodyBytes));
    if (decoded is! Map<String, dynamic>) {
      throw const FormatException('Unexpected OpenAI image response.');
    }
    final dynamic data = decoded['data'];
    if (data is! List || data.isEmpty || data.first is! Map<String, dynamic>) {
      throw const FormatException('OpenAI image response has no image data.');
    }
    final Map<String, dynamic> first = data.first as Map<String, dynamic>;
    final String? b64 =
        (first['b64_json'] ?? first['b64'] ?? first['image_base64']) as String?;
    if (b64 != null && b64.isNotEmpty) {
      return _applyAiBackgroundIfNeeded(base64Decode(b64), background);
    }
    final String? url = first['url'] as String?;
    if (url != null && url.isNotEmpty) {
      final http.Response imageResponse = await http.get(Uri.parse(url));
      if (imageResponse.statusCode >= 200 && imageResponse.statusCode < 300) {
        return _applyAiBackgroundIfNeeded(imageResponse.bodyBytes, background);
      }
      throw StateError(
        'OpenAI image download failed (${imageResponse.statusCode}).',
      );
    }
    throw const FormatException('OpenAI image response missing PNG payload.');
  }

  Future<void> _openVectorGeneratorBottomSheet() async {
    final bool allowSolidBackground = _workspaceLayerForEdit(_layers) != null;
    bool sheetOpen = true;
    _AiImageEngine selectedEngine = _defaultAiVectorEngine;
    _AiImageModel selectedOpenAiModel = _defaultAiVectorModel;
    _GeminiImageModel selectedGeminiModel = _defaultGeminiAiVectorModel;
    _AiVectorKind selectedKind = _defaultAiVectorKind;
    _AiVectorStyle selectedStyle = _defaultAiVectorStyle;
    _AiVectorQuality selectedQuality = _defaultAiVectorQuality;
    _AiVectorSize selectedSize = _defaultAiVectorSize;
    _AiVectorBackground selectedBackground = allowSolidBackground
        ? _defaultAiVectorBackground
        : _AiVectorBackground.transparent;

    final TextEditingController promptController =
        TextEditingController(text: _lastVectorPrompt);

    try {
      final _AiVectorSheetResult? sheetResult =
          await showModalBottomSheet<_AiVectorSheetResult>(
        context: context,
        isScrollControlled: false,
        isDismissible: false,
        enableDrag: false,
        barrierColor: Colors.transparent,
        backgroundColor: const Color(0xFF1E1F22),
        shape: const RoundedRectangleBorder(
          borderRadius: BorderRadius.vertical(top: Radius.circular(22)),
        ),
        builder: (sheetContext) {
          bool isGenerating = false;
          Uint8List? generatedPngBytes;
          _AiVectorRequest? generatedRequest;
          String? generationError;

          Future<void> generatePreview(
            StateSetter setSheetState,
          ) async {
            if (isGenerating) return;
            final String prompt = promptController.text.trim();
            final _AiVectorBackground effectiveBackground = allowSolidBackground
                ? selectedBackground
                : _AiVectorBackground.transparent;
            if (prompt.isEmpty) {
              setSheetState(() {
                generationError = 'Type a short description first.';
              });
              return;
            }

            setSheetState(() {
              isGenerating = true;
              generationError = null;
            });

            try {
              final Uint8List pngBytes = selectedEngine == _AiImageEngine.openAi
                  ? await _generateAiVectorPng(
                      userInput: prompt,
                      model: selectedOpenAiModel,
                      kind: selectedKind,
                      style: selectedStyle,
                      quality: selectedQuality,
                      size: selectedSize,
                      background: effectiveBackground,
                    )
                  : await _generateGeminiVectorPng(
                      userInput: prompt,
                      model: selectedGeminiModel,
                      kind: selectedKind,
                      style: selectedStyle,
                      size: selectedSize,
                      background: effectiveBackground,
                    );
              if (!sheetContext.mounted || !sheetOpen) {
                return;
              }
              setSheetState(() {
                generatedPngBytes = pngBytes;
                generatedRequest = _AiVectorRequest(
                  prompt: prompt,
                  engine: selectedEngine,
                  openAiModel: selectedOpenAiModel,
                  geminiModel: selectedGeminiModel,
                  kind: selectedKind,
                  style: selectedStyle,
                  quality: selectedQuality,
                  size: selectedSize,
                  background: effectiveBackground,
                );
                generationError = null;
              });
            } catch (error) {
              if (!sheetContext.mounted || !sheetOpen) {
                return;
              }
              setSheetState(() {
                generationError = error.toString();
              });
            } finally {
              if (sheetContext.mounted && sheetOpen) {
                setSheetState(() {
                  isGenerating = false;
                });
              }
            }
          }

          return SafeArea(
            top: false,
            child: SizedBox(
              height: MediaQuery.sizeOf(sheetContext).height * 0.5,
              child: Padding(
                padding: const EdgeInsets.fromLTRB(12, 8, 12, 10),
                child: StatefulBuilder(
                  builder: (sheetContext, setSheetState) {
                    return Column(
                      children: [
                        Container(
                          width: 32,
                          height: 3,
                          decoration: BoxDecoration(
                            color: const Color(0xFF605E5E),
                            borderRadius: BorderRadius.circular(4),
                          ),
                        ),
                        const SizedBox(height: 8),
                        Row(
                          children: [
                            const Expanded(
                              child: Text(
                                'AI Vectors (PNG)',
                                style: TextStyle(
                                  color: Color(0xFFF3F3F2),
                                  fontSize: 15,
                                  fontWeight: FontWeight.w700,
                                ),
                              ),
                            ),
                            InkWell(
                              onTap: isGenerating
                                  ? () {}
                                  : () {
                                      sheetOpen = false;
                                      Navigator.of(sheetContext).pop();
                                    },
                              borderRadius: BorderRadius.circular(14),
                              child: const Padding(
                                padding: EdgeInsets.all(4),
                                child: Icon(
                                  Icons.close_rounded,
                                  size: 18,
                                  color: Color(0xFFB8B7B5),
                                ),
                              ),
                            ),
                          ],
                        ),
                        const SizedBox(height: 8),
                        Expanded(
                          child: SingleChildScrollView(
                            child: Column(
                              children: [
                                Container(
                                  width: double.infinity,
                                  padding: const EdgeInsets.symmetric(
                                    horizontal: 10,
                                    vertical: 8,
                                  ),
                                  decoration: BoxDecoration(
                                    color: const Color(0xFF1E1F22),
                                    borderRadius: BorderRadius.circular(10),
                                    border: Border.all(
                                      color: const Color(0xFF605E5E),
                                    ),
                                  ),
                                  child: TextField(
                                    controller: promptController,
                                    maxLines: 2,
                                    minLines: 1,
                                    textInputAction: TextInputAction.done,
                                    style: const TextStyle(
                                      fontSize: 13,
                                      color: Color(0xFFF3F3F2),
                                    ),
                                    onChanged: (_) {
                                      if (!sheetContext.mounted || !sheetOpen) {
                                        return;
                                      }
                                      setSheetState(() {
                                        generationError = null;
                                      });
