  Future<ui.Image> _decodeUiImage(Uint8List bytes) async {
    // Fast path: use platform codec directly to avoid expensive Dart-side
    // decode/re-encode work on normal images from gallery/camera.
    try {
      final ui.Codec codec = await ui.instantiateImageCodec(bytes);
      final ui.FrameInfo frameInfo = await codec.getNextFrame();
      return frameInfo.image;
    } catch (_) {}

    // Fallback path keeps the previous orientation-normalization behavior
    // for edge cases where the direct codec path cannot decode the bytes.
    try {
      final img.Image? decoded = img.decodeImage(bytes);
      if (decoded != null) {
        final img.Image normalized = (decoded.exif.imageIfd.hasOrientation &&
                (decoded.exif.imageIfd.orientation ?? 1) != 1)
            ? img.bakeOrientation(decoded)
            : decoded;
        final Uint8List normalizedBytes = Uint8List.fromList(
          img.encodePng(normalized, level: 2),
        );
        final ui.Codec normalizedCodec = await ui.instantiateImageCodec(
          normalizedBytes,
        );
        final ui.FrameInfo normalizedFrame =
            await normalizedCodec.getNextFrame();
        return normalizedFrame.image;
      }
    } catch (_) {}
    return painting.decodeImageFromList(bytes);
  }

  Future<ui.Image> _decodeUiImageFromRgba(
    Uint8List rgba, {
    required int width,
    required int height,
  }) {
    final Completer<ui.Image> completer = Completer<ui.Image>();
    ui.decodeImageFromPixels(
      rgba,
      width,
      height,
      ui.PixelFormat.rgba8888,
      (ui.Image image) {
        if (!completer.isCompleted) {
          completer.complete(image);
        }
      },
    );
    return completer.future;
  }

  Size _imageSourceSize(ui.Image image) {
    return Size(image.width.toDouble(), image.height.toDouble());
  }

