  void _reorderLayersFromSheet({
    required int oldDisplayIndex,
    required int newDisplayIndex,
  }) {
    if (_layers.length < 2) return;
    final List<EditorLayer> displayLayers = _layers.reversed.toList();
    if (oldDisplayIndex < 0 || oldDisplayIndex >= displayLayers.length) return;

    final int backgroundDisplayIndex =
        displayLayers.indexWhere((layer) => layer.isBackground);
    if (displayLayers[oldDisplayIndex].isBackground) return;

    int targetDisplayIndex = newDisplayIndex;
    if (targetDisplayIndex > oldDisplayIndex) {
      targetDisplayIndex -= 1;
    }
    int maxDisplayIndex = displayLayers.length - 1;
    if (backgroundDisplayIndex >= 0) {
      maxDisplayIndex = backgroundDisplayIndex - 1;
      if (maxDisplayIndex < 0) return;
    }
    targetDisplayIndex = targetDisplayIndex.clamp(0, maxDisplayIndex);
    if (targetDisplayIndex == oldDisplayIndex) return;

    _pushUndoSnapshot();
    final EditorLayer moved = displayLayers.removeAt(oldDisplayIndex);
    displayLayers.insert(targetDisplayIndex, moved);
    setState(() {
      _layers = displayLayers.reversed.toList(growable: true);
    });
  }

  void _toggleLayerVisibility(String layerId) {
    final List<EditorLayer> nextLayers = List<EditorLayer>.from(_layers);
    final int index = nextLayers.indexWhere((layer) => layer.id == layerId);
    if (index < 0) return;
    _pushUndoSnapshot();
    final EditorLayer layer = nextLayers[index];
    nextLayers[index] = layer.copyWith(isVisible: !layer.isVisible);
    setState(() {
      _layers = nextLayers;
      if (!nextLayers[index].isVisible && _selectedLayerId == layerId) {
        _selectedLayerId = null;
      }
      if (!nextLayers[index].isVisible &&
          _marqueeSelection != null &&
          _marqueeSelection!.layerId == layerId) {
        _marqueeSelection = null;
      }
      if (!nextLayers[index].isVisible &&
          _overlayCutConfig != null &&
          _overlayCutConfig!.layerId == layerId) {
        _isOverlayCutFloatingOpen = false;
        _overlayCutBaseline = null;
      }
      if (!nextLayers[index].isVisible &&
          _overlayImageShadowFloatingLayerId == layerId) {
        _isOverlayImageShadowFloatingOpen = false;
        _overlayImageShadowFloatingBaseline = null;
        _overlayImageShadowFloatingLayerId = null;
      }
      if (!nextLayers[index].isVisible &&
          _cropToolConfig != null &&
          _cropToolConfig!.layerId == layerId) {
        _isCropFloatingOpen = false;
      }
      if (!nextLayers[index].isVisible &&
          _expandToolConfig != null &&
          _expandToolConfig!.layerId == layerId) {
        _expandToolConfig = null;
      }
    });
  }

  void _duplicateLayer(String layerId) {
    final int index = _layers.indexWhere((layer) => layer.id == layerId);
    if (index < 0) return;
    final EditorLayer source = _layers[index];

    String duplicateName(String baseName) {
      final String normalized =
          baseName.trim().isEmpty ? 'Layer' : baseName.trim();
      final String base = '$normalized Copy';
      if (!_layers.any((layer) => layer.name == base)) return base;
      int suffix = 2;
      while (_layers.any((layer) => layer.name == '$base $suffix')) {
        suffix++;
      }
      return '$base $suffix';
    }

    final String newId = 'layer_${_nextLayerId++}';
    final Uint8List? nextThumbnail = source.thumbnailBytes == null
        ? null
        : Uint8List.fromList(source.thumbnailBytes!);
    final EditorLayer duplicate = source.copyWith(
      id: newId,
      name: duplicateName(source.name),
      isVisible: true,
      isBackground: false,
      position: source.position,
      thumbnailBytes: nextThumbnail,
    );

    _pushUndoSnapshot();
    setState(() {
      final List<EditorLayer> nextLayers = List<EditorLayer>.from(_layers);
      nextLayers.insert(index + 1, duplicate);
      _layers = nextLayers;
    });
    _onLayerSelected(newId);
  }

  void _deleteLayer(String layerId) {
    final int index = _layers.indexWhere((layer) => layer.id == layerId);
    if (index < 0) return;
    final EditorLayer target = _layers[index];
    _pushUndoSnapshot();
    setState(() {
      final List<EditorLayer> nextLayers = List<EditorLayer>.from(_layers);
      nextLayers.removeAt(index);
      _layers = nextLayers;
      if (_selectedLayerId == layerId) {
        _selectedLayerId = null;
      }
      if (_marqueeSelection != null && _marqueeSelection!.layerId == layerId) {
        _marqueeSelection = null;
      }
      if (_overlayCutConfig != null && _overlayCutConfig!.layerId == layerId) {
        _overlayCutConfig = null;
        _overlayCutBaseline = null;
        _isOverlayCutFloatingOpen = false;
      }
      if (_overlayImageShadowFloatingLayerId == layerId) {
        _isOverlayImageShadowFloatingOpen = false;
        _overlayImageShadowFloatingBaseline = null;
        _overlayImageShadowFloatingLayerId = null;
      }
      if (_cropToolConfig != null && _cropToolConfig!.layerId == layerId) {
        _cropToolConfig = null;
        _isCropFloatingOpen = false;
      }
      if (_expandToolConfig != null && _expandToolConfig!.layerId == layerId) {
        _expandToolConfig = null;
      }
      if (target.isBackground) {
        // Removing workspace should leave no visual residue on canvas.
        _pencilStrokes = <_BrushStroke>[];
      }
    });
  }

  Future<ui.Image> _renderMergedLayersImage({
    required Set<String> layerIds,
    required Size workspaceSize,
  }) async {
    final int outputWidth = math.max(1, workspaceSize.width.round());
    final int outputHeight = math.max(1, workspaceSize.height.round());
    final ui.PictureRecorder recorder = ui.PictureRecorder();
    final Canvas canvas = Canvas(
      recorder,
      Rect.fromLTWH(0, 0, outputWidth.toDouble(), outputHeight.toDouble()),
    );
    final Rect artboard = Rect.fromLTWH(
      0,
      0,
      workspaceSize.width,
      workspaceSize.height,
    );
    _drawExportLayers(
      canvas: canvas,
      artboard: artboard,
      workspaceSize: workspaceSize,
      includeLayerIds: layerIds,
    );
    final ui.Picture picture = recorder.endRecording();
    return picture.toImage(outputWidth, outputHeight);
  }

  Future<void> _mergeLayersByIds(Set<String> layerIds) async {
    if (_isLayersMergeInProgress) return;
    final Set<String> selectedIds = Set<String>.from(layerIds);
    if (selectedIds.length < 2) {
      _showExportMessage('Select at least 2 layers to merge.', isError: true);
      return;
    }

    final EditorLayer? workspace = _workspaceLayerForEdit(_layers);
    final Size? workspaceSize =
        workspace == null ? null : _workspaceSourceSize(workspace);
    if (workspaceSize == null) {
      _showExportMessage('No workspace available for layer merge.',
          isError: true);
      return;
    }

    final bool includesBackground = _layers
        .any((layer) => selectedIds.contains(layer.id) && layer.isBackground);

    setState(() {
      _isLayersMergeInProgress = true;
    });

    try {
      final ui.Image mergedImage = await _renderMergedLayersImage(
        layerIds: selectedIds,
        workspaceSize: workspaceSize,
      );
      final Uint8List mergedThumbnail =
          await _encodeUiImageToPngBytes(mergedImage);
      if (!mounted) return;

      final String mergedLayerId = 'layer_${_nextLayerId++}';
      final EditorLayer mergedLayer = EditorLayer(
        id: mergedLayerId,
        name: includesBackground ? 'Merged Background' : 'Merged Layer',
        type: EditorLayerType.image,
        isVisible: true,
        isBackground: includesBackground,
        image: mergedImage,
        thumbnailBytes: mergedThumbnail,
        solidSize: _imageSourceSize(mergedImage),
        position: includesBackground
            ? null
            : Offset(workspaceSize.width / 2, workspaceSize.height / 2),
        layerScale: 1.0,
        layerRotation: 0.0,
      );

      _pushUndoSnapshot();
      setState(() {
        final List<EditorLayer> nextLayers = List<EditorLayer>.from(_layers);
        final List<int> selectedIndexes = <int>[];
        for (int i = 0; i < nextLayers.length; i++) {
          if (selectedIds.contains(nextLayers[i].id)) {
            selectedIndexes.add(i);
          }
        }
        if (selectedIndexes.length < 2) {
          return;
        }
        selectedIndexes.sort();
        final int topMostIndex = selectedIndexes.last;
        for (int i = selectedIndexes.length - 1; i >= 0; i--) {
          nextLayers.removeAt(selectedIndexes[i]);
        }

        if (includesBackground) {
          nextLayers.removeWhere((layer) => layer.isBackground);
          nextLayers.insert(0, mergedLayer);
        } else {
          final int removedBeforeTop =
              selectedIndexes.where((index) => index < topMostIndex).length;
          final int insertIndex = (topMostIndex - removedBeforeTop)
              .clamp(0, nextLayers.length)
              .toInt();
          nextLayers.insert(insertIndex, mergedLayer);
        }

        _layers = nextLayers;
        _selectedLayerId = mergedLayerId;
        if (_marqueeSelection != null &&
            selectedIds.contains(_marqueeSelection!.layerId)) {
          _marqueeSelection = null;
        }
        if (_overlayCutConfig != null &&
            selectedIds.contains(_overlayCutConfig!.layerId)) {
          _overlayCutConfig = null;
          _overlayCutBaseline = null;
          _isOverlayCutFloatingOpen = false;
        }
        if (_overlayImageShadowFloatingLayerId != null &&
            selectedIds.contains(_overlayImageShadowFloatingLayerId)) {
          _isOverlayImageShadowFloatingOpen = false;
          _overlayImageShadowFloatingBaseline = null;
          _overlayImageShadowFloatingLayerId = null;
        }
        if (_cropToolConfig != null &&
            selectedIds.contains(_cropToolConfig!.layerId)) {
          _cropToolConfig = null;
          _isCropFloatingOpen = false;
        }
        if (_expandToolConfig != null &&
            selectedIds.contains(_expandToolConfig!.layerId)) {
          _expandToolConfig = null;
        }
      });
      _showExportMessage('Layers merged successfully.');
    } catch (_) {
      if (!mounted) return;
      _showExportMessage('Layer merge failed. Please try again.',
          isError: true);
    } finally {
      if (mounted) {
        setState(() {
          _isLayersMergeInProgress = false;
        });
      }
    }
  }

