  Widget _buildTextFontsFloatingOverlay() {
    final EditorLayer? selectedTextLayer = _selectedTextLayer();
    if (!_isTextFontsFloatingOpen || selectedTextLayer == null) {
      return const SizedBox.shrink();
    }

    const double uiScale = 0.80;
    double scaled(double value, {required double min}) =>
        math.max(min, value * uiScale);

    final BorderRadius panelRadius = BorderRadius.circular(scaled(16, min: 12));
    final List<_TextFontOption> allLocaleOptions =
        _fontOptionsForLocale(_textFontLocale);
    final List<_TextFontOption> options = _filteredTextFontOptions(
      locale: _textFontLocale,
      query: _textFontSearchQuery,
    );
    final String selectedFamily =
        selectedTextLayer.textFontFamily ?? allLocaleOptions.first.family;
    final int selectedIndexRaw =
        options.indexWhere((option) => option.family == selectedFamily);
    final int selectedIndex = selectedIndexRaw < 0
        ? 0
        : selectedIndexRaw.clamp(0, math.max(0, options.length - 1)).toInt();
    final bool canGoBack = options.isNotEmpty && selectedIndex > 0;
    final bool canGoNext =
        options.isNotEmpty && selectedIndex < options.length - 1;
    final double cardHeight = scaled(50, min: 40);
    final double cardSpacing = scaled(6, min: 4);
    const double visibleCards = 4;
    final double listHeight =
        (cardHeight * visibleCards) + (cardSpacing * (visibleCards - 1));
    final double itemExtent = cardHeight + cardSpacing;

    return Positioned(
      left: _textToolsHorizontalInset,
      right: _textToolsHorizontalInset,
      bottom: _textFloatingPanelBottomOffset(scaled(20, min: 14)),
      child: Column(
        mainAxisSize: MainAxisSize.min,
        children: [
          _buildBottomUpPanelAnimation(
            keyId: 'text-fonts-panel-search',
            delay: 0.0,
            child: _buildTextFloatingCard(
              uiScale: uiScale,
              borderRadius: panelRadius,
              child: Row(
                children: [
                  Expanded(
                    child: Container(
                      height: scaled(34, min: 30),
                      padding: EdgeInsets.symmetric(
                        horizontal: scaled(10, min: 8),
                      ),
                      decoration: BoxDecoration(
                        color: _floatingPanelSurfaceSolid,
                        borderRadius: BorderRadius.circular(
                          scaled(10, min: 8),
                        ),
                        border: Border.all(
                          color: _floatingPanelStrokeSolid,
                          width: 0.45,
                        ),
                      ),
                      child: TextField(
                        controller: _textFontSearchController,
                        onChanged: (value) {
                          setState(() {
                            _textFontSearchQuery = value;
                          });
                          WidgetsBinding.instance.addPostFrameCallback((_) {
                            if (_textFontsFloatingScrollController.hasClients) {
                              _textFontsFloatingScrollController.jumpTo(0);
                            }
                          });
                        },
                        style: TextStyle(
                          color: _floatingPanelTextPrimary,
                          fontSize: scaled(12.5, min: 10.5),
                          fontWeight: FontWeight.w600,
                        ),
                        textAlignVertical: TextAlignVertical.center,
                        decoration: InputDecoration(
                          isCollapsed: true,
                          border: InputBorder.none,
                          hintText: 'Search font',
                          hintStyle: TextStyle(
                            color: _floatingPanelHint,
                            fontSize: scaled(12, min: 10),
                            fontWeight: FontWeight.w500,
                          ),
                        ),
                      ),
                    ),
                  ),
                  SizedBox(width: scaled(8, min: 6)),
                  _buildTextFontArrowButton(
                    icon: Icons.chevron_left_rounded,
                    enabled: canGoBack,
                    onTap: () => _jumpTextFontSelection(
                      -1,
                      itemExtent: itemExtent,
                    ),
                    scale: uiScale,
                  ),
                  SizedBox(width: scaled(6, min: 4)),
                  _buildTextFontArrowButton(
                    icon: Icons.chevron_right_rounded,
                    enabled: canGoNext,
                    onTap: () => _jumpTextFontSelection(
                      1,
                      itemExtent: itemExtent,
                    ),
                    scale: uiScale,
                  ),
                ],
              ),
            ),
          ),
          SizedBox(height: scaled(8, min: 6)),
          _buildBottomUpPanelAnimation(
            keyId: 'text-fonts-panel-locale',
            delay: 0.08,
            child: _buildTextFloatingCard(
              uiScale: uiScale,
              borderRadius: panelRadius,
              child: Row(
                children: [
                  Expanded(
                    child: _TextLocaleToggleButton(
                      label: 'English',
                      selected: _textFontLocale == _TextFontLocale.english,
                      scale: uiScale,
                      onTap: () {
                        if (_textFontLocale == _TextFontLocale.english) {
                          return;
                        }
                        setState(() {
                          _textFontLocale = _TextFontLocale.english;
                          _textFontSearchQuery = '';
                          _textFontSearchController.clear();
                        });
                      },
                    ),
                  ),
                  SizedBox(width: scaled(8, min: 6)),
                  Expanded(
                    child: _TextLocaleToggleButton(
                      label: 'عربي',
                      selected: _textFontLocale == _TextFontLocale.arabic,
                      scale: uiScale,
                      fontFamily: 'Cairo',
                      onTap: () {
                        if (_textFontLocale == _TextFontLocale.arabic) {
                          return;
                        }
                        setState(() {
                          _textFontLocale = _TextFontLocale.arabic;
                          _textFontSearchQuery = '';
                          _textFontSearchController.clear();
                        });
                      },
                    ),
                  ),
                ],
              ),
            ),
          ),
          SizedBox(height: scaled(8, min: 6)),
          _buildBottomUpPanelAnimation(
            keyId: 'text-fonts-panel-list',
            delay: 0.16,
            child: SizedBox(
              height: listHeight,
              child: ClipRRect(
                borderRadius: BorderRadius.circular(scaled(10, min: 8)),
                child: options.isEmpty
                    ? Container(
                        alignment: Alignment.center,
                        decoration: BoxDecoration(
                          color: _floatingPanelSurfaceSolid,
                          border: Border.all(
                            color: _floatingPanelStrokeSolid,
                            width: 0.45,
                          ),
                          borderRadius: BorderRadius.circular(
                            scaled(10, min: 8),
                          ),
                        ),
                        child: Text(
                          'No fonts found',
                          style: TextStyle(
                            color: _floatingPanelTextSecondary,
                            fontSize: scaled(12, min: 10),
                            fontWeight: FontWeight.w600,
                          ),
                        ),
                      )
                    : ListView.separated(
                        controller: _textFontsFloatingScrollController,
                        primary: false,
                        padding: EdgeInsets.zero,
                        itemCount: options.length,
                        separatorBuilder: (_, __) =>
                            SizedBox(height: cardSpacing),
                        itemBuilder: (context, index) {
                          final _TextFontOption option = options[index];
                          final bool selected = selectedFamily == option.family;
                          final int titleWeight = _resolveSupportedWeight(
                            option.family,
                            600,
                          );
                          return SizedBox(
                            height: cardHeight,
                            child: _BouncyInkWell(
                              borderRadius: BorderRadius.circular(
                                scaled(10, min: 8),
                              ),
                              onTap: () => _applyTextFontOption(option),
                              pressedScale: 0.986,
                              child: Container(
                                width: double.infinity,
                                padding: EdgeInsets.symmetric(
                                  horizontal: scaled(10, min: 8),
                                  vertical: scaled(8, min: 6),
                                ),
                                decoration: BoxDecoration(
                                  color: selected
                                      ? _floatingPanelSelected
                                      : _floatingPanelSurfaceSolid,
                                  borderRadius: BorderRadius.circular(
                                    scaled(10, min: 8),
                                  ),
                                  border: Border.all(
                                    color: selected
                                        ? Colors.transparent
                                        : _floatingPanelStrokeSolid,
                                    width: selected ? 0 : 0.55,
                                  ),
                                ),
                                child: Directionality(
                                  textDirection: option.direction,
                                  child: Row(
                                    children: [
                                      Expanded(
                                        child: Text(
                                          option.label,
                                          maxLines: 1,
                                          overflow: TextOverflow.ellipsis,
                                          style: TextStyle(
                                            color: selected
                                                ? const Color(0xFF19191A)
                                                : _floatingPanelTextSecondary,
                                            fontSize: scaled(14, min: 11),
                                            fontWeight: _fontWeightFromValue(
                                              titleWeight,
                                            ),
                                            fontFamily: option.family,
                                            height: 1.0,
                                          ),
                                        ),
                                      ),
                                    ],
                                  ),
                                ),
                              ),
                            ),
                          );
                        },
                      ),
              ),
            ),
          ),
        ],
      ),
    );
  }

  Widget _buildTextFontArrowButton({
    required IconData icon,
    required VoidCallback onTap,
    required bool enabled,
    required double scale,
  }) {
    final double clampedScale = scale.clamp(0.7, 1.15).toDouble();
    final double size = (34 * clampedScale).clamp(28, 36).toDouble();
    final double radius = (10 * clampedScale).clamp(8, 12).toDouble();
    return _BouncyInkWell(
      borderRadius: BorderRadius.circular(radius),
      onTap: enabled ? onTap : null,
      pressedScale: 0.94,
      child: AnimatedContainer(
        duration: const Duration(milliseconds: 120),
        width: size,
        height: size,
        decoration: BoxDecoration(
          color: enabled ? _floatingPanelSurfaceSolid : const Color(0xFF2C2D30),
          borderRadius: BorderRadius.circular(radius),
          border: Border.all(color: _floatingPanelStrokeSolid, width: 0.45),
        ),
        child: Icon(
          icon,
          size: (20 * clampedScale).clamp(14, 20).toDouble(),
          color: enabled ? _floatingPanelTextSecondary : _floatingPanelHint,
        ),
      ),
    );
  }

