  Widget _buildTextEffectFloatingOverlay() {
    final _TextEffectFloatingPanel? panel = _activeTextEffectFloatingPanel;
    final EditorLayer? selectedTextLayer = _selectedTextLayer();
    if (panel == null || selectedTextLayer == null) {
      return const SizedBox.shrink();
    }

    final double uiScale = _textSidebarScale;
    double scaled(double value, {required double min}) =>
        math.max(min, value * uiScale);
    final Color selectedStrokeColor =
        selectedTextLayer.textStrokeColor ?? const Color(0xFFFFFFFF);
    final double selectedStrokeWidth = selectedTextLayer.textStrokeWidth ?? 0;
    final Color selectedShadowColor =
        selectedTextLayer.textShadowColor ?? const Color(0xFF19191A);
    final double selectedShadowOffsetX =
        selectedTextLayer.textShadowOffsetX ?? 0;
    final double selectedShadowOffsetY =
        selectedTextLayer.textShadowOffsetY ?? 0;
    final double selectedShadowBlur = selectedTextLayer.textShadowBlur ?? 0;
    final double selectedShadowOpacity =
        selectedTextLayer.textShadowOpacity ?? 0;
    final double selectedTextOpacity = selectedTextLayer.textOpacity ?? 100;
    final double selectedTextBend = selectedTextLayer.textBend ?? 0;
    final double shadowUiScale = (uiScale * 0.88).clamp(0.6, 0.72).toDouble();

    final BorderRadius panelRadius = BorderRadius.circular(scaled(16, min: 12));

    return Positioned(
      left: _textToolsHorizontalInset,
      right: _textToolsHorizontalInset,
      bottom: _textFloatingPanelBottomOffset(scaled(20, min: 14)),
      child: _buildBottomUpPanelAnimation(
        keyId: 'text-effect-panel-${panel.name}',
        child: _buildTextFloatingCard(
          uiScale: uiScale,
          borderRadius: panelRadius,
          child: SizedBox(
            width: double.infinity,
            child: Column(
              mainAxisSize: MainAxisSize.min,
              crossAxisAlignment: CrossAxisAlignment.start,
              children: [
                ...switch (panel) {
                  _TextEffectFloatingPanel.opacity => <Widget>[
                      _SettingsSliderTile(
                        label: 'Opacity',
                        value: selectedTextOpacity,
                        min: 0,
                        max: 100,
                        valueText: '${selectedTextOpacity.toStringAsFixed(0)}%',
                        scale: uiScale,
                        compact: true,
                        showHeader: false,
                        onChanged: (value) {
                          _updateTextLayer(
                            selectedTextLayer.id,
                            textOpacity: value,
                            recordHistory: false,
                          );
                        },
                      ),
                    ],
                  _TextEffectFloatingPanel.bend => <Widget>[
                      _SettingsSliderTile(
                        label: 'Bend',
                        value: selectedTextBend,
                        min: -100,
                        max: 100,
                        valueText: _formatSignedValue(
                          selectedTextBend,
                          fractionDigits: 0,
                        ),
                        scale: uiScale,
                        compact: true,
