class _ExportRenderScreen extends StatefulWidget {
  const _ExportRenderScreen({
    required this.workspaceSize,
    required this.buildPreview,
    required this.runExport,
  });

  final Size workspaceSize;
  final Future<Uint8List> Function() buildPreview;
  final Future<bool> Function(
    _ExportSettings settings,
    _ExportProgressReporter onProgress,
  ) runExport;

  @override
  State<_ExportRenderScreen> createState() => _ExportRenderScreenState();
}

class _ExportRenderScreenState extends State<_ExportRenderScreen>
    with TickerProviderStateMixin {
  late Future<Uint8List> _previewFuture;
  late AnimationController _ringController;
  late AnimationController _progressController;

  _ExportFormat _selectedFormat = _ExportFormat.png;
  _ExportQualityPreset _selectedQuality = _ExportQualityPreset.high;
  bool _isSubmitting = false;
  String _statusLabel = 'Ready';
  double _targetProgress = 0.0;
  double _displayProgress = 0.0;
  double _progressFrom = 0.0;
  double _progressTo = 0.0;

  @override
  void initState() {
    super.initState();
    _previewFuture = widget.buildPreview();
    _ringController = AnimationController(
      vsync: this,
      duration: const Duration(milliseconds: 1800),
    )..repeat();
    _progressController = AnimationController(
      vsync: this,
      duration: const Duration(milliseconds: 260),
    )..addListener(() {
        if (!mounted) return;
        final double t =
            Curves.easeOutCubic.transform(_progressController.value);
        final double next = _progressFrom + ((_progressTo - _progressFrom) * t);
        if ((next - _displayProgress).abs() <= 0.0001) return;
        setState(() {
          _displayProgress = next;
        });
      });
  }

  @override
  void dispose() {
    _ringController.dispose();
    _progressController.dispose();
    super.dispose();
  }

  void _setProgressSmooth(double value, {Duration? duration}) {
    final double clamped = value.clamp(0.0, 1.0).toDouble();
    final double monotonicTarget = math.max(_targetProgress, clamped);
    if ((monotonicTarget - _displayProgress).abs() <= 0.0001) {
      _targetProgress = monotonicTarget;
      return;
    }
    final double delta = (monotonicTarget - _displayProgress).abs();
    final int autoMs = (260 + (delta * 1050).round()).clamp(280, 1200).toInt();
    _progressFrom = _displayProgress;
    _progressTo = monotonicTarget;
    _targetProgress = monotonicTarget;
    _progressController.duration = duration ?? Duration(milliseconds: autoMs);
    _progressController.forward(from: 0);
  }

  Future<void> _runExportNow() async {
    if (_isSubmitting) return;
    setState(() {
      _isSubmitting = true;
      _statusLabel = 'Preparing export...';
      _targetProgress = 0.0;
      _displayProgress = 0.0;
      _progressFrom = 0.0;
      _progressTo = 0.0;
    });
    final bool success = await widget.runExport(
      _ExportSettings(format: _selectedFormat, quality: _selectedQuality),
      (label, progress) {
        if (!mounted) return;
        final double nextProgress = progress.clamp(0.0, 1.0);
        setState(() {
          _statusLabel = label;
        });
        _setProgressSmooth(nextProgress);
      },
    );
    if (!mounted) return;
    if (success) {
      setState(() {
        _statusLabel = 'Done';
      });
      _setProgressSmooth(1.0, duration: const Duration(milliseconds: 420));
      await Future<void>.delayed(const Duration(milliseconds: 420));
      if (mounted) {
        Navigator.of(context).pop();
      }
      return;
    }
    setState(() {
      _isSubmitting = false;
      _statusLabel = 'Export failed';
    });
  }

  void _reloadPreview() {
    if (_isSubmitting) return;
    setState(() {
      _previewFuture = widget.buildPreview();
    });
  }

  bool get _usesIndeterminateOrbit {
    if (!_isSubmitting) return false;
    final String label = _statusLabel.toLowerCase().trim();
    if (label.startsWith('preparing')) return true;
    if (label.startsWith('preparing source')) return true;
    if (label.startsWith('resizing')) return true;
    return _displayProgress < 0.18;
  }

  @override
  Widget build(BuildContext context) {
    final double workspaceAspectRatio = (widget.workspaceSize.height == 0)
        ? 1.0
        : (widget.workspaceSize.width / widget.workspaceSize.height)
            .clamp(0.4, 2.4)
            .toDouble();
    return PopScope(
      canPop: !_isSubmitting,
      child: Scaffold(
        backgroundColor: WonderPicEditorScreen._pageBg,
        appBar: AppBar(
          backgroundColor: WonderPicEditorScreen._barsFill,
          elevation: 0,
          title: const Text(
            'Render Export',
            style: TextStyle(
              color: Color(0xFFF3F3F2),
              fontWeight: FontWeight.w800,
              fontSize: 16,
            ),
          ),
          leading: IconButton(
            icon: const Icon(Icons.arrow_back_ios_new_rounded),
            color: WonderPicEditorScreen._iconColor,
            onPressed: _isSubmitting ? null : () => Navigator.of(context).pop(),
          ),
        ),
        body: SafeArea(
          top: false,
          child: Padding(
            padding: const EdgeInsets.fromLTRB(16, 12, 16, 14),
            child: Column(
              children: [
                Expanded(
                  child: SingleChildScrollView(
                    child: Column(
                      crossAxisAlignment: CrossAxisAlignment.start,
                      children: [
                        Container(
                          width: double.infinity,
                          padding: const EdgeInsets.all(10),
                          decoration: BoxDecoration(
                            color: const Color(0xFF1E1F22),
                            borderRadius: BorderRadius.circular(16),
                            border: Border.all(color: const Color(0x2B4F5358)),
                          ),
                          child: AspectRatio(
                            aspectRatio: workspaceAspectRatio,
                            child: FutureBuilder<Uint8List>(
                              future: _previewFuture,
                              builder: (context, snapshot) {
                                if (snapshot.connectionState !=
                                    ConnectionState.done) {
                                  return Container(
                                    decoration: BoxDecoration(
                                      color: const Color(0xFF17181A),
                                      borderRadius: BorderRadius.circular(14),
                                    ),
                                    alignment: Alignment.center,
                                    child: const SizedBox(
                                      width: 26,
                                      height: 26,
                                      child: CircularProgressIndicator(
                                        strokeWidth: 2.4,
                                        color: Color(0xFFD4D4D3),
                                      ),
                                    ),
                                  );
                                }
                                if (!snapshot.hasData ||
                                    snapshot.data == null) {
                                  return Container(
                                    decoration: BoxDecoration(
                                      color: const Color(0xFF17181A),
                                      borderRadius: BorderRadius.circular(14),
                                    ),
                                    alignment: Alignment.center,
                                    child: TextButton.icon(
                                      onPressed: _reloadPreview,
                                      icon: const Icon(Icons.refresh_rounded),
                                      label: const Text('Retry Preview'),
                                    ),
                                  );
                                }
                                return Container(
                                  decoration: BoxDecoration(
                                    color: const Color(0xFF17181A),
                                    borderRadius: BorderRadius.circular(14),
                                  ),
                                  clipBehavior: Clip.antiAlias,
                                  child: Stack(
                                    fit: StackFit.expand,
                                    children: [
                                      Image.memory(
                                        snapshot.data!,
                                        fit: BoxFit.contain,
                                        filterQuality: FilterQuality.high,
                                      ),
                                      if (_isSubmitting)
                                        Positioned.fill(
                                          child: IgnorePointer(
                                            child: AnimatedBuilder(
                                              animation: _ringController,
                                              builder: (context, _) {
                                                return CustomPaint(
                                                  painter: _ExportOrbitPainter(
                                                    phase:
                                                        _ringController.value,
                                                    progress: _displayProgress,
                                                    indeterminate:
                                                        _usesIndeterminateOrbit,
                                                  ),
                                                );
                                              },
                                            ),
                                          ),
                                        ),
                                    ],
                                  ),
                                );
                              },
                            ),
                          ),
                        ),
                        const SizedBox(height: 10),
                        AnimatedOpacity(
                          duration: const Duration(milliseconds: 180),
                          opacity: _isSubmitting ? 1 : 0.72,
                          child: Text(
                            _isSubmitting
                                ? '$_statusLabel (${(_displayProgress * 100).round()}%)'
                                : 'Preview matches your current canvas composition.',
                            style: const TextStyle(
                              color: Color(0xFFD4D4D3),
                              fontSize: 12.2,
                              fontWeight: FontWeight.w600,
                            ),
                          ),
                        ),
                        const SizedBox(height: 14),
                        const Text(
                          'Format',
                          style: TextStyle(
                            color: Color(0xFFD4D4D3),
                            fontWeight: FontWeight.w700,
                            fontSize: 12.5,
                          ),
                        ),
                        const SizedBox(height: 8),
                        Row(
                          children: _ExportFormat.values.map((format) {
                            final bool isSelected = _selectedFormat == format;
                            return Expanded(
                              child: Padding(
                                padding: EdgeInsets.only(
                                  right: format == _ExportFormat.png ? 8 : 0,
                                ),
                                child: _ExportChoiceButton(
                                  label: format.label,
                                  selected: isSelected,
                                  onTap: _isSubmitting
                                      ? () {}
                                      : () {
                                          setState(() {
                                            _selectedFormat = format;
                                          });
                                        },
                                ),
                              ),
                            );
                          }).toList(growable: false),
                        ),
                        const SizedBox(height: 12),
                        const Text(
                          'Quality',
                          style: TextStyle(
                            color: Color(0xFFD4D4D3),
                            fontWeight: FontWeight.w700,
                            fontSize: 12.5,
                          ),
                        ),
                        const SizedBox(height: 8),
                        Wrap(
                          spacing: 8,
                          runSpacing: 8,
                          children: _ExportQualityPreset.values.map((quality) {
                            final bool isSelected = _selectedQuality == quality;
                            return _ExportChoiceChip(
                              label: quality.label,
                              selected: isSelected,
                              onTap: _isSubmitting
                                  ? () {}
                                  : () {
                                      setState(() {
                                        _selectedQuality = quality;
                                      });
                                    },
                            );
                          }).toList(growable: false),
                        ),
                      ],
                    ),
                  ),
                ),
                const SizedBox(height: 10),
                SizedBox(
                  width: double.infinity,
                  child: FilledButton(
                    style: FilledButton.styleFrom(
                      backgroundColor: _isSubmitting
                          ? const Color(0xFFA8B05A)
                          : kActiveAccent,
                      foregroundColor: kActiveAccentForeground,
                      padding: const EdgeInsets.symmetric(vertical: 13),
                      shape: RoundedRectangleBorder(
                        borderRadius: BorderRadius.circular(13),
                      ),
                    ),
                    onPressed: _isSubmitting ? null : _runExportNow,
                    child: Text(
                      _isSubmitting ? 'Exporting...' : 'Save To Gallery',
                      style: const TextStyle(
                        fontWeight: FontWeight.w800,
                        fontSize: 13.8,
                      ),
                    ),
                  ),
                ),
              ],
            ),
          ),
        ),
      ),
    );
  }
}

class _ExportOrbitPainter extends CustomPainter {
  const _ExportOrbitPainter({
    required this.phase,
    required this.progress,
    required this.indeterminate,
  });

  final double phase;
  final double progress;
  final bool indeterminate;

  @override
  void paint(Canvas canvas, Size size) {
    if (size.width <= 2 || size.height <= 2) return;
    final Rect ringRect = Rect.fromLTWH(
      0.9,
      0.9,
      size.width - 1.8,
      size.height - 1.8,
    );
    final double radius = math
        .min(14.0, math.min(ringRect.width, ringRect.height) * 0.08)
        .toDouble();
    final Path borderPath = _roundedRectBorderPathFromTopCenter(
      ringRect,
      radius,
    );
    final ui.PathMetric metric = borderPath.computeMetrics().first;
    final double totalLength = metric.length;

    final Paint trackPaint = Paint()
      ..style = PaintingStyle.stroke
      ..strokeWidth = 2.35
      ..strokeCap = StrokeCap.round
      ..color = const Color(0x2F9AA1AC);
    final Paint trackGlow = Paint()
      ..style = PaintingStyle.stroke
      ..strokeWidth = 4.8
      ..strokeCap = StrokeCap.round
      ..color = const Color(0x1B8C949E)
      ..maskFilter = const MaskFilter.blur(BlurStyle.normal, 1.9);
    canvas.drawPath(borderPath, trackGlow);
    canvas.drawPath(borderPath, trackPaint);

    final double clampedProgress = progress.clamp(0.0, 1.0);
    final double progressLength = totalLength * clampedProgress;
    if (indeterminate) {
      final double growth =
          Curves.easeOutCubic.transform(phase.clamp(0.0, 1.0));
      final double sweepFraction = 0.05 + (0.25 * growth);
      final double sweep = totalLength * sweepFraction;
      final double head = (phase * totalLength) % totalLength;
      final double tail = head - sweep;
      final Path orbitPath = _extractWrappedPath(
        metric: metric,
        start: tail,
        end: head,
        totalLength: totalLength,
      );
      final Paint orbitGlow = Paint()
        ..style = PaintingStyle.stroke
        ..strokeCap = StrokeCap.round
        ..strokeWidth = 5.7
        ..color = const Color(0x3EF3FF8C)
        ..maskFilter = const MaskFilter.blur(BlurStyle.normal, 2.2);
      final Paint orbitPaint = Paint()
        ..style = PaintingStyle.stroke
        ..strokeCap = StrokeCap.round
        ..strokeWidth = 3.2
        ..shader = const LinearGradient(
          colors: <Color>[
            Color(0x08F3FF8C),
            Color(0xAAF3FF8C),
            Color(0xFFF3FF8C),
          ],
        ).createShader(ringRect);
      canvas.drawPath(orbitPath, orbitGlow);
      canvas.drawPath(orbitPath, orbitPaint);
      return;
    }

    if (progressLength > 0.15) {
      final Path donePath = metric.extractPath(0, progressLength);
      final Paint glowPaint = Paint()
        ..style = PaintingStyle.stroke
        ..strokeWidth = 5.0
        ..strokeCap = StrokeCap.round
        ..color = const Color(0x33E6F24A)
        ..maskFilter = const MaskFilter.blur(BlurStyle.normal, 2.1);
      canvas.drawPath(donePath, glowPaint);
      final Paint donePaint = Paint()
        ..style = PaintingStyle.stroke
        ..strokeWidth = 2.95
        ..strokeCap = StrokeCap.round
        ..shader = const LinearGradient(
          colors: <Color>[
            Color(0x50E6F24A),
            Color(0xFFEAF95A),
            Color(0xFFF7FFBF),
          ],
        ).createShader(ringRect);
      canvas.drawPath(donePath, donePaint);

      // Pulse rides over the already completed arc: it grows from the start
      // of progress up to the current progress end, then repeats smoothly.
      final double pulseT = Curves.easeInOutCubic.transform(phase);
      final double pulseEnd = (progressLength * pulseT).clamp(
        0.0,
        progressLength,
      );
      if (pulseEnd > 0.8) {
        final Path pulsePath = metric.extractPath(0, pulseEnd);
        final Paint pulseGlow = Paint()
          ..style = PaintingStyle.stroke
          ..strokeWidth = 6.6
          ..strokeCap = StrokeCap.round
          ..color = const Color(0x4FF3FF8C)
          ..maskFilter = const MaskFilter.blur(BlurStyle.normal, 2.5);
        final Paint pulsePaint = Paint()
          ..style = PaintingStyle.stroke
          ..strokeWidth = 3.7
          ..strokeCap = StrokeCap.round
          ..shader = const LinearGradient(
            colors: <Color>[
              Color(0x18F3FF8C),
              Color(0x88F3FF8C),
              Color(0xFFF3FF8C),
            ],
          ).createShader(ringRect);
        canvas.drawPath(pulsePath, pulseGlow);
        canvas.drawPath(pulsePath, pulsePaint);
      }
    }

    if (clampedProgress < 0.999) {
      final double headPosition =
          progressLength.clamp(0.0, totalLength).toDouble();
      final double headSweep = (totalLength * 0.048).clamp(
        totalLength * 0.022,
        totalLength * 0.09,
      );
      final double headStart =
          (headPosition - headSweep).clamp(0.0, totalLength).toDouble();
      final Path headPath = metric.extractPath(headStart, headPosition);
      final Paint headGlow = Paint()
        ..style = PaintingStyle.stroke
        ..strokeWidth = 5.5
        ..strokeCap = StrokeCap.round
        ..color = const Color(0x3DF6FFB0)
        ..maskFilter = const MaskFilter.blur(BlurStyle.normal, 2.1);
      final Paint headPaint = Paint()
        ..style = PaintingStyle.stroke
        ..strokeWidth = 3.25
        ..strokeCap = StrokeCap.round
        ..color = const Color(0xFFF5FFAC);
      canvas.drawPath(headPath, headGlow);
      canvas.drawPath(headPath, headPaint);

      final ui.Tangent? tangent = metric.getTangentForOffset(headPosition);
      if (tangent != null) {
        const double dotRadius = 3.0;
        canvas.drawCircle(
          tangent.position,
          dotRadius + 1.8,
          Paint()
            ..style = PaintingStyle.fill
            ..color = const Color(0x40F5FFAC)
            ..maskFilter = const MaskFilter.blur(BlurStyle.normal, 1.9),
        );
        canvas.drawCircle(
          tangent.position,
          dotRadius,
          Paint()
            ..style = PaintingStyle.fill
            ..color = const Color(0xFFF5FFAC),
        );
      }
    }
  }

  Path _extractWrappedPath({
    required ui.PathMetric metric,
    required double start,
    required double end,
    required double totalLength,
  }) {
    double from = start;
    double to = end;
    while (from < 0) {
      from += totalLength;
      to += totalLength;
    }
    final double wrappedFrom = from % totalLength;
    final double wrappedTo = to % totalLength;
    if (wrappedTo >= wrappedFrom) {
      return metric.extractPath(wrappedFrom, wrappedTo);
    }
    return Path()
      ..addPath(metric.extractPath(wrappedFrom, totalLength), Offset.zero)
      ..addPath(metric.extractPath(0, wrappedTo), Offset.zero);
  }

  Path _roundedRectBorderPathFromTopCenter(Rect rect, double radius) {
    final double r = radius.clamp(0.0, math.min(rect.width, rect.height) / 2);
    final double cx = rect.center.dx;
    final Path path = Path()
      ..moveTo(cx, rect.top)
      ..lineTo(rect.right - r, rect.top)
      ..arcToPoint(
        Offset(rect.right, rect.top + r),
        radius: Radius.circular(r),
        clockwise: true,
      )
      ..lineTo(rect.right, rect.bottom - r)
      ..arcToPoint(
        Offset(rect.right - r, rect.bottom),
        radius: Radius.circular(r),
        clockwise: true,
      )
      ..lineTo(rect.left + r, rect.bottom)
      ..arcToPoint(
        Offset(rect.left, rect.bottom - r),
        radius: Radius.circular(r),
        clockwise: true,
      )
      ..lineTo(rect.left, rect.top + r)
      ..arcToPoint(
        Offset(rect.left + r, rect.top),
        radius: Radius.circular(r),
        clockwise: true,
      )
      ..lineTo(cx, rect.top);
    return path;
  }

  @override
  bool shouldRepaint(covariant _ExportOrbitPainter oldDelegate) {
    return oldDelegate.phase != phase ||
        oldDelegate.progress != progress ||
        oldDelegate.indeterminate != indeterminate;
  }
}

class _NavItem extends StatelessWidget {
  const _NavItem({required this.icon, required this.label, this.onTap});

