class _TextLocaleToggleButton extends StatelessWidget {
  const _TextLocaleToggleButton({
    required this.label,
    required this.selected,
    required this.onTap,
    this.scale = 1.0,
    this.fontFamily,
  });

  final String label;
  final bool selected;
  final VoidCallback onTap;
  final double scale;
  final String? fontFamily;

  @override
  Widget build(BuildContext context) {
    final double clampedScale = scale.clamp(0.65, 1.2).toDouble();
    final double buttonHeight = (40 * clampedScale).clamp(30, 44).toDouble();
    final double cornerRadius = (10 * clampedScale).clamp(8, 12).toDouble();
    final double fontSize = (14.5 * clampedScale).clamp(11, 15).toDouble();
    return _BouncyInkWell(
      onTap: onTap,
      pressedScale: 0.965,
      borderRadius: BorderRadius.circular(cornerRadius),
      child: Container(
        height: buttonHeight,
        alignment: Alignment.center,
        decoration: BoxDecoration(
          color: selected ? kActiveAccent : WonderPicEditorScreen._panelBg,
          borderRadius: BorderRadius.circular(cornerRadius),
          border: Border.all(
            color: selected ? Colors.transparent : const Color(0x2B4F5358),
            width: selected ? 0 : 0.55,
          ),
        ),
        child: Text(
          label,
          style: TextStyle(
            color: selected ? kActiveAccentForeground : const Color(0xFFB8B7B5),
            fontWeight: FontWeight.w700,
            fontSize: fontSize,
            fontFamily: fontFamily,
          ),
        ),
      ),
    );
  }
}

class _BouncyInkWell extends StatefulWidget {
  const _BouncyInkWell({
    required this.child,
    required this.onTap,
    this.borderRadius,
    this.pressedScale = 0.96,
    this.duration = const Duration(milliseconds: 120),
  });

  final Widget child;
  final VoidCallback? onTap;
  final BorderRadius? borderRadius;
  final double pressedScale;
  final Duration duration;

  @override
  State<_BouncyInkWell> createState() => _BouncyInkWellState();
}

class _BouncyInkWellState extends State<_BouncyInkWell> {
  bool _pressed = false;

  @override
  Widget build(BuildContext context) {
    final bool enabled = widget.onTap != null;
    return AnimatedScale(
      scale: _pressed && enabled ? widget.pressedScale : 1,
      duration: widget.duration,
      curve: Curves.easeOutBack,
      child: Material(
        color: Colors.transparent,
        child: InkWell(
          onTap: widget.onTap,
          borderRadius: widget.borderRadius,
          onHighlightChanged: (value) {
            if (_pressed == value) return;
            setState(() {
              _pressed = value;
            });
          },
          child: widget.child,
        ),
      ),
    );
  }
}

class _SettingsSliderTile extends StatelessWidget {
  const _SettingsSliderTile({
    required this.label,
    required this.value,
    required this.min,
    required this.max,
    required this.valueText,
    required this.onChanged,
    this.scale = 1.0,
    this.showHeader = true,
    this.compact = false,
  });

  final String label;
  final double value;
  final double min;
  final double max;
  final String valueText;
  final ValueChanged<double> onChanged;
  final double scale;
  final bool showHeader;
  final bool compact;

  @override
  Widget build(BuildContext context) {
    final double clampedScale = scale.clamp(0.65, 1.2).toDouble();
    final bool compactNoHeader = compact && !showHeader;
    final double padH = compact
        ? (7 * clampedScale).clamp(5, 8).toDouble()
        : (10 * clampedScale).clamp(8, 12).toDouble();
    final double padTop = compactNoHeader
        ? (2.2 * clampedScale).clamp(1.2, 3).toDouble()
        : compact
            ? (6 * clampedScale).clamp(4, 7).toDouble()
            : (10 * clampedScale).clamp(8, 12).toDouble();
    final double padBottom = compactNoHeader
        ? (0.6 * clampedScale).clamp(0.2, 1).toDouble()
        : compact
            ? (1.2 * clampedScale).clamp(0.6, 2).toDouble()
            : (6 * clampedScale).clamp(4, 8).toDouble();
    final double radius = compact
        ? (10 * clampedScale).clamp(8, 10).toDouble()
        : (12 * clampedScale).clamp(9, 12).toDouble();
    final double labelFont = (12.5 * clampedScale).clamp(10, 13).toDouble();
    final double valueFont = (11.5 * clampedScale).clamp(9.5, 12).toDouble();
    final double trackHeight = compact ? 2.2 : 3.2;
    final double thumbRadius = compact ? 6.6 : 9;
    final double overlayRadius = compact ? 10 : 15;
    return Theme(
      data: Theme.of(context).copyWith(
        materialTapTargetSize: MaterialTapTargetSize.shrinkWrap,
        sliderTheme: SliderThemeData(
          activeTrackColor: const Color(0xFFC3CBD9),
          inactiveTrackColor: const Color(0xFF3A3D42),
          thumbColor: const Color(0xFFF3F6FC),
