double _cloneHardnessToHardRadiusFactor(double hardness) {
  final double normalized = (hardness / 100).clamp(0.0, 1.0);
  if (normalized <= 0) return 0;
  if (normalized >= 1) return 1;
  // Non-linear mapping so softness reaches deeper into the brush body,
  // especially around 70-85 hardness.
  return math.pow(normalized, 2.1).toDouble();
}

double _cloneSoftEdgeAlpha(double edgeT) {
  final double t = edgeT.clamp(0.0, 1.0);
  return math.pow(1.0 - t, 1.35).toDouble();
}

double _cloneStampSpacingPx({
  required double radiusPx,
  required double hardness,
}) {
  final double hardFactor = (hardness / 100).clamp(0.0, 1.0);
  final double spacingFactor = 0.16 + ((1.0 - hardFactor) * 0.14);
  return (radiusPx * spacingFactor).clamp(0.35, 14.0).toDouble();
}

double _cloneFlowOpacityFactor({
  required double baseOpacityFactor,
  required double radiusPx,
  required double stampSpacingPx,
  required bool stationary,
}) {
  final double base = baseOpacityFactor.clamp(0.0, 1.0);
  if (stationary) return base;
  final double spacingRatio =
      (stampSpacingPx / math.max(1.0, radiusPx)).clamp(0.08, 1.0);
  final double flowScale = math.pow(spacingRatio, 0.9).toDouble();
  return (base * flowScale).clamp(0.0, 1.0);
}

bool _isUvInsideUnitSquare(Offset uv) {
  return uv.dx >= 0.0 && uv.dx <= 1.0 && uv.dy >= 0.0 && uv.dy <= 1.0;
}

