  Offset _lastGestureFocal = Offset.zero;

  Offset _layerStartPosition = Offset.zero;
  Offset _layerStartScenePoint = Offset.zero;
  double _layerStartScale = 1.0;
  double _layerStartRotation = 0.0;
  Offset _transformStartCenterScene = Offset.zero;
  double _transformStartWidthScene = 0;
  double _transformStartHeightScene = 0;
  double _transformStartRotation = 0;
  double _resizeStartAabbHalfX = 1;
  double _resizeStartAabbHalfY = 1;
  Offset _resizeStartDirection = const Offset(1, 0);
  double _resizeStartProjection = 1.0;
  double _lastResizeAppliedScale = 1.0;
  double _rotateStartAngle = 0.0;
  bool _moveSnapXActive = false;
  bool _moveSnapYActive = false;
  bool _resizeSnapActive = false;
  bool _rotationSnapActive = false;
  Offset _overlayCutStartCenterUv = Offset.zero;
  double _overlayCutStartScaleX = 0.5;
  double _overlayCutStartScaleY = 0.5;
  double _overlayCutStartRotation = 0.0;
  double _overlayCutRotateStartAngle = 0.0;
  Offset _overlayCutResizeStartDirection = const Offset(1, 0);
  double _overlayCutResizeStartProjection = 1.0;
  _OverlayCutResizeHandle _overlayCutResizeHandle =
      _OverlayCutResizeHandle.corner;
  Rect _overlayCutStartRectLocal = Rect.zero;
  Rect _cropStartRectUv = Rect.zero;
  _CropResizeHandle _cropResizeHandle = _CropResizeHandle.bottomRight;
  _ExpandResizeHandle _expandResizeHandle = _ExpandResizeHandle.right;
  double _expandStartLeft = 0.0;
  double _expandStartTop = 0.0;
  double _expandStartRight = 0.0;
  double _expandStartBottom = 0.0;
  Offset? _marqueeStartUv;
  final List<Offset> _freeMarqueePointsUv = <Offset>[];
  Offset? _pendingCloneDownScenePoint;
  bool _cloneHandledByScaleGesture = false;
  _SnapSession? _snapSession;
  List<_SmartGuideSegment> _smartGuideSegments = const <_SmartGuideSegment>[];
  Timer? _smartGuideAutoHideTimer;
  int _panSettleAnimationToken = 0;
  final TextEditingController _inlineTextController = TextEditingController();
  final FocusNode _inlineTextFocusNode = FocusNode();
  String? _inlineEditLayerId;
  _InlineTextEditorSession? _inlineEditSession;
  String _inlineEditInitialValue = '';
  bool _inlineEditHistoryCaptured = false;
  bool _isSyncingInlineText = false;
  Ticker? _visualEffectTicker;
  double _expandPreviewPhase = 0.0;
  bool _expandViewportPrepared = false;
  double _upscaleMagicPhase = 0.0;
  Offset? _expandViewportPanBefore;
  double? _expandViewportScaleBefore;
  bool _hasCapturedExpandViewport = false;
  static const Duration _expandViewportEnterDuration =
      Duration(milliseconds: 320);
  static const Duration _expandViewportExitDuration =
      Duration(milliseconds: 300);

  static const double _minScale = 0.2;
  static const double _maxScale = 8.0;

  @override
  void initState() {
    super.initState();
    _cloneSourceTapMode = widget.isCloneSourceArmed;
    _inlineTextController.addListener(_onInlineTextChanged);
    _inlineTextFocusNode.addListener(_onInlineTextFocusChanged);
    _syncVisualEffectTicker();
  }

  bool get _isExpandToolActive {
    return widget.isToolEnabled &&
        widget.activeTool == EditorTool.expand &&
        widget.expandToolConfig != null;
  }

  bool get _isUpscaleMagicActive {
    return widget.showUpscaleMagicEffect &&
        widget.upscaleMagicLayerId != null &&
        widget.upscaleMagicLayerId!.isNotEmpty;
  }

  void _syncVisualEffectTicker() {
    final bool shouldRun = _isExpandToolActive || _isUpscaleMagicActive;
    if (shouldRun) {
      if (_visualEffectTicker == null) {
        _visualEffectTicker = createTicker(_onVisualEffectTick)..start();
      } else if (!(_visualEffectTicker!.isActive)) {
        _visualEffectTicker!.start();
      }
      return;
    }
    _visualEffectTicker?.dispose();
    _visualEffectTicker = null;
  }

  void _onVisualEffectTick(Duration elapsed) {
    if (!mounted) return;
    final double seconds = elapsed.inMicroseconds / 1000000.0;
    if (_isExpandToolActive) {
      _expandPreviewPhase = (seconds * 0.58) % 1.0;
    }
    if (_isUpscaleMagicActive) {
      _upscaleMagicPhase = (seconds * 0.66) % 1.0;
    }
    _repaintCanvas();
  }

  @override
  Widget build(BuildContext context) {
    return LayoutBuilder(
      builder: (context, constraints) {
        final Size canvasSize = Size(
          constraints.maxWidth,
          constraints.maxHeight,
        );
        _lastCanvasSize = canvasSize;
        if (_isExpandToolActive && !_expandViewportPrepared) {
          WidgetsBinding.instance.addPostFrameCallback((_) {
            if (!mounted) return;
            _maybePrepareExpandViewport();
          });
        }

        final Widget canvasSurface = GestureDetector(
          behavior: HitTestBehavior.opaque,
          onTapDown: (details) => _onTapDown(details, canvasSize),
          onTapUp: (details) => _onTapUp(details, canvasSize),
          onTapCancel: _onTapCancel,
          onScaleStart: (details) => _onScaleStart(details, canvasSize),
          onScaleUpdate: (details) => _onScaleUpdate(details, canvasSize),
          onScaleEnd: _onScaleEnd,
          onDoubleTapDown: (details) => _onDoubleTapDown(details, canvasSize),
          child: CustomPaint(
            painter: _SkiaCanvasPainter(
              repaint: _canvasRepaintTick,
              strokes: widget.pencilStrokes,
              activeStrokeResolver: () {
                if (_interaction != _CanvasInteraction.drawing) return null;
                return _activeStroke;
              },
              layers: widget.layers,
              pan: _pan,
              scale: _scale,
              selectedLayerId: widget.selectedLayerId,
              activeTool: widget.activeTool,
              isToolEnabled: widget.isToolEnabled,
              editableImages: _editableImages,
              cloneSettings: widget.cloneSettings,
              showCloneBrushPreview: widget.showCloneBrushPreview,
              cloneSourcePointerUvResolver: _activeClonePointerUv,
              showCloneTargetPointer: widget.showCloneJoystickCursor,
              cloneTargetPointerUvResolver: _activeCloneTargetPointerUv,
              adaptiveImageResolver: _resolveImageForPaint,
              rotateHandleDistance: _topRotateHandleDistance,
              moveHandleDistance: _bottomMoveHandleDistance,
              marqueeSelection: widget.marqueeSelection,
              overlayCutConfig: widget.overlayCutConfig,
              cropToolConfig: widget.cropToolConfig,
              expandToolConfig: widget.expandToolConfig,
              expandAnimationPhaseResolver: () => _expandPreviewPhase,
              sketchMaskLayerId: widget.sketchMaskLayerId,
              sketchMaskStrokes: widget.sketchMaskStrokes,
              activeSketchMaskStrokeResolver: _activeSketchMaskStroke,
              hiddenTextLayerId: _inlineEditLayerId,
              smartGuidesResolver: () => _smartGuideSegments,
              showSmartGuidesResolver: () =>
                  _interaction == _CanvasInteraction.movingLayer ||
                  _interaction == _CanvasInteraction.resizingLayer ||
                  _interaction == _CanvasInteraction.rotatingLayer,
              showUpscaleMagicEffect: widget.showUpscaleMagicEffect,
              upscaleMagicLayerId: widget.upscaleMagicLayerId,
              upscaleMagicPhaseResolver: () => _upscaleMagicPhase,
            ),
            child: const SizedBox.expand(),
          ),
        );
        return Stack(
          fit: StackFit.expand,
          children: [
            canvasSurface,
            _buildSketchMaskBrushPreviewOverlay(canvasSize),
            _buildInlineTextEditor(canvasSize),
          ],
        );
      },
    );
  }

  Widget _buildSketchMaskBrushPreviewOverlay(Size canvasSize) {
    if (!widget.showSketchMaskBrushPreview ||
        !widget.sketchMaskDrawingEnabled ||
        !widget.isToolEnabled) {
      return const SizedBox.shrink();
    }
    final double diameter =
        widget.sketchMaskBrushPreviewSize.clamp(8.0, 220.0).toDouble();
    final Offset center = _resolveSketchMaskBrushPreviewCenter(canvasSize) ??
        Offset(canvasSize.width / 2, canvasSize.height / 2);
    final double left = (center.dx - (diameter / 2))
        .clamp(0.0, math.max(0.0, canvasSize.width - diameter))
        .toDouble();
    final double top = (center.dy - (diameter / 2))
        .clamp(0.0, math.max(0.0, canvasSize.height - diameter))
        .toDouble();
    return Positioned(
      left: left,
      top: top,
      child: IgnorePointer(
        child: Container(
          width: diameter,
          height: diameter,
          decoration: BoxDecoration(
            shape: BoxShape.circle,
            color: const Color(0x22FFFFFF),
            border: Border.all(
              color: const Color(0xBFFFFFFF),
              width: 1.25,
            ),
            boxShadow: const <BoxShadow>[
              BoxShadow(
                color: Color(0x220F172A),
                blurRadius: 10,
                spreadRadius: 0,
                offset: Offset(2, 4),
              ),
            ],
          ),
        ),
      ),
    );
  }

  Offset? _resolveSketchMaskBrushPreviewCenter(Size canvasSize) {
    final EditorLayer? workspace = _backgroundLayer(widget.layers);
    if (workspace == null) return null;
    final Size? workspaceSize = _workspaceSourceSize(workspace);
    if (workspaceSize == null) return null;
    final Rect artboard = _computeArtboardRect(
      canvasSize: canvasSize,
      workspaceSize: workspaceSize,
    );
    // Keep preview indicator stable while slider changes to avoid visual jitter.
    return _toViewportPoint(artboard.center);
  }

  Widget _buildInlineTextEditor(Size canvasSize) {
    final _InlineTextEditorLayout? layout =
        _resolveInlineTextEditorLayout(canvasSize);
    if (layout == null) {
      return const SizedBox.shrink();
    }
    final String currentText = _inlineTextController.text;
    final bool isArabic = _containsArabicCharacters(currentText);
    final TextDirection direction =
        isArabic ? TextDirection.rtl : TextDirection.ltr;
    final TextAlign align = isArabic ? TextAlign.right : TextAlign.left;
    final MediaQueryData noScaleMedia =
        MediaQuery.of(context).copyWith(textScaler: TextScaler.noScaling);
    return Positioned.fromRect(
      rect: layout.rect,
      child: Transform.rotate(
        angle: layout.rotation,
        alignment: Alignment.center,
        child: MediaQuery(
          data: noScaleMedia,
          child: TextField(
            controller: _inlineTextController,
            focusNode: _inlineTextFocusNode,
            keyboardType: TextInputType.text,
            textInputAction: TextInputAction.done,
            minLines: 1,
            maxLines: 1,
            autocorrect: false,
            enableSuggestions: false,
            enableInteractiveSelection: true,
            showCursor: true,
            scrollPadding: EdgeInsets.zero,
            textAlign: align,
            textDirection: direction,
            textAlignVertical: TextAlignVertical.center,
            cursorColor: const Color(0xFF334155),
            cursorWidth: 2.0,
            selectionHeightStyle: ui.BoxHeightStyle.tight,
            selectionWidthStyle: ui.BoxWidthStyle.tight,
            strutStyle: StrutStyle(
              fontSize: layout.fontSize,
              height: 1.05,
              forceStrutHeight: true,
            ),
            style: TextStyle(
              fontSize: layout.fontSize,
              height: 1.05,
              color: (layout.layer.textColor ?? const Color(0xFF1F2937))
                  .withOpacity(
                (((layout.layer.textColor ?? const Color(0xFF1F2937)).opacity) *
                        ((layout.layer.textOpacity ?? 100) / 100))
                    .clamp(0.0, 1.0),
              ),
              fontFamily: layout.layer.textFontFamily,
              fontWeight:
                  _fontWeightFromNumeric(layout.layer.textFontWeight ?? 400),
            ),
            decoration: const InputDecoration(
              border: InputBorder.none,
              isDense: true,
              contentPadding: EdgeInsets.symmetric(horizontal: 8, vertical: 0),
            ),
          ),
        ),
      ),
    );
  }

  _InlineTextEditorLayout? _resolveInlineTextEditorLayout(Size canvasSize) {
    final String? layerId = _inlineEditLayerId;
    if (layerId == null) return null;
    final EditorLayer? layer = _layerById(layerId);
    if (layer == null ||
        layer.type != EditorLayerType.text ||
        !layer.isVisible) {
      return null;
    }
    final EditorLayer? workspace = _backgroundLayer(widget.layers);
    if (workspace == null) return null;
    final Size? workspaceSize = _workspaceSourceSize(workspace);
    if (workspaceSize == null) return null;
    final Rect artboard = _computeArtboardRect(
      canvasSize: canvasSize,
      workspaceSize: workspaceSize,
    );
    final _TextLayerSceneData? data = _buildTextLayerSceneData(
      layer: layer,
      artboard: artboard,
      workspaceSize: workspaceSize,
      rotateHandleDistance: _topRotateHandleDistance,
      moveHandleDistance: _bottomMoveHandleDistance,
    );
    if (data == null) return null;
    final _InlineTextEditorSession session =
        _inlineEditSession != null && _inlineEditSession!.layerId == layerId
            ? _inlineEditSession!
            : _createInlineTextEditorSession(
                layerId: layer.id,
                layer: layer,
                data: data,
                artboard: artboard,
                workspaceSize: workspaceSize,
              );
    _inlineEditSession = session;
    final Offset centerViewport = _toViewportPoint(session.centerScene);
    final double fontSize =
        math.max(10, session.fontSizeScene * _scale).toDouble();
    final double width = math.max(72, session.widthScene * _scale).toDouble();
    final double height = math.max(44, session.heightScene * _scale).toDouble();
    final Rect rect = Rect.fromCenter(
      center: centerViewport,
      width: width,
      height: height,
    );
    return _InlineTextEditorLayout(
      layer: layer,
      rect: rect,
      rotation: session.rotation,
      fontSize: fontSize,
    );
  }

  _InlineTextEditorSession _createInlineTextEditorSession({
    required String layerId,
    required EditorLayer layer,
    required _TextLayerSceneData data,
    required Rect artboard,
    required Size workspaceSize,
  }) {
    final double unitScale = artboard.width / workspaceSize.width;
    final double fontSizeScene =
        ((layer.textFontSize ?? 92) * unitScale * layer.layerScale)
            .clamp(8, 500)
            .toDouble();
    final double widthScene = math.max(
      72 / _scale,
      data.width + (28 / _scale),
    );
    final double heightScene = math.max(
      44 / _scale,
      math.max(
        data.height + (18 / _scale),
        (fontSizeScene * 1.42) + (8 / _scale),
      ),
    );
    return _InlineTextEditorSession(
      layerId: layerId,
      centerScene: data.center,
      rotation: data.rotation,
      fontSizeScene: fontSizeScene,
      widthScene: widthScene,
      heightScene: heightScene,
    );
  }

  void _onInlineTextChanged() {
    if (_isSyncingInlineText) return;
    final String? layerId = _inlineEditLayerId;
    if (layerId == null) return;
    final String value = _inlineTextController.text;
    if (!_inlineEditHistoryCaptured && value != _inlineEditInitialValue) {
      _inlineEditHistoryCaptured = true;
      widget.onTextInlineEditStarted(layerId);
    }
    widget.onTextInlineChanged(layerId, value);
  }

  void _onInlineTextFocusChanged() {
    if (_inlineTextFocusNode.hasFocus) return;
    _closeInlineTextEditing();
  }

  void _startInlineTextEditing(String layerId) {
    final EditorLayer? layer = _layerById(layerId);
    if (layer == null ||
        layer.type != EditorLayerType.text ||
        !layer.isVisible) {
      return;
    }
    final String value = layer.textValue ?? 'Write your text here';
    _isSyncingInlineText = true;
    _inlineTextController.value = TextEditingValue(
      text: value,
      selection: TextSelection.collapsed(offset: value.length),
    );
    _isSyncingInlineText = false;
    _inlineEditInitialValue = value;
    _inlineEditHistoryCaptured = false;
    _inlineEditSession = null;
    if (_inlineEditLayerId != layerId) {
      setState(() {
        _inlineEditLayerId = layerId;
      });
    } else {
      _repaintCanvas();
    }
    WidgetsBinding.instance.addPostFrameCallback((_) {
      if (!mounted || _inlineEditLayerId != layerId) return;
      _inlineTextFocusNode.requestFocus();
    });
  }

  void _closeInlineTextEditing({bool rebuild = true}) {
    final String? layerId = _inlineEditLayerId;
    if (layerId == null) return;
    _inlineEditLayerId = null;
    _inlineEditSession = null;
    _inlineEditInitialValue = '';
    _inlineEditHistoryCaptured = false;
    widget.onTextInlineEditFinished(layerId);
    if (rebuild && mounted) {
      setState(() {});
    }
  }

  @override
  void dispose() {
    _visualEffectTicker?.dispose();
    _smartGuideAutoHideTimer?.cancel();
    _cancelPanSettleAnimation();
    _disposeAllMipmaps();
    _inlineTextController.removeListener(_onInlineTextChanged);
    _inlineTextFocusNode.removeListener(_onInlineTextFocusChanged);
    _inlineTextController.dispose();
    _inlineTextFocusNode.dispose();
    _canvasRepaintTick.dispose();
    super.dispose();
  }

  @override
  void didUpdateWidget(covariant _SkiaEditorCanvas oldWidget) {
    super.didUpdateWidget(oldWidget);
    final bool wasExpandToolActive = oldWidget.isToolEnabled &&
        oldWidget.activeTool == EditorTool.expand &&
        oldWidget.expandToolConfig != null;
    final bool isExpandToolActive = _isExpandToolActive;
    if (!wasExpandToolActive && isExpandToolActive) {
      _expandViewportPrepared = false;
      _captureViewportBeforeExpand();
    } else if (wasExpandToolActive && !isExpandToolActive) {
      _expandViewportPrepared = false;
      _restoreViewportAfterExpandExit();
    } else if (!isExpandToolActive) {
      _expandViewportPrepared = false;
      _clearCapturedExpandViewport();
    }
    _syncVisualEffectTicker();
    if (oldWidget.isCloneSourceArmed != widget.isCloneSourceArmed) {
      _cloneSourceTapMode = widget.isCloneSourceArmed;
    }
    if (oldWidget.cloneClearRequestToken != widget.cloneClearRequestToken) {
      unawaited(_clearCloneEditsOnSelectedLayer());
    }
    if (oldWidget.cloneJoystickDrawPressed &&
        !widget.cloneJoystickDrawPressed) {
      _finalizeCloneStrokeFromJoystick();
    }
    if (oldWidget.inlineTextEditRequestToken !=
        widget.inlineTextEditRequestToken) {
      final String? requestedLayerId = widget.inlineTextEditRequestLayerId;
      if (requestedLayerId != null) {
        _startInlineTextEditing(requestedLayerId);
      }
    }
    if (_inlineEditLayerId != null) {
      final EditorLayer? editingLayer = _layerById(_inlineEditLayerId);
      final bool shouldClose = editingLayer == null ||
          editingLayer.type != EditorLayerType.text ||
          !editingLayer.isVisible ||
          widget.selectedLayerId != editingLayer.id ||
          widget.activeTool != EditorTool.text;
      if (shouldClose) {
        _closeInlineTextEditing(rebuild: false);
      }
    }
    if (widget.activeTool != EditorTool.clone || !widget.isToolEnabled) {
      _cloneSourceTapMode = false;
      _clonePreviewSourceSnapshot = null;
      _clonePreviewSourceLayerId = null;
      _finalizeCloneStrokeFromJoystick();
    }
    final EditorLayer? oldBackground = _backgroundLayer(oldWidget.layers);
    final EditorLayer? newBackground = _backgroundLayer(widget.layers);
    final Size? oldSize =
        oldBackground == null ? null : _workspaceSourceSize(oldBackground);
    final Size? newSize =
        newBackground == null ? null : _workspaceSourceSize(newBackground);
    if (widget.activeTool != EditorTool.pencil &&
        _interaction == _CanvasInteraction.drawing) {
      _activeStroke = null;
      _interaction = _CanvasInteraction.none;
    }
    if (((widget.activeTool != EditorTool.sketchReplace &&
                widget.activeTool != EditorTool.replaceObject) ||
            !widget.sketchMaskDrawingEnabled ||
            !widget.isToolEnabled) &&
        _interaction == _CanvasInteraction.sketchMasking) {
      _interaction = _CanvasInteraction.none;
      _gestureLayerId = null;
      _activeSketchMaskPointsUv.clear();
      _activeSketchMaskRadiusUv = 0;
      _pendingSketchMaskStartScenePoint = null;
      _repaintCanvas();
    }
    if (!widget.isToolEnabled &&
        widget.overlayCutConfig == null &&
        widget.cropToolConfig == null &&
        widget.expandToolConfig == null) {
      _activeStroke = null;
      _activeSketchMaskPointsUv.clear();
      _activeSketchMaskRadiusUv = 0;
      _pendingSketchMaskStartScenePoint = null;
      _interaction = _CanvasInteraction.none;
      _gestureLayerId = null;
      _activeCloneStroke = null;
      _cloneOffsetUv = null;
      _lastCloneDestUv = null;
      _cloneChangedLayer = false;
      _pendingCloneSegments.clear();
      _cloneWorkFrameScheduled = false;
      _clonePreviewSourceSnapshot = null;
      _clonePreviewSourceLayerId = null;
      _marqueeStartUv = null;
      _freeMarqueePointsUv.clear();
      _pendingCloneDownScenePoint = null;
      _pendingSketchMaskStartScenePoint = null;
      _cloneJoystickStrokeActive = false;
    }
    if (widget.activeTool != EditorTool.clone &&
        _interaction == _CanvasInteraction.cloning) {
      _interaction = _CanvasInteraction.none;
      _gestureLayerId = null;
      _activeCloneStroke = null;
      _cloneOffsetUv = null;
      _lastCloneDestUv = null;
      _cloneChangedLayer = false;
      _pendingCloneSegments.clear();
      _cloneWorkFrameScheduled = false;
      _clonePreviewSourceSnapshot = null;
      _clonePreviewSourceLayerId = null;
      _cloneJoystickStrokeActive = false;
    }
    if (widget.activeTool != EditorTool.marquee &&
        _interaction == _CanvasInteraction.marqueeSelecting) {
      _interaction = _CanvasInteraction.none;
      _gestureLayerId = null;
      _marqueeStartUv = null;
      _freeMarqueePointsUv.clear();
    }
    if (widget.overlayCutConfig == null &&
        (_interaction == _CanvasInteraction.overlayCutMoving ||
            _interaction == _CanvasInteraction.overlayCutResizing ||
            _interaction == _CanvasInteraction.overlayCutRotating)) {
      _interaction = _CanvasInteraction.none;
      _gestureLayerId = null;
    }
    if (widget.activeTool != EditorTool.crop &&
        (_interaction == _CanvasInteraction.cropMoving ||
            _interaction == _CanvasInteraction.cropResizing)) {
      _interaction = _CanvasInteraction.none;
      _gestureLayerId = null;
    }
    if (widget.cropToolConfig == null &&
        (_interaction == _CanvasInteraction.cropMoving ||
            _interaction == _CanvasInteraction.cropResizing)) {
      _interaction = _CanvasInteraction.none;
      _gestureLayerId = null;
    }
    if (widget.activeTool != EditorTool.expand &&
        _interaction == _CanvasInteraction.expandResizing) {
      _interaction = _CanvasInteraction.none;
      _gestureLayerId = null;
    }
    if (widget.expandToolConfig == null &&
        _interaction == _CanvasInteraction.expandResizing) {
      _interaction = _CanvasInteraction.none;
      _gestureLayerId = null;
    }
    if (widget.activeTool == EditorTool.clone) {
      _primeSelectedCloneLayerBitmap();
      if (widget.showCloneJoystickCursor) {
        final EditorLayer? selectedCloneLayer = _selectedImageLayerForClone();
        if (selectedCloneLayer != null) {
          _ensureCloneTargetCursorUv(selectedCloneLayer);
        }
      }
    }
    _cleanupCloneCaches();
    _cleanupMipmapCaches();

    final Map<String, EditorLayer> oldById = <String, EditorLayer>{
      for (final EditorLayer layer in oldWidget.layers) layer.id: layer,
    };
    for (final EditorLayer layer in widget.layers) {
      if (layer.type != EditorLayerType.image || layer.image == null) {
        continue;
      }
      final EditorLayer? oldLayer = oldById[layer.id];
      final bool imageChanged = oldLayer == null ||
          oldLayer.type != EditorLayerType.image ||
          !identical(oldLayer.image, layer.image);
      if (!imageChanged) continue;
      final _EditableImageBuffer? existing = _editableImages[layer.id];
      if (existing != null) {
        if (identical(existing.fullImage, layer.image)) {
          continue;
        }
        if (existing.isCommittingFull || existing.pendingCommits.isNotEmpty) {
          existing.fullImage = layer.image!;
          continue;
        }
      }
      _editableImages.remove(layer.id);
      _bitmapLoadInFlight.remove(layer.id);
    }

    if (oldBackground?.id != newBackground?.id ||
        oldBackground?.thumbnailBytes != newBackground?.thumbnailBytes ||
        oldSize != newSize ||
        oldBackground?.solidColor != newBackground?.solidColor) {
      setState(() {
        _activeStroke = null;
        _pan = Offset.zero;
        _scale = 1.0;
        _interaction = _CanvasInteraction.none;
        _gestureLayerId = null;
        _activeCloneStroke = null;
        _editableImages.clear();
        _disposeAllMipmaps();
        _bitmapLoadInFlight.clear();
        _cloneBrushMaskCache.clear();
        _clonePointerUvByLayer.clear();
        _cloneTargetCursorUvByLayer.clear();
        _cloneOffsetUv = null;
        _lastCloneDestUv = null;
        _cloneChangedLayer = false;
        _clonePreviewSourceSnapshot = null;
        _clonePreviewSourceLayerId = null;
        _cloneJoystickStrokeActive = false;
        _clearCapturedExpandViewport();
      });
      _repaintCanvas();
    }
  }

  void _repaintCanvas() {
    _canvasRepaintTick.value++;
  }

  void _captureViewportBeforeExpand() {
    if (_hasCapturedExpandViewport) return;
    _expandViewportPanBefore = _pan;
    _expandViewportScaleBefore = _scale;
    _hasCapturedExpandViewport = true;
  }

  void _clearCapturedExpandViewport() {
    _expandViewportPanBefore = null;
    _expandViewportScaleBefore = null;
    _hasCapturedExpandViewport = false;
  }

  void _restoreViewportAfterExpandExit() {
    if (!_hasCapturedExpandViewport) return;
    _cancelPanSettleAnimation();
    final Offset targetPan = _expandViewportPanBefore ?? Offset.zero;
    final double targetScale = (_expandViewportScaleBefore ?? 1.0)
        .clamp(_minScale, _maxScale)
        .toDouble();
    _startPanSettleAnimation(
      targetPan,
      targetScale: targetScale,
      duration: _expandViewportExitDuration,
      curve: Curves.easeInOutCubic,
    );
    _clearCapturedExpandViewport();
  }

  void _maybePrepareExpandViewport() {
    if (!_isExpandToolActive || _expandViewportPrepared) return;
    if (_lastCanvasSize.width <= 0 || _lastCanvasSize.height <= 0) return;
    final EditorLayer? workspace = _backgroundLayer(widget.layers);
    if (workspace == null) return;
    final Size? workspaceSize = _workspaceSourceSize(workspace);
    if (workspaceSize == null) return;
    final Rect artboard = _computeArtboardRect(
      canvasSize: _lastCanvasSize,
      workspaceSize: workspaceSize,
    );
    final _ImageLayerSceneData? layerData = _activeExpandLayerData(
      artboard: artboard,
      workspaceSize: workspaceSize,
    );
    if (layerData == null) return;
    final double halfW = layerData.width / 2;
    final double halfH = layerData.height / 2;
    final double cosR = math.cos(layerData.rotation).abs();
    final double sinR = math.sin(layerData.rotation).abs();
    // Center the selected image and leave symmetric room on all sides
    // so handle dragging feels comfortable when entering Expand mode.
    double aabbHalfW = (halfW * cosR) + (halfH * sinR);
    double aabbHalfH = (halfW * sinR) + (halfH * cosR);
    const double previewPaddingFactor = 1.34;
    aabbHalfW *= previewPaddingFactor;
    aabbHalfH *= previewPaddingFactor;
    const double viewportPadding = 30.0;
    final double availableW =
        math.max(80.0, _lastCanvasSize.width - (viewportPadding * 2));
    final double availableH =
        math.max(80.0, _lastCanvasSize.height - (viewportPadding * 2));
    final double fitScaleX = availableW / math.max(1.0, aabbHalfW * 2);
    final double fitScaleY = availableH / math.max(1.0, aabbHalfH * 2);
    final double fitScale = math
        .min(fitScaleX, fitScaleY)
        .clamp(_minScale, math.min(_maxScale, 0.88))
        .toDouble();
    // Keep entry motion as a smooth zoom-out only, so the canvas never jumps
    // into an unexpected zoom-in when the tool is activated.
    final double nextScale =
        math.min(_scale, fitScale).clamp(_minScale, _maxScale).toDouble();
    final Offset viewportCenter =
        Offset(_lastCanvasSize.width / 2, _lastCanvasSize.height / 2);
    final Offset targetPan = viewportCenter - (layerData.center * nextScale);
    if ((nextScale - _scale).abs() > 0.0001 ||
        (targetPan - _pan).distance > 0.0001) {
      _startPanSettleAnimation(
        targetPan,
        targetScale: nextScale,
        duration: _expandViewportEnterDuration,
        curve: Curves.easeOutCubic,
      );
    } else {
      _repaintCanvas();
    }
    _expandViewportPrepared = true;
  }

  void _cancelPanSettleAnimation() {
    _panSettleAnimationToken++;
  }

  void _startPanSettleAnimation(
    Offset target, {
    double? targetScale,
    Duration duration = const Duration(milliseconds: 150),
    Curve curve = Curves.easeOutCubic,
  }) {
    final Offset start = _pan;
    final double startScale = _scale;
    final double endScale =
        (targetScale ?? _scale).clamp(_minScale, _maxScale).toDouble();
    if ((target - start).distance <= 0.05 &&
        (endScale - startScale).abs() <= 0.0005) {
      return;
    }
    final int token = ++_panSettleAnimationToken;
    Duration? startTimestamp;

    void tick(Duration timestamp) {
      if (!mounted || token != _panSettleAnimationToken) return;
      startTimestamp ??= timestamp;
      final double t = ((timestamp - startTimestamp!).inMicroseconds /
              duration.inMicroseconds)
          .clamp(0.0, 1.0);
      final double eased = curve.transform(t);
      final Offset next = Offset.lerp(start, target, eased) ?? target;
      final double nextScale =
          ui.lerpDouble(startScale, endScale, eased) ?? endScale;
      if ((next - _pan).distance > 0.0001 ||
          (nextScale - _scale).abs() > 0.0001) {
        setState(() {
          _pan = next;
          _scale = nextScale;
        });
      }
      if (t < 1.0) {
        SchedulerBinding.instance.scheduleFrameCallback(tick);
      }
    }

    SchedulerBinding.instance.scheduleFrameCallback(tick);
    SchedulerBinding.instance.ensureVisualUpdate();
  }

  void _onScaleStart(ScaleStartDetails details, Size canvasSize) {
    _cancelPanSettleAnimation();
    if (_inlineEditLayerId != null) {
      _closeInlineTextEditing();
    }
    _finalizeCloneStrokeFromJoystick();
    _multiTouchInitialized = false;
    _lastGestureScaleFactor = 1.0;
    _lastGestureFocal = details.localFocalPoint;
    _interaction = _CanvasInteraction.none;
    _gestureLayerId = null;
    _activeCloneStroke = null;
    _activeSketchMaskPointsUv.clear();
    _activeSketchMaskRadiusUv = 0;
    _cloneOffsetUv = null;
    _lastCloneDestUv = null;
    _cloneChangedLayer = false;
    _pendingCloneSegments.clear();
    _cloneWorkFrameScheduled = false;
    _clonePreviewSourceSnapshot = null;
    _clonePreviewSourceLayerId = null;
    _cloneHandledByScaleGesture = false;
    _pendingSketchMaskStartScenePoint = null;
    _smartGuideAutoHideTimer?.cancel();
    _snapSession = null;
    _moveSnapXActive = false;
    _moveSnapYActive = false;
    _resizeSnapActive = false;
    _rotationSnapActive = false;
    _setSmartGuides(const <_SmartGuideSegment>[], forceRepaint: false);

    if (details.pointerCount > 1) {
      _activeStroke = null;
      _activeSketchMaskPointsUv.clear();
      _activeSketchMaskRadiusUv = 0;
      _pendingCloneDownScenePoint = null;
      _pendingSketchMaskStartScenePoint = null;
      _multiTouchInitialized = true;
      _lastGestureScaleFactor = 1.0;
      _lastGestureFocal = details.localFocalPoint;
      return;
    }

    final EditorLayer? workspace = _backgroundLayer(widget.layers);
    if (workspace == null) return;
    final Size? workspaceSize = _workspaceSourceSize(workspace);
    if (workspaceSize == null) return;

    final Rect artboard = _computeArtboardRect(
      canvasSize: canvasSize,
      workspaceSize: workspaceSize,
    );
    final Offset scenePoint = _toScenePoint(details.localFocalPoint);
    final _OverlayCutConfig? overlayCutConfig = widget.overlayCutConfig;
    final _ImageLayerSceneData? overlayCutLayerData = overlayCutConfig == null
        ? null
        : _activeOverlayCutLayerData(
            artboard: artboard,
            workspaceSize: workspaceSize,
          );
    final _CropToolConfig? cropToolConfig = widget.cropToolConfig;
    final _ImageLayerSceneData? cropLayerData = cropToolConfig == null
        ? null
        : _activeCropLayerData(
            artboard: artboard,
            workspaceSize: workspaceSize,
          );
    final _ExpandToolConfig? expandToolConfig = widget.expandToolConfig;
    final _ImageLayerSceneData? expandLayerData = expandToolConfig == null
        ? null
        : _activeExpandLayerData(
            artboard: artboard,
            workspaceSize: workspaceSize,
          );

    if (overlayCutConfig != null && overlayCutLayerData != null) {
      _activeStroke = null;
      final bool consumed = _startOverlayCutInteraction(
        scenePoint: scenePoint,
        layerData: overlayCutLayerData,
        config: overlayCutConfig,
      );
      if (consumed) {
        _repaintCanvas();
      }
      return;
    }

    if (cropToolConfig != null && cropLayerData != null) {
      _activeStroke = null;
      final bool consumed = _startCropInteraction(
        scenePoint: scenePoint,
        layerData: cropLayerData,
        config: cropToolConfig,
      );
      if (consumed) {
        _repaintCanvas();
      }
      return;
    }

    if (expandToolConfig != null && expandLayerData != null) {
      _activeStroke = null;
      final bool consumed = _startExpandInteraction(
        scenePoint: scenePoint,
        layerData: expandLayerData,
        config: expandToolConfig,
      );
      if (consumed) {
        _repaintCanvas();
      }
      return;
    }

    if (!widget.isToolEnabled) {
      _activeStroke = null;
      _activeSketchMaskPointsUv.clear();
      _activeSketchMaskRadiusUv = 0;
      return;
    }

    if ((widget.activeTool == EditorTool.sketchReplace ||
            widget.activeTool == EditorTool.replaceObject) &&
        widget.sketchMaskDrawingEnabled) {
      _activeStroke = null;
      _interaction = _CanvasInteraction.none;
      _gestureLayerId = null;
      _activeSketchMaskPointsUv.clear();
      _activeSketchMaskRadiusUv = 0;
      _pendingSketchMaskStartScenePoint = scenePoint;
      return;
    }

    if (widget.activeTool == EditorTool.pencil) {
      if (!artboard.contains(scenePoint)) return;
      final Offset local = scenePoint - artboard.topLeft;
      final PencilSettings settings = widget.pencilSettings;
      final _BrushStroke stroke = _BrushStroke(
        points: <Offset>[local],
        color: settings.color.withOpacity(settings.opacity / 100),
        width: settings.size,
        hardness: settings.hardness,
        brushType: settings.type,
        angle: settings.angle,
      );
      _activeStroke = stroke;
      _interaction = _CanvasInteraction.drawing;
      _repaintCanvas();
      return;
    }

    if (widget.activeTool == EditorTool.clone) {
      _activeStroke = null;
      final Offset seedPoint = _pendingCloneDownScenePoint ?? scenePoint;
      _pendingCloneDownScenePoint = null;
      _cloneHandledByScaleGesture = _startCloneGesture(
        scenePoint: seedPoint,
        artboard: artboard,
      );
      return;
    }

    if (widget.activeTool == EditorTool.marquee) {
      _activeStroke = null;
      _startMarqueeGesture(scenePoint: scenePoint, artboard: artboard);
      return;
    }

    if (widget.activeTool != EditorTool.move) {
      _activeStroke = null;
      return;
    }

    _activeStroke = null;
    final EditorLayer? selectedLayer = _layerById(widget.selectedLayerId);
    final _TransformLayerSceneData? selectedData =
        _buildSelectedTransformLayerData(
      selectedLayer: selectedLayer,
      artboard: artboard,
      workspaceSize: workspaceSize,
    );

    if (selectedData != null) {
      // Strict handle-only interaction: move/resize/rotate are triggered only
      // from their dedicated handles.
      final double minLayerExtent =
          math.min(selectedData.width, selectedData.height);
      final bool isImageOverlay = selectedLayer?.type == EditorLayerType.image;
      final double tinyBoost =
          ((72 - minLayerExtent).clamp(0, 48) / 48).toDouble();
      final double imageBoost = isImageOverlay ? 1.2 : 0.0;
      final double rotateHandleRadiusBase =
          ((18 / _scale).clamp(12, 22) + (tinyBoost * 8) + imageBoost)
              .clamp(12, 30);
      final double moveHandleRadiusBase =
          ((18 / _scale).clamp(12, 22) + (tinyBoost * 8) + imageBoost)
              .clamp(12, 30);
      final double cornerHandleRadiusBase =
          ((20 / _scale).clamp(12, 24) + (tinyBoost * 9) + imageBoost)
              .clamp(12, 32);
      // Handle-only interaction stays strict, but we add small hit-slop so
      // taps on the exact controls feel easier and more stable.
      final double handleHitSlop =
          ((8 / _scale).clamp(4, 12) + (tinyBoost * 3) + (imageBoost * 0.6))
              .clamp(4, 14);
      final double rotateHandleRadius =
          (rotateHandleRadiusBase + handleHitSlop).clamp(12, 38);
      final double moveHandleRadius =
          (moveHandleRadiusBase + handleHitSlop).clamp(12, 38);
      final double cornerHandleRadius =
          (cornerHandleRadiusBase + handleHitSlop).clamp(12, 40);

      final double rotateDistance =
          (scenePoint - selectedData.rotateHandle).distance;
      final double moveHandleDistance =
          (scenePoint - selectedData.moveHandle).distance;
      final List<Offset> resizeHandles = selectedData.cornerHandles;
      double nearestCornerDistance = double.infinity;
      int nearestCornerIndex = -1;
      for (int i = 0; i < resizeHandles.length; i++) {
        final Offset handle = resizeHandles[i];
        final double distance = (scenePoint - handle).distance;
        if (distance < nearestCornerDistance) {
          nearestCornerDistance = distance;
          nearestCornerIndex = i;
        }
      }

      void beginMove() {
        _interaction = _CanvasInteraction.movingLayer;
        _gestureLayerId = selectedData.layerId;
        _layerStartPosition = selectedLayer!.position ??
            Offset(workspaceSize.width / 2, workspaceSize.height / 2);
        widget.onTransformInteractionStart();
        _layerStartScenePoint = scenePoint;
        _beginSnapSession(
          layerId: selectedData.layerId,
          artboard: artboard,
          workspaceSize: workspaceSize,
          selectedData: selectedData,
        );
      }

      void beginRotate() {
        _interaction = _CanvasInteraction.rotatingLayer;
        _gestureLayerId = selectedData.layerId;
        _layerStartRotation = selectedLayer!.layerRotation;
        widget.onTransformInteractionStart();
        _rotateStartAngle = math.atan2(
          scenePoint.dy - selectedData.center.dy,
          scenePoint.dx - selectedData.center.dx,
        );
        _beginSnapSession(
          layerId: selectedData.layerId,
          artboard: artboard,
          workspaceSize: workspaceSize,
          selectedData: selectedData,
        );
      }

      void beginResize() {
        _interaction = _CanvasInteraction.resizingLayer;
        _gestureLayerId = selectedData.layerId;
        _layerStartScale = selectedLayer!.layerScale;
        widget.onTransformInteractionStart();
        final Offset handleVector = nearestCornerIndex >= 0
            ? (resizeHandles[nearestCornerIndex] - selectedData.center)
            : const Offset(1, 0);
        final double handleDistance = handleVector.distance;
        final Offset resizeDirection = handleDistance <= 0.0001
            ? const Offset(1, 0)
            : (handleVector / handleDistance);
        final Offset startVector = scenePoint - selectedData.center;
        _resizeStartDirection = resizeDirection;
        final double startProjection = (startVector.dx * resizeDirection.dx) +
            (startVector.dy * resizeDirection.dy);
        _resizeStartProjection = math.max(
          math.max(1.0, handleDistance * 0.55),
          startProjection.abs(),
        );
        _lastResizeAppliedScale = _layerStartScale;
        _beginSnapSession(
          layerId: selectedData.layerId,
          artboard: artboard,
          workspaceSize: workspaceSize,
          selectedData: selectedData,
        );
      }

      final bool hitRotate = rotateDistance <= rotateHandleRadius;
      final bool hitMove = moveHandleDistance <= moveHandleRadius;
      final bool hitCorner = nearestCornerDistance <= cornerHandleRadius;
      if (hitRotate || hitMove || hitCorner) {
        // Strong-center hits lock immediately to the intended control to avoid
        // occasional mis-pick when controls get visually close on small layers.
        final bool strongCornerHit =
            hitCorner && nearestCornerDistance <= cornerHandleRadius * 0.72;
        final bool strongMoveHit =
            hitMove && moveHandleDistance <= moveHandleRadius * 0.72;
        final bool strongRotateHit =
            hitRotate && rotateDistance <= rotateHandleRadius * 0.72;
        if (strongCornerHit) {
          beginResize();
          return;
        }
        if (strongMoveHit) {
          beginMove();
          return;
        }
        if (strongRotateHit) {
          beginRotate();
          return;
        }

        double bestScore = double.infinity;
        String action = '';
        if (hitRotate) {
          final double score =
              rotateDistance / math.max(0.0001, rotateHandleRadius);
          if (score < bestScore) {
            bestScore = score;
            action = 'rotate';
          }
        }
        if (hitMove) {
          final double score =
              moveHandleDistance / math.max(0.0001, moveHandleRadius);
          if (score < bestScore) {
            bestScore = score;
            action = 'move';
          }
        }
        if (hitCorner) {
          final double score =
              nearestCornerDistance / math.max(0.0001, cornerHandleRadius);
          if (score < bestScore) {
            action = 'resize';
          }
        }
        if (action == 'rotate') {
          beginRotate();
          return;
        }
        if (action == 'move') {
          beginMove();
          return;
        }
        if (action == 'resize') {
          beginResize();
          return;
        }
      }
    }

    // Selection/activation is controlled only by the Layers list.
    _interaction = _CanvasInteraction.none;
    _snapSession = null;
    _moveSnapXActive = false;
    _moveSnapYActive = false;
    _resizeSnapActive = false;
    _rotationSnapActive = false;
    _setSmartGuides(const <_SmartGuideSegment>[], forceRepaint: false);
  }

  void _onScaleUpdate(ScaleUpdateDetails details, Size canvasSize) {
    if (_multiTouchInitialized && details.pointerCount < 2) {
      // Keep pinch session stable until gesture end; switching back to
      // one-finger updates in the same gesture causes jumpy pan/zoom.
      return;
    }
    if (details.pointerCount > 1) {
      if (!_multiTouchInitialized) {
        _multiTouchInitialized = true;
        _lastGestureScaleFactor = details.scale <= 0 ? 1.0 : details.scale;
        _lastGestureFocal = details.localFocalPoint;
      }
      final bool wasTransforming =
          _interaction == _CanvasInteraction.movingLayer ||
              _interaction == _CanvasInteraction.resizingLayer ||
              _interaction == _CanvasInteraction.rotatingLayer;
      _flushPendingCloneSegments();
      if (_interaction == _CanvasInteraction.marqueeSelecting) {
        _finalizeMarqueeSelection();
      }
      _activeStroke = null;
      _activeSketchMaskPointsUv.clear();
      _activeSketchMaskRadiusUv = 0;
      _interaction = _CanvasInteraction.none;
      _gestureLayerId = null;
      _activeCloneStroke = null;
      _smartGuideAutoHideTimer?.cancel();
      _snapSession = null;
      _moveSnapXActive = false;
      _moveSnapYActive = false;
      _resizeSnapActive = false;
      _rotationSnapActive = false;
      _setSmartGuides(const <_SmartGuideSegment>[], forceRepaint: true);
      if (wasTransforming) {
        widget.onTransformInteractionEnd();
      }
      final Offset focal = details.localFocalPoint;
      final Offset focalDelta = focal - _lastGestureFocal;
      final Offset translatedPan = _pan + focalDelta;
      final double previousScaleFactor =
          _lastGestureScaleFactor == 0 ? 1.0 : _lastGestureScaleFactor;
      final double rawScaleDelta = details.scale / previousScaleFactor;
      double nextScale = _scale;
      Offset nextPan = translatedPan;
      if (rawScaleDelta.isFinite && rawScaleDelta > 0) {
        final Offset focalSceneAfterTranslation = Offset(
          (focal.dx - translatedPan.dx) / _scale,
          (focal.dy - translatedPan.dy) / _scale,
        );
        nextScale = (_scale * rawScaleDelta).clamp(_minScale, _maxScale);
        nextPan = Offset(
          focal.dx - (focalSceneAfterTranslation.dx * nextScale),
          focal.dy - (focalSceneAfterTranslation.dy * nextScale),
        );
      }
      setState(() {
        _scale = nextScale;
        _pan = nextPan;
      });
      _lastGestureScaleFactor = details.scale <= 0 ? 1.0 : details.scale;
      _lastGestureFocal = focal;
      return;
    }

    final EditorLayer? workspace = _backgroundLayer(widget.layers);
    if (workspace == null) return;
    final Size? workspaceSize = _workspaceSourceSize(workspace);
    if (workspaceSize == null) return;

    final Rect artboard = _computeArtboardRect(
      canvasSize: canvasSize,
      workspaceSize: workspaceSize,
    );
    final Offset scenePoint = _toScenePoint(details.localFocalPoint);
    if (_interaction == _CanvasInteraction.overlayCutMoving ||
        _interaction == _CanvasInteraction.overlayCutResizing ||
        _interaction == _CanvasInteraction.overlayCutRotating) {
      final _OverlayCutConfig? config = widget.overlayCutConfig;
      final _ImageLayerSceneData? layerData = config == null
          ? null
          : _activeOverlayCutLayerData(
              artboard: artboard,
              workspaceSize: workspaceSize,
            );
      if (config != null && layerData != null) {
        _updateOverlayCutInteraction(
          scenePoint: scenePoint,
          layerData: layerData,
          config: config,
        );
      }
      _repaintCanvas();
      return;
    }

    if (_interaction == _CanvasInteraction.cropMoving ||
        _interaction == _CanvasInteraction.cropResizing) {
      final _CropToolConfig? config = widget.cropToolConfig;
      final _ImageLayerSceneData? layerData = config == null
          ? null
          : _activeCropLayerData(
              artboard: artboard,
              workspaceSize: workspaceSize,
            );
      if (config != null && layerData != null) {
        _updateCropInteraction(
          scenePoint: scenePoint,
          layerData: layerData,
          config: config,
        );
      }
      _repaintCanvas();
      return;
    }

    if (_interaction == _CanvasInteraction.expandResizing) {
      final _ExpandToolConfig? config = widget.expandToolConfig;
      final _ImageLayerSceneData? layerData = config == null
          ? null
          : _activeExpandLayerData(
              artboard: artboard,
              workspaceSize: workspaceSize,
            );
      if (config != null && layerData != null) {
        _updateExpandInteraction(
          scenePoint: scenePoint,
          layerData: layerData,
          config: config,
        );
      }
      _repaintCanvas();
      return;
    }

    if (!widget.isToolEnabled) {
      return;
    }

    if (_interaction == _CanvasInteraction.none &&
        _pendingSketchMaskStartScenePoint != null &&
        (widget.activeTool == EditorTool.sketchReplace ||
            widget.activeTool == EditorTool.replaceObject) &&
        widget.sketchMaskDrawingEnabled) {
      final Offset startScenePoint = _pendingSketchMaskStartScenePoint!;
      final double movementDistance = (scenePoint - startScenePoint).distance;
      final double startThreshold = (6.0 / _scale).clamp(1.2, 12.0).toDouble();
      if (movementDistance < startThreshold) return;
      final bool started = _startSketchMaskGesture(
        scenePoint: startScenePoint,
        artboard: artboard,
        workspaceSize: workspaceSize,
      );
      _pendingSketchMaskStartScenePoint = null;
      if (started) {
        _updateSketchMaskGesture(
          scenePoint: scenePoint,
          artboard: artboard,
          workspaceSize: workspaceSize,
        );
      } else {
        _activeSketchMaskPointsUv.clear();
        _activeSketchMaskRadiusUv = 0;
      }
      return;
    }

    if (_interaction == _CanvasInteraction.sketchMasking) {
      _updateSketchMaskGesture(
        scenePoint: scenePoint,
        artboard: artboard,
        workspaceSize: workspaceSize,
      );
      return;
    }

    if (_interaction == _CanvasInteraction.drawing) {
      if (_activeStroke == null) return;
      final Offset local = scenePoint - artboard.topLeft;
      _activeStroke!.points.add(
        Offset(
          _clampDouble(local.dx, 0, artboard.width),
          _clampDouble(local.dy, 0, artboard.height),
        ),
      );
      _repaintCanvas();
      return;
    }

    if (_interaction == _CanvasInteraction.cloning) {
      _updateCloneGesture(scenePoint: scenePoint, artboard: artboard);
      return;
    }

    if (_interaction == _CanvasInteraction.marqueeSelecting) {
      _updateMarqueeGesture(scenePoint: scenePoint, artboard: artboard);
      return;
    }

    final String? layerId = _gestureLayerId;
    if (layerId == null) return;
    final EditorLayer? targetLayer = _layerById(layerId);
    if (targetLayer == null) return;
    final _TransformLayerSceneData? data = _buildSelectedTransformLayerData(
      selectedLayer: targetLayer,
      artboard: artboard,
      workspaceSize: workspaceSize,
    );
    if (data == null) return;

    if (_interaction == _CanvasInteraction.movingLayer) {
      final double sourcePerScene = workspaceSize.width / artboard.width;
      final Offset deltaScene = scenePoint - _layerStartScenePoint;
      final Offset rawCenter = _transformStartCenterScene + deltaScene;
      final _MoveSnapResult snapped = _applyMoveSnapping(
        rawCenter: rawCenter,
        thresholdScene: _snapThresholdPx / _scale,
      );
      final Offset snappedDeltaScene =
          snapped.center - _transformStartCenterScene;
      final Offset nextPos = Offset(
        _layerStartPosition.dx + (snappedDeltaScene.dx * sourcePerScene),
        _layerStartPosition.dy + (snappedDeltaScene.dy * sourcePerScene),
      );
      _setSmartGuides(snapped.guides, forceRepaint: true);
      if (snapped.guides.isEmpty) {
        _smartGuideAutoHideTimer?.cancel();
      } else {
        _scheduleSmartGuideAutoHide();
      }
      widget.onLayerTransformChanged(
        layerId,
        position: Offset(
          _clampDouble(nextPos.dx, 0, workspaceSize.width),
          _clampDouble(nextPos.dy, 0, workspaceSize.height),
        ),
      );
      return;
    }

    if (_interaction == _CanvasInteraction.resizingLayer) {
      // Stable resize: use projection onto the initial handle vector, which
      // removes perpendicular finger noise that causes visual jitter.
      final Offset currentVector = scenePoint - _transformStartCenterScene;
      final double projectedDistance =
          (currentVector.dx * _resizeStartDirection.dx) +
              (currentVector.dy * _resizeStartDirection.dy);
      final double safeProjection = math.max(0.0, projectedDistance.abs());
      final double ratio = safeProjection / _resizeStartProjection;
      final double rawScale =
          (_layerStartScale * ratio).clamp(_minLayerScale, _maxLayerScale);
      final bool tinyLayer =
          _layerStartScale <= 0.38 || math.min(data.width, data.height) <= 76;
      final double smoothing = targetLayer.type == EditorLayerType.text
          ? (tinyLayer ? 0.24 : 0.42)
          : (tinyLayer ? 0.34 : 0.58);
      final double stabilizedScale = _lastResizeAppliedScale +
          ((rawScale - _lastResizeAppliedScale) * smoothing);
      final double minStep = tinyLayer ? 0.0014 : 0.00035;
      if ((stabilizedScale - _lastResizeAppliedScale).abs() < minStep) {
        return;
      }
      _lastResizeAppliedScale = stabilizedScale;
      _resizeSnapActive = false;
      _smartGuideAutoHideTimer?.cancel();
      _setSmartGuides(const <_SmartGuideSegment>[], forceRepaint: false);
      widget.onLayerTransformChanged(layerId, layerScale: stabilizedScale);
      return;
    }

    if (_interaction == _CanvasInteraction.rotatingLayer) {
      final double currentAngle = math.atan2(
          scenePoint.dy - data.center.dy, scenePoint.dx - data.center.dx);
      final double rawRotation =
          _layerStartRotation + (currentAngle - _rotateStartAngle);
      final _RotationSnapResult snapped = _applyRotationSnapping(
        rawRotation: rawRotation,
        center: data.center,
      );
      _setSmartGuides(snapped.guides, forceRepaint: true);
      if (snapped.guides.isEmpty) {
        _smartGuideAutoHideTimer?.cancel();
      } else {
        _scheduleSmartGuideAutoHide();
      }
      widget.onLayerTransformChanged(layerId, layerRotation: snapped.rotation);
    }
  }

  void _onScaleEnd(ScaleEndDetails details) {
    _multiTouchInitialized = false;
    final _BrushStroke? completedStroke =
        _interaction == _CanvasInteraction.drawing && _activeStroke != null
            ? _activeStroke!.copy()
            : null;
    final _SketchMaskStroke? completedSketchMaskStroke =
        _interaction == _CanvasInteraction.sketchMasking &&
                _gestureLayerId != null &&
                _activeSketchMaskPointsUv.isNotEmpty
            ? _SketchMaskStroke(
                layerId: _gestureLayerId!,
                pointsUv: List<Offset>.from(_activeSketchMaskPointsUv),
                radiusUv: _activeSketchMaskRadiusUv,
              )
            : null;
    final bool endedTransform =
        _interaction == _CanvasInteraction.movingLayer ||
            _interaction == _CanvasInteraction.resizingLayer ||
            _interaction == _CanvasInteraction.rotatingLayer;
    _flushPendingCloneSegments();
    if (_interaction == _CanvasInteraction.cloning && _cloneChangedLayer) {
      final String? layerId = _gestureLayerId;
      final _CloneStrokeSession? stroke = _activeCloneStroke;
      if (layerId != null && stroke != null) {
        final _EditableImageBuffer? buffer = _editableImages[layerId];
        if (buffer != null) {
          if (buffer.usesPreview) {
            _queueEditableImageRefresh(layerId);
            _enqueueFullResolutionCommit(
              layerId: layerId,
              stroke: stroke.freeze(),
            );
          } else {
            _queueEditableImageRefresh(layerId, notifyParent: true);
          }
        }
      }
      _repaintCanvas();
    }
    if (_interaction == _CanvasInteraction.marqueeSelecting) {
      _finalizeMarqueeSelection();
    }
    _activeStroke = null;
    _activeSketchMaskPointsUv.clear();
    _activeSketchMaskRadiusUv = 0;
    _interaction = _CanvasInteraction.none;
    _gestureLayerId = null;
    _activeCloneStroke = null;
    _cloneOffsetUv = null;
    _lastCloneDestUv = null;
    _cloneChangedLayer = false;
    _pendingCloneSegments.clear();
    _cloneWorkFrameScheduled = false;
    _clonePreviewSourceSnapshot = null;
    _clonePreviewSourceLayerId = null;
    _cloneJoystickStrokeActive = false;
    _pendingCloneDownScenePoint = null;
    _pendingSketchMaskStartScenePoint = null;
    _smartGuideAutoHideTimer?.cancel();
    _marqueeStartUv = null;
    _freeMarqueePointsUv.clear();
    _snapSession = null;
    _moveSnapXActive = false;
    _moveSnapYActive = false;
    _resizeSnapActive = false;
    _rotationSnapActive = false;
    _setSmartGuides(const <_SmartGuideSegment>[], forceRepaint: false);
    if (completedStroke != null) {
      widget.onPencilStrokeCommitted(completedStroke);
    }
    if (completedSketchMaskStroke != null) {
      widget.onSketchMaskStrokeCommitted(completedSketchMaskStroke);
    }
    _repaintCanvas();
    if (endedTransform) {
      widget.onTransformInteractionEnd();
    }
  }

  void _onTapDown(TapDownDetails details, Size canvasSize) {
    if (_inlineEditLayerId != null) {
      final _InlineTextEditorLayout? layout =
          _resolveInlineTextEditorLayout(canvasSize);
      final bool isInsideEditor =
          layout?.rect.inflate(8).contains(details.localPosition) ?? false;
      if (!isInsideEditor) {
        _closeInlineTextEditing();
      }
    }
    if (!widget.isToolEnabled) return;
    if (widget.activeTool != EditorTool.clone) return;
    final EditorLayer? workspace = _backgroundLayer(widget.layers);
    if (workspace == null) return;
    final Size? workspaceSize = _workspaceSourceSize(workspace);
    if (workspaceSize == null) return;
    final Rect artboard = _computeArtboardRect(
      canvasSize: canvasSize,
      workspaceSize: workspaceSize,
    );
    final Offset scenePoint = _toScenePoint(details.localPosition);
    if (!artboard.contains(scenePoint)) {
      _pendingCloneDownScenePoint = null;
      return;
    }
    _pendingCloneDownScenePoint = scenePoint;
  }

  void _onTapUp(TapUpDetails details, Size canvasSize) {
    if (_cloneHandledByScaleGesture) {
      _cloneHandledByScaleGesture = false;
      return;
    }
    if (_interaction != _CanvasInteraction.none) return;
    final EditorLayer? workspace = _backgroundLayer(widget.layers);
    if (workspace == null) return;
    final Size? workspaceSize = _workspaceSourceSize(workspace);
    if (workspaceSize == null) return;
    final Rect artboard = _computeArtboardRect(
      canvasSize: canvasSize,
      workspaceSize: workspaceSize,
    );
    final Offset scenePoint = _toScenePoint(details.localPosition);
    if (widget.isToolEnabled && widget.activeTool == EditorTool.clone) {
      _cloneTapAtPoint(scenePoint: scenePoint, artboard: artboard);
    }
  }

  void _onTapCancel() {
    _pendingCloneDownScenePoint = null;
    _pendingSketchMaskStartScenePoint = null;
    _cloneHandledByScaleGesture = false;
    _smartGuideAutoHideTimer?.cancel();
    _setSmartGuides(const <_SmartGuideSegment>[], forceRepaint: true);
  }

  void _onDoubleTapDown(TapDownDetails details, Size canvasSize) {
    final EditorLayer? workspace = _backgroundLayer(widget.layers);
    if (workspace == null) return;
    final Size? workspaceSize = _workspaceSourceSize(workspace);
    if (workspaceSize == null) return;

    final Rect artboard = _computeArtboardRect(
      canvasSize: canvasSize,
      workspaceSize: workspaceSize,
    );
    final Offset scenePoint = _toScenePoint(details.localPosition);

    if (widget.isToolEnabled && widget.activeTool == EditorTool.crop) {
      final _CropToolConfig? config = widget.cropToolConfig;
      if (config == null) return;
      final _ImageLayerSceneData? layerData = _activeCropLayerData(
        artboard: artboard,
        workspaceSize: workspaceSize,
      );
      if (layerData == null) return;
      final double cropRotation =
          layerData.rotation + _cropPreviewRotation(config);
      final Rect cropRectLocal = _cropRectLocal(
        layerData: layerData,
        config: config,
      );
      final Offset localPoint =
          _rotateVector(scenePoint - layerData.center, -cropRotation);
      if (cropRectLocal.contains(localPoint)) {
        widget.onCropCommitRequested();
      }
      return;
    }

    final EditorLayer? selectedLayer = _layerById(widget.selectedLayerId);
    if (selectedLayer == null ||
        !selectedLayer.isVisible ||
        selectedLayer.isBackground) {
      return;
    }
    final _TransformLayerSceneData? selectedData =
        _buildSelectedTransformLayerData(
      selectedLayer: selectedLayer,
      artboard: artboard,
      workspaceSize: workspaceSize,
    );
    if (selectedData == null) return;
    if (!_pointInRotatedLayerBounds(
      scenePoint,
      selectedData,
      padding: (6 / _scale).clamp(3, 10),
    )) {
      return;
    }
    if (selectedLayer.type == EditorLayerType.text) {
      widget.onTextLayerDoubleTap(selectedLayer.id);
      return;
    }
    widget.onLayerDoubleTap(selectedLayer.id);
  }

  Offset? _activeClonePointerUv() {
    if (!widget.isToolEnabled) return null;
    if (widget.activeTool != EditorTool.clone) return null;
    final EditorLayer? selectedLayer = _selectedImageLayerForClone();
    if (selectedLayer == null) return null;
    return _clonePointerUvByLayer[selectedLayer.id];
  }

  Offset? _activeCloneTargetPointerUv() {
    if (!widget.showCloneJoystickCursor) return null;
    if (!widget.isToolEnabled || widget.activeTool != EditorTool.clone) {
      return null;
    }
    final EditorLayer? selectedLayer = _selectedImageLayerForClone();
    if (selectedLayer == null) return null;
    return _cloneTargetCursorUvByLayer[selectedLayer.id] ??
        const Offset(0.5, 0.5);
  }

  Rect? _currentArtboardForCloneJoystick() {
    if (_lastCanvasSize.width <= 0 || _lastCanvasSize.height <= 0) return null;
    final EditorLayer? workspace = _backgroundLayer(widget.layers);
    if (workspace == null) return null;
    final Size? workspaceSize = _workspaceSourceSize(workspace);
    if (workspaceSize == null) return null;
    return _computeArtboardRect(
      canvasSize: _lastCanvasSize,
      workspaceSize: workspaceSize,
    );
  }

  Offset _ensureCloneTargetCursorUv(EditorLayer layer) {
    final Offset seed =
        _cloneTargetCursorUvByLayer[layer.id] ?? const Offset(0.5, 0.5);
    final Offset clamped = _clampUv(seed);
    _cloneTargetCursorUvByLayer[layer.id] = clamped;
    return clamped;
  }

  Offset _uvToScenePoint(Offset uv, Rect artboard) {
    return Offset(
      artboard.left + (uv.dx * artboard.width),
      artboard.top + (uv.dy * artboard.height),
    );
  }

  bool _canStartCloneFromCursor(EditorLayer layer) {
    if (!(widget.isCloneBrushSelected || widget.isCloneEraseSelected)) {
      return false;
    }
    if (widget.isCloneEraseSelected) return true;
    return _clonePointerUvByLayer[layer.id] != null;
  }

  bool _startCloneStrokeFromJoystickAtCursor({
    required EditorLayer layer,
    required Rect artboard,
    required Offset cursorUv,
  }) {
    if (_interaction != _CanvasInteraction.none) return false;
    if (!_canStartCloneFromCursor(layer)) return false;
    final Offset scenePoint = _uvToScenePoint(cursorUv, artboard);
    _cloneJoystickStrokeActive = _startCloneGesture(
      scenePoint: scenePoint,
      artboard: artboard,
    );
    return _cloneJoystickStrokeActive;
  }

  void beginCloneJoystickDraw() {
    if (!widget.isToolEnabled || widget.activeTool != EditorTool.clone) {
      return;
    }
    if (_cloneJoystickStrokeActive) return;
    final EditorLayer? layer = _selectedImageLayerForClone();
    final Rect? artboard = _currentArtboardForCloneJoystick();
    if (layer == null || artboard == null) return;
    final Offset cursorUv = _ensureCloneTargetCursorUv(layer);
    _startCloneStrokeFromJoystickAtCursor(
      layer: layer,
      artboard: artboard,
      cursorUv: cursorUv,
    );
  }

  void moveCloneJoystickByScreenDelta(
    Offset screenDelta, {
    required bool drawPressed,
  }) {
    if (!widget.isToolEnabled || widget.activeTool != EditorTool.clone) {
      _finalizeCloneStrokeFromJoystick();
      return;
    }
    final EditorLayer? layer = _selectedImageLayerForClone();
    final Rect? artboard = _currentArtboardForCloneJoystick();
    if (layer == null || artboard == null) {
      _finalizeCloneStrokeFromJoystick();
      return;
    }

    Offset cursorUv = _ensureCloneTargetCursorUv(layer);
    final double safeScale = _scale <= 0 ? 1.0 : _scale;
    final Offset deltaScene = Offset(
      screenDelta.dx / safeScale,
      screenDelta.dy / safeScale,
    );
    final Offset deltaUv = Offset(
      deltaScene.dx / artboard.width,
      deltaScene.dy / artboard.height,
    );
    final Offset nextCursorUv = _clampUv(cursorUv + deltaUv);
    final bool cursorMoved = (nextCursorUv - cursorUv).distanceSquared > 0.0;
    if (cursorMoved) {
      cursorUv = nextCursorUv;
      _cloneTargetCursorUvByLayer[layer.id] = cursorUv;
      _repaintCanvas();
    }

    final Offset scenePoint = _uvToScenePoint(cursorUv, artboard);
    if (drawPressed) {
      if (!_cloneJoystickStrokeActive) {
        _startCloneStrokeFromJoystickAtCursor(
          layer: layer,
          artboard: artboard,
          cursorUv: cursorUv,
        );
      } else if (_interaction == _CanvasInteraction.cloning) {
        _updateCloneGesture(scenePoint: scenePoint, artboard: artboard);
      }
    } else {
      _finalizeCloneStrokeFromJoystick();
    }
  }

  void endCloneJoystickDraw() {
    _finalizeCloneStrokeFromJoystick();
  }

  void _finalizeCloneStrokeFromJoystick() {
    if (!_cloneJoystickStrokeActive) return;
    _flushPendingCloneSegments();
    if (_interaction == _CanvasInteraction.cloning && _cloneChangedLayer) {
      final String? layerId = _gestureLayerId;
      final _CloneStrokeSession? stroke = _activeCloneStroke;
      if (layerId != null && stroke != null) {
        final _EditableImageBuffer? buffer = _editableImages[layerId];
        if (buffer != null) {
          if (buffer.usesPreview) {
            _queueEditableImageRefresh(layerId);
            _enqueueFullResolutionCommit(
              layerId: layerId,
              stroke: stroke.freeze(),
            );
          } else {
            _queueEditableImageRefresh(layerId, notifyParent: true);
          }
        }
      }
    }
    _interaction = _CanvasInteraction.none;
    _gestureLayerId = null;
    _activeCloneStroke = null;
    _cloneOffsetUv = null;
    _lastCloneDestUv = null;
    _cloneChangedLayer = false;
    _pendingCloneSegments.clear();
    _cloneWorkFrameScheduled = false;
    _clonePreviewSourceSnapshot = null;
    _clonePreviewSourceLayerId = null;
    _cloneJoystickStrokeActive = false;
    _repaintCanvas();
  }

  void _cleanupCloneCaches() {
    final Set<String> validImageLayerIds = widget.layers
        .where(
          (layer) => layer.type == EditorLayerType.image && layer.image != null,
        )
        .map((layer) => layer.id)
        .toSet();

    _editableImages
        .removeWhere((layerId, _) => !validImageLayerIds.contains(layerId));
    _clonePointerUvByLayer.removeWhere(
      (layerId, _) => !validImageLayerIds.contains(layerId),
    );
    _cloneTargetCursorUvByLayer.removeWhere(
      (layerId, _) => !validImageLayerIds.contains(layerId),
    );
    _bitmapLoadInFlight
        .removeWhere((layerId) => !validImageLayerIds.contains(layerId));
  }

  void _cleanupMipmapCaches() {
    final Set<String> validImageLayerIds = widget.layers
        .where(
          (layer) => layer.type == EditorLayerType.image && layer.image != null,
        )
        .map((layer) => layer.id)
        .toSet();
    final List<String> staleIds = _layerMipmaps.keys
        .where((layerId) => !validImageLayerIds.contains(layerId))
        .toList(growable: false);
    for (final String layerId in staleIds) {
      final _LayerMipmapChain? chain = _layerMipmaps.remove(layerId);
      chain?.dispose();
      _mipmapBuildInFlight.remove(layerId);
    }

    for (final EditorLayer layer in widget.layers) {
      if (layer.type != EditorLayerType.image || layer.image == null) continue;
      final _LayerMipmapChain? chain = _layerMipmaps[layer.id];
      if (chain == null) continue;
      if (!identical(chain.sourceImage, layer.image)) {
        chain.dispose();
        _layerMipmaps.remove(layer.id);
        _mipmapBuildInFlight.remove(layer.id);
      }
    }
  }

  void _disposeAllMipmaps() {
    for (final _LayerMipmapChain chain in _layerMipmaps.values) {
      chain.dispose();
    }
    _layerMipmaps.clear();
    _mipmapBuildInFlight.clear();
  }

  ui.Image _resolveImageForPaint(
    EditorLayer layer,
    ui.Image sourceImage,
    double drawWidthScene,
    double drawHeightScene,
    double viewScale,
  ) {
    if (_editableImages.containsKey(layer.id)) {
      return sourceImage;
    }
    final double targetLongPx =
        (math.max(drawWidthScene, drawHeightScene) * viewScale).clamp(
      1.0,
      32768.0,
    );
    final int sourceLong = math.max(sourceImage.width, sourceImage.height);
    if (sourceLong <= (targetLongPx * 2.15)) {
      return sourceImage;
    }

    final int desiredLevel = _desiredMipmapLevel(
      sourceLong: sourceLong,
      targetLongPx: targetLongPx,
    );
    if (desiredLevel <= 0) {
      return sourceImage;
    }

    final _LayerMipmapChain chain = _obtainMipmapChain(
      layerId: layer.id,
      sourceImage: sourceImage,
    );
    _ensureMipmapLevel(
      layerId: layer.id,
      chain: chain,
      level: desiredLevel,
    );

    if (chain.levels.isEmpty) return sourceImage;
    final int index = math.min(desiredLevel, chain.levels.length) - 1;
    if (index < 0 || index >= chain.levels.length) return sourceImage;
    return chain.levels[index];
  }

  int _desiredMipmapLevel({
    required int sourceLong,
    required double targetLongPx,
  }) {
    if (targetLongPx <= 0) return 0;
    final double downscaleRatio = sourceLong / targetLongPx;
    if (downscaleRatio < 2.35) return 0;
    final double levelBias = (math.log(downscaleRatio) / math.ln2) - 0.6;
    final int level = levelBias.floor();
    return level.clamp(1, _maxMipmapLevels).toInt();
  }

  _LayerMipmapChain _obtainMipmapChain({
    required String layerId,
    required ui.Image sourceImage,
  }) {
    final _LayerMipmapChain? existing = _layerMipmaps[layerId];
    if (existing != null && identical(existing.sourceImage, sourceImage)) {
      return existing;
    }
    existing?.dispose();
    final _LayerMipmapChain chain = _LayerMipmapChain(sourceImage: sourceImage);
    _layerMipmaps[layerId] = chain;
    _mipmapBuildInFlight.remove(layerId);
    return chain;
  }

  void _ensureMipmapLevel({
    required String layerId,
    required _LayerMipmapChain chain,
    required int level,
  }) {
    if (chain.levels.length >= level) return;
    if (_mipmapBuildInFlight.contains(layerId)) return;
    _mipmapBuildInFlight.add(layerId);
    unawaited(
      _buildMipmapLevels(
        layerId: layerId,
        sourceIdentity: chain.sourceImage,
        targetLevel: level,
      ).whenComplete(() {
        _mipmapBuildInFlight.remove(layerId);
      }),
    );
  }

  Future<void> _buildMipmapLevels({
    required String layerId,
    required ui.Image sourceIdentity,
    required int targetLevel,
  }) async {
    while (mounted) {
      final _LayerMipmapChain? chain = _layerMipmaps[layerId];
      if (chain == null) return;
      if (!identical(chain.sourceImage, sourceIdentity)) return;
      if (chain.levels.length >= targetLevel) return;

      final ui.Image parent =
          chain.levels.isEmpty ? chain.sourceImage : chain.levels.last;
      if (parent.width <= 2 && parent.height <= 2) {
        return;
      }

      final ui.Image next = await _downscaleImageByHalf(parent);
      if (!mounted) {
        next.dispose();
        return;
      }
      final _LayerMipmapChain? latest = _layerMipmaps[layerId];
      if (latest == null || !identical(latest.sourceImage, sourceIdentity)) {
        next.dispose();
        return;
      }
      latest.levels.add(next);
      _repaintCanvas();
    }
  }

  Future<ui.Image> _downscaleImageByHalf(ui.Image source) async {
    final int width = math.max(1, (source.width / 2).round());
    final int height = math.max(1, (source.height / 2).round());
    final ui.PictureRecorder recorder = ui.PictureRecorder();
    final Rect bounds = Rect.fromLTWH(
      0,
      0,
      width.toDouble(),
      height.toDouble(),
    );
    final Canvas canvas = Canvas(recorder, bounds);
    canvas.drawImageRect(
      source,
      Rect.fromLTWH(0, 0, source.width.toDouble(), source.height.toDouble()),
      bounds,
      Paint()
        ..isAntiAlias = true
        ..filterQuality = FilterQuality.high,
    );
    final ui.Picture picture = recorder.endRecording();
    return picture.toImage(width, height);
  }

  EditorLayer? _selectedImageLayerForClone({String? layerId}) {
    final EditorLayer? layer = _layerById(layerId ?? widget.selectedLayerId);
    if (layer == null) return null;
    if (!layer.isVisible) return null;
    if (layer.type != EditorLayerType.image) return null;
    if (layer.image == null) return null;
    return layer;
  }

  EditorLayer? _selectedBackgroundImageLayerForMarquee() {
    return _selectedImageLayerForClone();
  }

  void _primeSelectedCloneLayerBitmap() {
    final EditorLayer? selectedLayer = _selectedImageLayerForClone();
    if (selectedLayer == null) return;
    _prepareEditableImageBuffer(selectedLayer);
  }

  Future<void> _clearCloneEditsOnSelectedLayer() async {
    final EditorLayer? selectedLayer = _selectedImageLayerForClone();
    if (selectedLayer == null) return;
    await _prepareEditableImageBuffer(selectedLayer);
    if (!mounted) return;
    final _EditableImageBuffer? buffer = _editableImages[selectedLayer.id];
    if (buffer == null) return;
    if (buffer.fullPixels.length != buffer.cloneBaseFullPixels.length ||
        buffer.previewPixels.length != buffer.cloneBasePreviewPixels.length) {
      return;
    }

    buffer.fullPixels.setAll(0, buffer.cloneBaseFullPixels);
    buffer.previewPixels.setAll(0, buffer.cloneBasePreviewPixels);
    buffer.pendingCommits.clear();
    buffer.commitGeneration++;
    buffer.isCommittingFull = false;
    buffer.previewFrameRequested = false;
    buffer.previewNeedsAnotherBuild = false;
    _pendingCloneSegments.clear();
    _cloneWorkFrameScheduled = false;
    _cloneChangedLayer = false;
    _cloneOffsetUv = null;
    _lastCloneDestUv = null;
    _activeCloneStroke = null;
    _clonePreviewSourceSnapshot = null;
    _clonePreviewSourceLayerId = null;

    final ui.Image restoredFullImage = await _imageFromPixels(
      pixels: buffer.fullPixels,
      width: buffer.fullWidth,
      height: buffer.fullHeight,
    );
    if (!mounted) return;
    buffer.fullImage = restoredFullImage;
    if (buffer.usesPreview) {
      final ui.Image restoredPreviewImage = await _imageFromPixels(
        pixels: buffer.previewPixels,
        width: buffer.previewWidth,
        height: buffer.previewHeight,
      );
      if (!mounted) return;
      buffer.previewImage = restoredPreviewImage;
    } else {
      buffer.previewImage = restoredFullImage;
    }
    _repaintCanvas();
    widget.onLayerImageChanged(selectedLayer.id, restoredFullImage);
  }

  Future<void> _prepareEditableImageBuffer(EditorLayer layer) async {
    if (layer.image == null) return;
    if (_editableImages.containsKey(layer.id) ||
        _bitmapLoadInFlight.contains(layer.id)) {
      return;
    }
    _bitmapLoadInFlight.add(layer.id);
    try {
      final ByteData? data = await layer.image!.toByteData(
        format: ui.ImageByteFormat.rawRgba,
      );
      if (!mounted || data == null) return;
      final int fullWidth = layer.image!.width;
      final int fullHeight = layer.image!.height;
      final Uint8List fullPixels =
          Uint8List.fromList(data.buffer.asUint8List(0, data.lengthInBytes));

      int previewWidth = fullWidth;
      int previewHeight = fullHeight;
      double previewScale = 1.0;
      Uint8List previewPixels = fullPixels;
      ui.Image previewImage = layer.image!;

      final int maxSide = math.max(fullWidth, fullHeight);
      final int maxPreviewDimension = _targetPreviewDimension(maxSide);
      if (maxSide > maxPreviewDimension) {
        previewScale = maxPreviewDimension / maxSide;
        previewWidth = math.max(1, (fullWidth * previewScale).round());
        previewHeight = math.max(1, (fullHeight * previewScale).round());
        previewPixels = _downscaleRgbaNearest(
          sourcePixels: fullPixels,
          sourceWidth: fullWidth,
          sourceHeight: fullHeight,
          targetWidth: previewWidth,
          targetHeight: previewHeight,
        );
        previewImage = await _imageFromPixels(
          pixels: previewPixels,
          width: previewWidth,
          height: previewHeight,
        );
      }
      if (!mounted) return;
      setState(() {
        _editableImages[layer.id] = _EditableImageBuffer(
          fullWidth: fullWidth,
          fullHeight: fullHeight,
          fullPixels: fullPixels,
          cloneBaseFullPixels: Uint8List.fromList(fullPixels),
          fullImage: layer.image!,
          previewWidth: previewWidth,
          previewHeight: previewHeight,
          previewPixels: previewPixels,
          cloneBasePreviewPixels: Uint8List.fromList(previewPixels),
          previewImage: previewImage,
          previewScale: previewScale,
        );
      });
    } catch (_) {
      if (mounted) {
        widget.onCanvasMessage('Could not prepare image for clone');
      }
    } finally {
      _bitmapLoadInFlight.remove(layer.id);
    }
  }

  int _targetPreviewDimension(int maxSide) {
    if (maxSide >= 7200) return 1024;
    if (maxSide >= 4800) return 1280;
    if (maxSide >= 3400) return 1536;
    return 2048;
  }

  _SketchMaskStroke? _activeSketchMaskStroke() {
    if (_interaction != _CanvasInteraction.sketchMasking) return null;
    final String? layerId = _gestureLayerId;
    if (layerId == null || _activeSketchMaskPointsUv.isEmpty) return null;
    if (_activeSketchMaskRadiusUv <= 0) return null;
    return _SketchMaskStroke(
      layerId: layerId,
      pointsUv: List<Offset>.from(_activeSketchMaskPointsUv),
      radiusUv: _activeSketchMaskRadiusUv,
    );
  }

  bool _startSketchMaskGesture({
    required Offset scenePoint,
    required Rect artboard,
    required Size workspaceSize,
  }) {
    if (!widget.sketchMaskDrawingEnabled) return false;
    final _ImageLayerSceneData? layerData = _resolveSketchMaskLayerData(
      artboard: artboard,
      workspaceSize: workspaceSize,
    );
    if (layerData == null) return false;
    final Offset? uv = _scenePointToLayerUv(
      scenePoint: scenePoint,
      layerData: layerData,
    );
    if (uv == null) return false;
    final double layerLongSide = math.max(
      1.0,
      math.max(layerData.width, layerData.height),
    );
    final double radiusScene =
        ((widget.sketchMaskBrushSize / _scale).clamp(2.0, 240.0) / 2)
            .toDouble();
    final double radiusUv = (radiusScene / layerLongSide).clamp(
      0.0007,
      0.35,
    );
    _interaction = _CanvasInteraction.sketchMasking;
    _gestureLayerId = layerData.layerId;
    _activeSketchMaskRadiusUv = radiusUv.toDouble();
    _activeSketchMaskPointsUv
      ..clear()
      ..add(uv);
    _repaintCanvas();
    return true;
  }

  void _updateSketchMaskGesture({
    required Offset scenePoint,
    required Rect artboard,
    required Size workspaceSize,
  }) {
    if (_interaction != _CanvasInteraction.sketchMasking) return;
    final String? layerId = _gestureLayerId;
    if (layerId == null) return;
    final _ImageLayerSceneData? layerData = _resolveSketchMaskLayerData(
      artboard: artboard,
      workspaceSize: workspaceSize,
      layerId: layerId,
    );
    if (layerData == null) return;
    final Offset? uv = _scenePointToLayerUv(
      scenePoint: scenePoint,
      layerData: layerData,
      clampToBounds: true,
    );
    if (uv == null) return;
    if (_activeSketchMaskPointsUv.isNotEmpty &&
        (uv - _activeSketchMaskPointsUv.last).distance < 0.00045) {
      return;
    }
    _activeSketchMaskPointsUv.add(uv);
    _repaintCanvas();
  }

  _ImageLayerSceneData? _resolveSketchMaskLayerData({
    required Rect artboard,
    required Size workspaceSize,
    String? layerId,
  }) {
    final String? targetLayerId = layerId ?? widget.sketchMaskLayerId;
    if (targetLayerId == null) return null;
    final EditorLayer? layer = _layerById(targetLayerId);
    if (layer == null ||
        !layer.isVisible ||
        layer.type != EditorLayerType.image ||
        layer.image == null) {
      return null;
    }
    final ui.Image image =
        _editableImages[layer.id]?.displayImage ?? layer.image!;
    return _buildImageLayerSceneData(
      layer: layer,
      image: image,
      artboard: artboard,
      workspaceSize: workspaceSize,
      rotateHandleDistance: _topRotateHandleDistance,
      moveHandleDistance: _bottomMoveHandleDistance,
    );
  }

  Offset? _scenePointToLayerUv({
    required Offset scenePoint,
    required _ImageLayerSceneData layerData,
    bool clampToBounds = false,
  }) {
    if (layerData.width <= 0.0001 || layerData.height <= 0.0001) return null;
    final Offset local =
        _rotateVector(scenePoint - layerData.center, -layerData.rotation);
    double u = (local.dx / layerData.width) + 0.5;
    double v = (local.dy / layerData.height) + 0.5;
    if (clampToBounds) {
      return Offset(
        u.clamp(0.0, 1.0).toDouble(),
        v.clamp(0.0, 1.0).toDouble(),
      );
    }
    if (u < 0.0 || u > 1.0 || v < 0.0 || v > 1.0) {
      return null;
    }
    return Offset(u, v);
  }

  bool _startCloneGesture({
    required Offset scenePoint,
    required Rect artboard,
  }) {
    return _cloneAtPoint(
      scenePoint: scenePoint,
      artboard: artboard,
      continuous: true,
    );
  }

  bool _cloneTapAtPoint({
    required Offset scenePoint,
    required Rect artboard,
  }) {
    return _cloneAtPoint(
      scenePoint: scenePoint,
      artboard: artboard,
      continuous: false,
    );
  }

  bool _cloneAtPoint({
    required Offset scenePoint,
    required Rect artboard,
    required bool continuous,
  }) {
    final EditorLayer? layer = _selectedImageLayerForClone();
    if (layer == null) {
      widget.onCanvasMessage(
        'Clone tool works only when an Image Layer is selected',
      );
      return false;
    }
    if (!artboard.contains(scenePoint)) return false;

    final Offset tapUv = _toUv(scenePoint, artboard);
    final bool isEraseStroke = widget.isCloneEraseSelected;

    if (_cloneSourceTapMode) {
      _clonePointerUvByLayer[layer.id] = tapUv;
      _cloneSourceTapMode = false;
      _prepareEditableImageBuffer(layer);
      _repaintCanvas();
      widget.onCloneSourcePicked();
      return true;
    }

    if (!widget.isCloneBrushSelected && !isEraseStroke) {
      return false;
    }

    final Offset? sourceUv =
        isEraseStroke ? null : _clonePointerUvByLayer[layer.id];
    if (!isEraseStroke && sourceUv == null) {
      return false;
    }

    final _EditableImageBuffer? buffer = _editableImages[layer.id];
    if (buffer == null) {
      _prepareEditableImageBuffer(layer);
      widget.onCanvasMessage('Preparing layer for clone, try again');
      return false;
    }

    final _CloneStrokeSession stroke = _CloneStrokeSession(
      layerId: layer.id,
      mode: isEraseStroke ? _CloneStrokeMode.erase : _CloneStrokeMode.clone,
      sourceOffsetUv: isEraseStroke ? Offset.zero : (sourceUv! - tapUv),
      settings: widget.cloneSettings,
      artboardWidth: artboard.width,
      destPointsUv: <Offset>[tapUv],
    );
    if (isEraseStroke) {
      _clonePreviewSourceSnapshot = null;
      _clonePreviewSourceLayerId = null;
    } else {
      _clonePreviewSourceSnapshot = Uint8List.fromList(buffer.previewPixels);
      _clonePreviewSourceLayerId = layer.id;
    }
    if (continuous) {
      _interaction = _CanvasInteraction.cloning;
      _gestureLayerId = layer.id;
      _cloneOffsetUv = stroke.sourceOffsetUv;
      _lastCloneDestUv = tapUv;
      _activeCloneStroke = stroke;
    }

    _enqueueCloneSegment(
      layerId: layer.id,
      fromDestUv: tapUv,
      toDestUv: tapUv,
      stroke: stroke,
    );
    _flushPendingCloneSegments();
    if (continuous) {
      _cloneChangedLayer = true;
    } else {
      if (buffer.usesPreview) {
        _queueEditableImageRefresh(layer.id);
        _enqueueFullResolutionCommit(
          layerId: layer.id,
          stroke: stroke.freeze(),
        );
      } else {
        _queueEditableImageRefresh(layer.id, notifyParent: true);
      }
      _clonePreviewSourceSnapshot = null;
      _clonePreviewSourceLayerId = null;
    }
    return true;
  }

  void _startMarqueeGesture({
    required Offset scenePoint,
    required Rect artboard,
  }) {
    final EditorLayer? selectedImage =
        _selectedBackgroundImageLayerForMarquee();
    if (selectedImage == null) {
      widget.onMarqueeSelectionChanged(null);
      return;
    }
    if (!artboard.contains(scenePoint)) return;

    final Offset startUv = _toUv(scenePoint, artboard);
    _interaction = _CanvasInteraction.marqueeSelecting;
    _gestureLayerId = selectedImage.id;
    _marqueeStartUv = startUv;
    _freeMarqueePointsUv.clear();

    if (widget.marqueeMode == MarqueeSelectionMode.freehand) {
      _freeMarqueePointsUv.add(startUv);
      widget.onMarqueeSelectionChanged(
        _buildFreehandSelection(selectedImage.id),
      );
      return;
    }
    widget.onMarqueeSelectionChanged(
      _buildBoundsSelection(
        layerId: selectedImage.id,
        startUv: startUv,
        endUv: startUv,
      ),
    );
  }

  void _updateMarqueeGesture({
    required Offset scenePoint,
    required Rect artboard,
  }) {
    final String? layerId = _gestureLayerId;
    if (layerId == null) return;
    if (!artboard.contains(scenePoint)) return;
    final Offset currentUv = _toUv(scenePoint, artboard);

    if (widget.marqueeMode == MarqueeSelectionMode.freehand) {
      if (_freeMarqueePointsUv.isEmpty ||
          (_freeMarqueePointsUv.last - currentUv).distance > 0.002) {
        _freeMarqueePointsUv.add(currentUv);
        widget.onMarqueeSelectionChanged(_buildFreehandSelection(layerId));
      }
      return;
    }

    final Offset? startUv = _marqueeStartUv;
    if (startUv == null) return;
    widget.onMarqueeSelectionChanged(
      _buildBoundsSelection(
        layerId: layerId,
        startUv: startUv,
        endUv: currentUv,
      ),
    );
  }

  void _finalizeMarqueeSelection() {
    final MarqueeSelection? selection = widget.marqueeSelection;
    if (selection != null && !selection.hasUsableArea) {
      widget.onMarqueeSelectionChanged(null);
    }
  }

  MarqueeSelection _buildBoundsSelection({
    required String layerId,
    required Offset startUv,
    required Offset endUv,
  }) {
    final Rect bounds = Rect.fromLTRB(
      math.min(startUv.dx, endUv.dx),
      math.min(startUv.dy, endUv.dy),
      math.max(startUv.dx, endUv.dx),
      math.max(startUv.dy, endUv.dy),
    );
    return MarqueeSelection(
      layerId: layerId,
      mode: widget.marqueeMode,
      boundsUv: bounds,
    );
  }

  MarqueeSelection _buildFreehandSelection(String layerId) {
    if (_freeMarqueePointsUv.isEmpty) {
      return MarqueeSelection(
        layerId: layerId,
        mode: MarqueeSelectionMode.freehand,
        boundsUv: Rect.zero,
      );
    }
    double minX = _freeMarqueePointsUv.first.dx;
    double minY = _freeMarqueePointsUv.first.dy;
    double maxX = _freeMarqueePointsUv.first.dx;
    double maxY = _freeMarqueePointsUv.first.dy;
    for (final Offset point in _freeMarqueePointsUv) {
      if (point.dx < minX) minX = point.dx;
      if (point.dy < minY) minY = point.dy;
      if (point.dx > maxX) maxX = point.dx;
      if (point.dy > maxY) maxY = point.dy;
    }
    return MarqueeSelection(
      layerId: layerId,
      mode: MarqueeSelectionMode.freehand,
      boundsUv: Rect.fromLTRB(minX, minY, maxX, maxY),
      freePathUv: List<Offset>.from(_freeMarqueePointsUv),
    );
  }

  void _updateCloneGesture({
    required Offset scenePoint,
    required Rect artboard,
  }) {
    final String? layerId = _gestureLayerId;
    final Offset? sourceOffsetUv = _cloneOffsetUv;
    final _CloneStrokeSession? stroke = _activeCloneStroke;
    if (layerId == null || sourceOffsetUv == null || stroke == null) return;
    final _EditableImageBuffer? buffer = _editableImages[layerId];
    if (buffer == null) return;

    final Offset nextDestUv = _toUv(scenePoint, artboard);
    final Offset fromDestUv = _lastCloneDestUv ?? nextDestUv;
    final double radiusPx = math.max(
      1.0,
      (stroke.settings.size * buffer.previewWidth / stroke.artboardWidth) / 2,
    );
    final double stampSpacingPx = _cloneStampSpacingPx(
      radiusPx: radiusPx,
      hardness: stroke.settings.hardness,
    );
    final double minMovementPx = (stampSpacingPx * 0.45).clamp(0.2, 2.2);
    final double movementPx =
        (nextDestUv - fromDestUv).distance * buffer.previewWidth;
    if (movementPx < minMovementPx) return;

    _enqueueCloneSegment(
      layerId: layerId,
      fromDestUv: fromDestUv,
      toDestUv: nextDestUv,
      stroke: stroke,
    );
    _flushPendingCloneSegments();

    stroke.destPointsUv.add(nextDestUv);
    _lastCloneDestUv = nextDestUv;
    _cloneChangedLayer = true;
  }

  void _enqueueCloneSegment({
    required String layerId,
    required Offset fromDestUv,
    required Offset toDestUv,
    required _CloneStrokeSession stroke,
  }) {
    _pendingCloneSegments.add(
      _ClonePendingSegment(
        layerId: layerId,
        mode: stroke.mode,
        fromDestUv: fromDestUv,
        toDestUv: toDestUv,
        sourceOffsetUv: stroke.sourceOffsetUv,
        settings: stroke.settings,
        artboardWidth: stroke.artboardWidth,
      ),
    );
    _scheduleCloneWorkFrame();
  }

  void _scheduleCloneWorkFrame() {
    if (_cloneWorkFrameScheduled) return;
    _cloneWorkFrameScheduled = true;
    SchedulerBinding.instance.scheduleFrameCallback((_) {
      _cloneWorkFrameScheduled = false;
      _flushPendingCloneSegments();
      if (_pendingCloneSegments.isNotEmpty) {
        _scheduleCloneWorkFrame();
      }
    });
    SchedulerBinding.instance.ensureVisualUpdate();
  }

  void _flushPendingCloneSegments() {
    if (_pendingCloneSegments.isEmpty) return;
    final List<_ClonePendingSegment> pending =
        List<_ClonePendingSegment>.from(_pendingCloneSegments);
    _pendingCloneSegments.clear();
    final Uint8List? sharedSourceSnapshot = _clonePreviewSourceSnapshot;
    final String? sharedSourceLayerId = _clonePreviewSourceLayerId;
    final Set<String> touchedLayerIds = <String>{};
    for (final _ClonePendingSegment segment in pending) {
      final _EditableImageBuffer? buffer = _editableImages[segment.layerId];
      if (buffer == null) continue;
      if (segment.mode == _CloneStrokeMode.erase) {
        if (buffer.cloneBasePreviewPixels.length !=
            buffer.previewPixels.length) {
          continue;
        }
        _paintRestoreSegmentOnPixels(
          sourcePixels: buffer.cloneBasePreviewPixels,
          targetPixels: buffer.previewPixels,
          targetWidth: buffer.previewWidth,
          targetHeight: buffer.previewHeight,
          fromDestUv: segment.fromDestUv,
          toDestUv: segment.toDestUv,
          settings: segment.settings,
          artboardWidth: segment.artboardWidth,
        );
      } else {
        final Uint8List sourcePixels;
        if (sharedSourceSnapshot != null &&
            sharedSourceLayerId == segment.layerId &&
            sharedSourceSnapshot.length == buffer.previewPixels.length) {
          sourcePixels = sharedSourceSnapshot;
        } else {
          sourcePixels = buffer.previewPixels;
        }
        _paintCloneSegmentOnPixels(
          sourcePixels: sourcePixels,
          targetPixels: buffer.previewPixels,
          targetWidth: buffer.previewWidth,
          targetHeight: buffer.previewHeight,
          fromDestUv: segment.fromDestUv,
          toDestUv: segment.toDestUv,
          sourceOffsetUv: segment.sourceOffsetUv,
          settings: segment.settings,
          artboardWidth: segment.artboardWidth,
          onSourceAdvanced: (sourceUv) {
            _clonePointerUvByLayer[segment.layerId] = sourceUv;
          },
        );
      }
      touchedLayerIds.add(segment.layerId);
    }
    for (final String layerId in touchedLayerIds) {
      _requestPreviewFrameRefresh(layerId);
    }
    _repaintCanvas();
  }

  void _requestPreviewFrameRefresh(String layerId) {
    final _EditableImageBuffer? buffer = _editableImages[layerId];
    if (buffer == null) return;
    buffer.previewFrameRequested = true;
    if (buffer.previewFrameScheduled) return;
    buffer.previewFrameScheduled = true;
    SchedulerBinding.instance.scheduleFrameCallback((_) {
      final _EditableImageBuffer? latest = _editableImages[layerId];
      if (!mounted || latest == null) return;
      latest.previewFrameScheduled = false;
      if (!latest.previewFrameRequested) return;
      latest.previewFrameRequested = false;
      _queueEditableImageRefresh(layerId);
    });
    SchedulerBinding.instance.ensureVisualUpdate();
  }

  void _paintCloneSegmentOnPixels({
    required Uint8List sourcePixels,
    required Uint8List targetPixels,
    required int targetWidth,
    required int targetHeight,
    required Offset fromDestUv,
    required Offset toDestUv,
    required Offset sourceOffsetUv,
    required CloneStampSettings settings,
    required double artboardWidth,
    ValueChanged<Offset>? onSourceAdvanced,
  }) {
    final double radiusPx =
        math.max(1.0, (settings.size * targetWidth / artboardWidth) / 2);
    final _CloneBrushMask brushMask = _resolveCloneBrushMask(
      radiusPx: radiusPx,
      hardness: settings.hardness,
    );
    final Offset delta = toDestUv - fromDestUv;
    final double distancePx = delta.distance * targetWidth;
    final double stampSpacingPx = _cloneStampSpacingPx(
      radiusPx: radiusPx,
      hardness: settings.hardness,
    );
    final bool stationary = distancePx <= 0.001;
    final int steps =
        stationary ? 1 : math.max(1, (distancePx / stampSpacingPx).ceil());
    final double flowOpacityFactor = _cloneFlowOpacityFactor(
      baseOpacityFactor: settings.opacity / 100,
      radiusPx: radiusPx,
      stampSpacingPx: stampSpacingPx,
      stationary: stationary,
    );
    if (stationary) {
      final Offset destUv = _clampUv(toDestUv);
      final Offset sourceUv = destUv + sourceOffsetUv;
      if (_isUvInsideUnitSquare(sourceUv)) {
        _applyCloneStamp(
          sourcePixels: sourcePixels,
          targetPixels: targetPixels,
          width: targetWidth,
          height: targetHeight,
          sourceUv: sourceUv,
          destUv: destUv,
          brushMask: brushMask,
          opacityFactor: flowOpacityFactor,
        );
      }
      onSourceAdvanced?.call(_clampUv(sourceUv));
      return;
    }
    for (int i = 1; i <= steps; i++) {
      final double t = i / steps;
      final Offset destUv = _clampUv(
        Offset.lerp(fromDestUv, toDestUv, t) ?? toDestUv,
      );
      final Offset sourceUv = destUv + sourceOffsetUv;
      if (!_isUvInsideUnitSquare(sourceUv)) {
        onSourceAdvanced?.call(_clampUv(sourceUv));
        continue;
      }
      _applyCloneStamp(
        sourcePixels: sourcePixels,
        targetPixels: targetPixels,
        width: targetWidth,
        height: targetHeight,
        sourceUv: sourceUv,
        destUv: destUv,
        brushMask: brushMask,
        opacityFactor: flowOpacityFactor,
      );
      onSourceAdvanced?.call(sourceUv);
    }
  }

  void _paintRestoreSegmentOnPixels({
    required Uint8List sourcePixels,
    required Uint8List targetPixels,
    required int targetWidth,
    required int targetHeight,
    required Offset fromDestUv,
    required Offset toDestUv,
    required CloneStampSettings settings,
    required double artboardWidth,
  }) {
    final double radiusPx =
        math.max(1.0, (settings.size * targetWidth / artboardWidth) / 2);
    final _CloneBrushMask brushMask = _resolveCloneBrushMask(
      radiusPx: radiusPx,
      hardness: settings.hardness,
    );
    final Offset delta = toDestUv - fromDestUv;
    final double distancePx = delta.distance * targetWidth;
    final double stampSpacingPx = _cloneStampSpacingPx(
      radiusPx: radiusPx,
      hardness: settings.hardness,
    );
    final bool stationary = distancePx <= 0.001;
    final int steps =
        stationary ? 1 : math.max(1, (distancePx / stampSpacingPx).ceil());
    final double flowOpacityFactor = _cloneFlowOpacityFactor(
      baseOpacityFactor: settings.opacity / 100,
      radiusPx: radiusPx,
      stampSpacingPx: stampSpacingPx,
      stationary: stationary,
    );
    if (stationary) {
      _applyRestoreStamp(
        sourcePixels: sourcePixels,
        targetPixels: targetPixels,
        width: targetWidth,
        height: targetHeight,
        destUv: _clampUv(toDestUv),
        brushMask: brushMask,
        opacityFactor: flowOpacityFactor,
      );
      return;
    }
    for (int i = 1; i <= steps; i++) {
      final double t = i / steps;
      final Offset destUv = _clampUv(
        Offset.lerp(fromDestUv, toDestUv, t) ?? toDestUv,
      );
      _applyRestoreStamp(
        sourcePixels: sourcePixels,
        targetPixels: targetPixels,
        width: targetWidth,
        height: targetHeight,
        destUv: destUv,
        brushMask: brushMask,
        opacityFactor: flowOpacityFactor,
      );
    }
  }

  void _applyCloneStamp({
    required Uint8List sourcePixels,
    required Uint8List targetPixels,
    required int width,
    required int height,
    required Offset sourceUv,
    required Offset destUv,
    required _CloneBrushMask brushMask,
    required double opacityFactor,
  }) {
    final int sourceX = (sourceUv.dx * (width - 1)).round();
    final int sourceY = (sourceUv.dy * (height - 1)).round();
    final int destX = (destUv.dx * (width - 1)).round();
    final int destY = (destUv.dy * (height - 1)).round();
    final int radius = brushMask.radius;
    final int maskWidth = brushMask.size;
    final List<double> alphaGrid = brushMask.alphaGrid;

    for (int y = -radius; y <= radius; y++) {
      final int sy = sourceY + y;
      final int dy = destY + y;
      if (sy < 0 || sy >= height || dy < 0 || dy >= height) continue;
      for (int x = -radius; x <= radius; x++) {
        final int sx = sourceX + x;
        final int dx = destX + x;
        if (sx < 0 || sx >= width || dx < 0 || dx >= width) continue;
        final int maskIndex = ((y + radius) * maskWidth) + (x + radius);
        final double alpha = (alphaGrid[maskIndex] * opacityFactor).clamp(
          0.0,
          1.0,
        );
        if (alpha <= 0) continue;

        final int sourceIndex = ((sy * width) + sx) * 4;
        final int destIndex = ((dy * width) + dx) * 4;
        final int sr = sourcePixels[sourceIndex];
        final int sg = sourcePixels[sourceIndex + 1];
        final int sb = sourcePixels[sourceIndex + 2];
        final int sa = sourcePixels[sourceIndex + 3];

        targetPixels[destIndex] =
            _blendChannel(targetPixels[destIndex], sr, alpha);
        targetPixels[destIndex + 1] =
            _blendChannel(targetPixels[destIndex + 1], sg, alpha);
        targetPixels[destIndex + 2] =
            _blendChannel(targetPixels[destIndex + 2], sb, alpha);
        targetPixels[destIndex + 3] =
            _blendChannel(targetPixels[destIndex + 3], sa, alpha);
      }
    }
  }

  void _applyRestoreStamp({
    required Uint8List sourcePixels,
    required Uint8List targetPixels,
    required int width,
    required int height,
    required Offset destUv,
    required _CloneBrushMask brushMask,
    required double opacityFactor,
  }) {
    final int destX = (destUv.dx * (width - 1)).round();
    final int destY = (destUv.dy * (height - 1)).round();
    final int radius = brushMask.radius;
    final int maskWidth = brushMask.size;
    final List<double> alphaGrid = brushMask.alphaGrid;

    for (int y = -radius; y <= radius; y++) {
      final int dy = destY + y;
      if (dy < 0 || dy >= height) continue;
      for (int x = -radius; x <= radius; x++) {
        final int dx = destX + x;
        if (dx < 0 || dx >= width) continue;
        final int maskIndex = ((y + radius) * maskWidth) + (x + radius);
        final double alpha = (alphaGrid[maskIndex] * opacityFactor).clamp(
          0.0,
          1.0,
        );
        if (alpha <= 0) continue;

        final int sourceIndex = ((dy * width) + dx) * 4;
        final int destIndex = ((dy * width) + dx) * 4;
        final int sr = sourcePixels[sourceIndex];
        final int sg = sourcePixels[sourceIndex + 1];
        final int sb = sourcePixels[sourceIndex + 2];
        final int sa = sourcePixels[sourceIndex + 3];

        targetPixels[destIndex] =
            _blendChannel(targetPixels[destIndex], sr, alpha);
        targetPixels[destIndex + 1] =
            _blendChannel(targetPixels[destIndex + 1], sg, alpha);
        targetPixels[destIndex + 2] =
            _blendChannel(targetPixels[destIndex + 2], sb, alpha);
        targetPixels[destIndex + 3] =
            _blendChannel(targetPixels[destIndex + 3], sa, alpha);
      }
    }
  }

  void _enqueueFullResolutionCommit({
    required String layerId,
    required _CloneStrokeSession stroke,
  }) {
    if (stroke.layerId != layerId) return;
    final _EditableImageBuffer? buffer = _editableImages[layerId];
    if (buffer == null) return;
    buffer.pendingCommits.add(stroke);
    if (buffer.isCommittingFull) return;
    buffer.isCommittingFull = true;
    unawaited(_runFullResolutionCommitQueue(layerId));
  }

  Future<void> _runFullResolutionCommitQueue(String layerId) async {
    try {
      while (mounted) {
        final _EditableImageBuffer? buffer = _editableImages[layerId];
        if (buffer == null) return;
        if (buffer.pendingCommits.isEmpty) {
          buffer.isCommittingFull = false;
          return;
        }

        final List<_CloneStrokeSession> batch =
            List<_CloneStrokeSession>.from(buffer.pendingCommits);
        final int batchGeneration = buffer.commitGeneration;
        buffer.pendingCommits.clear();

        final Uint8List fullSnapshot = Uint8List.fromList(buffer.fullPixels);
        final Uint8List committedPixels = await _commitCloneBatchOnIsolate(
          pixels: fullSnapshot,
          basePixels:
              batch.any((stroke) => stroke.mode == _CloneStrokeMode.erase)
                  ? Uint8List.fromList(buffer.cloneBaseFullPixels)
                  : null,
          width: buffer.fullWidth,
          height: buffer.fullHeight,
          strokes: batch,
        );
        if (!mounted) return;

        final _EditableImageBuffer? latest = _editableImages[layerId];
        if (latest == null) return;
        if (latest.commitGeneration != batchGeneration) {
          continue;
        }
        if (latest.fullPixels.length != committedPixels.length) {
          latest.isCommittingFull = false;
          return;
        }
        latest.fullPixels.setAll(0, committedPixels);

        final ui.Image renderedImage = await _imageFromPixels(
          pixels: committedPixels,
          width: latest.fullWidth,
          height: latest.fullHeight,
        );
        if (!mounted) return;

        final _EditableImageBuffer? newest = _editableImages[layerId];
        if (newest == null) return;
        if (newest.commitGeneration != batchGeneration) {
          continue;
        }
        newest.fullImage = renderedImage;
        if (!newest.usesPreview &&
            newest.previewPixels.length == committedPixels.length) {
          newest.previewPixels.setAll(0, committedPixels);
          newest.previewImage = renderedImage;
          _repaintCanvas();
        }
        widget.onLayerImageChanged(layerId, renderedImage);
      }
    } catch (_) {
      final _EditableImageBuffer? buffer = _editableImages[layerId];
      if (buffer != null) {
        buffer.isCommittingFull = false;
      }
    }
  }

  Future<Uint8List> _commitCloneBatchOnIsolate({
    required Uint8List pixels,
    required Uint8List? basePixels,
    required int width,
    required int height,
    required List<_CloneStrokeSession> strokes,
  }) async {
    if (strokes.isEmpty) return pixels;
    final _CloneBatchPayload payload = _CloneBatchPayload(
      pixels: TransferableTypedData.fromList(<Uint8List>[pixels]),
      basePixels: basePixels == null
          ? null
          : TransferableTypedData.fromList(<Uint8List>[basePixels]),
      width: width,
      height: height,
      strokes: strokes
          .map(
            (stroke) => _CloneStrokePayload(
              modeIndex: stroke.mode.index,
              sourceOffsetDx: stroke.sourceOffsetUv.dx,
              sourceOffsetDy: stroke.sourceOffsetUv.dy,
              brushSize: stroke.settings.size,
              hardness: stroke.settings.hardness,
              opacity: stroke.settings.opacity,
              artboardWidth: stroke.artboardWidth,
              packedDestPoints: _packOffsets(stroke.destPointsUv),
            ),
          )
          .toList(growable: false),
    );
    final _CloneBatchResult result =
        await Isolate.run<_CloneBatchResult>(() => _applyCloneBatch(payload));
    return result.pixels.materialize().asUint8List();
  }

  Float32List _packOffsets(List<Offset> points) {
    final Float32List packed = Float32List(points.length * 2);
    for (int i = 0; i < points.length; i++) {
      packed[i * 2] = points[i].dx;
      packed[(i * 2) + 1] = points[i].dy;
    }
    return packed;
  }

  Uint8List _downscaleRgbaNearest({
    required Uint8List sourcePixels,
    required int sourceWidth,
    required int sourceHeight,
    required int targetWidth,
    required int targetHeight,
  }) {
    final Uint8List targetPixels = Uint8List(targetWidth * targetHeight * 4);
    for (int y = 0; y < targetHeight; y++) {
      final int sourceY = ((y * sourceHeight) / targetHeight).floor().clamp(
            0,
            sourceHeight - 1,
          );
      for (int x = 0; x < targetWidth; x++) {
        final int sourceX = ((x * sourceWidth) / targetWidth).floor().clamp(
              0,
              sourceWidth - 1,
            );
        final int sourceIndex = ((sourceY * sourceWidth) + sourceX) * 4;
        final int targetIndex = ((y * targetWidth) + x) * 4;
        targetPixels[targetIndex] = sourcePixels[sourceIndex];
        targetPixels[targetIndex + 1] = sourcePixels[sourceIndex + 1];
        targetPixels[targetIndex + 2] = sourcePixels[sourceIndex + 2];
        targetPixels[targetIndex + 3] = sourcePixels[sourceIndex + 3];
      }
    }
    return targetPixels;
  }

  int _blendChannel(int base, int source, double alpha) {
    final double mixed = base + ((source - base) * alpha);
    return mixed.clamp(0, 255).round();
  }

  _CloneBrushMask _resolveCloneBrushMask({
    required double radiusPx,
    required double hardness,
  }) {
    final int radius = math.max(1, radiusPx.ceil());
    final int hardnessInt = hardness.round().clamp(0, 100);
    final String key = '${radius}_$hardnessInt';
    final _CloneBrushMask? cached = _cloneBrushMaskCache[key];
    if (cached != null) return cached;

    final int size = (radius * 2) + 1;
    final double radiusSquared = radiusPx * radiusPx;
    final double hardRadius =
        radiusPx * _cloneHardnessToHardRadiusFactor(hardnessInt.toDouble());
    final double hardRadiusSquared = hardRadius * hardRadius;
    final List<double> alphaGrid = List<double>.filled(size * size, 0);

    for (int y = -radius; y <= radius; y++) {
      for (int x = -radius; x <= radius; x++) {
        final double distSquared = ((x * x) + (y * y)).toDouble();
        if (distSquared > radiusSquared) continue;
        double alpha = 1.0;
        if (hardRadius < radiusPx && distSquared > hardRadiusSquared) {
          final double dist = math.sqrt(distSquared);
          final double featherT =
              ((dist - hardRadius) / (radiusPx - hardRadius)).clamp(0.0, 1.0);
          alpha = _cloneSoftEdgeAlpha(featherT);
        }
        final int index = ((y + radius) * size) + (x + radius);
        alphaGrid[index] = alpha.clamp(0.0, 1.0);
      }
    }

    final _CloneBrushMask mask = _CloneBrushMask(
      radius: radius,
      size: size,
      alphaGrid: alphaGrid,
    );
    if (_cloneBrushMaskCache.length >= 48) {
      _cloneBrushMaskCache.remove(_cloneBrushMaskCache.keys.first);
    }
    _cloneBrushMaskCache[key] = mask;
    return mask;
  }

  void _queueEditableImageRefresh(String layerId, {bool notifyParent = false}) {
    final _EditableImageBuffer? buffer = _editableImages[layerId];
    if (buffer == null) return;
    if (notifyParent) {
      buffer.notifyParentAfterBuild = true;
    }
    if (buffer.isBuildingPreviewImage) {
      buffer.previewNeedsAnotherBuild = true;
      return;
    }

    buffer.isBuildingPreviewImage = true;
    final Uint8List snapshot = Uint8List.fromList(buffer.previewPixels);
    unawaited(
      _imageFromPixels(
        pixels: snapshot,
        width: buffer.previewWidth,
        height: buffer.previewHeight,
      )
          .then((ui.Image renderedImage) {
            if (!mounted) return;
            final _EditableImageBuffer? latest = _editableImages[layerId];
            if (latest == null) return;
            final bool notifyLayerChange = latest.notifyParentAfterBuild;
            latest.previewImage = renderedImage;
            if (!latest.usesPreview) {
              latest.fullImage = renderedImage;
            }
            latest.notifyParentAfterBuild = false;
            _repaintCanvas();
            if (notifyLayerChange && !latest.usesPreview) {
              widget.onLayerImageChanged(layerId, renderedImage);
            }
          })
          .catchError((_) {})
          .whenComplete(() {
            final _EditableImageBuffer? latest = _editableImages[layerId];
            if (latest == null) return;
            latest.isBuildingPreviewImage = false;
            if (latest.previewNeedsAnotherBuild) {
              latest.previewNeedsAnotherBuild = false;
              _queueEditableImageRefresh(layerId);
            }
          }),
    );
  }

  Future<ui.Image> _imageFromPixels({
    required Uint8List pixels,
    required int width,
    required int height,
  }) {
    final Completer<ui.Image> completer = Completer<ui.Image>();
    ui.decodeImageFromPixels(
      pixels,
      width,
      height,
      ui.PixelFormat.rgba8888,
      (ui.Image image) => completer.complete(image),
    );
    return completer.future;
  }

  Offset _toUv(Offset scenePoint, Rect artboard) {
    final double u = (scenePoint.dx - artboard.left) / artboard.width;
    final double v = (scenePoint.dy - artboard.top) / artboard.height;
    return _clampUv(Offset(u, v));
  }

  Offset _clampUv(Offset uv) {
    return Offset(
      _clampDouble(uv.dx, 0, 1),
      _clampDouble(uv.dy, 0, 1),
    );
  }

  double _clampDouble(double value, double min, double max) {
    if (value < min) return min;
    if (value > max) return max;
    return value;
  }

  Offset _toScenePoint(Offset localPoint) {
    return Offset(
      (localPoint.dx - _pan.dx) / _scale,
      (localPoint.dy - _pan.dy) / _scale,
    );
  }

  Offset _toViewportPoint(Offset scenePoint) {
    return Offset(
      (scenePoint.dx * _scale) + _pan.dx,
      (scenePoint.dy * _scale) + _pan.dy,
    );
  }

  Offset _clampPan(
    Offset rawPan,
    Size canvasSize, {
    double? scaleOverride,
    Rect? artboard,
    _PanClampMode panClampMode = _PanClampMode.hard,
  }) {
    final double viewScale = scaleOverride ?? _scale;
    if (artboard == null || viewScale <= 0) {
      return rawPan;
    }

    double clampAxis({
      required double rawPanAxis,
      required double canvasExtent,
      required double artMin,
      required double artMax,
      required bool alignStartWhenSmaller,
      required _PanClampMode panClampMode,
    }) {
      final double transformedMin = artMin * viewScale;
      final double transformedMax = artMax * viewScale;
      final double transformedExtent = transformedMax - transformedMin;

      if (transformedExtent <= canvasExtent) {
        if (panClampMode == _PanClampMode.hard) {
          final double alignedPan = alignStartWhenSmaller
              ? -transformedMin
              : ((canvasExtent - transformedExtent) / 2) - transformedMin;
          return alignedPan;
        }
        // Keep pan fully free while zooming when content is smaller than the
        // viewport to avoid top/center drift on pinch-out.
        return rawPanAxis;
      }

      final double minPan = canvasExtent - transformedMax;
      final double maxPan = -transformedMin;
      if (panClampMode == _PanClampMode.hard) {
        return _clampDouble(rawPanAxis, minPan, maxPan);
      }

      if (rawPanAxis < minPan) {
        final double overflow = minPan - rawPanAxis;
        final double rubber = _rubberBandDistance(overflow, canvasExtent);
        return minPan - rubber;
      }
      if (rawPanAxis > maxPan) {
        final double overflow = rawPanAxis - maxPan;
        final double rubber = _rubberBandDistance(overflow, canvasExtent);
        return maxPan + rubber;
      }
      return rawPanAxis;
    }

    return Offset(
      clampAxis(
        rawPanAxis: rawPan.dx,
        canvasExtent: canvasSize.width,
        artMin: artboard.left,
        artMax: artboard.right,
        alignStartWhenSmaller: false,
        panClampMode: panClampMode,
      ),
      clampAxis(
        rawPanAxis: rawPan.dy,
        canvasExtent: canvasSize.height,
        artMin: artboard.top,
        artMax: artboard.bottom,
        alignStartWhenSmaller: true,
        panClampMode: panClampMode,
      ),
    );
  }

  double _rubberBandDistance(double overflow, double viewportExtent) {
    if (overflow <= 0 || viewportExtent <= 0) {
      return 0;
    }
    final double resistance = viewportExtent * 1.2;
    return (overflow * resistance) / (overflow + resistance);
  }

  Offset _clampPanOnGestureEnd(
    Offset rawPan,
    Size canvasSize, {
    double? scaleOverride,
    Rect? artboard,
  }) {
    final double viewScale = scaleOverride ?? _scale;
    if (artboard == null || viewScale <= 0) {
      return rawPan;
    }

    double settleAxis({
      required double rawPanAxis,
      required double canvasExtent,
      required double artMin,
      required double artMax,
    }) {
      final double transformedMin = artMin * viewScale;
      final double transformedMax = artMax * viewScale;
      final double transformedExtent = transformedMax - transformedMin;

      // Keep user pan when content is smaller than viewport on this axis.
      if (transformedExtent <= canvasExtent) {
        return rawPanAxis;
      }

      final double minPan = canvasExtent - transformedMax;
      final double maxPan = -transformedMin;
      return _clampDouble(rawPanAxis, minPan, maxPan);
    }

    return Offset(
      settleAxis(
        rawPanAxis: rawPan.dx,
        canvasExtent: canvasSize.width,
        artMin: artboard.left,
        artMax: artboard.right,
      ),
      settleAxis(
        rawPanAxis: rawPan.dy,
        canvasExtent: canvasSize.height,
        artMin: artboard.top,
        artMax: artboard.bottom,
      ),
    );
  }

  Rect _aabbForTransform({
    required Offset center,
    required double width,
    required double height,
    required double rotation,
  }) {
    final double absCos = math.cos(rotation).abs();
    final double absSin = math.sin(rotation).abs();
    final double halfWidth = ((absCos * width) + (absSin * height)) / 2;
    final double halfHeight = ((absSin * width) + (absCos * height)) / 2;
    return Rect.fromLTRB(
      center.dx - halfWidth,
      center.dy - halfHeight,
      center.dx + halfWidth,
      center.dy + halfHeight,
    );
  }

  void _beginSnapSession({
    required String layerId,
    required Rect artboard,
    required Size workspaceSize,
    required _TransformLayerSceneData selectedData,
  }) {
    final List<_SnapLayerTarget> otherTargets = <_SnapLayerTarget>[];
    final List<double> xTargets = <double>[
      artboard.left,
      artboard.center.dx,
      artboard.right,
    ];
    final List<double> yTargets = <double>[
      artboard.top,
      artboard.center.dy,
      artboard.bottom,
    ];
    for (final EditorLayer layer in widget.layers) {
      if (!layer.isVisible || layer.isBackground || layer.id == layerId) {
        continue;
      }
      final _TransformLayerSceneData? data = _buildSelectedTransformLayerData(
        selectedLayer: layer,
        artboard: artboard,
        workspaceSize: workspaceSize,
      );
      if (data == null) continue;
      final Rect rect = _aabbForTransform(
        center: data.center,
        width: data.width,
        height: data.height,
        rotation: data.rotation,
      );
      otherTargets.add(
        _SnapLayerTarget(
          layerId: layer.id,
          rect: rect,
        ),
      );
      xTargets
        ..add(rect.left)
        ..add(rect.center.dx)
        ..add(rect.right);
      yTargets
        ..add(rect.top)
        ..add(rect.center.dy)
        ..add(rect.bottom);
    }
    _snapSession = _SnapSession(
      layerId: layerId,
      artboard: artboard,
      otherTargets: otherTargets,
      xTargets: xTargets,
      yTargets: yTargets,
    );
    _transformStartCenterScene = selectedData.center;
    _transformStartWidthScene = selectedData.width;
    _transformStartHeightScene = selectedData.height;
    _transformStartRotation = selectedData.rotation;
    final Rect startAabb = _aabbForTransform(
      center: selectedData.center,
      width: selectedData.width,
      height: selectedData.height,
      rotation: selectedData.rotation,
    );
    _resizeStartAabbHalfX = math.max(0.0001, startAabb.width / 2);
    _resizeStartAabbHalfY = math.max(0.0001, startAabb.height / 2);
    _moveSnapXActive = false;
    _moveSnapYActive = false;
    _resizeSnapActive = false;
    _rotationSnapActive = false;
  }

  _MoveSnapResult _applyMoveSnapping({
    required Offset rawCenter,
    required double thresholdScene,
  }) {
    final _SnapSession? session = _snapSession;
    if (session == null) {
      _moveSnapXActive = false;
      _moveSnapYActive = false;
      return _MoveSnapResult(center: rawCenter, guides: const []);
    }
    final bool wasXActive = _moveSnapXActive;
    final bool wasYActive = _moveSnapYActive;
    final double xThreshold = thresholdScene * (wasXActive ? 1.22 : 0.62);
    final double yThreshold = thresholdScene * (wasYActive ? 1.22 : 0.62);
    final Rect rawRect = _aabbForTransform(
      center: rawCenter,
      width: _transformStartWidthScene,
      height: _transformStartHeightScene,
      rotation: _transformStartRotation,
    );
    final _AxisSnapChoice xChoice = _bestXAxisSnap(
      rect: rawRect,
      session: session,
      thresholdScene: xThreshold,
    );
    final double xSoftDelta = xChoice.isSnapped
        ? _softSnapDelta(
            rawDelta: xChoice.delta,
            snapDistance: xChoice.delta.abs(),
            threshold: xThreshold,
            sticky: wasXActive,
          )
        : 0;
    final Rect afterX = rawRect.shift(Offset(xSoftDelta, 0));
    final _AxisSnapChoice yChoice = _bestYAxisSnap(
      rect: afterX,
      session: session,
      thresholdScene: yThreshold,
    );
    final double ySoftDelta = yChoice.isSnapped
        ? _softSnapDelta(
            rawDelta: yChoice.delta,
            snapDistance: yChoice.delta.abs(),
            threshold: yThreshold,
            sticky: wasYActive,
          )
        : 0;
    _moveSnapXActive = xChoice.isSnapped;
    _moveSnapYActive = yChoice.isSnapped;
    final List<_SmartGuideSegment> guides = <_SmartGuideSegment>[
      if (xChoice.isSnapped) ...xChoice.guides,
      if (yChoice.isSnapped) ...yChoice.guides,
    ];
    return _MoveSnapResult(
      center: rawCenter + Offset(xSoftDelta, ySoftDelta),
      guides: guides,
    );
  }

  _AxisSnapChoice _bestXAxisSnap({
    required Rect rect,
    required _SnapSession session,
    required double thresholdScene,
  }) {
    final _AxisSnapChoice direct = _bestAxisTargetSnapX(
      rect: rect,
      session: session,
      thresholdScene: thresholdScene,
    );
    final _AxisSnapChoice spacing = _bestEqualSpacingSnapX(
      rect: rect,
      session: session,
      thresholdScene: thresholdScene,
    );
    if (!direct.isSnapped) return spacing;
    if (!spacing.isSnapped) return direct;
    final double spacingBonus = thresholdScene * 0.18;
    if (spacing.delta.abs() + spacingBonus < direct.delta.abs()) {
      return spacing;
    }
    return direct;
  }

  _AxisSnapChoice _bestYAxisSnap({
    required Rect rect,
    required _SnapSession session,
    required double thresholdScene,
  }) {
    final _AxisSnapChoice direct = _bestAxisTargetSnapY(
      rect: rect,
      session: session,
      thresholdScene: thresholdScene,
    );
    final _AxisSnapChoice spacing = _bestEqualSpacingSnapY(
      rect: rect,
      session: session,
      thresholdScene: thresholdScene,
    );
    if (!direct.isSnapped) return spacing;
    if (!spacing.isSnapped) return direct;
    final double spacingBonus = thresholdScene * 0.18;
    if (spacing.delta.abs() + spacingBonus < direct.delta.abs()) {
      return spacing;
    }
    return direct;
  }

  _AxisSnapChoice _bestAxisTargetSnapX({
    required Rect rect,
    required _SnapSession session,
    required double thresholdScene,
  }) {
    const _AxisSnapChoice none = _AxisSnapChoice(
      delta: 0,
      target: 0,
      anchor: 0,
    );
    final List<double> anchors = <double>[
      rect.left,
      rect.center.dx,
      rect.right
    ];
    double bestAbs = double.infinity;
    double bestDelta = 0;
    double bestTarget = 0;
    double bestAnchor = 0;
    bool found = false;
    for (final double anchor in anchors) {
      for (final double target in session.xTargets) {
        final double delta = target - anchor;
        final double distance = delta.abs();
        if (distance > thresholdScene || distance >= bestAbs) continue;
        bestAbs = distance;
        bestDelta = delta;
        bestTarget = target;
        bestAnchor = anchor;
        found = true;
      }
    }
    if (!found) return none;
    return _AxisSnapChoice(
      delta: bestDelta,
      target: bestTarget,
      anchor: bestAnchor,
      guides: <_SmartGuideSegment>[
        _SmartGuideSegment(
          start: Offset(bestTarget, session.artboard.top),
          end: Offset(bestTarget, session.artboard.bottom),
          emphasized: true,
        ),
      ],
    );
  }

  _AxisSnapChoice _bestAxisTargetSnapY({
    required Rect rect,
    required _SnapSession session,
    required double thresholdScene,
  }) {
    const _AxisSnapChoice none = _AxisSnapChoice(
      delta: 0,
      target: 0,
      anchor: 0,
    );
    final List<double> anchors = <double>[
      rect.top,
      rect.center.dy,
      rect.bottom
    ];
    double bestAbs = double.infinity;
    double bestDelta = 0;
    double bestTarget = 0;
    double bestAnchor = 0;
    bool found = false;
    for (final double anchor in anchors) {
      for (final double target in session.yTargets) {
        final double delta = target - anchor;
        final double distance = delta.abs();
        if (distance > thresholdScene || distance >= bestAbs) continue;
        bestAbs = distance;
        bestDelta = delta;
        bestTarget = target;
        bestAnchor = anchor;
        found = true;
      }
    }
    if (!found) return none;
    return _AxisSnapChoice(
      delta: bestDelta,
      target: bestTarget,
      anchor: bestAnchor,
      guides: <_SmartGuideSegment>[
        _SmartGuideSegment(
          start: Offset(session.artboard.left, bestTarget),
          end: Offset(session.artboard.right, bestTarget),
          emphasized: true,
        ),
      ],
    );
  }

  _AxisSnapChoice _bestEqualSpacingSnapX({
    required Rect rect,
    required _SnapSession session,
    required double thresholdScene,
  }) {
    const _AxisSnapChoice none = _AxisSnapChoice(
      delta: 0,
      target: 0,
      anchor: 0,
    );
    if (session.otherTargets.length < 2) return none;
    double bestAbs = double.infinity;
    _AxisSnapChoice best = none;
    for (int i = 0; i < session.otherTargets.length - 1; i++) {
      for (int j = i + 1; j < session.otherTargets.length; j++) {
        Rect leftRect = session.otherTargets[i].rect;
        Rect rightRect = session.otherTargets[j].rect;
        if (leftRect.center.dx > rightRect.center.dx) {
          final Rect swap = leftRect;
          leftRect = rightRect;
          rightRect = swap;
        }
        if (leftRect.right >= rightRect.left) continue;
        final double overlapLeft = _verticalOverlap(rect, leftRect);
        final double overlapRight = _verticalOverlap(rect, rightRect);
        final double minOverlap = math.max(
          4.0,
          math.min(
                rect.height,
                math.min(leftRect.height, rightRect.height),
              ) *
              0.12,
        );
        if (overlapLeft < minOverlap || overlapRight < minOverlap) continue;
        final double available = rightRect.left - leftRect.right - rect.width;
        if (available < 0) continue;
        final double targetLeft = leftRect.right + (available / 2);
        final double delta = targetLeft - rect.left;
        final double distance = delta.abs();
        if (distance > thresholdScene || distance >= bestAbs) continue;
        final double y = _spacingGuideY(rect, leftRect, rightRect);
        final double snappedLeft = rect.left + delta;
        final double snappedRight = rect.right + delta;
        bestAbs = distance;
        best = _AxisSnapChoice(
          delta: delta,
          target: targetLeft,
          anchor: rect.left,
          guides: <_SmartGuideSegment>[
            _SmartGuideSegment(
              start: Offset(leftRect.right, y),
              end: Offset(snappedLeft, y),
            ),
            _SmartGuideSegment(
              start: Offset(snappedRight, y),
              end: Offset(rightRect.left, y),
            ),
          ],
        );
      }
    }
    return best;
  }

  _AxisSnapChoice _bestEqualSpacingSnapY({
    required Rect rect,
    required _SnapSession session,
    required double thresholdScene,
  }) {
    const _AxisSnapChoice none = _AxisSnapChoice(
      delta: 0,
      target: 0,
      anchor: 0,
    );
    if (session.otherTargets.length < 2) return none;
    double bestAbs = double.infinity;
    _AxisSnapChoice best = none;
    for (int i = 0; i < session.otherTargets.length - 1; i++) {
      for (int j = i + 1; j < session.otherTargets.length; j++) {
        Rect topRect = session.otherTargets[i].rect;
        Rect bottomRect = session.otherTargets[j].rect;
        if (topRect.center.dy > bottomRect.center.dy) {
          final Rect swap = topRect;
          topRect = bottomRect;
          bottomRect = swap;
        }
        if (topRect.bottom >= bottomRect.top) continue;
        final double overlapTop = _horizontalOverlap(rect, topRect);
        final double overlapBottom = _horizontalOverlap(rect, bottomRect);
        final double minOverlap = math.max(
          4.0,
          math.min(
                rect.width,
                math.min(topRect.width, bottomRect.width),
              ) *
              0.12,
        );
        if (overlapTop < minOverlap || overlapBottom < minOverlap) continue;
        final double available = bottomRect.top - topRect.bottom - rect.height;
        if (available < 0) continue;
        final double targetTop = topRect.bottom + (available / 2);
        final double delta = targetTop - rect.top;
        final double distance = delta.abs();
        if (distance > thresholdScene || distance >= bestAbs) continue;
        final double x = _spacingGuideX(rect, topRect, bottomRect);
        final double snappedTop = rect.top + delta;
        final double snappedBottom = rect.bottom + delta;
        bestAbs = distance;
        best = _AxisSnapChoice(
          delta: delta,
          target: targetTop,
          anchor: rect.top,
          guides: <_SmartGuideSegment>[
            _SmartGuideSegment(
              start: Offset(x, topRect.bottom),
              end: Offset(x, snappedTop),
            ),
            _SmartGuideSegment(
              start: Offset(x, snappedBottom),
              end: Offset(x, bottomRect.top),
            ),
          ],
        );
      }
    }
    return best;
  }

  // ignore: unused_element
  _ScaleSnapResult _applyResizeSnapping({
    required double rawScale,
    required double thresholdScene,
  }) {
    final _SnapSession? session = _snapSession;
    if (session == null || _layerStartScale <= 0) {
      _resizeSnapActive = false;
      return _ScaleSnapResult(scale: rawScale, guides: const []);
    }
    final bool wasActive = _resizeSnapActive;
    final double effectiveThreshold = thresholdScene * (wasActive ? 1.7 : 0.88);
    double bestScale = rawScale;
    double bestError = double.infinity;
    double bestScaleDistance = double.infinity;
    List<_SmartGuideSegment> bestGuides = const <_SmartGuideSegment>[];

    void consider({
      required double scaleCandidate,
      required double error,
      required _SmartGuideSegment guide,
    }) {
      if (error > effectiveThreshold) return;
      final double scaleDistance = (scaleCandidate - rawScale).abs();
      if (error > bestError + 0.0001) return;
      if ((error - bestError).abs() <= 0.0001 &&
          scaleDistance >= bestScaleDistance) {
        return;
      }
      bestError = error;
      bestScaleDistance = scaleDistance;
      bestScale = scaleCandidate;
      bestGuides = <_SmartGuideSegment>[guide];
    }

    final Offset center = _transformStartCenterScene;
    final double baseHalfX = math.max(0.0001, _resizeStartAabbHalfX);
    final double baseHalfY = math.max(0.0001, _resizeStartAabbHalfY);
    for (final double target in session.xTargets) {
      final double rightFactor = (target - center.dx) / baseHalfX;
      if (rightFactor > 0) {
        final double candidate = (_layerStartScale * rightFactor)
            .clamp(_minLayerScale, _maxLayerScale)
            .toDouble();
        final double factor = candidate / _layerStartScale;
        final double right = center.dx + (baseHalfX * factor);
        consider(
          scaleCandidate: candidate,
          error: (right - target).abs(),
          guide: _SmartGuideSegment(
            start: Offset(target, session.artboard.top),
            end: Offset(target, session.artboard.bottom),
            emphasized: true,
          ),
        );
      }
      final double leftFactor = (center.dx - target) / baseHalfX;
      if (leftFactor > 0) {
        final double candidate = (_layerStartScale * leftFactor)
            .clamp(_minLayerScale, _maxLayerScale)
            .toDouble();
        final double factor = candidate / _layerStartScale;
        final double left = center.dx - (baseHalfX * factor);
        consider(
          scaleCandidate: candidate,
          error: (left - target).abs(),
          guide: _SmartGuideSegment(
            start: Offset(target, session.artboard.top),
            end: Offset(target, session.artboard.bottom),
            emphasized: true,
          ),
        );
      }
    }
    for (final double target in session.yTargets) {
      final double bottomFactor = (target - center.dy) / baseHalfY;
      if (bottomFactor > 0) {
        final double candidate = (_layerStartScale * bottomFactor)
            .clamp(_minLayerScale, _maxLayerScale)
            .toDouble();
        final double factor = candidate / _layerStartScale;
        final double bottom = center.dy + (baseHalfY * factor);
        consider(
          scaleCandidate: candidate,
          error: (bottom - target).abs(),
          guide: _SmartGuideSegment(
            start: Offset(session.artboard.left, target),
            end: Offset(session.artboard.right, target),
            emphasized: true,
          ),
        );
      }
      final double topFactor = (center.dy - target) / baseHalfY;
      if (topFactor > 0) {
        final double candidate = (_layerStartScale * topFactor)
            .clamp(_minLayerScale, _maxLayerScale)
            .toDouble();
        final double factor = candidate / _layerStartScale;
        final double top = center.dy - (baseHalfY * factor);
        consider(
          scaleCandidate: candidate,
          error: (top - target).abs(),
          guide: _SmartGuideSegment(
            start: Offset(session.artboard.left, target),
            end: Offset(session.artboard.right, target),
            emphasized: true,
          ),
        );
      }
    }
    if (bestError == double.infinity) {
      _resizeSnapActive = false;
      return _ScaleSnapResult(scale: rawScale, guides: const []);
    }
    _resizeSnapActive = true;
    final double blendedScale = _softSnapValue(
      rawValue: rawScale,
      snappedValue: bestScale,
      snapDistance: bestError,
      threshold: effectiveThreshold,
      sticky: wasActive,
    );
    return _ScaleSnapResult(scale: blendedScale, guides: bestGuides);
  }

  _RotationSnapResult _applyRotationSnapping({
    required double rawRotation,
    required Offset center,
  }) {
    const double snapStep = _rotationSnapStepDegrees * (math.pi / 180);
    final bool wasActive = _rotationSnapActive;
    final double threshold = (_rotationSnapThresholdDegrees * (math.pi / 180)) *
        (wasActive ? 1.8 : 0.9);
    final double snapped = (rawRotation / snapStep).round() * snapStep;
    final double delta = _normalizeAngle(rawRotation - snapped).abs();
    if (delta > threshold) {
      _rotationSnapActive = false;
      return _RotationSnapResult(rotation: rawRotation, guides: const []);
    }
    _rotationSnapActive = true;
    final Rect artboard = _snapSession?.artboard ??
        Rect.fromLTWH(
          center.dx - 400,
          center.dy - 400,
          800,
          800,
        );
    final double radius =
        math.max(artboard.width, artboard.height).clamp(240, 1800) * 0.75;
    final Offset direction = Offset(math.cos(snapped), math.sin(snapped));
    final double blendedRotation = _softSnapAngle(
      rawRotation: rawRotation,
      snappedRotation: snapped,
      snapDistance: delta,
      threshold: threshold,
      sticky: wasActive,
    );
    return _RotationSnapResult(
      rotation: blendedRotation,
      guides: <_SmartGuideSegment>[
        _SmartGuideSegment(
          start: center - (direction * radius),
          end: center + (direction * radius),
          emphasized: true,
        ),
      ],
    );
  }

  double _softSnapDelta({
    required double rawDelta,
    required double snapDistance,
    required double threshold,
    required bool sticky,
  }) {
    if (threshold <= 0.0001) return 0;
    // Move-only magnetic snap: engage only when very close to the snap target.
    final double magneticZone = threshold * 0.22;
    if (snapDistance > magneticZone) return 0;
    if (snapDistance <= 0.16) return rawDelta * 0.68;
    final double t = (1 - (snapDistance / magneticZone)).clamp(0.0, 1.0);
    final double smooth = t * t * (3 - (2 * t));
    final double base = sticky ? 0.08 : 0.05;
    final double strength = (base + (0.55 * smooth)).clamp(0.0, 0.68);
    return rawDelta * strength;
  }

  double _softSnapValue({
    required double rawValue,
    required double snappedValue,
    required double snapDistance,
    required double threshold,
    required bool sticky,
  }) {
    final double diff = snappedValue - rawValue;
    if (diff.abs() <= 0.0005) return snappedValue;
    if (snapDistance <= 0.35) return snappedValue;
    final double strength = _softSnapStrength(
      snapDistance: snapDistance,
      threshold: threshold,
      sticky: sticky,
    );
    return rawValue + (diff * strength);
  }

  double _softSnapAngle({
    required double rawRotation,
    required double snappedRotation,
    required double snapDistance,
    required double threshold,
    required bool sticky,
  }) {
    final double diff = _normalizeAngle(snappedRotation - rawRotation);
    if (diff.abs() <= 0.0035 || snapDistance <= 0.0035) {
      return snappedRotation;
    }
    final double strength = _softSnapStrength(
      snapDistance: snapDistance,
      threshold: threshold,
      sticky: sticky,
    );
    return rawRotation + (diff * strength);
  }

  double _softSnapStrength({
    required double snapDistance,
    required double threshold,
    required bool sticky,
  }) {
    if (threshold <= 0.0001) return 0;
    final double t = (1 - (snapDistance / threshold)).clamp(0.0, 1.0);
    final double smooth = t * t * (3 - (2 * t));
    final double base = sticky ? 0.72 : 0.50;
    final double strength = base + (0.42 * smooth);
    return strength.clamp(0.0, 1.0);
  }

  double _verticalOverlap(Rect a, Rect b) {
    return math.max(0, math.min(a.bottom, b.bottom) - math.max(a.top, b.top));
  }

  double _horizontalOverlap(Rect a, Rect b) {
    return math.max(0, math.min(a.right, b.right) - math.max(a.left, b.left));
  }

  double _spacingGuideY(Rect moving, Rect a, Rect b) {
    final double top = math.max(moving.top, math.max(a.top, b.top));
    final double bottom = math.min(moving.bottom, math.min(a.bottom, b.bottom));
    if (bottom > top) return (top + bottom) / 2;
    return moving.center.dy;
  }

  double _spacingGuideX(Rect moving, Rect a, Rect b) {
    final double left = math.max(moving.left, math.max(a.left, b.left));
    final double right = math.min(moving.right, math.min(a.right, b.right));
    if (right > left) return (left + right) / 2;
    return moving.center.dx;
  }

  double _normalizeAngle(double value) {
    double angle = value;
    while (angle <= -math.pi) {
      angle += (2 * math.pi);
    }
    while (angle > math.pi) {
      angle -= (2 * math.pi);
    }
    return angle;
  }

  void _scheduleSmartGuideAutoHide() {
    _smartGuideAutoHideTimer?.cancel();
    _smartGuideAutoHideTimer = Timer(const Duration(milliseconds: 130), () {
      if (!mounted) return;
      if (_interaction != _CanvasInteraction.movingLayer &&
          _interaction != _CanvasInteraction.resizingLayer &&
          _interaction != _CanvasInteraction.rotatingLayer) {
        return;
      }
      _setSmartGuides(const <_SmartGuideSegment>[], forceRepaint: true);
    });
  }

  void _setSmartGuides(
    List<_SmartGuideSegment> guides, {
    required bool forceRepaint,
  }) {
    final List<_SmartGuideSegment> normalized = guides.isEmpty
        ? const <_SmartGuideSegment>[]
        : List<_SmartGuideSegment>.unmodifiable(guides);
    final bool changed =
        !_guideListsEqualApprox(_smartGuideSegments, normalized);
    final bool hadGuides = _smartGuideSegments.isNotEmpty;
    _smartGuideSegments = normalized;
    if (changed || forceRepaint || hadGuides || normalized.isNotEmpty) {
      _repaintCanvas();
    }
  }

  bool _guideListsEqualApprox(
    List<_SmartGuideSegment> a,
    List<_SmartGuideSegment> b,
  ) {
    if (identical(a, b)) return true;
    if (a.length != b.length) return false;
    for (int i = 0; i < a.length; i++) {
      final _SmartGuideSegment left = a[i];
      final _SmartGuideSegment right = b[i];
      if (left.emphasized != right.emphasized) return false;
      if ((left.start.dx - right.start.dx).abs() > 0.2) return false;
      if ((left.start.dy - right.start.dy).abs() > 0.2) return false;
      if ((left.end.dx - right.end.dx).abs() > 0.2) return false;
      if ((left.end.dy - right.end.dy).abs() > 0.2) return false;
    }
    return true;
  }

  EditorLayer? _backgroundLayer(List<EditorLayer> layers) {
    for (final EditorLayer layer in layers) {
      if (layer.isBackground && _workspaceSourceSize(layer) != null) {
        return layer;
      }
    }
    return null;
  }

  EditorLayer? _layerById(String? layerId) {
    if (layerId == null) return null;
    for (final EditorLayer layer in widget.layers) {
      if (layer.id == layerId) return layer;
    }
    return null;
  }

  _TransformLayerSceneData? _buildSelectedTransformLayerData({
    required EditorLayer? selectedLayer,
    required Rect artboard,
    required Size workspaceSize,
  }) {
    if (selectedLayer == null) return null;
    switch (selectedLayer.type) {
      case EditorLayerType.text:
        return _buildTextLayerSceneData(
          layer: selectedLayer,
          artboard: artboard,
          workspaceSize: workspaceSize,
          rotateHandleDistance: _topRotateHandleDistance,
          moveHandleDistance: _bottomMoveHandleDistance,
        );
      case EditorLayerType.image:
        if (selectedLayer.isBackground || selectedLayer.image == null) {
          return null;
        }
        final ui.Image image =
            _editableImages[selectedLayer.id]?.displayImage ??
                selectedLayer.image!;
        return _buildImageLayerSceneData(
          layer: selectedLayer,
          image: image,
          artboard: artboard,
          workspaceSize: workspaceSize,
          rotateHandleDistance: _topRotateHandleDistance,
          moveHandleDistance: _bottomMoveHandleDistance,
        );
      case EditorLayerType.vector:
      case EditorLayerType.mask:
      case EditorLayerType.solid:
        return null;
    }
  }

  _ImageLayerSceneData? _activeOverlayCutLayerData({
    required Rect artboard,
    required Size workspaceSize,
  }) {
    final _OverlayCutConfig? config = widget.overlayCutConfig;
    if (config == null) return null;
    final EditorLayer? layer = _layerById(config.layerId);
    if (layer == null ||
        !layer.isVisible ||
        layer.type != EditorLayerType.image ||
        layer.isBackground) {
      return null;
    }
    final ui.Image? image =
        _editableImages[layer.id]?.displayImage ?? layer.image;
    if (image == null) return null;
    return _buildImageLayerSceneData(
      layer: layer,
      image: image,
      artboard: artboard,
      workspaceSize: workspaceSize,
      rotateHandleDistance: _topRotateHandleDistance,
      moveHandleDistance: _bottomMoveHandleDistance,
    );
  }

  Rect _overlayCutShapeRectLocal({
    required _ImageLayerSceneData layerData,
    required _OverlayCutConfig config,
  }) {
    return Rect.fromCenter(
      center: Offset(
        ((config.centerUv.dx - 0.5) * layerData.width),
        ((config.centerUv.dy - 0.5) * layerData.height),
      ),
      width: math.max(2, layerData.width * config.scaleX),
      height: math.max(2, layerData.height * config.scaleY),
    );
  }

  List<Offset> _overlayCutCornerHandlesScene({
    required _ImageLayerSceneData layerData,
    required Rect shapeRectLocal,
    required double shapeRotation,
  }) {
    final Offset shapeCenter = shapeRectLocal.center;
    final List<Offset> localCorners = <Offset>[
      shapeRectLocal.topLeft,
      shapeRectLocal.topRight,
      shapeRectLocal.bottomRight,
      shapeRectLocal.bottomLeft,
    ];
    return localCorners
        .map(
          (corner) => _overlayCutLocalToScene(
            layerData: layerData,
            localPoint: shapeCenter +
                _rotateVector(corner - shapeCenter, shapeRotation),
          ),
        )
        .toList(growable: false);
  }

  List<Offset> _overlayCutEdgeHandlesScene({
    required _ImageLayerSceneData layerData,
    required Rect shapeRectLocal,
    required double shapeRotation,
  }) {
    final Offset shapeCenter = shapeRectLocal.center;
    final List<Offset> localEdges = <Offset>[
      shapeRectLocal.centerLeft,
      shapeRectLocal.centerRight,
      shapeRectLocal.topCenter,
      shapeRectLocal.bottomCenter,
    ];
    return localEdges
        .map(
          (point) => _overlayCutLocalToScene(
            layerData: layerData,
            localPoint:
                shapeCenter + _rotateVector(point - shapeCenter, shapeRotation),
          ),
        )
        .toList(growable: false);
  }

  Offset _overlayCutLocalToScene({
    required _ImageLayerSceneData layerData,
    required Offset localPoint,
  }) {
    return layerData.center + _rotateVector(localPoint, layerData.rotation);
  }

  Offset _overlayCutRotateHandleScene({
    required _ImageLayerSceneData layerData,
    required Rect shapeRectLocal,
    required double shapeRotation,
  }) {
    final Offset shapeCenter = shapeRectLocal.center;
    final Offset bottomCenter = shapeRectLocal.bottomCenter;
    final Offset rotatedBottomCenter =
        shapeCenter + _rotateVector(bottomCenter - shapeCenter, shapeRotation);
    final double handleDistance = (34 / _scale).clamp(20, 56).toDouble();
    final Offset handleLocal = rotatedBottomCenter +
        _rotateVector(Offset(0, handleDistance), shapeRotation);
    return _overlayCutLocalToScene(
      layerData: layerData,
      localPoint: handleLocal,
    );
  }

  Offset _clampOverlayCutCenterUv(
    Offset centerUv,
    double scaleX,
    double scaleY,
  ) {
    final double halfX = (scaleX / 2).clamp(0.0, 0.5).toDouble();
    final double halfY = (scaleY / 2).clamp(0.0, 0.5).toDouble();
    final double minX = halfX;
    final double maxX = 1 - halfX;
    final double minY = halfY;
    final double maxY = 1 - halfY;
    if (minX >= maxX || minY >= maxY) {
      return const Offset(0.5, 0.5);
    }
    return Offset(
      centerUv.dx.clamp(minX, maxX).toDouble(),
      centerUv.dy.clamp(minY, maxY).toDouble(),
    );
  }

  bool _startOverlayCutInteraction({
    required Offset scenePoint,
    required _ImageLayerSceneData layerData,
    required _OverlayCutConfig config,
  }) {
    final Rect shapeRectLocal = _overlayCutShapeRectLocal(
      layerData: layerData,
      config: config,
    );
    final List<Offset> cornerHandles = _overlayCutCornerHandlesScene(
      layerData: layerData,
      shapeRectLocal: shapeRectLocal,
      shapeRotation: config.rotationRadians,
    );
    final List<Offset> edgeHandles = _overlayCutEdgeHandlesScene(
      layerData: layerData,
      shapeRectLocal: shapeRectLocal,
      shapeRotation: config.rotationRadians,
    );
    final Offset rotateHandle = _overlayCutRotateHandleScene(
      layerData: layerData,
      shapeRectLocal: shapeRectLocal,
      shapeRotation: config.rotationRadians,
    );
    final double minShapeExtent =
        math.min(shapeRectLocal.width, shapeRectLocal.height);
    final double tinyShapeBoost =
        ((92 - minShapeExtent).clamp(0, 64) / 64).toDouble();
    final double cornerHandleRadius =
        (((28 / _scale).clamp(14, 42)) + (tinyShapeBoost * 10))
            .clamp(14, 50)
            .toDouble();
    final double edgeHandleRadius =
        (((24 / _scale).clamp(13, 36)) + (tinyShapeBoost * 8))
            .clamp(13, 44)
            .toDouble();
    final double rotateHandleRadius =
        (((24 / _scale).clamp(14, 36)) + (tinyShapeBoost * 8))
            .clamp(14, 44)
            .toDouble();
    double nearestCornerDistance = double.infinity;
    int nearestCornerIndex = -1;
    for (int i = 0; i < cornerHandles.length; i++) {
      final Offset handle = cornerHandles[i];
      final double distance = (scenePoint - handle).distance;
      if (distance < nearestCornerDistance) {
        nearestCornerDistance = distance;
        nearestCornerIndex = i;
      }
    }
    double nearestEdgeDistance = double.infinity;
    int nearestEdgeIndex = -1;
    for (int i = 0; i < edgeHandles.length; i++) {
      final double distance = (scenePoint - edgeHandles[i]).distance;
      if (distance < nearestEdgeDistance) {
        nearestEdgeDistance = distance;
        nearestEdgeIndex = i;
      }
    }

    _overlayCutStartRectLocal = shapeRectLocal;
    _overlayCutStartCenterUv = config.centerUv;
    _overlayCutStartScaleX = config.scaleX;
    _overlayCutStartScaleY = config.scaleY;
    _overlayCutStartRotation = config.rotationRadians;
    _layerStartScenePoint = scenePoint;

    if ((scenePoint - rotateHandle).distance <= rotateHandleRadius) {
      _interaction = _CanvasInteraction.overlayCutRotating;
      final Offset shapeCenterScene = _overlayCutLocalToScene(
        layerData: layerData,
        localPoint: shapeRectLocal.center,
      );
      _overlayCutRotateStartAngle = math.atan2(
        scenePoint.dy - shapeCenterScene.dy,
        scenePoint.dx - shapeCenterScene.dx,
      );
      return true;
    }

    if (nearestCornerDistance <= cornerHandleRadius &&
        nearestCornerDistance <= nearestEdgeDistance) {
      _interaction = _CanvasInteraction.overlayCutResizing;
      _overlayCutResizeHandle = _OverlayCutResizeHandle.corner;
      final Offset localPoint =
          _rotateVector(scenePoint - layerData.center, -layerData.rotation);
      final Offset alignedLocalPoint = shapeRectLocal.center +
          _rotateVector(
            localPoint - shapeRectLocal.center,
            -config.rotationRadians,
          );
      final List<Offset> localCorners = <Offset>[
        shapeRectLocal.topLeft,
        shapeRectLocal.topRight,
        shapeRectLocal.bottomRight,
        shapeRectLocal.bottomLeft,
      ];
      final Offset handleLocalVector = nearestCornerIndex >= 0
          ? (localCorners[nearestCornerIndex] - shapeRectLocal.center)
          : const Offset(1, 0);
      final double handleDistance = handleLocalVector.distance;
      final Offset resizeDirection = handleDistance <= 0.0001
          ? const Offset(1, 0)
          : (handleLocalVector / handleDistance);
      final Offset startVector = alignedLocalPoint - shapeRectLocal.center;
      final double startProjection = (startVector.dx * resizeDirection.dx) +
          (startVector.dy * resizeDirection.dy);
      _overlayCutResizeStartDirection = resizeDirection;
      _overlayCutResizeStartProjection = math.max(
        math.max(1.0, handleDistance * 0.55),
        startProjection.abs(),
      );
      return true;
    }
    if (nearestEdgeDistance <= edgeHandleRadius && nearestEdgeIndex >= 0) {
      _interaction = _CanvasInteraction.overlayCutResizing;
      switch (nearestEdgeIndex) {
        case 0:
          _overlayCutResizeHandle = _OverlayCutResizeHandle.left;
          break;
        case 1:
          _overlayCutResizeHandle = _OverlayCutResizeHandle.right;
          break;
        case 2:
          _overlayCutResizeHandle = _OverlayCutResizeHandle.top;
          break;
        case 3:
          _overlayCutResizeHandle = _OverlayCutResizeHandle.bottom;
          break;
      }
      return true;
    }

    final Offset localPoint =
        _rotateVector(scenePoint - layerData.center, -layerData.rotation);
    final bool insideShape = _overlayCutContainsPoint(
      point: localPoint,
      shapeRect: shapeRectLocal,
      shape: config.shape,
      rotationRadians: config.rotationRadians,
    );
    if (!insideShape) {
      return false;
    }

    _interaction = _CanvasInteraction.overlayCutMoving;
    return true;
  }

  void _updateOverlayCutInteraction({
    required Offset scenePoint,
    required _ImageLayerSceneData layerData,
    required _OverlayCutConfig config,
  }) {
    if (_interaction == _CanvasInteraction.overlayCutMoving) {
      final Offset deltaScene = scenePoint - _layerStartScenePoint;
      final Offset deltaLocal = _rotateVector(deltaScene, -layerData.rotation);
      final Offset nextCenter = _clampOverlayCutCenterUv(
        Offset(
          _overlayCutStartCenterUv.dx + (deltaLocal.dx / layerData.width),
          _overlayCutStartCenterUv.dy + (deltaLocal.dy / layerData.height),
        ),
        _overlayCutStartScaleX,
        _overlayCutStartScaleY,
      );
      if ((nextCenter - config.centerUv).distance > 0.0001) {
        widget.onOverlayCutConfigChanged(
          config.copyWith(centerUv: nextCenter),
        );
      }
      return;
    }
    if (_interaction == _CanvasInteraction.overlayCutRotating) {
      final Offset shapeCenterScene = _overlayCutLocalToScene(
        layerData: layerData,
        localPoint: _overlayCutStartRectLocal.center,
      );
      final double currentAngle = math.atan2(
        scenePoint.dy - shapeCenterScene.dy,
        scenePoint.dx - shapeCenterScene.dx,
      );
      final double rawRotation = _overlayCutStartRotation +
          (currentAngle - _overlayCutRotateStartAngle);
      final double nextRotation = math.atan2(
        math.sin(rawRotation),
        math.cos(rawRotation),
      );
      if ((nextRotation - config.rotationRadians).abs() > 0.0001) {
        widget.onOverlayCutConfigChanged(
          config.copyWith(rotationRadians: nextRotation),
        );
      }
      return;
    }
    if (_interaction != _CanvasInteraction.overlayCutResizing) {
      return;
    }
    final Rect startRect = _overlayCutStartRectLocal;
    final Offset localPoint =
        _rotateVector(scenePoint - layerData.center, -layerData.rotation);
    final Offset alignedLocalPoint = startRect.center +
        _rotateVector(
          localPoint - startRect.center,
          -_overlayCutStartRotation,
        );
    const double minScaleAxis = 0.06;
    final double halfLayerW = layerData.width / 2;
    final double halfLayerH = layerData.height / 2;

    if (_overlayCutResizeHandle == _OverlayCutResizeHandle.corner) {
      final Offset currentVector = alignedLocalPoint - startRect.center;
      final double projectedDistance =
          (currentVector.dx * _overlayCutResizeStartDirection.dx) +
              (currentVector.dy * _overlayCutResizeStartDirection.dy);
      final double safeProjection = math.max(0.0, projectedDistance.abs());
      final double scaleFactor =
          safeProjection / _overlayCutResizeStartProjection;
      final double rawScaleX = (_overlayCutStartScaleX * scaleFactor)
          .clamp(minScaleAxis, 1.0)
          .toDouble();
      final double rawScaleY = (_overlayCutStartScaleY * scaleFactor)
          .clamp(minScaleAxis, 1.0)
          .toDouble();
      final double nextScaleX = rawScaleX;
      final double nextScaleY = rawScaleY;
      final Offset clampedCenter = _clampOverlayCutCenterUv(
        _overlayCutStartCenterUv,
        nextScaleX,
        nextScaleY,
      );
      if ((nextScaleX - config.scaleX).abs() > 0.0001 ||
          (nextScaleY - config.scaleY).abs() > 0.0001 ||
          (clampedCenter - config.centerUv).distance > 0.0001) {
        widget.onOverlayCutConfigChanged(
          config.copyWith(
            centerUv: clampedCenter,
            scaleX: nextScaleX,
            scaleY: nextScaleY,
          ),
        );
      }
      return;
    }

    if (_overlayCutResizeHandle == _OverlayCutResizeHandle.left ||
        _overlayCutResizeHandle == _OverlayCutResizeHandle.right) {
      final double fixedX =
          _overlayCutResizeHandle == _OverlayCutResizeHandle.left
              ? startRect.right
              : startRect.left;
      final double minWidth = layerData.width * minScaleAxis;
      final double nextMovableX =
          _overlayCutResizeHandle == _OverlayCutResizeHandle.left
              ? alignedLocalPoint.dx
                  .clamp(-halfLayerW, fixedX - minWidth)
                  .toDouble()
              : alignedLocalPoint.dx
                  .clamp(fixedX + minWidth, halfLayerW)
                  .toDouble();
      final double left =
          _overlayCutResizeHandle == _OverlayCutResizeHandle.left
              ? nextMovableX
              : fixedX;
      final double right =
          _overlayCutResizeHandle == _OverlayCutResizeHandle.left
              ? fixedX
              : nextMovableX;
      final double nextScaleX = ((right - left) / layerData.width)
          .clamp(minScaleAxis, 1.0)
          .toDouble();
      final double centerXLocal = (left + right) / 2;
      final Offset nextCenter = _clampOverlayCutCenterUv(
        Offset(
          0.5 + (centerXLocal / layerData.width),
          _overlayCutStartCenterUv.dy,
        ),
        nextScaleX,
        _overlayCutStartScaleY,
      );
      if ((nextScaleX - config.scaleX).abs() > 0.0001 ||
          (nextCenter - config.centerUv).distance > 0.0001) {
        widget.onOverlayCutConfigChanged(
          config.copyWith(centerUv: nextCenter, scaleX: nextScaleX),
        );
      }
      return;
    }

    if (_overlayCutResizeHandle == _OverlayCutResizeHandle.top ||
        _overlayCutResizeHandle == _OverlayCutResizeHandle.bottom) {
      final double fixedY =
          _overlayCutResizeHandle == _OverlayCutResizeHandle.top
              ? startRect.bottom
              : startRect.top;
      final double minHeight = layerData.height * minScaleAxis;
      final double nextMovableY =
          _overlayCutResizeHandle == _OverlayCutResizeHandle.top
              ? alignedLocalPoint.dy
                  .clamp(-halfLayerH, fixedY - minHeight)
                  .toDouble()
              : alignedLocalPoint.dy
                  .clamp(fixedY + minHeight, halfLayerH)
                  .toDouble();
      final double top = _overlayCutResizeHandle == _OverlayCutResizeHandle.top
          ? nextMovableY
          : fixedY;
      final double bottom =
          _overlayCutResizeHandle == _OverlayCutResizeHandle.top
              ? fixedY
              : nextMovableY;
      final double nextScaleY = ((bottom - top) / layerData.height)
          .clamp(minScaleAxis, 1.0)
          .toDouble();
      final double centerYLocal = (top + bottom) / 2;
      final Offset nextCenter = _clampOverlayCutCenterUv(
        Offset(
          _overlayCutStartCenterUv.dx,
          0.5 + (centerYLocal / layerData.height),
        ),
        _overlayCutStartScaleX,
        nextScaleY,
      );
      if ((nextScaleY - config.scaleY).abs() > 0.0001 ||
          (nextCenter - config.centerUv).distance > 0.0001) {
        widget.onOverlayCutConfigChanged(
          config.copyWith(centerUv: nextCenter, scaleY: nextScaleY),
        );
      }
    }
  }

  _ImageLayerSceneData? _activeExpandLayerData({
    required Rect artboard,
    required Size workspaceSize,
  }) {
    final _ExpandToolConfig? config = widget.expandToolConfig;
    if (config == null) return null;
    final EditorLayer? layer = _layerById(config.layerId);
    if (layer == null ||
        !layer.isVisible ||
        layer.type != EditorLayerType.image) {
      return null;
    }
    final ui.Image? image =
        _editableImages[layer.id]?.displayImage ?? layer.image;
    if (image == null) return null;
    return _buildImageLayerSceneData(
      layer: layer,
      image: image,
      artboard: artboard,
      workspaceSize: workspaceSize,
      rotateHandleDistance: _topRotateHandleDistance,
      moveHandleDistance: _bottomMoveHandleDistance,
    );
  }

  double _clampExpandAmountCanvas(double value) {
    return value.clamp(0.0, 3.0).toDouble();
  }

  Rect _expandedRectLocalFromConfig({
    required _ImageLayerSceneData layerData,
    required _ExpandToolConfig config,
  }) {
    final double left = (-layerData.width / 2) -
        (_clampExpandAmountCanvas(config.leftExpand) * layerData.width);
    final double right = (layerData.width / 2) +
        (_clampExpandAmountCanvas(config.rightExpand) * layerData.width);
    final double top = (-layerData.height / 2) -
        (_clampExpandAmountCanvas(config.topExpand) * layerData.height);
    final double bottom = (layerData.height / 2) +
        (_clampExpandAmountCanvas(config.bottomExpand) * layerData.height);
    return Rect.fromLTRB(left, top, right, bottom);
  }

  List<Offset> _expandEdgeHandlesScene({
    required _ImageLayerSceneData layerData,
    required Rect expandedRectLocal,
  }) {
    final List<Offset> localEdges = <Offset>[
      expandedRectLocal.centerLeft,
      expandedRectLocal.centerRight,
      expandedRectLocal.topCenter,
      expandedRectLocal.bottomCenter,
    ];
    return localEdges
        .map(
          (point) =>
              layerData.center + _rotateVector(point, layerData.rotation),
        )
        .toList(growable: false);
  }

  bool _startExpandInteraction({
    required Offset scenePoint,
    required _ImageLayerSceneData layerData,
    required _ExpandToolConfig config,
  }) {
    final Rect expandedRectLocal = _expandedRectLocalFromConfig(
      layerData: layerData,
      config: config,
    );
    final List<Offset> edgeHandles = _expandEdgeHandlesScene(
      layerData: layerData,
      expandedRectLocal: expandedRectLocal,
    );
    final double minExpandExtent =
        math.min(expandedRectLocal.width, expandedRectLocal.height);
    final double tinyExpandBoost =
        ((140 - minExpandExtent).clamp(0, 100) / 100).toDouble();
    final double edgeHandleRadius =
        (((28 / _scale).clamp(13, 44)) + (tinyExpandBoost * 9))
            .clamp(13, 52)
            .toDouble();
    double nearestEdgeDistance = double.infinity;
    int nearestEdgeIndex = -1;
    for (int i = 0; i < edgeHandles.length; i++) {
      final double distance = (scenePoint - edgeHandles[i]).distance;
      if (distance < nearestEdgeDistance) {
        nearestEdgeDistance = distance;
        nearestEdgeIndex = i;
      }
    }
    if (nearestEdgeDistance > edgeHandleRadius || nearestEdgeIndex < 0) {
      _interaction = _CanvasInteraction.none;
      _gestureLayerId = null;
      return false;
    }

    _interaction = _CanvasInteraction.expandResizing;
    _gestureLayerId = config.layerId;
    _layerStartScenePoint = scenePoint;
    _expandStartLeft = _clampExpandAmountCanvas(config.leftExpand);
    _expandStartTop = _clampExpandAmountCanvas(config.topExpand);
    _expandStartRight = _clampExpandAmountCanvas(config.rightExpand);
    _expandStartBottom = _clampExpandAmountCanvas(config.bottomExpand);
    switch (nearestEdgeIndex) {
      case 0:
        _expandResizeHandle = _ExpandResizeHandle.left;
        break;
      case 1:
        _expandResizeHandle = _ExpandResizeHandle.right;
        break;
      case 2:
        _expandResizeHandle = _ExpandResizeHandle.top;
        break;
      case 3:
        _expandResizeHandle = _ExpandResizeHandle.bottom;
        break;
    }
    return true;
  }

  void _updateExpandInteraction({
    required Offset scenePoint,
    required _ImageLayerSceneData layerData,
    required _ExpandToolConfig config,
  }) {
    if (_interaction != _CanvasInteraction.expandResizing) return;
    final Offset deltaScene = scenePoint - _layerStartScenePoint;
    final Offset deltaLocal = _rotateVector(deltaScene, -layerData.rotation);
    double nextLeft = _expandStartLeft;
    double nextTop = _expandStartTop;
    double nextRight = _expandStartRight;
    double nextBottom = _expandStartBottom;
    switch (_expandResizeHandle) {
      case _ExpandResizeHandle.left:
        nextLeft = _clampExpandAmountCanvas(
          _expandStartLeft + ((-deltaLocal.dx) / layerData.width),
        );
        break;
      case _ExpandResizeHandle.right:
        nextRight = _clampExpandAmountCanvas(
          _expandStartRight + (deltaLocal.dx / layerData.width),
        );
        break;
      case _ExpandResizeHandle.top:
        nextTop = _clampExpandAmountCanvas(
          _expandStartTop + ((-deltaLocal.dy) / layerData.height),
        );
        break;
      case _ExpandResizeHandle.bottom:
        nextBottom = _clampExpandAmountCanvas(
          _expandStartBottom + (deltaLocal.dy / layerData.height),
        );
        break;
    }
    if ((nextLeft - config.leftExpand).abs() <= 0.0001 &&
        (nextTop - config.topExpand).abs() <= 0.0001 &&
        (nextRight - config.rightExpand).abs() <= 0.0001 &&
        (nextBottom - config.bottomExpand).abs() <= 0.0001) {
      return;
    }
    widget.onExpandToolConfigChanged(
      config.copyWith(
        leftExpand: nextLeft,
        topExpand: nextTop,
        rightExpand: nextRight,
        bottomExpand: nextBottom,
      ),
    );
  }

  _ImageLayerSceneData? _activeCropLayerData({
    required Rect artboard,
    required Size workspaceSize,
  }) {
    final _CropToolConfig? config = widget.cropToolConfig;
    if (config == null) return null;
    final EditorLayer? layer = _layerById(config.layerId);
    if (layer == null ||
        !layer.isVisible ||
        layer.type != EditorLayerType.image) {
      return null;
    }
    final ui.Image? image =
        _editableImages[layer.id]?.displayImage ?? layer.image;
    if (image == null) return null;
    return _buildImageLayerSceneData(
      layer: layer,
      image: image,
      artboard: artboard,
      workspaceSize: workspaceSize,
      rotateHandleDistance: _topRotateHandleDistance,
      moveHandleDistance: _bottomMoveHandleDistance,
    );
  }

  double _cropPreviewRotation(_CropToolConfig config) {
    final int quarterTurns = ((config.quarterTurns % 4) + 4) % 4;
    return (quarterTurns * (math.pi / 2)) +
        (config.straightenDegrees * (math.pi / 180));
  }

  double? _cropUvAspectRatioCanvas({
    required _CropToolConfig config,
    required _ImageLayerSceneData layerData,
  }) {
    final double? targetAspect = config.ratioPreset.aspectRatio;
    if (targetAspect == null || targetAspect <= 0) return null;
    double orientedWidth = layerData.width.abs();
    double orientedHeight = layerData.height.abs();
    if (orientedWidth <= 0 || orientedHeight <= 0) return null;
    final int turns = ((config.quarterTurns % 4) + 4) % 4;
    if (turns.isOdd) {
      final double swap = orientedWidth;
      orientedWidth = orientedHeight;
      orientedHeight = swap;
    }
    final double imageAspect = orientedWidth / orientedHeight;
    if (imageAspect <= 0) return null;
    return targetAspect / imageAspect;
  }

  Rect _cropRectLocal({
    required _ImageLayerSceneData layerData,
    required _CropToolConfig config,
  }) {
    final double? uvAspect = _cropUvAspectRatioCanvas(
      config: config,
      layerData: layerData,
    );
    final Rect rectUv = _clampCropRectUvCanvas(
      config.cropRectUv,
      aspectRatio: uvAspect,
    );
    return Rect.fromCenter(
      center: Offset(
        ((rectUv.center.dx - 0.5) * layerData.width),
        ((rectUv.center.dy - 0.5) * layerData.height),
      ),
      width: math.max(2, rectUv.width * layerData.width),
      height: math.max(2, rectUv.height * layerData.height),
    );
  }

  Rect _clampCropRectUvCanvas(
    Rect rect, {
    double? aspectRatio,
  }) {
    const double minSize = 0.06;
    final Rect normalized = Rect.fromLTRB(
      rect.left.clamp(0.0, 1.0).toDouble(),
      rect.top.clamp(0.0, 1.0).toDouble(),
      rect.right.clamp(0.0, 1.0).toDouble(),
      rect.bottom.clamp(0.0, 1.0).toDouble(),
    );
    double width = normalized.width.abs().clamp(minSize, 1.0).toDouble();
    double height = normalized.height.abs().clamp(minSize, 1.0).toDouble();
    final double? ratio = aspectRatio;
    if (ratio != null && ratio > 0) {
      if ((width / height) > ratio) {
        width = height * ratio;
      } else {
        height = width / ratio;
      }
      width = width.clamp(minSize, 1.0).toDouble();
      height = (width / ratio).clamp(minSize, 1.0).toDouble();
      if (height > 1.0) {
        height = 1.0;
        width = (height * ratio).clamp(minSize, 1.0).toDouble();
      }
      if (width > 1.0) {
        width = 1.0;
        height = (width / ratio).clamp(minSize, 1.0).toDouble();
      }
    }
    final Offset center = normalized.center;
    final double halfW = (width / 2).clamp(0.0, 0.5).toDouble();
    final double halfH = (height / 2).clamp(0.0, 0.5).toDouble();
    final Offset clampedCenter = Offset(
      center.dx.clamp(halfW, 1 - halfW).toDouble(),
      center.dy.clamp(halfH, 1 - halfH).toDouble(),
    );
    return Rect.fromCenter(
      center: clampedCenter,
      width: width,
      height: height,
    );
  }

  List<Offset> _cropCornerHandlesScene({
    required _ImageLayerSceneData layerData,
    required Rect cropRectLocal,
    required double rotation,
  }) {
    final List<Offset> localCorners = <Offset>[
      cropRectLocal.topLeft,
      cropRectLocal.topRight,
      cropRectLocal.bottomRight,
      cropRectLocal.bottomLeft,
    ];
    return localCorners
        .map((corner) => layerData.center + _rotateVector(corner, rotation))
        .toList(growable: false);
  }

  List<Offset> _cropEdgeHandlesScene({
    required _ImageLayerSceneData layerData,
    required Rect cropRectLocal,
    required double rotation,
  }) {
    final List<Offset> localEdges = <Offset>[
      cropRectLocal.centerLeft,
      cropRectLocal.centerRight,
      cropRectLocal.topCenter,
      cropRectLocal.bottomCenter,
    ];
    return localEdges
        .map((point) => layerData.center + _rotateVector(point, rotation))
        .toList(growable: false);
  }

  bool _startCropInteraction({
    required Offset scenePoint,
    required _ImageLayerSceneData layerData,
    required _CropToolConfig config,
  }) {
    final double cropRotation =
        layerData.rotation + _cropPreviewRotation(config);
    final Rect cropRectLocal =
        _cropRectLocal(layerData: layerData, config: config);
    final List<Offset> cornerHandles = _cropCornerHandlesScene(
      layerData: layerData,
      cropRectLocal: cropRectLocal,
      rotation: cropRotation,
    );
    final List<Offset> edgeHandles = _cropEdgeHandlesScene(
      layerData: layerData,
      cropRectLocal: cropRectLocal,
      rotation: cropRotation,
    );

    final double minCropExtent =
        math.min(cropRectLocal.width, cropRectLocal.height);
    final double tinyCropBoost =
        ((96 - minCropExtent).clamp(0, 68) / 68).toDouble();
    final double cornerHandleRadius =
        (((29 / _scale).clamp(14, 44)) + (tinyCropBoost * 10))
            .clamp(14, 52)
            .toDouble();
    final double edgeHandleRadius =
        (((25 / _scale).clamp(13, 38)) + (tinyCropBoost * 8))
            .clamp(13, 45)
            .toDouble();
    double nearestCornerDistance = double.infinity;
    int nearestCornerIndex = -1;
    for (int i = 0; i < cornerHandles.length; i++) {
      final double distance = (scenePoint - cornerHandles[i]).distance;
      if (distance < nearestCornerDistance) {
        nearestCornerDistance = distance;
        nearestCornerIndex = i;
      }
    }
    double nearestEdgeDistance = double.infinity;
    int nearestEdgeIndex = -1;
    for (int i = 0; i < edgeHandles.length; i++) {
      final double distance = (scenePoint - edgeHandles[i]).distance;
      if (distance < nearestEdgeDistance) {
        nearestEdgeDistance = distance;
        nearestEdgeIndex = i;
      }
    }

    _cropStartRectUv = _clampCropRectUvCanvas(
      config.cropRectUv,
      aspectRatio: _cropUvAspectRatioCanvas(
        config: config,
        layerData: layerData,
      ),
    );
    _layerStartScenePoint = scenePoint;
    _gestureLayerId = config.layerId;

    if (nearestCornerDistance <= cornerHandleRadius &&
        nearestCornerDistance <= nearestEdgeDistance &&
        nearestCornerIndex >= 0) {
      _interaction = _CanvasInteraction.cropResizing;
      switch (nearestCornerIndex) {
        case 0:
          _cropResizeHandle = _CropResizeHandle.topLeft;
          break;
        case 1:
          _cropResizeHandle = _CropResizeHandle.topRight;
          break;
        case 2:
          _cropResizeHandle = _CropResizeHandle.bottomRight;
          break;
        case 3:
          _cropResizeHandle = _CropResizeHandle.bottomLeft;
          break;
      }
      return true;
    }
    if (nearestEdgeDistance <= edgeHandleRadius && nearestEdgeIndex >= 0) {
      _interaction = _CanvasInteraction.cropResizing;
      switch (nearestEdgeIndex) {
        case 0:
          _cropResizeHandle = _CropResizeHandle.left;
          break;
        case 1:
          _cropResizeHandle = _CropResizeHandle.right;
          break;
        case 2:
          _cropResizeHandle = _CropResizeHandle.top;
          break;
        case 3:
          _cropResizeHandle = _CropResizeHandle.bottom;
          break;
      }
      return true;
    }

    final Offset localPoint =
        _rotateVector(scenePoint - layerData.center, -cropRotation);
    if (!cropRectLocal.contains(localPoint)) {
      _interaction = _CanvasInteraction.none;
      _gestureLayerId = null;
      return false;
    }
    _interaction = _CanvasInteraction.cropMoving;
    return true;
  }

  void _updateCropInteraction({
    required Offset scenePoint,
    required _ImageLayerSceneData layerData,
    required _CropToolConfig config,
  }) {
    final double cropRotation =
        layerData.rotation + _cropPreviewRotation(config);
    if (_interaction == _CanvasInteraction.cropMoving) {
      final double? uvAspect = _cropUvAspectRatioCanvas(
        config: config,
        layerData: layerData,
      );
      final Offset deltaScene = scenePoint - _layerStartScenePoint;
      final Offset deltaLocal = _rotateVector(deltaScene, -cropRotation);
      final Offset deltaUv = Offset(
        deltaLocal.dx / layerData.width,
        deltaLocal.dy / layerData.height,
      );
      final Rect nextRect = _clampCropRectUvCanvas(
        _cropStartRectUv.shift(deltaUv),
        aspectRatio: uvAspect,
      );
      if ((nextRect.center - config.cropRectUv.center).distance > 0.0001) {
        widget.onCropToolConfigChanged(
          config.copyWith(cropRectUv: nextRect),
        );
      }
      return;
    }
    if (_interaction != _CanvasInteraction.cropResizing) return;

    final Offset localPoint =
        _rotateVector(scenePoint - layerData.center, -cropRotation);
    final Offset uvPoint = Offset(
      (localPoint.dx / layerData.width) + 0.5,
      (localPoint.dy / layerData.height) + 0.5,
    );
    const double minSize = 0.06;
    double left = _cropStartRectUv.left;
    double top = _cropStartRectUv.top;
    double right = _cropStartRectUv.right;
    double bottom = _cropStartRectUv.bottom;

    final bool updatesLeft = _cropResizeHandle == _CropResizeHandle.left ||
        _cropResizeHandle == _CropResizeHandle.topLeft ||
        _cropResizeHandle == _CropResizeHandle.bottomLeft;
    final bool updatesRight = _cropResizeHandle == _CropResizeHandle.right ||
        _cropResizeHandle == _CropResizeHandle.topRight ||
        _cropResizeHandle == _CropResizeHandle.bottomRight;
    final bool updatesTop = _cropResizeHandle == _CropResizeHandle.top ||
        _cropResizeHandle == _CropResizeHandle.topLeft ||
        _cropResizeHandle == _CropResizeHandle.topRight;
    final bool updatesBottom = _cropResizeHandle == _CropResizeHandle.bottom ||
        _cropResizeHandle == _CropResizeHandle.bottomLeft ||
        _cropResizeHandle == _CropResizeHandle.bottomRight;

    if (updatesLeft) {
      left = uvPoint.dx;
    }
    if (updatesRight) {
      right = uvPoint.dx;
    }
    if (updatesTop) {
      top = uvPoint.dy;
    }
    if (updatesBottom) {
      bottom = uvPoint.dy;
    }

    if (updatesLeft && right - left < minSize) {
      left = right - minSize;
    }
    if (updatesRight && right - left < minSize) {
      right = left + minSize;
    }
    if (updatesTop && bottom - top < minSize) {
      top = bottom - minSize;
    }
    if (updatesBottom && bottom - top < minSize) {
      bottom = top + minSize;
    }

    final Rect rawRect = Rect.fromLTRB(
      math.min(left, right),
      math.min(top, bottom),
      math.max(left, right),
      math.max(top, bottom),
    );
    final Rect nextRect = _clampCropRectUvCanvas(
      rawRect,
      aspectRatio: _cropUvAspectRatioCanvas(
        config: config,
        layerData: layerData,
      ),
    );
    final Rect currentRect = _clampCropRectUvCanvas(
      config.cropRectUv,
      aspectRatio: _cropUvAspectRatioCanvas(
        config: config,
        layerData: layerData,
      ),
    );
    if (!_rectApproxEqual(nextRect, currentRect)) {
      widget.onCropToolConfigChanged(
        config.copyWith(cropRectUv: nextRect),
      );
    }
  }

  bool _rectApproxEqual(Rect a, Rect b, {double epsilon = 0.0001}) {
    return (a.left - b.left).abs() <= epsilon &&
        (a.top - b.top).abs() <= epsilon &&
        (a.right - b.right).abs() <= epsilon &&
        (a.bottom - b.bottom).abs() <= epsilon;
  }
}

class _BrushStroke {
  _BrushStroke({
    required this.points,
    required this.color,
    required this.width,
    this.hardness = 75,
    this.brushType = PencilBrushType.round,
    this.angle = 0,
  });

  final List<Offset> points;
  final Color color;
  final double width;
  final double hardness;
  final PencilBrushType brushType;
  final double angle;

  _BrushStroke copy() {
    return _BrushStroke(
      points: List<Offset>.from(points),
      color: color,
      width: width,
      hardness: hardness,
      brushType: brushType,
      angle: angle,
    );
  }

  bool isContentEqual(_BrushStroke other) {
    if (color != other.color) return false;
    if (width != other.width) return false;
    if (hardness != other.hardness) return false;
    if (brushType != other.brushType) return false;
    if (angle != other.angle) return false;
    if (points.length != other.points.length) return false;
    for (int i = 0; i < points.length; i++) {
      if (points[i] != other.points[i]) return false;
    }
    return true;
  }
}

