  }

  void _drawUpscaleMagicOverlay(
    Canvas canvas,
    _ImageLayerSceneData layerData, {
    required double phase,
    required double viewScale,
  }) {
    final double safeViewScale = viewScale.clamp(0.2, 8.0).toDouble();
    final double borderWidth = (1.15 / safeViewScale).clamp(0.5, 2.1);
    final double starBase = (7.0 / safeViewScale).clamp(3.2, 9.5);
    final double shadowBlur = (16.0 / safeViewScale).clamp(6.0, 24.0);
    final Rect layerRect = Rect.fromCenter(
      center: Offset.zero,
      width: layerData.width,
      height: layerData.height,
    );
    final double radiusValue =
        (12.0 / safeViewScale).clamp(5.0, 16.0).toDouble();
    final RRect overlayRRect = RRect.fromRectAndRadius(
      layerRect,
      Radius.circular(radiusValue),
    );
    final double p = phase % 1.0;

    canvas.save();
    canvas.translate(layerData.center.dx, layerData.center.dy);
    canvas.rotate(layerData.rotation);
    canvas.save();
    canvas.clipRRect(overlayRRect);

    canvas.saveLayer(
      layerRect,
      Paint()..imageFilter = ui.ImageFilter.blur(sigmaX: 4.6, sigmaY: 4.6),
    );
    canvas.drawRect(
      layerRect,
      Paint()
        ..color = const Color(0x2289C6FF)
        ..style = PaintingStyle.fill,
    );
    canvas.restore();

    final double beamWidth = (96.0 / safeViewScale)
        .clamp(layerRect.width * 0.24, layerRect.width * 0.72)
        .toDouble();
    final double beamTravel = layerRect.width + (beamWidth * 2.0);
    final double beamStart = layerRect.left - beamWidth;
    final double shimmerCenter = beamStart + ((p * beamTravel) % beamTravel);
    final Rect shimmerRect = Rect.fromCenter(
      center: Offset(shimmerCenter, layerRect.center.dy),
      width: beamWidth,
      height: layerRect.height * 1.35,
    );
    final Paint shimmerPaint = Paint()
      ..blendMode = BlendMode.plus
      ..shader = LinearGradient(
        begin: Alignment.centerLeft,
        end: Alignment.centerRight,
        colors: const <Color>[
          Color(0x00FFFFFF),
          Color(0x54FFFFFF),
          Color(0x00FFFFFF),
        ],
        stops: const <double>[0.0, 0.5, 1.0],
      ).createShader(shimmerRect);
    canvas.drawRect(layerRect, shimmerPaint);

    final List<Offset> stars = <Offset>[
      Offset(layerRect.left + (layerRect.width * 0.18),
          layerRect.top + (layerRect.height * 0.22)),
      Offset(layerRect.right - (layerRect.width * 0.16),
          layerRect.top + (layerRect.height * 0.28)),
      Offset(layerRect.left + (layerRect.width * 0.28),
          layerRect.bottom - (layerRect.height * 0.18)),
      Offset(layerRect.right - (layerRect.width * 0.22),
          layerRect.bottom - (layerRect.height * 0.24)),
    ];
    for (int i = 0; i < stars.length; i++) {
      final double t = ((p * 0.72) + (i * 0.16)) * (2 * math.pi);
      final double pulse = 0.76 + (0.24 * ((math.sin(t) + 1) / 2));
      final double starRadius = starBase * pulse;
      final Offset c = stars[i];
      final Paint corePaint = Paint()
        ..style = PaintingStyle.fill
        ..color = const Color(0xFFE6F24A).withOpacity(0.24 + (0.26 * pulse));
      canvas.drawCircle(c, starRadius * 0.36, corePaint);
      final Paint crossPaint = Paint()
        ..style = PaintingStyle.stroke
        ..strokeWidth = (0.95 / safeViewScale).clamp(0.35, 1.35)
        ..strokeCap = StrokeCap.round
        ..color = const Color(0xFFF7FFB0).withOpacity(0.26 + (0.32 * pulse));
      canvas.drawLine(
        Offset(c.dx - starRadius, c.dy),
        Offset(c.dx + starRadius, c.dy),
        crossPaint,
      );
      canvas.drawLine(
        Offset(c.dx, c.dy - starRadius),
        Offset(c.dx, c.dy + starRadius),
        crossPaint,
      );
    }
    canvas.restore();

    canvas.drawRRect(
      overlayRRect,
      Paint()
        ..style = PaintingStyle.stroke
        ..strokeWidth = borderWidth
        ..color = const Color(0xBDE6F24A),
    );
    canvas.drawRRect(
      overlayRRect,
      Paint()
        ..style = PaintingStyle.stroke
        ..strokeWidth = borderWidth * 2.25
        ..color = const Color(0x52E6F24A)
        ..maskFilter = MaskFilter.blur(BlurStyle.normal, shadowBlur),
    );
    canvas.restore();
  }

  Rect _expandRectLocalForPainter({
    required _ImageLayerSceneData layerData,
    required _ExpandToolConfig config,
  }) {
    double clampSide(double value) => value.clamp(0.0, 3.0).toDouble();
    final double left = (-layerData.width / 2) -
        (clampSide(config.leftExpand) * layerData.width);
    final double right = (layerData.width / 2) +
        (clampSide(config.rightExpand) * layerData.width);
    final double top = (-layerData.height / 2) -
        (clampSide(config.topExpand) * layerData.height);
    final double bottom = (layerData.height / 2) +
        (clampSide(config.bottomExpand) * layerData.height);
    return Rect.fromLTRB(left, top, right, bottom);
  }

  Rect _clampCropRectUvForPainter(
    Rect rect, {
    double? aspectRatio,
  }) {
    const double minSize = 0.06;
    final Rect normalized = Rect.fromLTRB(
      rect.left.clamp(0.0, 1.0).toDouble(),
      rect.top.clamp(0.0, 1.0).toDouble(),
      rect.right.clamp(0.0, 1.0).toDouble(),
      rect.bottom.clamp(0.0, 1.0).toDouble(),
    );
    double width = normalized.width.abs().clamp(minSize, 1.0).toDouble();
    double height = normalized.height.abs().clamp(minSize, 1.0).toDouble();
    final double? ratio = aspectRatio;
    if (ratio != null && ratio > 0) {
      if ((width / height) > ratio) {
        width = height * ratio;
      } else {
        height = width / ratio;
      }
      width = width.clamp(minSize, 1.0).toDouble();
      height = (width / ratio).clamp(minSize, 1.0).toDouble();
      if (height > 1.0) {
        height = 1.0;
        width = (height * ratio).clamp(minSize, 1.0).toDouble();
      }
      if (width > 1.0) {
        width = 1.0;
        height = (width / ratio).clamp(minSize, 1.0).toDouble();
      }
    }
    final Offset center = normalized.center;
    final double halfW = (width / 2).clamp(0.0, 0.5).toDouble();
    final double halfH = (height / 2).clamp(0.0, 0.5).toDouble();
    final Offset clampedCenter = Offset(
      center.dx.clamp(halfW, 1 - halfW).toDouble(),
      center.dy.clamp(halfH, 1 - halfH).toDouble(),
    );
    return Rect.fromCenter(
      center: clampedCenter,
      width: width,
      height: height,
    );
  }

  double? _cropUvAspectRatioForPainter(
    _CropToolConfig config,
    _ImageLayerSceneData layerData,
  ) {
    final double? targetAspect = config.ratioPreset.aspectRatio;
    if (targetAspect == null || targetAspect <= 0) return null;
    double orientedWidth = layerData.width.abs();
    double orientedHeight = layerData.height.abs();
    if (orientedWidth <= 0 || orientedHeight <= 0) return null;
    final int turns = ((config.quarterTurns % 4) + 4) % 4;
    if (turns.isOdd) {
      final double swap = orientedWidth;
      orientedWidth = orientedHeight;
      orientedHeight = swap;
    }
    final double imageAspect = orientedWidth / orientedHeight;
    if (imageAspect <= 0) return null;
    return targetAspect / imageAspect;
  }

  void _drawCropPreview(
    Canvas canvas,
    _ImageLayerSceneData layerData,
    _CropToolConfig config,
  ) {
    final Rect cropRectUv = _clampCropRectUvForPainter(
      config.cropRectUv,
      aspectRatio: _cropUvAspectRatioForPainter(config, layerData),
    );
    final Rect cropRectLocal = _cropRectLocalFromUv(
      layerData: layerData,
      cropRectUv: cropRectUv,
    );
    final double previewRotation =
        layerData.rotation + _cropPreviewRotationRadians(config);

    canvas.save();
    canvas.translate(layerData.center.dx, layerData.center.dy);
    canvas.rotate(previewRotation);
    final Rect layerRect = Rect.fromCenter(
      center: Offset.zero,
      width: layerData.width,
      height: layerData.height,
    );
    final Path cropPath = Path()..addRect(cropRectLocal);
    final Path outsidePath = Path.combine(
      PathOperation.difference,
      Path()..addRect(layerRect),
      cropPath,
    );
    canvas.drawPath(
      outsidePath,
      Paint()
        ..style = PaintingStyle.fill
        ..color = const Color(0x5A0F172A),
    );
    final Paint framePaint = Paint()
      ..style = PaintingStyle.stroke
      ..strokeWidth = 1.2
      ..color = const Color(0xFFEAF1FF);
    canvas.drawRect(cropRectLocal, framePaint);

    final Paint gridPaint = Paint()
      ..style = PaintingStyle.stroke
      ..strokeWidth = 0.9
      ..color = const Color(0x75EAF1FF);
    final double thirdW = cropRectLocal.width / 3;
    final double thirdH = cropRectLocal.height / 3;
    for (int i = 1; i <= 2; i++) {
      final double x = cropRectLocal.left + (thirdW * i);
      final double y = cropRectLocal.top + (thirdH * i);
      canvas.drawLine(
        Offset(x, cropRectLocal.top),
        Offset(x, cropRectLocal.bottom),
        gridPaint,
      );
      canvas.drawLine(
        Offset(cropRectLocal.left, y),
        Offset(cropRectLocal.right, y),
        gridPaint,
      );
    }

    final double invScale = (1 / scale).clamp(0.28, 2.4);
    final double cornerRadius = (6.2 * invScale).clamp(3.8, 10.5);
    final double edgeRadius = (5.6 * invScale).clamp(3.4, 9.2);
    final double handleStroke = (1.3 * invScale).clamp(0.7, 2.4);
    final Paint handleFill = Paint()
      ..color = const Color(0xFFF3F3F2)
      ..style = PaintingStyle.fill;
    final Paint handleStrokePaint = Paint()
      ..color = const Color(0xFF9DB8FF)
      ..style = PaintingStyle.stroke
      ..strokeWidth = handleStroke;

    final List<Offset> corners = <Offset>[
      cropRectLocal.topLeft,
      cropRectLocal.topRight,
      cropRectLocal.bottomRight,
      cropRectLocal.bottomLeft,
    ];
    for (final Offset corner in corners) {
      canvas.drawCircle(corner, cornerRadius, handleFill);
      canvas.drawCircle(corner, cornerRadius, handleStrokePaint);
    }
    final List<Offset> edges = <Offset>[
      cropRectLocal.centerLeft,
      cropRectLocal.centerRight,
      cropRectLocal.topCenter,
      cropRectLocal.bottomCenter,
    ];
    for (final Offset edge in edges) {
      canvas.drawCircle(edge, edgeRadius, handleFill);
      canvas.drawCircle(edge, edgeRadius, handleStrokePaint);
    }
    canvas.restore();
  }

  double _hash01(double seed) {
    final double raw = math.sin(seed * 12.9898 + 78.233) * 43758.5453;
    return raw - raw.floorToDouble();
  }

  void _drawExpandPreview(
    Canvas canvas,
    _ImageLayerSceneData layerData,
    _ExpandToolConfig config, {
    required double animationPhase,
  }) {
    final Rect originalRect = Rect.fromCenter(
      center: Offset.zero,
      width: layerData.width,
      height: layerData.height,
    );
    final Rect expandedRect = _expandRectLocalForPainter(
      layerData: layerData,
      config: config,
    );
    final Path expandedPath = Path()..addRect(expandedRect);
    final Path originalPath = Path()..addRect(originalRect);
    final Path generatedAreaPath = Path.combine(
      PathOperation.difference,
      expandedPath,
      originalPath,
    );

    canvas.save();
    canvas.translate(layerData.center.dx, layerData.center.dy);
    canvas.rotate(layerData.rotation);

    canvas.drawPath(
      generatedAreaPath,
      Paint()
        ..style = PaintingStyle.fill
        ..color = const Color(0x3447648D),
    );
    canvas.save();
    canvas.clipPath(generatedAreaPath);
    final double safeViewScale = scale.clamp(0.2, 8.0).toDouble();
    final double beamWidth = (120.0 / safeViewScale)
        .clamp(expandedRect.width * 0.22, expandedRect.width * 0.72)
        .toDouble();
    final double beamTravel = expandedRect.width + (beamWidth * 2.0);
    final double beamStart = expandedRect.left - beamWidth;
    final double shimmerCenterX =
        beamStart + ((animationPhase * beamTravel) % beamTravel);
    final Rect shimmerRect = Rect.fromCenter(
      center: Offset(shimmerCenterX, expandedRect.center.dy),
      width: beamWidth,
      height: expandedRect.height * 1.4,
    );
    final Paint shimmer = Paint()
      ..shader = ui.Gradient.linear(
        shimmerRect.topLeft,
        shimmerRect.topRight,
        const <Color>[
          Color(0x00FFFFFF),
          Color(0x54FFFFFF),
          Color(0x00FFFFFF),
        ],
        const <double>[0.0, 0.52, 1.0],
      );
    canvas.drawRect(expandedRect, shimmer);

    final double sparkleInvScale = (1 / scale).clamp(0.28, 2.4);
    for (int i = 0; i < 22; i++) {
      final double seed = i + 1.0;
      final double x =
          expandedRect.left + (_hash01(seed * 1.91) * expandedRect.width);
      final double y =
          expandedRect.top + (_hash01(seed * 3.73) * expandedRect.height);
      final double twinkle = 0.5 +
          (0.5 *
              math.sin((animationPhase * 2 * math.pi * 1.25) + (seed * 0.92)));
      final double radius =
          ((0.7 + (_hash01(seed * 5.27) * 1.3)) * sparkleInvScale)
              .clamp(0.35, 1.9);
      canvas.drawCircle(
        Offset(x, y),
        radius,
        Paint()
          ..isAntiAlias = true
          ..style = PaintingStyle.fill
          ..color =
              const Color(0xFFEAF1FF).withOpacity(0.14 + (0.18 * twinkle)),
      );
    }
    canvas.restore();

    final Paint expandedFrame = Paint()
      ..style = PaintingStyle.stroke
      ..strokeWidth = 1.3
      ..color = const Color(0xFFDAE9FF);
    final Paint originalFrame = Paint()
      ..style = PaintingStyle.stroke
      ..strokeWidth = 1.0
      ..color = const Color(0x80EAF1FF);
    canvas.drawRect(expandedRect, expandedFrame);
    canvas.drawRect(originalRect, originalFrame);

    final double invScale = (1 / scale).clamp(0.28, 2.4);
    final double handleRadius = (6.1 * invScale).clamp(3.8, 10.3);
    final double handleStroke = (1.25 * invScale).clamp(0.68, 2.3);
    final Paint handleFill = Paint()
      ..color = const Color(0xFFF3F3F2)
      ..style = PaintingStyle.fill;
    final Paint handleStrokePaint = Paint()
      ..color = const Color(0xFF9DB8FF)
      ..style = PaintingStyle.stroke
      ..strokeWidth = handleStroke;
    final List<Offset> edgeHandles = <Offset>[
      expandedRect.centerLeft,
      expandedRect.centerRight,
      expandedRect.topCenter,
      expandedRect.bottomCenter,
    ];
    for (final Offset handle in edgeHandles) {
      canvas.drawCircle(handle, handleRadius, handleFill);
      canvas.drawCircle(handle, handleRadius, handleStrokePaint);
    }
    canvas.restore();
  }

  void _drawSelectionControls(
    Canvas canvas,
    _TransformLayerSceneData data, {
    required double viewScale,
  }) {
    final double invScale = (1 / viewScale).clamp(0.28, 2.4);
    final double frameStroke = (1.2 * invScale).clamp(0.7, 2.3);
    final double handleRadius = (6.0 * invScale).clamp(3.8, 9.8);
    final double handleStrokeWidth = (1.3 * invScale).clamp(0.7, 2.4);
    final double rotateRadius = (9.0 * invScale).clamp(5.2, 14.5);
    final double moveRadius = (9.0 * invScale).clamp(5.2, 14.5);
    final double lineStroke = (1.2 * invScale).clamp(0.7, 2.3);
    final double bottomLineStroke = (1.5 * invScale).clamp(0.9, 2.9);
    final double moveHubRadius = (5.1 * invScale).clamp(3.0, 8.0);
    final List<Offset> frameCorners = data.cornerHandles;
    final List<Offset> resizeHandles = frameCorners;

    final Paint frame = Paint()
      ..color = const Color(0xFF5B7CFF)
      ..style = PaintingStyle.stroke
      ..strokeWidth = frameStroke;
    final Path path = Path()
      ..moveTo(frameCorners[0].dx, frameCorners[0].dy)
      ..lineTo(frameCorners[1].dx, frameCorners[1].dy)
      ..lineTo(frameCorners[2].dx, frameCorners[2].dy)
      ..lineTo(frameCorners[3].dx, frameCorners[3].dy)
      ..close();
    canvas.drawPath(path, frame);

    final Paint cornerHandleFill = Paint()
      ..color = const Color(0xFFDDE8FF)
      ..style = PaintingStyle.fill;
    final Paint cornerHandleStroke = Paint()
      ..color = const Color(0xFF8EACFF)
      ..style = PaintingStyle.stroke
      ..strokeWidth = handleStrokeWidth;
    for (final Offset handle in resizeHandles) {
      canvas.drawCircle(handle, handleRadius, cornerHandleFill);
      canvas.drawCircle(handle, handleRadius, cornerHandleStroke);
    }

    final Paint controlHandleFill = Paint()
      ..color = Colors.white
      ..style = PaintingStyle.fill;
    final Paint controlHandleStroke = Paint()
      ..color = const Color(0xFF5B7CFF)
      ..style = PaintingStyle.stroke
      ..strokeWidth = handleStrokeWidth;

    final Paint linePaint = Paint()
      ..color = const Color(0xFF5B7CFF)
      ..strokeWidth = lineStroke
      ..style = PaintingStyle.stroke;
    canvas.drawLine(data.rotateLineStart, data.rotateHandle, linePaint);
    canvas.drawCircle(data.rotateHandle, rotateRadius, controlHandleFill);
    canvas.drawCircle(data.rotateHandle, rotateRadius, controlHandleStroke);
    _drawRotateGlyph(
      canvas,
      data.rotateHandle,
      viewScale: viewScale,
    );

    final Paint moveLinePaint = Paint()
      ..color = const Color(0xFF5B7CFF)
      ..strokeWidth = bottomLineStroke
      ..style = PaintingStyle.stroke;
    canvas.drawLine(data.moveLineStart, data.moveHandle, moveLinePaint);
    canvas.drawCircle(data.moveLineStart, moveHubRadius, controlHandleFill);
    canvas.drawCircle(data.moveLineStart, moveHubRadius, controlHandleStroke);
    canvas.drawCircle(data.moveHandle, moveRadius, controlHandleFill);
    canvas.drawCircle(data.moveHandle, moveRadius, controlHandleStroke);
    _drawMoveGlyph(
      canvas,
      data.moveHandle,
      viewScale: viewScale,
    );
  }

  void _drawRotateGlyph(
    Canvas canvas,
    Offset center, {
    required double viewScale,
  }) {
    final double invScale = (1 / viewScale).clamp(0.28, 2.4);
    final double glyphRadius = (4.2 * invScale).clamp(2.3, 6.8);
    final double glyphStroke = (1.25 * invScale).clamp(0.7, 2.1);
    final double arrowDxA = 2.2 * invScale;
    final double arrowDxB = 0.8 * invScale;
    final double arrowDyA = 0.6 * invScale;
    final double arrowDyB = 1.5 * invScale;

    final Paint arcPaint = Paint()
      ..color = const Color(0xFF5B7CFF)
      ..style = PaintingStyle.stroke
      ..strokeWidth = glyphStroke
      ..strokeCap = StrokeCap.round;
    final Rect arcRect = Rect.fromCircle(center: center, radius: glyphRadius);
    canvas.drawArc(arcRect, -0.2 * math.pi, 1.5 * math.pi, false, arcPaint);
    final Offset tip = Offset(
      center.dx + (math.cos(1.25 * math.pi) * glyphRadius),
      center.dy + (math.sin(1.25 * math.pi) * glyphRadius),
    );
    final Path arrow = Path()
      ..moveTo(tip.dx, tip.dy)
      ..lineTo(tip.dx - arrowDxA, tip.dy + arrowDyA)
      ..lineTo(tip.dx - arrowDxB, tip.dy - arrowDyB)
      ..close();
    final Paint fill = Paint()..color = const Color(0xFF5B7CFF);
    canvas.drawPath(arrow, fill);
  }

  void _drawMoveGlyph(
    Canvas canvas,
    Offset center, {
    required double viewScale,
  }) {
    final double invScale = (1 / viewScale).clamp(0.28, 2.4);
    final double stroke = (1.4 * invScale).clamp(0.8, 2.4);
    final double arm = (4.6 * invScale).clamp(2.6, 7.4);
    final double arrow = (1.8 * invScale).clamp(1.0, 2.8);

    final Paint paint = Paint()
      ..color = const Color(0xFF5B7CFF)
      ..style = PaintingStyle.stroke
      ..strokeWidth = stroke
      ..strokeCap = StrokeCap.round;

    canvas.drawLine(
      Offset(center.dx - arm, center.dy),
      Offset(center.dx + arm, center.dy),
      paint,
    );
    canvas.drawLine(
      Offset(center.dx, center.dy - arm),
      Offset(center.dx, center.dy + arm),
      paint,
    );

    final Paint fill = Paint()
      ..color = const Color(0xFF5B7CFF)
      ..style = PaintingStyle.fill;
    final Path up = Path()
      ..moveTo(center.dx, center.dy - (arm + arrow))
      ..lineTo(center.dx - arrow, center.dy - arm)
      ..lineTo(center.dx + arrow, center.dy - arm)
      ..close();
    final Path down = Path()
      ..moveTo(center.dx, center.dy + (arm + arrow))
      ..lineTo(center.dx - arrow, center.dy + arm)
      ..lineTo(center.dx + arrow, center.dy + arm)
      ..close();
    canvas.drawPath(up, fill);
    canvas.drawPath(down, fill);
  }

  void _drawStrokes(
    Canvas canvas,
    Rect artboard,
    List<_BrushStroke> drawingStrokes,
  ) {
    for (final _BrushStroke stroke in drawingStrokes) {
      if (stroke.points.isEmpty) continue;
      final Paint paint = Paint()
        ..color = stroke.color
        ..strokeWidth = stroke.width
        ..style = PaintingStyle.stroke
        ..isAntiAlias = true;

      switch (stroke.brushType) {
        case PencilBrushType.round:
          paint
            ..strokeCap = StrokeCap.round
            ..strokeJoin = StrokeJoin.round;
          break;
        case PencilBrushType.soft:
          paint
            ..strokeCap = StrokeCap.round
            ..strokeJoin = StrokeJoin.round
            ..maskFilter = MaskFilter.blur(
              BlurStyle.normal,
              (100 - stroke.hardness).clamp(0, 100) / 20,
            );
          break;
        case PencilBrushType.marker:
          paint
            ..strokeCap = StrokeCap.square
            ..strokeJoin = StrokeJoin.miter;
          break;
        case PencilBrushType.calligraphy:
          paint
            ..strokeCap = StrokeCap.square
            ..strokeJoin = StrokeJoin.round;
          break;
      }

      if (stroke.points.length == 1) {
        canvas.drawCircle(
          artboard.topLeft + stroke.points.first,
          stroke.width / 2,
          paint,
        );
        continue;
      }

      final Path path = Path();
      final Offset firstPoint = artboard.topLeft + stroke.points.first;
      path.moveTo(firstPoint.dx, firstPoint.dy);
      for (int i = 1; i < stroke.points.length; i++) {
        final Offset prev = artboard.topLeft + stroke.points[i - 1];
        final Offset curr = artboard.topLeft + stroke.points[i];
        final Offset mid =
            Offset((prev.dx + curr.dx) / 2, (prev.dy + curr.dy) / 2);
        path.quadraticBezierTo(prev.dx, prev.dy, mid.dx, mid.dy);
      }
      canvas.drawPath(path, paint);

      if (stroke.brushType == PencilBrushType.calligraphy) {
        final double rad = stroke.angle * (math.pi / 180);
        final Offset offset = Offset(
          math.cos(rad) * (stroke.width * 0.18),
          math.sin(rad) * (stroke.width * 0.18),
        );
        canvas.save();
        canvas.translate(offset.dx, offset.dy);
        final Paint secondPass = Paint()
          ..color = stroke.color.withOpacity(stroke.color.opacity * 0.65)
          ..strokeWidth = stroke.width * 0.72
          ..style = PaintingStyle.stroke
          ..strokeCap = StrokeCap.round
          ..strokeJoin = StrokeJoin.round
          ..isAntiAlias = true;
        canvas.drawPath(path, secondPass);
        canvas.restore();
      }
    }
  }

  void _drawCloneTargetPointer(
    Canvas canvas,
    Rect artboard,
    Offset uv,
    CloneStampSettings settings, {
    required double viewScale,
  }) {
    final Offset center = Offset(
      artboard.left + (uv.dx * artboard.width),
      artboard.top + (uv.dy * artboard.height),
    );
    final double safeScale = viewScale <= 0 ? 1.0 : viewScale;
    final double radiusScreen = (settings.size / 2).clamp(4.0, 84.0);
    final double radius = radiusScreen / safeScale;
    final double opacity = (settings.opacity / 100).clamp(0.05, 1.0);
    final double hardnessFactor =
        _cloneHardnessToHardRadiusFactor(settings.hardness);
    final double hardStop = hardnessFactor.clamp(0.02, 0.98);
    final double midStop = (hardStop + ((1 - hardStop) * 0.5)).clamp(
      hardStop + 0.01,
      0.995,
    );

    final Paint fill = Paint()
      ..isAntiAlias = true
      ..shader = ui.Gradient.radial(
        center,
        radius,
        <Color>[
          Colors.white.withOpacity((0.10 + (0.23 * opacity)).clamp(0.06, 0.40)),
          Colors.white.withOpacity((0.10 + (0.23 * opacity)).clamp(0.06, 0.40)),
          Colors.white.withOpacity((0.04 + (0.12 * opacity)).clamp(0.02, 0.18)),
          Colors.white.withOpacity(0.0),
        ],
        <double>[0.0, hardStop, midStop, 1.0],
      );
    canvas.drawCircle(center, radius, fill);

    final Paint ring = Paint()
      ..isAntiAlias = true
      ..style = PaintingStyle.stroke
      ..strokeWidth = (1.0 / safeScale).clamp(0.4, 2.0)
      ..color = Colors.white.withOpacity((0.34 + (0.46 * opacity)).clamp(
        0.2,
        0.82,
      ));
    canvas.drawCircle(center, radius, ring);

    final double crossHalf = (radiusScreen * 0.28).clamp(4.0, 10.0) / safeScale;
    final Paint cross = Paint()
      ..isAntiAlias = true
      ..style = PaintingStyle.stroke
      ..strokeCap = StrokeCap.round
      ..strokeWidth = (0.95 / safeScale).clamp(0.4, 1.9)
      ..color = Colors.white.withOpacity((0.26 + (0.44 * opacity)).clamp(
        0.16,
        0.72,
      ));
    canvas.drawLine(
      Offset(center.dx - crossHalf, center.dy),
      Offset(center.dx + crossHalf, center.dy),
      cross,
    );
    canvas.drawLine(
      Offset(center.dx, center.dy - crossHalf),
      Offset(center.dx, center.dy + crossHalf),
      cross,
    );
  }

  void _drawCloneSourcePointer(
    Canvas canvas,
    Rect artboard,
    Offset uv,
    CloneStampSettings settings, {
    required double viewScale,
  }) {
    final Offset center = Offset(
      artboard.left + (uv.dx * artboard.width),
      artboard.top + (uv.dy * artboard.height),
    );
    final double safeScale = viewScale <= 0 ? 1.0 : viewScale;
    final double opacityFactor = (settings.opacity / 100).clamp(0.05, 1.0);
    final double hardnessFactor =
        _cloneHardnessToHardRadiusFactor(settings.hardness);
    final double radiusScreen = (settings.size / 2).clamp(7.0, 78.0);
    final double radius = radiusScreen / safeScale;
    final double hardRadius = radius * hardnessFactor.clamp(0.06, 1.0);
    final double crossHalf =
        (radiusScreen * 0.85).clamp(10.0, 30.0) / safeScale;
    final double outerStroke = (1.45 / safeScale).clamp(0.5, 3.0);
    final double innerStroke = (1.1 / safeScale).clamp(0.45, 2.5);

    final Paint outer = Paint()
      ..color =
          const Color(0xFFE8EEF9).withOpacity(0.34 + (0.52 * opacityFactor))
      ..style = PaintingStyle.stroke
      ..strokeWidth = outerStroke
      ..isAntiAlias = true;
    final Paint inner = Paint()
      ..color =
          const Color(0xFFD4D4D3).withOpacity(0.42 + (0.56 * opacityFactor))
      ..style = PaintingStyle.stroke
      ..strokeWidth = innerStroke
      ..isAntiAlias = true;
    final Paint core = Paint()
      ..color = Colors.white.withOpacity((0.18 + (0.44 * opacityFactor)).clamp(
        0.14,
        0.68,
      ))
      ..style = PaintingStyle.fill
      ..isAntiAlias = true;

    canvas.drawCircle(center, radius, outer);
    canvas.drawCircle(center, radius * 0.9, inner);
    if (hardnessFactor < 0.995) {
      canvas.drawCircle(
        center,
        hardRadius,
        Paint()
          ..style = PaintingStyle.stroke
          ..strokeWidth = (0.9 / safeScale).clamp(0.35, 2.0)
          ..color =
              Colors.white.withOpacity((0.14 + (0.4 * opacityFactor)).clamp(
            0.08,
            0.54,
          ))
          ..isAntiAlias = true,
      );
    }
    canvas.drawCircle(center, (2.0 / safeScale).clamp(0.75, 4.0), core);
    canvas.drawLine(
      Offset(center.dx - crossHalf, center.dy),
      Offset(center.dx + crossHalf, center.dy),
      inner,
    );
    canvas.drawLine(
      Offset(center.dx, center.dy - crossHalf),
      Offset(center.dx, center.dy + crossHalf),
      inner,
    );
  }

  void _drawCloneBrushPreviewIndicator(
    Canvas canvas,
    Size canvasSize,
    CloneStampSettings settings, {
    required double viewScale,
  }) {
    final double safeScale = viewScale <= 0 ? 1.0 : viewScale;
    final Offset center = Offset(
      ((canvasSize.width / 2) - pan.dx) / safeScale,
      ((canvasSize.height / 2) - pan.dy) / safeScale,
    );
    final double radiusScreen =
        (settings.size / 2).clamp(3.5, canvasSize.shortestSide * 0.42);
    final double radius = radiusScreen / safeScale;
    final double opacity = (settings.opacity / 100).clamp(0.05, 1.0);
    final double hardnessFactor =
        _cloneHardnessToHardRadiusFactor(settings.hardness);
    final double hardStop = hardnessFactor.clamp(0.02, 0.98);
    final double midStop = (hardStop + ((1 - hardStop) * 0.5)).clamp(
      hardStop + 0.01,
      0.995,
    );

    final double coreAlpha = (0.14 + (0.30 * opacity)).clamp(0.08, 0.52);
    final double edgeAlpha = (0.04 + (0.20 * opacity)).clamp(0.02, 0.28);
    final double outlineAlpha = (0.36 + (0.56 * opacity)).clamp(0.22, 0.92);

    final Paint fill = Paint()
      ..isAntiAlias = true
      ..shader = ui.Gradient.radial(
        center,
        radius,
        <Color>[
          Colors.white.withOpacity(coreAlpha),
          Colors.white.withOpacity(coreAlpha),
          Colors.white.withOpacity(edgeAlpha),
          Colors.white.withOpacity(0.0),
        ],
        <double>[0.0, hardStop, midStop, 1.0],
      );
    canvas.drawCircle(center, radius, fill);

    final Paint outline = Paint()
      ..isAntiAlias = true
      ..style = PaintingStyle.stroke
      ..strokeWidth = (1.1 / safeScale).clamp(0.45, 2.2)
      ..color = Colors.white.withOpacity(outlineAlpha);
    canvas.drawCircle(center, radius, outline);

    if (hardnessFactor < 0.98) {
      final Paint hardEdge = Paint()
        ..isAntiAlias = true
        ..style = PaintingStyle.stroke
        ..strokeWidth = (0.9 / safeScale).clamp(0.4, 2.0)
        ..color = Colors.white
            .withOpacity((0.18 + (0.34 * opacity)).clamp(0.1, 0.52));
      canvas.drawCircle(center, radius * hardStop, hardEdge);
    }
  }

  void _drawMarqueeSelection(
    Canvas canvas,
    Rect artboard,
    MarqueeSelection selection,
  ) {
    final Path path = _buildMarqueePath(artboard, selection);
    if (path.computeMetrics().isEmpty) return;

    final Paint darkStroke = Paint()
      ..color = const Color(0xFF1F2430)
      ..style = PaintingStyle.stroke
      ..strokeWidth = 1.1
      ..isAntiAlias = true;
    final Paint lightStroke = Paint()
      ..color = const Color(0xFFEFF3FA)
      ..style = PaintingStyle.stroke
      ..strokeWidth = 1.1
      ..isAntiAlias = true;
    _drawDashedPath(
      canvas: canvas,
      source: path,
      paint: darkStroke,
      dashLength: 7,
      gapLength: 5,
      phase: 0,
    );
    _drawDashedPath(
      canvas: canvas,
      source: path,
      paint: lightStroke,
      dashLength: 7,
      gapLength: 5,
      phase: 7,
    );
  }

  Path _buildMarqueePath(Rect artboard, MarqueeSelection selection) {
    final Path path = Path();
    final Rect sceneBounds = Rect.fromLTRB(
      artboard.left + (selection.boundsUv.left * artboard.width),
      artboard.top + (selection.boundsUv.top * artboard.height),
      artboard.left + (selection.boundsUv.right * artboard.width),
      artboard.top + (selection.boundsUv.bottom * artboard.height),
    );
    switch (selection.mode) {
      case MarqueeSelectionMode.rectangular:
        path.addRect(sceneBounds);
        return path;
      case MarqueeSelectionMode.object:
        if (sceneBounds.width <= 0 || sceneBounds.height <= 0) return path;
        path.moveTo(sceneBounds.center.dx, sceneBounds.top);
        path.lineTo(sceneBounds.right, sceneBounds.bottom);
        path.lineTo(sceneBounds.left, sceneBounds.bottom);
        path.close();
        return path;
      case MarqueeSelectionMode.elliptical:
        path.addOval(sceneBounds);
        return path;
      case MarqueeSelectionMode.freehand:
        if (selection.freePathUv.length < 2) return path;
        final Offset first = selection.freePathUv.first;
        path.moveTo(
          artboard.left + (first.dx * artboard.width),
          artboard.top + (first.dy * artboard.height),
        );
        for (int i = 1; i < selection.freePathUv.length; i++) {
          final Offset point = selection.freePathUv[i];
          path.lineTo(
            artboard.left + (point.dx * artboard.width),
            artboard.top + (point.dy * artboard.height),
          );
        }
        path.close();
        return path;
    }
  }

  void _drawDashedPath({
    required Canvas canvas,
    required Path source,
    required Paint paint,
    required double dashLength,
    required double gapLength,
    required double phase,
  }) {
    final double dashCycle = dashLength + gapLength;
    for (final ui.PathMetric metric in source.computeMetrics()) {
      final double total = metric.length;
      if (total <= 0) continue;
      double distance = -phase;
      while (distance < total) {
        final double from = distance < 0 ? 0 : distance;
        final double to = math.min(from + dashLength, total);
        if (to > from) {
          canvas.drawPath(metric.extractPath(from, to), paint);
        }
        distance += dashCycle;
      }
    }
  }

  void _drawOverlayCutPreview(
    Canvas canvas,
    _ImageLayerSceneData layerData,
    _OverlayCutConfig config,
  ) {
    canvas.save();
    canvas.translate(layerData.center.dx, layerData.center.dy);
    canvas.rotate(layerData.rotation);
    final Rect layerRect = Rect.fromCenter(
      center: Offset.zero,
      width: layerData.width,
      height: layerData.height,
    );
    final Rect shapeRect = Rect.fromCenter(
      center: Offset(
        ((config.centerUv.dx - 0.5) * layerData.width),
        ((config.centerUv.dy - 0.5) * layerData.height),
      ),
      width: math.max(2, layerData.width * config.scaleX),
      height: math.max(2, layerData.height * config.scaleY),
    );
    final Path shapePath = _buildOverlayCutShapePath(
      shape: config.shape,
      shapeRect: shapeRect,
      rotationRadians: config.rotationRadians,
    );
    final Path dimmed = Path.combine(
      PathOperation.difference,
      Path()..addRect(layerRect),
      shapePath,
    );
    canvas.drawPath(
      dimmed,
      Paint()
        ..style = PaintingStyle.fill
        ..color = const Color(0x4A0F172A),
    );
    canvas.drawPath(
      shapePath,
      Paint()
        ..style = PaintingStyle.stroke
        ..strokeWidth = 1.2
        ..color = const Color(0xFFEAF1FF),
    );
    final double invScale = (1 / scale).clamp(0.28, 2.4);
    final double handleRadius = (6.2 * invScale).clamp(3.8, 10.2);
    final double handleStroke = (1.3 * invScale).clamp(0.7, 2.4);
    final Paint handleFill = Paint()
      ..color = Colors.white
      ..style = PaintingStyle.fill;
    final Paint handleOutline = Paint()
      ..color = const Color(0xFF5B7CFF)
      ..style = PaintingStyle.stroke
      ..strokeWidth = handleStroke;
    final double edgeHandleRadius = (5.5 * invScale).clamp(3.2, 9.0);
    final double rotateHandleRadius = (9.0 * invScale).clamp(5.2, 14.5);
    final double rotateLineStroke = (1.2 * invScale).clamp(0.7, 2.3);
    final double rotateLineLength = (26 * invScale).clamp(14, 38).toDouble();
    final Offset shapeCenter = shapeRect.center;
    Offset rotateFromShapeCenter(Offset point) =>
        shapeCenter +
        _rotateVector(point - shapeCenter, config.rotationRadians);
    final List<Offset> localCorners = <Offset>[
      shapeRect.topLeft,
      shapeRect.topRight,
      shapeRect.bottomRight,
      shapeRect.bottomLeft,
    ];
    for (final Offset rawCorner in localCorners) {
      final Offset corner = rotateFromShapeCenter(rawCorner);
      canvas.drawCircle(corner, handleRadius, handleFill);
      canvas.drawCircle(corner, handleRadius, handleOutline);
    }
    final List<Offset> edgeHandles = <Offset>[
      shapeRect.centerLeft,
      shapeRect.centerRight,
      shapeRect.topCenter,
      shapeRect.bottomCenter,
    ];
    for (final Offset rawHandle in edgeHandles) {
      final Offset handle = rotateFromShapeCenter(rawHandle);
      canvas.drawCircle(handle, edgeHandleRadius, handleFill);
      canvas.drawCircle(handle, edgeHandleRadius, handleOutline);
    }
    final Offset rotateLineStart =
        rotateFromShapeCenter(shapeRect.bottomCenter);
    final Offset rotateHandle = rotateLineStart +
        _rotateVector(Offset(0, rotateLineLength), config.rotationRadians);
    final Paint rotateLinePaint = Paint()
      ..color = const Color(0xFF5B7CFF)
      ..style = PaintingStyle.stroke
      ..strokeWidth = rotateLineStroke;
    canvas.drawLine(rotateLineStart, rotateHandle, rotateLinePaint);
    canvas.drawCircle(rotateHandle, rotateHandleRadius, handleFill);
    canvas.drawCircle(rotateHandle, rotateHandleRadius, handleOutline);
    _drawRotateGlyph(canvas, rotateHandle, viewScale: scale);
    canvas.restore();
  }

  @override
  bool shouldRepaint(covariant _SkiaCanvasPainter oldDelegate) {
    return oldDelegate.strokes != strokes ||
        oldDelegate.layers != layers ||
        oldDelegate.pan != pan ||
        oldDelegate.scale != scale ||
        oldDelegate.selectedLayerId != selectedLayerId ||
        oldDelegate.activeTool != activeTool ||
        oldDelegate.isToolEnabled != isToolEnabled ||
        oldDelegate.editableImages != editableImages ||
        oldDelegate.cloneSettings != cloneSettings ||
        oldDelegate.showCloneBrushPreview != showCloneBrushPreview ||
        oldDelegate.showCloneTargetPointer != showCloneTargetPointer ||
        oldDelegate.marqueeSelection != marqueeSelection ||
        oldDelegate.overlayCutConfig != overlayCutConfig ||
        oldDelegate.cropToolConfig != cropToolConfig ||
        oldDelegate.expandToolConfig != expandToolConfig;
  }

  EditorLayer? _backgroundLayer(List<EditorLayer> layers) {
    for (final EditorLayer layer in layers) {
      if (layer.isBackground && _workspaceSourceSize(layer) != null) {
        return layer;
      }
    }
    return null;
  }

  ui.Image? _resolveLayerSourceImage(EditorLayer layer) {
    if (layer.type != EditorLayerType.image) return null;
    return editableImages[layer.id]?.displayImage ?? layer.image;
  }
}

class _CloneStampToolIcon extends StatelessWidget {
  const _CloneStampToolIcon({required this.color});

  final Color color;

  @override
  Widget build(BuildContext context) {
    return SizedBox(
      width: 20,
      height: 20,
      child: Center(
        child: SizedBox(
          width: 17,
          height: 17,
          child: CustomPaint(
            painter: _CloneStampToolPainter(color),
          ),
        ),
      ),
    );
  }
}

class _CloneStampToolPainter extends CustomPainter {
  _CloneStampToolPainter(this.color);

  final Color color;

  @override
  void paint(Canvas canvas, Size size) {
    final fill = Paint()
      ..color = color
      ..style = PaintingStyle.fill
      ..isAntiAlias = true;

    canvas.drawCircle(
      Offset(size.width * 0.50, size.height * 0.22),
      size.width * 0.16,
      fill,
    );

    final neckPath = Path()
      ..moveTo(size.width * 0.40, size.height * 0.33)
      ..quadraticBezierTo(
        size.width * 0.42,
        size.height * 0.30,
        size.width * 0.45,
        size.height * 0.30,
      )
      ..lineTo(size.width * 0.55, size.height * 0.30)
      ..quadraticBezierTo(
        size.width * 0.58,
        size.height * 0.30,
        size.width * 0.60,
        size.height * 0.33,
      )
      ..lineTo(size.width * 0.60, size.height * 0.56)
      ..lineTo(size.width * 0.40, size.height * 0.56)
      ..close();
    canvas.drawPath(neckPath, fill);

    canvas.drawRRect(
      RRect.fromRectAndRadius(
        Rect.fromLTWH(
          size.width * 0.12,
          size.height * 0.56,
          size.width * 0.76,
          size.height * 0.23,
        ),
        Radius.circular(size.width * 0.08),
      ),
      fill,
    );

    canvas.drawRRect(
      RRect.fromRectAndRadius(
        Rect.fromLTWH(
          size.width * 0.20,
          size.height * 0.82,
          size.width * 0.60,
          size.height * 0.10,
        ),
        Radius.circular(size.width * 0.06),
      ),
      fill,
    );
  }

  @override
  bool shouldRepaint(covariant _CloneStampToolPainter oldDelegate) {
    return oldDelegate.color != color;
  }
}

class _LogoBackgroundStats {
  const _LogoBackgroundStats({
    required this.meanR,
    required this.meanG,
    required this.meanB,
    required this.meanLuma,
    required this.colorStd,
    required this.lumaStd,
  });

  final double meanR;
  final double meanG;
  final double meanB;
  final double meanLuma;
  final double colorStd;
  final double lumaStd;
}

double _logoLuma(int r, int g, int b) {
  return (0.299 * r) + (0.587 * g) + (0.114 * b);
}

double _colorDistanceSquaredToStats(
  Uint8List rgba,
  int pixelIndex,
  _LogoBackgroundStats stats,
) {
  final int offset = pixelIndex * 4;
  final double dr = rgba[offset] - stats.meanR;
  final double dg = rgba[offset + 1] - stats.meanG;
  final double db = rgba[offset + 2] - stats.meanB;
  return (dr * dr) + (dg * dg) + (db * db);
}

double _colorDistanceSquaredBetweenPixels(
  Uint8List rgba,
  int a,
  int b,
) {
  final int ao = a * 4;
  final int bo = b * 4;
  final double dr = (rgba[ao] - rgba[bo]).toDouble();
  final double dg = (rgba[ao + 1] - rgba[bo + 1]).toDouble();
  final double db = (rgba[ao + 2] - rgba[bo + 2]).toDouble();
  return (dr * dr) + (dg * dg) + (db * db);
}

_LogoBackgroundStats _computeLogoBackgroundStats(
  Uint8List rgba,
  int width,
  int height,
) {
  double sumR = 0;
  double sumG = 0;
  double sumB = 0;
  double sumL = 0;
  int count = 0;

  void take(int x, int y) {
    final int idx = ((y * width) + x) * 4;
    final int alpha = rgba[idx + 3];
    if (alpha <= 3) return;
    final int r = rgba[idx];
    final int g = rgba[idx + 1];
    final int b = rgba[idx + 2];
    sumR += r;
    sumG += g;
    sumB += b;
    sumL += _logoLuma(r, g, b);
    count++;
  }

  for (int x = 0; x < width; x++) {
    take(x, 0);
    if (height > 1) take(x, height - 1);
  }
  for (int y = 1; y < height - 1; y++) {
    take(0, y);
    if (width > 1) take(width - 1, y);
  }

  if (count == 0) {
    return const _LogoBackgroundStats(
      meanR: 255,
      meanG: 255,
      meanB: 255,
      meanLuma: 255,
      colorStd: 0,
      lumaStd: 0,
    );
  }

  final double meanR = sumR / count;
  final double meanG = sumG / count;
  final double meanB = sumB / count;
  final double meanL = sumL / count;

  double colorVariance = 0;
  double lumaVariance = 0;

  void measure(int x, int y) {
    final int idx = ((y * width) + x) * 4;
    final int alpha = rgba[idx + 3];
    if (alpha <= 3) return;
    final double dr = rgba[idx] - meanR;
    final double dg = rgba[idx + 1] - meanG;
    final double db = rgba[idx + 2] - meanB;
    final double dl =
        _logoLuma(rgba[idx], rgba[idx + 1], rgba[idx + 2]) - meanL;
    colorVariance += ((dr * dr) + (dg * dg) + (db * db));
    lumaVariance += (dl * dl);
  }

  for (int x = 0; x < width; x++) {
    measure(x, 0);
    if (height > 1) measure(x, height - 1);
  }
  for (int y = 1; y < height - 1; y++) {
    measure(0, y);
    if (width > 1) measure(width - 1, y);
  }

  final double colorStd = math.sqrt(colorVariance / count);
  final double lumaStd = math.sqrt(lumaVariance / count);

  return _LogoBackgroundStats(
    meanR: meanR,
    meanG: meanG,
    meanB: meanB,
    meanLuma: meanL,
    colorStd: colorStd,
    lumaStd: lumaStd,
  );
}

bool _isLogoBackgroundCandidate({
  required Uint8List rgba,
  required int pixelIndex,
  required _LogoBackgroundStats stats,
  required double colorToleranceSquared,
  required double lumaTolerance,
}) {
  final int offset = pixelIndex * 4;
  final int alpha = rgba[offset + 3];
  if (alpha <= 3) return true;
  final double colorDistanceSq = _colorDistanceSquaredToStats(
    rgba,
    pixelIndex,
    stats,
  );
  if (colorDistanceSq > colorToleranceSquared) return false;

  final double luma = _logoLuma(
    rgba[offset],
    rgba[offset + 1],
    rgba[offset + 2],
  );
  if ((luma - stats.meanLuma).abs() > lumaTolerance) {
    return false;
  }

  if (stats.meanLuma >= 170 && luma < stats.meanLuma - 40) {
    return false;
  }
  if (stats.meanLuma <= 85 && luma > stats.meanLuma + 40) {
    return false;
  }
  return true;
}

Uint8List _removeBackgroundForLogoPngCompute(Uint8List sourcePngBytes) {
  return _removeBackgroundForLogoPng(sourcePngBytes);
}

Map<String, Object> _prepareObjectRemovalMasksCompute({
  required Uint8List baseMaskPngBytes,
  required int expandRadiusPx,
  required int cleanupRadiusPx,
}) {
  final img.Image? decodedMask = img.decodeImage(baseMaskPngBytes);
  if (decodedMask == null || decodedMask.width < 1 || decodedMask.height < 1) {
    return <String, Object>{
      'expandedMaskBytes': baseMaskPngBytes,
      'cleanupMaskBytes': Uint8List(0),
      'hasCleanupMask': false,
      'detailCleanupMaskBytes': Uint8List(0),
      'hasDetailCleanupMask': false,
    };
  }

  final int width = decodedMask.width;
  final int height = decodedMask.height;
  final Uint8List baseMask = _extractBinaryMask(decodedMask);
  if (!_binaryMaskHasAny(baseMask)) {
    return <String, Object>{
      'expandedMaskBytes': baseMaskPngBytes,
      'cleanupMaskBytes': Uint8List(0),
      'hasCleanupMask': false,
      'detailCleanupMaskBytes': Uint8List(0),
      'hasDetailCleanupMask': false,
    };
  }

  final Uint8List expandedMask = _dilateBinaryMask(
    baseMask,
    width: width,
    height: height,
    radiusPx: expandRadiusPx.clamp(1, 24),
  );
  final Uint8List expandedMaskPng = _encodeBinaryMaskToPng(
    expandedMask,
    width: width,
    height: height,
  );

  if (cleanupRadiusPx <= 0) {
    return <String, Object>{
      'expandedMaskBytes': expandedMaskPng,
      'cleanupMaskBytes': Uint8List(0),
      'hasCleanupMask': false,
      'detailCleanupMaskBytes': Uint8List(0),
      'hasDetailCleanupMask': false,
    };
  }

  final Uint8List cleanupMask = _buildCleanupRingMask(
    expandedMask,
    width: width,
    height: height,
    radiusPx: cleanupRadiusPx.clamp(1, 14),
  );
  final bool hasCleanupMask = _binaryMaskHasAny(cleanupMask);
  final int detailRadius = math.max(1, (cleanupRadiusPx * 0.5).round());
  final Uint8List detailCleanupMask = _buildCleanupRingMask(
    expandedMask,
    width: width,
    height: height,
    radiusPx: detailRadius,
  );
  final bool hasDetailCleanupMask = _binaryMaskHasAny(detailCleanupMask);

  return <String, Object>{
    'expandedMaskBytes': expandedMaskPng,
    'cleanupMaskBytes': hasCleanupMask
        ? _encodeBinaryMaskToPng(
            cleanupMask,
            width: width,
            height: height,
          )
        : Uint8List(0),
    'hasCleanupMask': hasCleanupMask,
    'detailCleanupMaskBytes': hasDetailCleanupMask
        ? _encodeBinaryMaskToPng(
            detailCleanupMask,
            width: width,
            height: height,
          )
        : Uint8List(0),
    'hasDetailCleanupMask': hasDetailCleanupMask,
  };
}

Map<String, Object> _prepareObjectRemovalRoiBundleCompute({
  required Uint8List sourceImagePngBytes,
  required Uint8List expandedMaskPngBytes,
  required Uint8List cleanupMaskPngBytes,
  required bool hasCleanupMask,
  required Uint8List detailCleanupMaskPngBytes,
  required bool hasDetailCleanupMask,
  required int roiMarginPx,
  required int blendFeatherPx,
}) {
  final img.Image? source = img.decodeImage(sourceImagePngBytes);
  if (source == null || source.width < 1 || source.height < 1) {
    return <String, Object>{
      'sourceRoiBytes': sourceImagePngBytes,
      'expandedMaskRoiBytes': expandedMaskPngBytes,
      'cleanupMaskRoiBytes': Uint8List(0),
      'hasCleanupMask': false,
      'detailCleanupMaskRoiBytes': Uint8List(0),
      'hasDetailCleanupMask': false,
      'blendMaskRoiBytes': Uint8List(0),
      'roiLeft': 0,
      'roiTop': 0,
      'roiWidth': 0,
      'roiHeight': 0,
    };
  }

  final int width = source.width;
  final int height = source.height;
  final Uint8List expandedMask = _decodeMaskToBinaryForSize(
    maskPngBytes: expandedMaskPngBytes,
    width: width,
    height: height,
  );
  if (!_binaryMaskHasAny(expandedMask)) {
    return <String, Object>{
      'sourceRoiBytes': sourceImagePngBytes,
      'expandedMaskRoiBytes': expandedMaskPngBytes,
      'cleanupMaskRoiBytes': Uint8List(0),
      'hasCleanupMask': false,
      'detailCleanupMaskRoiBytes': Uint8List(0),
      'hasDetailCleanupMask': false,
      'blendMaskRoiBytes': Uint8List(0),
      'roiLeft': 0,
      'roiTop': 0,
      'roiWidth': 0,
      'roiHeight': 0,
    };
  }

  final ({int left, int top, int right, int bottom})? bounds =
      _binaryMaskBounds(expandedMask, width: width, height: height);
  if (bounds == null) {
    return <String, Object>{
      'sourceRoiBytes': sourceImagePngBytes,
      'expandedMaskRoiBytes': expandedMaskPngBytes,
      'cleanupMaskRoiBytes': Uint8List(0),
      'hasCleanupMask': false,
      'detailCleanupMaskRoiBytes': Uint8List(0),
      'hasDetailCleanupMask': false,
      'blendMaskRoiBytes': Uint8List(0),
      'roiLeft': 0,
      'roiTop': 0,
      'roiWidth': 0,
      'roiHeight': 0,
    };
  }

  final int safeMargin =
      roiMarginPx.clamp(4, math.max(width, height).clamp(4, 4096));
  final int roiLeft = (bounds.left - safeMargin).clamp(0, width - 1);
  final int roiTop = (bounds.top - safeMargin).clamp(0, height - 1);
  final int roiRight = (bounds.right + safeMargin).clamp(roiLeft, width - 1);
  final int roiBottom = (bounds.bottom + safeMargin).clamp(roiTop, height - 1);
  final int roiWidth = roiRight - roiLeft + 1;
  final int roiHeight = roiBottom - roiTop + 1;

  final img.Image sourceRoi = img.copyCrop(
    source,
    x: roiLeft,
    y: roiTop,
    width: roiWidth,
    height: roiHeight,
  );
  final Uint8List sourceRoiBytes = Uint8List.fromList(
    img.encodePng(sourceRoi, level: 3),
  );

  final Uint8List expandedMaskRoi = _cropBinaryMask(
    expandedMask,
    sourceWidth: width,
    roiLeft: roiLeft,
    roiTop: roiTop,
    roiWidth: roiWidth,
    roiHeight: roiHeight,
  );
  final Uint8List expandedMaskRoiBytes = _encodeBinaryMaskToPng(
    expandedMaskRoi,
    width: roiWidth,
    height: roiHeight,
  );

  final Uint8List cleanupMask = hasCleanupMask
      ? _decodeMaskToBinaryForSize(
          maskPngBytes: cleanupMaskPngBytes,
          width: width,
          height: height,
        )
      : Uint8List(width * height);
  final Uint8List cleanupMaskRoi = _cropBinaryMask(
    cleanupMask,
    sourceWidth: width,
    roiLeft: roiLeft,
    roiTop: roiTop,
    roiWidth: roiWidth,
    roiHeight: roiHeight,
  );
  final bool hasCleanupMaskRoi = _binaryMaskHasAny(cleanupMaskRoi);

  final Uint8List detailCleanupMask = hasDetailCleanupMask
      ? _decodeMaskToBinaryForSize(
          maskPngBytes: detailCleanupMaskPngBytes,
          width: width,
          height: height,
        )
      : Uint8List(width * height);
  final Uint8List detailCleanupMaskRoi = _cropBinaryMask(
    detailCleanupMask,
    sourceWidth: width,
    roiLeft: roiLeft,
    roiTop: roiTop,
    roiWidth: roiWidth,
    roiHeight: roiHeight,
  );
  final bool hasDetailCleanupMaskRoi = _binaryMaskHasAny(detailCleanupMaskRoi);

  final Uint8List blendMaskRoi = _buildObjectRemovalBlendMask(
    expandedMaskRoi: expandedMaskRoi,
    width: roiWidth,
    height: roiHeight,
    featherPx: blendFeatherPx,
  );

  return <String, Object>{
    'sourceRoiBytes': sourceRoiBytes,
    'expandedMaskRoiBytes': expandedMaskRoiBytes,
    'cleanupMaskRoiBytes': hasCleanupMaskRoi
        ? _encodeBinaryMaskToPng(
            cleanupMaskRoi,
            width: roiWidth,
            height: roiHeight,
          )
        : Uint8List(0),
    'hasCleanupMask': hasCleanupMaskRoi,
    'detailCleanupMaskRoiBytes': hasDetailCleanupMaskRoi
        ? _encodeBinaryMaskToPng(
            detailCleanupMaskRoi,
            width: roiWidth,
            height: roiHeight,
          )
        : Uint8List(0),
    'hasDetailCleanupMask': hasDetailCleanupMaskRoi,
    'blendMaskRoiBytes': blendMaskRoi,
    'roiLeft': roiLeft,
    'roiTop': roiTop,
    'roiWidth': roiWidth,
    'roiHeight': roiHeight,
  };
}

Uint8List _compositeObjectRemovalRoiResultCompute({
  required Uint8List sourceImagePngBytes,
  required Uint8List outputRoiPngBytes,
  required Uint8List blendMaskRoiBytes,
  required int roiLeft,
  required int roiTop,
  required int roiWidth,
  required int roiHeight,
}) {
  final img.Image? source = img.decodeImage(sourceImagePngBytes);
  final img.Image? patch = img.decodeImage(outputRoiPngBytes);
  if (source == null ||
      patch == null ||
      source.width < 1 ||
      source.height < 1) {
    return sourceImagePngBytes;
  }
  if (roiWidth < 1 || roiHeight < 1) {
    return sourceImagePngBytes;
  }
  final int safeLeft = roiLeft.clamp(0, source.width - 1);
  final int safeTop = roiTop.clamp(0, source.height - 1);
  final int safeWidth = roiWidth.clamp(1, source.width - safeLeft);
  final int safeHeight = roiHeight.clamp(1, source.height - safeTop);
  final int roiPixelCount = safeWidth * safeHeight;
  if (blendMaskRoiBytes.length < roiPixelCount) {
    return sourceImagePngBytes;
  }

  final img.Image safePatch =
      (patch.width == safeWidth && patch.height == safeHeight)
          ? patch
          : img.copyResize(
              patch,
              width: safeWidth,
              height: safeHeight,
              interpolation: img.Interpolation.cubic,
            );

  final Uint8List sourceRgba = Uint8List.fromList(
    source.getBytes(order: img.ChannelOrder.rgba),
  );
  final Uint8List patchRgba = Uint8List.fromList(
    safePatch.getBytes(order: img.ChannelOrder.rgba),
  );
  final Uint8List outRgba = Uint8List.fromList(sourceRgba);

  for (int y = 0; y < safeHeight; y++) {
    final int sourceRow = (safeTop + y) * source.width;
    final int roiRow = y * safeWidth;
    for (int x = 0; x < safeWidth; x++) {
      final int roiIndex = roiRow + x;
      final double blendAlpha = (blendMaskRoiBytes[roiIndex] / 255.0).clamp(
        0.0,
        1.0,
      );
      if (blendAlpha <= 0.0001) continue;

      final int sourceIndex = ((sourceRow + safeLeft + x) * 4);
      final int patchIndex = roiIndex * 4;
      final double patchAlpha = (patchRgba[patchIndex + 3] / 255.0).clamp(
        0.0,
        1.0,
      );
      final double alpha = (blendAlpha * patchAlpha).clamp(0.0, 1.0);
      if (alpha <= 0.0001) continue;

      outRgba[sourceIndex] = ((sourceRgba[sourceIndex] * (1 - alpha)) +
              (patchRgba[patchIndex] * alpha))
          .round()
          .clamp(0, 255);
      outRgba[sourceIndex + 1] = ((sourceRgba[sourceIndex + 1] * (1 - alpha)) +
              (patchRgba[patchIndex + 1] * alpha))
          .round()
          .clamp(0, 255);
      outRgba[sourceIndex + 2] = ((sourceRgba[sourceIndex + 2] * (1 - alpha)) +
              (patchRgba[patchIndex + 2] * alpha))
          .round()
          .clamp(0, 255);
      outRgba[sourceIndex + 3] =
          ((sourceRgba[sourceIndex + 3] * (1 - alpha)) + (255 * alpha))
              .round()
              .clamp(0, 255);
    }
  }

  final img.Image output = img.Image.fromBytes(
    width: source.width,
    height: source.height,
    bytes: outRgba.buffer,
    order: img.ChannelOrder.rgba,
    numChannels: 4,
  );
  return Uint8List.fromList(img.encodePng(output, level: 2));
}

Uint8List _decodeMaskToBinaryForSize({
  required Uint8List maskPngBytes,
  required int width,
  required int height,
}) {
  final img.Image? decoded = img.decodeImage(maskPngBytes);
  if (decoded == null || width < 1 || height < 1) {
    return Uint8List(width * height);
  }
  final img.Image sized = (decoded.width == width && decoded.height == height)
      ? decoded
      : img.copyResize(
          decoded,
          width: width,
          height: height,
          interpolation: img.Interpolation.nearest,
        );
  return _extractBinaryMask(sized);
}

({int left, int top, int right, int bottom})? _binaryMaskBounds(
  Uint8List mask, {
  required int width,
  required int height,
}) {
  if (width < 1 || height < 1 || mask.length < width * height) return null;
  int minX = width;
  int minY = height;
  int maxX = -1;
  int maxY = -1;
  for (int y = 0; y < height; y++) {
    final int rowOffset = y * width;
    for (int x = 0; x < width; x++) {
      if (mask[rowOffset + x] == 0) continue;
      if (x < minX) minX = x;
      if (y < minY) minY = y;
      if (x > maxX) maxX = x;
      if (y > maxY) maxY = y;
    }
  }
  if (maxX < minX || maxY < minY) return null;
  return (left: minX, top: minY, right: maxX, bottom: maxY);
}

Uint8List _cropBinaryMask(
  Uint8List sourceMask, {
  required int sourceWidth,
  required int roiLeft,
  required int roiTop,
  required int roiWidth,
  required int roiHeight,
}) {
  if (roiWidth < 1 || roiHeight < 1 || sourceWidth < 1) {
    return Uint8List(0);
  }
  final Uint8List out = Uint8List(roiWidth * roiHeight);
  for (int y = 0; y < roiHeight; y++) {
    final int sourceRow = (roiTop + y) * sourceWidth + roiLeft;
    final int outRow = y * roiWidth;
    for (int x = 0; x < roiWidth; x++) {
      out[outRow + x] = sourceMask[sourceRow + x];
    }
  }
  return out;
}

Uint8List _buildObjectRemovalBlendMask({
  required Uint8List expandedMaskRoi,
  required int width,
  required int height,
  required int featherPx,
}) {
  if (width < 1 || height < 1 || expandedMaskRoi.length < width * height) {
    return Uint8List(0);
  }
  if (!_binaryMaskHasAny(expandedMaskRoi)) {
    return Uint8List(width * height);
  }

  final Uint8List rgba = Uint8List(width * height * 4);
  for (int i = 0; i < expandedMaskRoi.length; i++) {
    final int value = expandedMaskRoi[i] == 0 ? 0 : 255;
    final int index = i * 4;
    rgba[index] = value;
    rgba[index + 1] = value;
    rgba[index + 2] = value;
    rgba[index + 3] = 255;
  }
  img.Image maskImage = img.Image.fromBytes(
    width: width,
    height: height,
    bytes: rgba.buffer,
    order: img.ChannelOrder.rgba,
    numChannels: 4,
  );
  final int safeFeather = featherPx.clamp(1, 64);
  if (safeFeather > 0) {
    maskImage = img.gaussianBlur(maskImage, radius: safeFeather);
  }
  final Uint8List blurRgba = Uint8List.fromList(
    maskImage.getBytes(order: img.ChannelOrder.rgba),
  );
  final Uint8List limitMask = _dilateBinaryMask(
    expandedMaskRoi,
    width: width,
    height: height,
    radiusPx: math.max(1, (safeFeather * 2.0).round()),
  );
  final Uint8List blend = Uint8List(width * height);
  for (int i = 0; i < blend.length; i++) {
    if (limitMask[i] == 0) {
      blend[i] = 0;
      continue;
    }
    if (expandedMaskRoi[i] != 0) {
      blend[i] = 255;
      continue;
    }
    blend[i] = blurRgba[i * 4];
  }
  return blend;
}

Uint8List _extractBinaryMask(img.Image maskImage) {
  final int width = maskImage.width;
  final int height = maskImage.height;
  final Uint8List rgba = Uint8List.fromList(
    maskImage.getBytes(order: img.ChannelOrder.rgba),
  );
  final Uint8List mask = Uint8List(width * height);
  for (int i = 0; i < mask.length; i++) {
    final int index = i * 4;
    final int alpha = rgba[index + 3];
    if (alpha <= 6) continue;
    final int luminance = rgba[index] + rgba[index + 1] + rgba[index + 2];
    if (luminance >= 40) {
      mask[i] = 1;
    }
  }
  return mask;
}

bool _binaryMaskHasAny(Uint8List mask) {
  for (final int value in mask) {
    if (value != 0) return true;
  }
  return false;
}

Uint8List _dilateBinaryMask(
  Uint8List source, {
  required int width,
  required int height,
  required int radiusPx,
}) {
  if (radiusPx <= 0) return Uint8List.fromList(source);
  final List<int> kernel = _buildDiskKernel(radiusPx);
  final Uint8List out = Uint8List(source.length);
  for (int y = 0; y < height; y++) {
    for (int x = 0; x < width; x++) {
      bool on = false;
      for (int i = 0; i < kernel.length; i += 2) {
        final int nx = x + kernel[i];
        final int ny = y + kernel[i + 1];
        if (nx < 0 || ny < 0 || nx >= width || ny >= height) continue;
        if (source[(ny * width) + nx] != 0) {
          on = true;
          break;
        }
      }
      if (on) {
        out[(y * width) + x] = 1;
      }
    }
  }
  return out;
}

Uint8List _erodeBinaryMask(
  Uint8List source, {
  required int width,
  required int height,
  required int radiusPx,
}) {
  if (radiusPx <= 0) return Uint8List.fromList(source);
  final List<int> kernel = _buildDiskKernel(radiusPx);
  final Uint8List out = Uint8List(source.length);
  for (int y = 0; y < height; y++) {
    for (int x = 0; x < width; x++) {
      bool keep = true;
      for (int i = 0; i < kernel.length; i += 2) {
        final int nx = x + kernel[i];
        final int ny = y + kernel[i + 1];
        if (nx < 0 || ny < 0 || nx >= width || ny >= height) {
          keep = false;
          break;
        }
        if (source[(ny * width) + nx] == 0) {
          keep = false;
          break;
        }
      }
      if (keep) {
        out[(y * width) + x] = 1;
      }
    }
  }
  return out;
}

Uint8List _buildCleanupRingMask(
  Uint8List expandedMask, {
  required int width,
  required int height,
  required int radiusPx,
}) {
  if (radiusPx <= 0) return Uint8List(expandedMask.length);
  final Uint8List outer = _dilateBinaryMask(
    expandedMask,
    width: width,
    height: height,
    radiusPx: radiusPx,
  );
  final int innerRadius = math.max(1, (radiusPx * 0.65).round());
  final Uint8List inner = _erodeBinaryMask(
    expandedMask,
    width: width,
    height: height,
    radiusPx: innerRadius,
  );
  final Uint8List ring = Uint8List(expandedMask.length);
  for (int i = 0; i < ring.length; i++) {
    if (outer[i] != 0 && inner[i] == 0) {
      ring[i] = 1;
    }
  }
  return ring;
}

List<int> _buildDiskKernel(int radiusPx) {
  final int safeRadius = math.max(1, radiusPx);
  final int radiusSq = safeRadius * safeRadius;
  final List<int> kernel = <int>[];
  for (int dy = -safeRadius; dy <= safeRadius; dy++) {
    final int dySq = dy * dy;
    for (int dx = -safeRadius; dx <= safeRadius; dx++) {
      if ((dx * dx) + dySq > radiusSq) continue;
      kernel.add(dx);
      kernel.add(dy);
    }
  }
  return kernel;
}

Uint8List _encodeBinaryMaskToPng(
  Uint8List mask, {
  required int width,
  required int height,
}) {
  final Uint8List rgba = Uint8List(width * height * 4);
  for (int i = 0; i < mask.length; i++) {
    final int value = mask[i] == 0 ? 0 : 255;
    final int index = i * 4;
    rgba[index] = value;
    rgba[index + 1] = value;
    rgba[index + 2] = value;
    rgba[index + 3] = 255;
  }
  final img.Image encoded = img.Image.fromBytes(
    width: width,
    height: height,
    bytes: rgba.buffer,
    order: img.ChannelOrder.rgba,
    numChannels: 4,
  );
  return Uint8List.fromList(img.encodePng(encoded, level: 3));
}

Uint8List _composeReferenceIntoMaskedRegionPng({
  required Uint8List sourcePngBytes,
  required Uint8List maskPngBytes,
  required Uint8List referencePngBytes,
}) {
  final img.Image? source = img.decodeImage(sourcePngBytes);
  final img.Image? decodedMask = img.decodeImage(maskPngBytes);
  final img.Image? reference = img.decodeImage(referencePngBytes);
  if (source == null || decodedMask == null || reference == null) {
    return sourcePngBytes;
  }

  final int width = source.width;
  final int height = source.height;
  if (width <= 1 || height <= 1) return sourcePngBytes;

  final img.Image mask =
      (decodedMask.width == width && decodedMask.height == height)
          ? decodedMask
          : img.copyResize(
              decodedMask,
              width: width,
              height: height,
              interpolation: img.Interpolation.nearest,
            );

  final Uint8List sourceRgba = Uint8List.fromList(
    source.getBytes(order: img.ChannelOrder.rgba),
  );
  final Uint8List maskRgba = Uint8List.fromList(
    mask.getBytes(order: img.ChannelOrder.rgba),
  );

  int minX = width;
  int minY = height;
  int maxX = -1;
  int maxY = -1;
  for (int y = 0; y < height; y++) {
    for (int x = 0; x < width; x++) {
      final int idx = ((y * width) + x) * 4;
      final int maskValue = maskRgba[idx];
      if (maskValue < 8) continue;
      if (x < minX) minX = x;
      if (y < minY) minY = y;
      if (x > maxX) maxX = x;
      if (y > maxY) maxY = y;
    }
  }

  if (maxX < minX || maxY < minY) {
    return sourcePngBytes;
  }

  final int targetWidth = (maxX - minX + 1).clamp(1, width);
  final int targetHeight = (maxY - minY + 1).clamp(1, height);
  final double refAspect = reference.width / math.max(1, reference.height);
  final double targetAspect = targetWidth / math.max(1, targetHeight);

  int scaledWidth;
  int scaledHeight;
  if (refAspect >= targetAspect) {
    scaledHeight = targetHeight;
    scaledWidth = math.max(1, (scaledHeight * refAspect).ceil());
  } else {
    scaledWidth = targetWidth;
    scaledHeight = math.max(1, (scaledWidth / refAspect).ceil());
  }

  final img.Image scaledReference = img.copyResize(
    reference,
    width: scaledWidth,
    height: scaledHeight,
    interpolation: img.Interpolation.cubic,
  );
  final Uint8List referenceRgba = Uint8List.fromList(
    scaledReference.getBytes(order: img.ChannelOrder.rgba),
  );

  final int cropX = ((scaledWidth - targetWidth) * 0.5).round().clamp(
        0,
        math.max(0, scaledWidth - targetWidth),
      );
  final int cropY = ((scaledHeight - targetHeight) * 0.5).round().clamp(
        0,
        math.max(0, scaledHeight - targetHeight),
      );

  final Uint8List outputRgba = Uint8List.fromList(sourceRgba);
  for (int y = minY; y <= maxY; y++) {
    for (int x = minX; x <= maxX; x++) {
      final int idx = ((y * width) + x) * 4;
      final double maskAlpha = (maskRgba[idx] / 255.0).clamp(0.0, 1.0);
      if (maskAlpha <= 0.01) continue;

      final double u = targetWidth <= 1 ? 0 : (x - minX) / (targetWidth - 1);
      final double v = targetHeight <= 1 ? 0 : (y - minY) / (targetHeight - 1);
      final int refX = (cropX + (u * (targetWidth - 1)).round()).clamp(
        0,
        scaledWidth - 1,
      );
      final int refY = (cropY + (v * (targetHeight - 1)).round()).clamp(
        0,
        scaledHeight - 1,
      );
      final int refIndex = ((refY * scaledWidth) + refX) * 4;
      final double refAlpha =
          (referenceRgba[refIndex + 3] / 255.0).clamp(0.0, 1.0);
      final double blend = (maskAlpha * refAlpha).clamp(0.0, 1.0);
      if (blend <= 0.01) continue;

      outputRgba[idx] =
          ((sourceRgba[idx] * (1 - blend)) + (referenceRgba[refIndex] * blend))
              .round()
              .clamp(0, 255);
      outputRgba[idx + 1] = ((sourceRgba[idx + 1] * (1 - blend)) +
              (referenceRgba[refIndex + 1] * blend))
          .round()
          .clamp(0, 255);
      outputRgba[idx + 2] = ((sourceRgba[idx + 2] * (1 - blend)) +
              (referenceRgba[refIndex + 2] * blend))
          .round()
          .clamp(0, 255);
      outputRgba[idx + 3] =
          ((sourceRgba[idx + 3] * (1 - blend)) + (255 * blend))
              .round()
              .clamp(0, 255);
    }
  }

  final img.Image output = img.Image.fromBytes(
    width: width,
    height: height,
    bytes: outputRgba.buffer,
    order: img.ChannelOrder.rgba,
    numChannels: 4,
  );
  return Uint8List.fromList(img.encodePng(output, level: 2));
}

Uint8List _removeBackgroundForLogoPng(Uint8List sourcePngBytes) {
  final img.Image? decoded = img.decodeImage(sourcePngBytes);
  if (decoded == null) {
    throw StateError('Could not decode image for logo background removal.');
  }

  final int width = decoded.width;
  final int height = decoded.height;
  if (width < 2 || height < 2) {
    return sourcePngBytes;
  }

  final int total = width * height;
  final Uint8List rgba = Uint8List.fromList(
    decoded.getBytes(order: img.ChannelOrder.rgba),
  );
  final _LogoBackgroundStats stats = _computeLogoBackgroundStats(
    rgba,
    width,
    height,
  );

  final double colorTolerance =
      (stats.colorStd * 1.85 + 18).clamp(16, 78).toDouble();
  final double strongColorTolerance =
      (colorTolerance * 0.92).clamp(14, 72).toDouble();
  final double localColorTolerance =
      (colorTolerance * 0.78).clamp(12, 64).toDouble();
  final double lumaTolerance =
      (stats.lumaStd * 1.7 + 16).clamp(14, 64).toDouble();

  final double colorToleranceSq = colorTolerance * colorTolerance;
  final double strongColorToleranceSq =
      strongColorTolerance * strongColorTolerance;
  final double localColorToleranceSq =
      localColorTolerance * localColorTolerance;

  final Uint8List candidateMask = Uint8List(total);
  for (int i = 0; i < total; i++) {
    candidateMask[i] = _isLogoBackgroundCandidate(
      rgba: rgba,
      pixelIndex: i,
      stats: stats,
      colorToleranceSquared: colorToleranceSq,
      lumaTolerance: lumaTolerance,
    )
        ? 1
        : 0;
  }

  final Uint8List backgroundMask = Uint8List(total);
  final Int32List queue = Int32List(total);
  int head = 0;
  int tail = 0;

  void seedAt(int x, int y) {
    final int idx = (y * width) + x;
    if (backgroundMask[idx] == 1) return;
    if (candidateMask[idx] == 1) {
      backgroundMask[idx] = 1;
      queue[tail++] = idx;
    }
  }

  for (int x = 0; x < width; x++) {
    seedAt(x, 0);
    if (height > 1) seedAt(x, height - 1);
  }
  for (int y = 1; y < height - 1; y++) {
    seedAt(0, y);
    if (width > 1) seedAt(width - 1, y);
  }

  while (head < tail) {
    final int idx = queue[head++];
    final int x = idx % width;
    final int y = idx ~/ width;
    final int xMin = x > 0 ? x - 1 : x;
    final int xMax = x < width - 1 ? x + 1 : x;
    final int yMin = y > 0 ? y - 1 : y;
    final int yMax = y < height - 1 ? y + 1 : y;

    for (int ny = yMin; ny <= yMax; ny++) {
      final int rowOffset = ny * width;
      for (int nx = xMin; nx <= xMax; nx++) {
        if (nx == x && ny == y) continue;
        final int nidx = rowOffset + nx;
        if (backgroundMask[nidx] == 1 || candidateMask[nidx] == 0) continue;

        final double distToMeanSq = _colorDistanceSquaredToStats(
          rgba,
          nidx,
          stats,
        );
        if (distToMeanSq > colorToleranceSq) continue;

        final double distToCurrentSq = _colorDistanceSquaredBetweenPixels(
          rgba,
          idx,
          nidx,
        );

        if (distToMeanSq <= strongColorToleranceSq ||
            distToCurrentSq <= localColorToleranceSq) {
          backgroundMask[nidx] = 1;
          queue[tail++] = nidx;
        }
      }
    }
  }

  final Uint8List seenCandidate = Uint8List(total);
  for (int i = 0; i < total; i++) {
    if (candidateMask[i] == 0 ||
        backgroundMask[i] == 1 ||
        seenCandidate[i] == 1) {
      continue;
    }
    int compHead = 0;
    int compTail = 0;
    bool touchesBorder = false;
    queue[compTail++] = i;
    seenCandidate[i] = 1;

    while (compHead < compTail) {
      final int idx = queue[compHead++];
      final int x = idx % width;
      final int y = idx ~/ width;
      if (x == 0 || y == 0 || x == width - 1 || y == height - 1) {
        touchesBorder = true;
      }
      final int xMin = x > 0 ? x - 1 : x;
      final int xMax = x < width - 1 ? x + 1 : x;
      final int yMin = y > 0 ? y - 1 : y;
      final int yMax = y < height - 1 ? y + 1 : y;
      for (int ny = yMin; ny <= yMax; ny++) {
        final int rowOffset = ny * width;
        for (int nx = xMin; nx <= xMax; nx++) {
          if (nx == x && ny == y) continue;
          final int nidx = rowOffset + nx;
          if (candidateMask[nidx] == 0 ||
              backgroundMask[nidx] == 1 ||
              seenCandidate[nidx] == 1) {
            continue;
          }
          seenCandidate[nidx] = 1;
          queue[compTail++] = nidx;
        }
      }
    }

    if (!touchesBorder) {
      for (int k = 0; k < compTail; k++) {
        backgroundMask[queue[k]] = 1;
      }
    }
  }

  for (int i = 0; i < total; i++) {
    if (backgroundMask[i] == 1) {
      rgba[(i * 4) + 3] = 0;
    }
  }

  final Uint8List visited = Uint8List(total);
  int largestArea = 0;
  for (int i = 0; i < total; i++) {
    if (visited[i] == 1 || rgba[(i * 4) + 3] == 0) continue;
    int compHead = 0;
    int compTail = 0;
    queue[compTail++] = i;
    visited[i] = 1;
    while (compHead < compTail) {
      final int idx = queue[compHead++];
      final int x = idx % width;
      final int y = idx ~/ width;
      final int xMin = x > 0 ? x - 1 : x;
      final int xMax = x < width - 1 ? x + 1 : x;
      final int yMin = y > 0 ? y - 1 : y;
      final int yMax = y < height - 1 ? y + 1 : y;
      for (int ny = yMin; ny <= yMax; ny++) {
        final int rowOffset = ny * width;
        for (int nx = xMin; nx <= xMax; nx++) {
          if (nx == x && ny == y) continue;
          final int nidx = rowOffset + nx;
          if (visited[nidx] == 1 || rgba[(nidx * 4) + 3] == 0) continue;
          visited[nidx] = 1;
          queue[compTail++] = nidx;
        }
      }
    }
    if (compTail > largestArea) {
      largestArea = compTail;
    }
  }

  final int minArea =
      math.max(10, math.min(1400, (largestArea * 0.004).round()));
  final Uint8List visited2 = Uint8List(total);
  for (int i = 0; i < total; i++) {
    if (visited2[i] == 1 || rgba[(i * 4) + 3] == 0) continue;
    int compHead = 0;
    int compTail = 0;
    queue[compTail++] = i;
    visited2[i] = 1;
    while (compHead < compTail) {
      final int idx = queue[compHead++];
      final int x = idx % width;
      final int y = idx ~/ width;
      final int xMin = x > 0 ? x - 1 : x;
      final int xMax = x < width - 1 ? x + 1 : x;
      final int yMin = y > 0 ? y - 1 : y;
      final int yMax = y < height - 1 ? y + 1 : y;
      for (int ny = yMin; ny <= yMax; ny++) {
        final int rowOffset = ny * width;
        for (int nx = xMin; nx <= xMax; nx++) {
          if (nx == x && ny == y) continue;
          final int nidx = rowOffset + nx;
          if (visited2[nidx] == 1 || rgba[(nidx * 4) + 3] == 0) continue;
          visited2[nidx] = 1;
          queue[compTail++] = nidx;
        }
      }
    }

    if (compTail < minArea) {
      for (int k = 0; k < compTail; k++) {
        rgba[(queue[k] * 4) + 3] = 0;
      }
    }
  }

  final img.Image result = img.Image.fromBytes(
    width: width,
    height: height,
    bytes: rgba.buffer,
    order: img.ChannelOrder.rgba,
    numChannels: 4,
  );
  return Uint8List.fromList(img.encodePng(result, level: 4));
}

Uint8List _applyBlurToImagePng({
  required Uint8List sourcePngBytes,
  required String modeKey,
  required double radius,
  required double amount,
}) {
  final img.Image? decoded = img.decodeImage(sourcePngBytes);
  if (decoded == null) {
    throw StateError('Could not decode source image for blur.');
  }
  if (decoded.width <= 0 || decoded.height <= 0) {
    throw StateError('Invalid image size for blur.');
  }

  final double safeAmount = (amount.clamp(0.0, 100.0) / 100.0).toDouble();
  if (safeAmount <= 0.0001) {
    return sourcePngBytes;
  }
  final int safeRadius = radius.round().clamp(1, 120);

  final img.Image source = decoded.numChannels == 4
      ? img.Image.from(decoded)
      : decoded.convert(numChannels: 4);
  final img.Image gaussianBlurred = img.gaussianBlur(
    img.Image.from(source),
    radius: safeRadius,
  );
  final Uint8List sourceRgba = Uint8List.fromList(
    source.getBytes(order: img.ChannelOrder.rgba),
  );
  final Uint8List gaussianRgba = Uint8List.fromList(
    gaussianBlurred.getBytes(order: img.ChannelOrder.rgba),
  );

  Uint8List effectRgba = gaussianRgba;
  double blendFactor = safeAmount;

  if (modeKey == BlurMode.lens.name) {
    final img.Image lensBlurred = img.adjustColor(
      img.Image.from(gaussianBlurred),
      contrast: (1.0 + (safeAmount * 0.20)).clamp(0.0, 2.0),
      saturation: (1.0 + (safeAmount * 0.12)).clamp(0.0, 2.0),
      brightness: (1.0 + (safeAmount * 0.04)).clamp(0.0, 2.0),
    );
    effectRgba = Uint8List.fromList(
      lensBlurred.getBytes(order: img.ChannelOrder.rgba),
    );
    blendFactor = (0.42 + (safeAmount * 0.58)).clamp(0.0, 1.0).toDouble();
  } else if (modeKey == BlurMode.bokeh.name) {
    final int glowRadius = math.max(2, (safeRadius * 1.8).round());
    final img.Image glowBlurred = img.gaussianBlur(
      img.Image.from(source),
      radius: glowRadius,
    );
    final Uint8List glowRgba = Uint8List.fromList(
      glowBlurred.getBytes(order: img.ChannelOrder.rgba),
    );
    effectRgba = _composeBokehBlurRgba(
      sourceRgba: sourceRgba,
      baseBlurRgba: gaussianRgba,
      glowBlurRgba: glowRgba,
      amountFactor: safeAmount,
    );
    blendFactor = (0.46 + (safeAmount * 0.54)).clamp(0.0, 1.0).toDouble();
  }

  final Uint8List outputRgba = _blendRgbaPreserveAlpha(
    sourceRgba: sourceRgba,
    effectRgba: effectRgba,
    blend: blendFactor,
  );

  final img.Image output = img.Image.fromBytes(
    width: source.width,
    height: source.height,
    bytes: outputRgba.buffer,
    order: img.ChannelOrder.rgba,
    numChannels: 4,
  );
  return Uint8List.fromList(img.encodePng(output, level: 2));
}

Uint8List _composeBokehBlurRgba({
  required Uint8List sourceRgba,
  required Uint8List baseBlurRgba,
  required Uint8List glowBlurRgba,
  required double amountFactor,
}) {
  final Uint8List output = Uint8List(sourceRgba.length);
  final double threshold = (0.64 - (amountFactor * 0.2)).clamp(0.36, 0.74);
  for (int i = 0; i + 3 < sourceRgba.length; i += 4) {
    final int srcR = sourceRgba[i];
    final int srcG = sourceRgba[i + 1];
    final int srcB = sourceRgba[i + 2];
    final int blurR = baseBlurRgba[i];
    final int blurG = baseBlurRgba[i + 1];
    final int blurB = baseBlurRgba[i + 2];
    final int glowR = glowBlurRgba[i];
    final int glowG = glowBlurRgba[i + 1];
    final int glowB = glowBlurRgba[i + 2];

    final double luminance =
        ((0.2126 * srcR) + (0.7152 * srcG) + (0.0722 * srcB)) / 255.0;
    final double sparkle =
        ((luminance - threshold) / (1 - threshold)).clamp(0.0, 1.0).toDouble();
    final double glowMix = (sparkle * amountFactor).clamp(0.0, 1.0).toDouble();
    final double whiteLift = (glowMix * (0.18 + (0.36 * amountFactor))).clamp(
      0.0,
      0.85,
    );
    final double colorLift = (glowMix * 0.36).clamp(0.0, 1.0).toDouble();

    output[i] = (((blurR * (1 - colorLift)) + (glowR * colorLift)) +
            ((255 - blurR) * whiteLift))
        .round()
        .clamp(0, 255);
    output[i + 1] = (((blurG * (1 - colorLift)) + (glowG * colorLift)) +
            ((255 - blurG) * whiteLift))
        .round()
        .clamp(0, 255);
    output[i + 2] = (((blurB * (1 - colorLift)) + (glowB * colorLift)) +
            ((255 - blurB) * whiteLift))
        .round()
        .clamp(0, 255);
    output[i + 3] = sourceRgba[i + 3];
  }
  return output;
}

Uint8List _blendRgbaPreserveAlpha({
  required Uint8List sourceRgba,
  required Uint8List effectRgba,
  required double blend,
}) {
  final double safeBlend = blend.clamp(0.0, 1.0).toDouble();
  if (safeBlend <= 0.0001) return Uint8List.fromList(sourceRgba);
  if (safeBlend >= 0.9999) {
    final Uint8List out = Uint8List.fromList(effectRgba);
    for (int i = 3; i < out.length; i += 4) {
      out[i] = sourceRgba[i];
    }
    return out;
  }
  final Uint8List output = Uint8List(sourceRgba.length);
  final double inv = 1 - safeBlend;
  for (int i = 0; i + 3 < sourceRgba.length; i += 4) {
    output[i] =
        ((sourceRgba[i] * inv) + (effectRgba[i] * safeBlend)).round().clamp(
              0,
              255,
            );
    output[i + 1] =
        ((sourceRgba[i + 1] * inv) + (effectRgba[i + 1] * safeBlend))
            .round()
            .clamp(0, 255);
    output[i + 2] =
        ((sourceRgba[i + 2] * inv) + (effectRgba[i + 2] * safeBlend))
            .round()
            .clamp(0, 255);
    output[i + 3] = sourceRgba[i + 3];
  }
  return output;
}

Map<String, Object> _prepareExpandSourcePayloadIsolate({
  required Uint8List sourceRgba,
  required int sourceWidth,
  required int sourceHeight,
  required double leftExpand,
  required double topExpand,
  required double rightExpand,
  required double bottomExpand,
  required int maxLongSide,
  required int maxPixels,
  required int sourceJpegQuality,
}) {
  final double safeLeft = leftExpand.clamp(0.0, 3.0).toDouble();
  final double safeTop = topExpand.clamp(0.0, 3.0).toDouble();
  final double safeRight = rightExpand.clamp(0.0, 3.0).toDouble();
  final double safeBottom = bottomExpand.clamp(0.0, 3.0).toDouble();

  img.Image working = img.Image.fromBytes(
    width: sourceWidth,
    height: sourceHeight,
    bytes: sourceRgba.buffer,
    order: img.ChannelOrder.rgba,
    numChannels: 4,
  );

  final double widthFactor = 1.0 + safeLeft + safeRight;
  final double heightFactor = 1.0 + safeTop + safeBottom;
  final double targetWidthF = working.width * widthFactor;
  final double targetHeightF = working.height * heightFactor;

  double scale = 1.0;
  final int safeMaxLong = math.max(512, maxLongSide);
  final int safeMaxPixels = math.max(1024 * 1024, maxPixels);
  final double longSide = math.max(targetWidthF, targetHeightF);
  if (longSide > safeMaxLong) {
    scale = math.min(scale, safeMaxLong / longSide);
  }
  final double targetPixels = targetWidthF * targetHeightF;
  if (targetPixels > safeMaxPixels) {
    scale = math.min(scale, math.sqrt(safeMaxPixels / targetPixels));
  }
  if (scale < 0.999) {
    final int scaledWidth = math.max(1, (working.width * scale).round());
    final int scaledHeight = math.max(1, (working.height * scale).round());
    working = img.copyResize(
      working,
      width: scaledWidth,
      height: scaledHeight,
      interpolation: img.Interpolation.linear,
    );
  }

  final int srcW = working.width;
  final int srcH = working.height;
  final int leftPx = math.max(0, (srcW * safeLeft).round());
  final int topPx = math.max(0, (srcH * safeTop).round());
  final int rightPx = math.max(0, (srcW * safeRight).round());
  final int bottomPx = math.max(0, (srcH * safeBottom).round());
  final int outW = math.max(srcW + leftPx + rightPx, 1);
  final int outH = math.max(srcH + topPx + bottomPx, 1);

  final Uint8List src = working.getBytes(order: img.ChannelOrder.rgba);
  final Uint8List expandedRgba = Uint8List(outW * outH * 4);
  for (int y = 0; y < outH; y++) {
    final int sy = (y - topPx).clamp(0, srcH - 1);
    for (int x = 0; x < outW; x++) {
      final int sx = (x - leftPx).clamp(0, srcW - 1);
      final int srcIndex = ((sy * srcW) + sx) * 4;
      final int outIndex = ((y * outW) + x) * 4;
      expandedRgba[outIndex] = src[srcIndex];
      expandedRgba[outIndex + 1] = src[srcIndex + 1];
      expandedRgba[outIndex + 2] = src[srcIndex + 2];
      expandedRgba[outIndex + 3] = 255;
    }
  }

  final img.Image expandedImage = img.Image.fromBytes(
    width: outW,
    height: outH,
    bytes: expandedRgba.buffer,
    order: img.ChannelOrder.rgba,
    numChannels: 4,
  );
  final int safeJpegQuality = sourceJpegQuality.clamp(70, 100).toInt();
  return <String, Object>{
    'sourceImageBytes': Uint8List.fromList(
      img.encodeJpg(expandedImage, quality: safeJpegQuality),
    ),
  };
}

Uint8List _downscaleRgbaForExportIsolate({
  required Uint8List sourceRgba,
  required int sourceWidth,
  required int sourceHeight,
  required int targetWidth,
  required int targetHeight,
  required bool applySharpen,
}) {
  img.Image working = img.Image.fromBytes(
    width: sourceWidth,
    height: sourceHeight,
    bytes: sourceRgba.buffer,
    order: img.ChannelOrder.rgba,
    numChannels: 4,
  );

  while (working.width > (targetWidth * 1.7) ||
      working.height > (targetHeight * 1.7)) {
    final int stepWidth = math.max(targetWidth, (working.width / 1.7).round());
    final int stepHeight =
        math.max(targetHeight, (working.height / 1.7).round());
    if (stepWidth == working.width && stepHeight == working.height) {
      break;
    }
    working = img.copyResize(
      working,
      width: stepWidth,
      height: stepHeight,
      interpolation: img.Interpolation.linear,
    );
  }

  final img.Image resized =
      (working.width == targetWidth && working.height == targetHeight)
          ? working
          : img.copyResize(
              working,
              width: targetWidth,
              height: targetHeight,
              interpolation: img.Interpolation.cubic,
            );

  if (applySharpen) {
    final double downscaleRatio = math.max(
      sourceWidth / targetWidth,
      sourceHeight / targetHeight,
    );
    final double amount = downscaleRatio <= 1.6 ? 0.09 : 0.04;
    img.convolution(
      resized,
      filter: const <num>[
        0,
        -1,
        0,
        -1,
        5,
        -1,
        0,
        -1,
        0,
      ],
      amount: amount,
    );
  }

  return Uint8List.fromList(resized.getBytes(order: img.ChannelOrder.rgba));
}

Uint8List _encodeJpgFromRgbaForAiUploadIsolate({
  required Uint8List rgba,
  required int width,
  required int height,
  required int quality,
  required int maxLongEdge,
}) {
  img.Image decoded = img.Image.fromBytes(
    width: width,
    height: height,
    bytes: rgba.buffer,
    order: img.ChannelOrder.rgba,
    numChannels: 4,
  );
  final int longestSide = math.max(decoded.width, decoded.height);
  final int safeMaxLongEdge = math.max(1024, maxLongEdge);
  if (longestSide > safeMaxLongEdge) {
    final double ratio = safeMaxLongEdge / longestSide;
    final int targetWidth = math.max(1, (decoded.width * ratio).round());
    final int targetHeight = math.max(1, (decoded.height * ratio).round());
    decoded = img.copyResize(
      decoded,
      width: targetWidth,
      height: targetHeight,
      interpolation: img.Interpolation.linear,
    );
  }
  return Uint8List.fromList(
    img.encodeJpg(decoded, quality: quality.clamp(70, 96).toInt()),
  );
}

Uint8List _encodeJpgFromBytesForAiUploadIsolate({
  required Uint8List encodedBytes,
  required int quality,
  required int maxLongEdge,
}) {
  img.Image? decoded = img.decodeImage(encodedBytes);
  if (decoded == null) {
    return encodedBytes;
  }
  decoded = img.bakeOrientation(decoded);
  final int longestSide = math.max(decoded.width, decoded.height);
  final int safeMaxLongEdge = math.max(1024, maxLongEdge);
  if (longestSide > safeMaxLongEdge) {
    final double ratio = safeMaxLongEdge / longestSide;
    final int targetWidth = math.max(1, (decoded.width * ratio).round());
    final int targetHeight = math.max(1, (decoded.height * ratio).round());
    decoded = img.copyResize(
      decoded,
      width: targetWidth,
      height: targetHeight,
      interpolation: img.Interpolation.linear,
    );
  }
  return Uint8List.fromList(
    img.encodeJpg(decoded, quality: quality.clamp(70, 95).toInt()),
  );
}

Uint8List _encodeJpgFromRgbaForExportIsolate({
  required Uint8List rgba,
  required int width,
  required int height,
  required int quality,
}) {
  final img.Image decoded = img.Image.fromBytes(
    width: width,
    height: height,
    bytes: rgba.buffer,
    order: img.ChannelOrder.rgba,
    numChannels: 4,
  );
  return Uint8List.fromList(img.encodeJpg(decoded, quality: quality));
}

class _TopToolsSnapPhysics extends ScrollPhysics {
  const _TopToolsSnapPhysics({
    required this.itemExtent,
    super.parent,
  });

  final double itemExtent;

  @override
  _TopToolsSnapPhysics applyTo(ScrollPhysics? ancestor) {
    return _TopToolsSnapPhysics(
      itemExtent: itemExtent,
      parent: buildParent(ancestor),
    );
  }

  double _targetPixels(ScrollMetrics position, double velocity) {
    final Tolerance tolerance = toleranceFor(position);
    double page = position.pixels / itemExtent;
    if (velocity < -tolerance.velocity) {
      page -= 0.5;
    } else if (velocity > tolerance.velocity) {
      page += 0.5;
    }
    return (page.roundToDouble() * itemExtent).clamp(
      position.minScrollExtent,
      position.maxScrollExtent,
    );
  }

  @override
  Simulation? createBallisticSimulation(
    ScrollMetrics position,
    double velocity,
  ) {
    final Simulation? parentSimulation =
        super.createBallisticSimulation(position, velocity);
    if (parentSimulation == null) return null;
    final double target = _targetPixels(position, velocity);
    if ((target - position.pixels).abs() < 0.5) {
      return parentSimulation;
    }
    return ScrollSpringSimulation(
      spring,
      position.pixels,
      target,
      velocity,
      tolerance: toleranceFor(position),
    );
  }
}
